def local_repository_root() -> Path:
    return PROJECT_ROOT.parent if PROJECT_ROOT.name == "literature_and_patents_search_skills" else PROJECT_ROOT


def ensure_local_git_repository() -> dict[str, Any]:
    repo_root = local_repository_root()
    if (repo_root / ".git").exists():
        return {"enabled": True, "status": "existing", "root": str(repo_root)}
    git_exe = shutil.which("git")
    if not git_exe:
        return {"enabled": False, "status": "git_not_found", "root": str(repo_root)}
    try:
        completed = subprocess.run(
            [git_exe, "init"],
            cwd=repo_root,
            text=True,
            capture_output=True,
            timeout=30,
        )
    except Exception as exc:
        return {"enabled": False, "status": f"git_init_failed:{exc.__class__.__name__}", "root": str(repo_root)}
    if completed.returncode != 0:
        return {"enabled": False, "status": f"git_init_exit_{completed.returncode}", "root": str(repo_root)}
    return {"enabled": True, "status": "initialized", "root": str(repo_root)}

