@dataclass
class SourceAttemptResult:
    records: list[Any]
    status: str = "complete"
    reason: str = ""
    fallback_hint: str = ""
    path: str = ""
    query_variant: str = "primary"
    reason_code: str = ""
    category: str = "source_run"
    retryable: bool = False
    retry_at: str = ""

    def __post_init__(self) -> None:
        if not self.reason or self.reason_code:
            return
        inferred = source_reason_detail(self.reason)
        self.reason_code = first_string(inferred.get("reason_code"))
        self.category = first_string(inferred.get("category")) or "source_run"
        self.retryable = bool(inferred.get("retryable"))
        self.retry_at = first_string(inferred.get("retry_at"))

    def reason_detail(self) -> dict[str, Any]:
        inferred = source_reason_detail(self.reason)
        return structured_reason(
            self.reason_code or first_string(inferred.get("reason_code")),
            category=self.category
            if self.reason_code
            else first_string(inferred.get("category")) or "source_run",
            retryable=self.retryable
            if self.reason_code
            else bool(inferred.get("retryable")),
            retry_at=self.retry_at or first_string(inferred.get("retry_at")),
        )


def coerce_source_attempt_result(
    value: SourceAttemptResult | list[Any],
    *,
    path: str,
    query_variant: str,
) -> SourceAttemptResult:
    if isinstance(value, SourceAttemptResult):
        detail = value.reason_detail()
        value.reason_code = first_string(detail.get("reason_code"))
        value.category = first_string(detail.get("category")) or "source_run"
        value.retryable = bool(detail.get("retryable"))
        value.retry_at = first_string(detail.get("retry_at"))
        return value
    if isinstance(value, list):
        return SourceAttemptResult(
            records=value,
            status="complete",
            path=path,
            query_variant=query_variant,
        )
    raise TypeError(f"Unexpected source attempt result: {type(value).__name__}")


