def positive_int_environment(name: str, default: int, *, minimum: int = 1) -> int:
    raw = os.getenv(name, "").strip()
    if not raw:
        return max(minimum, int(default))
    try:
        value = int(raw)
    except ValueError as exc:
        raise ValueError(f"{name} must be a positive integer") from exc
    if value < minimum:
        raise ValueError(f"{name} must be at least {minimum}")
    return value


def doi_cache_ttl_seconds(outcome: str) -> int:
    if outcome == "positive":
        return positive_int_environment(
            "LAPS_DOI_CACHE_POSITIVE_TTL_SECONDS",
            DEFAULT_DOI_CACHE_POSITIVE_TTL_SECONDS,
            minimum=60,
        )
    if outcome == "negative":
        return positive_int_environment(
            "LAPS_DOI_CACHE_NEGATIVE_TTL_SECONDS",
            DEFAULT_DOI_CACHE_NEGATIVE_TTL_SECONDS,
            minimum=60,
        )
    raise ValueError(f"Unsupported DOI cache outcome: {outcome}")


def doi_enrichment_cache_identity(
    *,
    normalized_title: str,
    source_input: str,
    publication_year: int = 0,
    first_author: str = "",
    enricher_version: str = DOI_ENRICHER_VERSION,
    registry_version: str = REGISTRY_VERSION,
    schema_version: str = CANONICAL_SCHEMA_VERSION,
) -> tuple[str, dict[str, Any]]:
    identity = {
        "normalized_title": normalize_title(normalized_title),
        "source_input": unicodedata.normalize("NFKC", source_input or "").casefold().strip(),
        "publication_year": max(0, int(publication_year or 0)),
        "first_author": normalize_title(first_author),
        "enricher_version": first_string(enricher_version),
        "registry_version": first_string(registry_version),
        "registry_schema_version": REGISTRY_SCHEMA_VERSION,
        "schema_version": first_string(schema_version),
    }
    encoded = json.dumps(
        identity,
        ensure_ascii=False,
        sort_keys=True,
        separators=(",", ":"),
    ).encode("utf-8")
    return hashlib.sha256(encoded).hexdigest(), identity


def structured_reason(
    reason_code: str,
    *,
    category: str,
    retryable: bool = False,
    retry_at: str | None = None,
) -> dict[str, Any]:
    return {
        "reason_code": first_string(reason_code) or "unknown",
        "category": first_string(category) or "unknown",
        "retryable": bool(retryable),
        "retry_at": first_string(retry_at) or None,
    }


def transient_http_attempt(result: "HttpAttemptResult") -> bool:
    return bool(
        result.retryable
        or result.status_code in {0, 408, 425, 429, 500, 502, 503, 504}
        or result.error_code in {"timeout", "network_error", "rate_limited"}
    )


def retry_after_seconds_from_text(value: str) -> int:
    match = re.search(r"retry_after_seconds[=:](\d+)", value or "", flags=re.IGNORECASE)
    return max(0, int(match.group(1))) if match else 0


def response_retry_after_seconds(response: Any, *, now: datetime | None = None) -> int:
    raw = first_string(response.headers.get("retry-after") if hasattr(response, "headers") else "")
    try:
        return max(0, int(float(raw)))
    except (TypeError, ValueError):
        try:
            retry_at = parsedate_to_datetime(raw)
        except (TypeError, ValueError, OverflowError):
            return 0
        if retry_at.tzinfo is None:
            retry_at = retry_at.replace(tzinfo=timezone.utc)
        current = now or datetime.now(timezone.utc)
        if current.tzinfo is None:
            current = current.replace(tzinfo=timezone.utc)
        remaining = (retry_at - current).total_seconds()
        return max(0, int(remaining + 0.999))


def retry_at_iso(seconds: float, *, now: float | None = None) -> str:
    if seconds <= 0:
        return ""
    current = time.time() if now is None else float(now)
    return datetime.fromtimestamp(
        current + float(seconds),
        tz=timezone.utc,
    ).isoformat(timespec="seconds")


def structured_retry_at_active(
    run: Mapping[str, Any] | None,
    *,
    now: datetime | None = None,
) -> bool:
    if not run or not bool(run.get("retryable")):
        return False
    raw_retry_at = first_string(run.get("retry_at"))
    if not raw_retry_at:
        return False
    try:
        retry_at = datetime.fromisoformat(raw_retry_at)
    except (TypeError, ValueError):
        return False
    if retry_at.tzinfo is None:
        retry_at = retry_at.replace(tzinfo=timezone.utc)
    current = now or datetime.now(timezone.utc)
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    return current < retry_at


def rate_limit_cooldown_active(reason: str, updated_at: str, *, now: datetime | None = None) -> bool:
    retry_after = retry_after_seconds_from_text(reason)
    if retry_after <= 0 or "rate_limit" not in (reason or "").casefold():
        return False
    try:
        updated = datetime.fromisoformat(updated_at)
        if updated.tzinfo is None:
            updated = updated.replace(tzinfo=timezone.utc)
    except (TypeError, ValueError):
        return False
    current = now or datetime.now(timezone.utc)
    return (current - updated).total_seconds() < retry_after


def auth_entry_cooldown_active(
    reason: str,
    updated_at: str,
    *,
    now: datetime | None = None,
) -> bool:
    normalized_reason = (reason or "").casefold()
    if not normalized_reason.startswith(
        (
            "all_auth_entries_cooled_down",
            "saved_auth_state_challenge_recurred_after_recovery",
            "post_auth_challenge_recurred",
        )
    ):
        return False
    retry_after = retry_after_seconds_from_text(reason)
    if retry_after <= 0:
        return False
    try:
        updated = datetime.fromisoformat(updated_at)
        if updated.tzinfo is None:
            updated = updated.replace(tzinfo=timezone.utc)
    except (TypeError, ValueError):
        return False
    current = now or datetime.now(timezone.utc)
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    return (current - updated).total_seconds() < retry_after


class SearchStateStore:
    def __init__(self, path: Path) -> None:
        self.path = path
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self._lock = threading.RLock()
        self._connection = sqlite3.connect(str(path), check_same_thread=False)
        self._connection.row_factory = sqlite3.Row
        with self._connection:
            self._connection.execute("PRAGMA journal_mode=WAL")
            self._connection.execute("PRAGMA synchronous=NORMAL")
            self._connection.execute(
                """
                CREATE TABLE IF NOT EXISTS source_runs (
                    record_type TEXT NOT NULL,
                    keyword TEXT NOT NULL,
                    source TEXT NOT NULL,
                    path TEXT NOT NULL,
                    query_variant TEXT NOT NULL DEFAULT 'primary_all_terms',
                    config_fingerprint TEXT NOT NULL,
                    status TEXT NOT NULL,
                    next_token TEXT NOT NULL DEFAULT '',
                    pages INTEGER NOT NULL DEFAULT 0,
                    fetched INTEGER NOT NULL DEFAULT 0,
                    accepted INTEGER NOT NULL DEFAULT 0,
                    duplicates INTEGER NOT NULL DEFAULT 0,
                    updated_records INTEGER NOT NULL DEFAULT 0,
                    conflicting_records INTEGER NOT NULL DEFAULT 0,
                    dropped INTEGER NOT NULL DEFAULT 0,
                    total_hint INTEGER,
                    page_signature TEXT NOT NULL DEFAULT '',
                    reason TEXT NOT NULL DEFAULT '',
                    reason_code TEXT NOT NULL DEFAULT '',
                    category TEXT NOT NULL DEFAULT 'source_run',
                    retryable INTEGER NOT NULL DEFAULT 0,
                    retry_at TEXT,
                    updated_at TEXT NOT NULL,
                    PRIMARY KEY (record_type, keyword, source, path, query_variant)
                )
                """
            )
            self._connection.execute(
                """
                CREATE TABLE IF NOT EXISTS occurrences (
                    record_type TEXT NOT NULL,
                    identity TEXT NOT NULL,
                    keyword TEXT NOT NULL,
                    source TEXT NOT NULL,
                    payload_json TEXT NOT NULL,
                    keyword_index INTEGER NOT NULL DEFAULT 0,
                    source_index INTEGER NOT NULL DEFAULT 0,
                    rank_value INTEGER,
                    query_variants_json TEXT NOT NULL DEFAULT '[]',
                    provenance_json TEXT NOT NULL DEFAULT '[]',
                    updated_at TEXT NOT NULL,
                    PRIMARY KEY (record_type, identity, keyword, source)
                )
                """
            )
            self._connection.execute(
                """
                CREATE TABLE IF NOT EXISTS requested_source_scope (
                    record_type TEXT NOT NULL,
                    keyword TEXT NOT NULL,
                    source TEXT NOT NULL,
                    config_fingerprint TEXT NOT NULL,
                    requested_at TEXT NOT NULL,
                    PRIMARY KEY (record_type, keyword, source)
                )
                """
            )
            self._connection.execute(
                """
                CREATE TABLE IF NOT EXISTS host_cooldowns (
                    host TEXT PRIMARY KEY,
                    cooldown_until REAL NOT NULL DEFAULT 0,
                    reason TEXT NOT NULL DEFAULT '',
                    updated_at TEXT NOT NULL
                )
                """
            )
            self._connection.execute(
                """
                CREATE TABLE IF NOT EXISTS doi_enrichment_cache (
                    cache_key TEXT PRIMARY KEY,
                    normalized_title TEXT NOT NULL,
                    source_input TEXT NOT NULL,
                    publication_year INTEGER NOT NULL DEFAULT 0,
                    first_author TEXT NOT NULL DEFAULT '',
                    enricher_version TEXT NOT NULL,
                    registry_version TEXT NOT NULL,
                    registry_schema_version TEXT NOT NULL,
                    schema_version TEXT NOT NULL,
                    outcome TEXT NOT NULL CHECK(outcome IN ('positive', 'negative')),
                    doi TEXT NOT NULL DEFAULT '',
                    reason_code TEXT NOT NULL,
                    category TEXT NOT NULL DEFAULT 'doi_enrichment',
                    retryable INTEGER NOT NULL DEFAULT 0,
                    retry_at TEXT,
                    updated_at REAL NOT NULL,
                    expires_at REAL NOT NULL
                )
                """
            )
            self._connection.execute(
                """
                CREATE INDEX IF NOT EXISTS idx_doi_enrichment_cache_expiry
                ON doi_enrichment_cache(expires_at)
                """
            )
            self._migrate_schema()

    def _table_columns(self, table: str) -> set[str]:
        rows = self._connection.execute(f"PRAGMA table_info({table})").fetchall()
        return {str(row["name"]) for row in rows}

    def _create_source_runs_table(self) -> None:
        self._connection.execute(
            """
            CREATE TABLE source_runs (
                record_type TEXT NOT NULL,
                keyword TEXT NOT NULL,
                source TEXT NOT NULL,
                path TEXT NOT NULL,
                query_variant TEXT NOT NULL DEFAULT 'primary_all_terms',
                config_fingerprint TEXT NOT NULL,
                status TEXT NOT NULL,
                next_token TEXT NOT NULL DEFAULT '',
                pages INTEGER NOT NULL DEFAULT 0,
                fetched INTEGER NOT NULL DEFAULT 0,
                accepted INTEGER NOT NULL DEFAULT 0,
                duplicates INTEGER NOT NULL DEFAULT 0,
                updated_records INTEGER NOT NULL DEFAULT 0,
                conflicting_records INTEGER NOT NULL DEFAULT 0,
                dropped INTEGER NOT NULL DEFAULT 0,
                total_hint INTEGER,
                page_signature TEXT NOT NULL DEFAULT '',
                reason TEXT NOT NULL DEFAULT '',
                reason_code TEXT NOT NULL DEFAULT '',
                category TEXT NOT NULL DEFAULT 'source_run',
                retryable INTEGER NOT NULL DEFAULT 0,
                retry_at TEXT,
                updated_at TEXT NOT NULL,
                PRIMARY KEY (record_type, keyword, source, path, query_variant)
            )
            """
        )

    def _migrate_schema(self) -> None:
        source_columns = self._table_columns("source_runs")
        if "query_variant" not in source_columns:
            self._connection.execute("ALTER TABLE source_runs RENAME TO source_runs_legacy_v1")
            self._create_source_runs_table()
            self._connection.execute(
                """
                INSERT INTO source_runs (
                    record_type, keyword, source, path, query_variant,
                    config_fingerprint, status, next_token, pages, fetched,
                    accepted, duplicates, updated_records, conflicting_records,
                    dropped, total_hint, page_signature, reason, updated_at
                    , reason_code, category, retryable, retry_at
                )
                SELECT record_type, keyword, source, path, 'legacy_primary',
                       config_fingerprint, status, next_token, pages, fetched,
                       accepted, duplicates, 0, 0, dropped, total_hint,
                       page_signature, reason, updated_at,
                       '', 'source_run', 0, NULL
                FROM source_runs_legacy_v1
                """
            )
            self._connection.execute("DROP TABLE source_runs_legacy_v1")
            source_columns = self._table_columns("source_runs")
        for column, definition in (
            ("updated_records", "INTEGER NOT NULL DEFAULT 0"),
            ("conflicting_records", "INTEGER NOT NULL DEFAULT 0"),
            ("reason_code", "TEXT NOT NULL DEFAULT ''"),
            ("category", "TEXT NOT NULL DEFAULT 'source_run'"),
            ("retryable", "INTEGER NOT NULL DEFAULT 0"),
            ("retry_at", "TEXT"),
        ):
            if column not in source_columns:
                self._connection.execute(
                    f"ALTER TABLE source_runs ADD COLUMN {column} {definition}"
                )
        occurrence_columns = self._table_columns("occurrences")
        if "query_variants_json" not in occurrence_columns:
            self._connection.execute(
                "ALTER TABLE occurrences ADD COLUMN query_variants_json TEXT NOT NULL DEFAULT '[]'"
            )
        if "provenance_json" not in occurrence_columns:
            self._connection.execute(
                "ALTER TABLE occurrences ADD COLUMN provenance_json TEXT NOT NULL DEFAULT '[]'"
            )
        legacy_reason_rows = self._connection.execute(
            """
            SELECT rowid, status, reason, updated_at
            FROM source_runs
            WHERE reason_code=''
            """
        ).fetchall()
        for row in legacy_reason_rows:
            detail = source_reason_detail(first_string(row["reason"]))
            reason_code = first_string(detail.get("reason_code"))
            if reason_code == "unspecified" and row["status"] == "complete":
                reason_code = "source_complete"
            legacy_retry_at = ""
            retry_after = retry_after_seconds_from_text(first_string(row["reason"]))
            if bool(detail.get("retryable")) and retry_after > 0:
                try:
                    updated_at = datetime.fromisoformat(
                        first_string(row["updated_at"])
                    )
                    if updated_at.tzinfo is None:
                        updated_at = updated_at.replace(tzinfo=timezone.utc)
                    legacy_retry_at = (updated_at + timedelta(seconds=retry_after)).isoformat(
                        timespec="seconds"
                    )
                except (TypeError, ValueError):
                    legacy_retry_at = ""
            self._connection.execute(
                """
                UPDATE source_runs
                SET reason_code=?, category=?, retryable=?, retry_at=?
                WHERE rowid=?
                """,
                (
                    reason_code,
                    first_string(detail.get("category")) or "source_run",
                    int(bool(detail.get("retryable"))),
                    legacy_retry_at or None,
                    int(row["rowid"]),
                ),
            )

    def close(self) -> None:
        with self._lock:
            self._connection.close()

    def __enter__(self) -> "SearchStateStore":
        return self

    def __exit__(self, exc_type: Any, exc: Any, traceback: Any) -> None:
        del exc_type, exc, traceback
        self.close()

    @staticmethod
    def _run_key(
        record_type: str,
        keyword: str,
        source: str,
        path: str,
        query_variant: str,
    ) -> tuple[str, str, str, str, str]:
        return record_type, keyword, source, path, query_variant

    def get_run(
        self,
        record_type: str,
        keyword: str,
        source: str,
        path: str,
        query_variant: str | None = None,
    ) -> dict[str, Any] | None:
        effective_variant = query_variant or current_query_variant()
        with self._lock:
            row = self._connection.execute(
                "SELECT * FROM source_runs WHERE record_type=? AND keyword=? AND source=? AND path=? AND query_variant=?",
                self._run_key(record_type, keyword, source, path, effective_variant),
            ).fetchone()
        return dict(row) if row is not None else None

    def reusable_run(
        self,
        record_type: str,
        keyword: str,
        source: str,
        path: str,
        config_fingerprint: str,
        query_variant: str | None = None,
    ) -> bool:
        run = self.get_run(record_type, keyword, source, path, query_variant)
        stable_incomplete = bool(
            run
            and run.get("status") == "incomplete"
            and str(run.get("reason") or "").startswith("source_result_window_cap:")
        )
        active_rate_limit = bool(
            run
            and run.get("status") == "incomplete"
            and rate_limit_cooldown_active(str(run.get("reason") or ""), str(run.get("updated_at") or ""))
        )
        active_auth_entry_cooldown = bool(
            run
            and run.get("status") == "incomplete"
            and auth_entry_cooldown_active(
                str(run.get("reason") or ""),
                str(run.get("updated_at") or ""),
            )
        )
        active_structured_retry = bool(
            run
            and run.get("status") == "incomplete"
            and structured_retry_at_active(run)
        )
        return bool(
            run
            and run.get("config_fingerprint") == config_fingerprint
            and (
                run.get("status") in {"complete", "blocked"}
                or stable_incomplete
                or active_rate_limit
                or active_auth_entry_cooldown
                or active_structured_retry
            )
        )

    def keywords(self) -> list[str]:
        with self._lock:
            occurrence_rows = self._connection.execute(
                """
                SELECT keyword, MIN(keyword_index) AS keyword_index
                FROM occurrences
                WHERE keyword<>''
                GROUP BY keyword
                ORDER BY keyword_index, keyword
                """
            ).fetchall()
            source_run_rows = self._connection.execute(
                """
                SELECT keyword, MIN(rowid) AS first_seen
                FROM source_runs
                WHERE keyword<>''
                GROUP BY keyword
                ORDER BY first_seen, keyword
                """
            ).fetchall()
        keywords = [str(row["keyword"]) for row in occurrence_rows]
        seen = set(keywords)
        for row in source_run_rows:
            keyword = str(row["keyword"])
            if keyword not in seen:
                keywords.append(keyword)
                seen.add(keyword)
        return keywords

    def replace_requested_source_scope(
        self,
        expected_source_keys: Iterable[SearchSourceKey],
        config_fingerprint: str,
    ) -> None:
        """Persist the latest requested provider scope before producer work.

        A source-run row is created only once a worker starts.  Keeping the
        request scope separately lets checkpoint materialization distinguish a
        legitimately source-filtered run from a producer interruption that
        occurred before one or more workers registered their rows.
        """

        normalized = sorted(
            {
                (
                    first_string(record_type),
                    first_string(keyword),
                    first_string(source),
                )
                for record_type, keyword, source in expected_source_keys
                if first_string(record_type)
                and first_string(keyword)
                and first_string(source)
            }
        )
        requested_pairs = sorted(
            {(record_type, keyword) for record_type, keyword, _ in normalized}
        )
        if not requested_pairs:
            return
        requested_at = datetime.now(timezone.utc).isoformat(timespec="seconds")
        with self._lock, self._connection:
            for record_type, keyword in requested_pairs:
                self._connection.execute(
                    """
                    DELETE FROM requested_source_scope
                    WHERE record_type=? AND keyword=?
                    """,
                    (record_type, keyword),
                )
            self._connection.executemany(
                """
                INSERT INTO requested_source_scope (
                    record_type, keyword, source, config_fingerprint,
                    requested_at
                ) VALUES (?, ?, ?, ?, ?)
                """,
                [
                    (
                        record_type,
                        keyword,
                        source,
                        config_fingerprint,
                        requested_at,
                    )
                    for record_type, keyword, source in normalized
                ],
            )

    def requested_source_keys(
        self,
        *,
        keywords: Iterable[str],
        include_literature: bool,
        include_patents: bool,
    ) -> set[SearchSourceKey]:
        selected_keywords = {
            first_string(keyword) for keyword in keywords if first_string(keyword)
        }
        selected_types = {
            record_type
            for record_type, included in (
                ("literature", include_literature),
                ("patent", include_patents),
            )
            if included
        }
        with self._lock:
            rows = self._connection.execute(
                """
                SELECT record_type, keyword, source
                FROM requested_source_scope
                ORDER BY record_type, keyword, source
                """
            ).fetchall()
        return {
            (
                first_string(row["record_type"]),
                first_string(row["keyword"]),
                first_string(row["source"]),
            )
            for row in rows
            if first_string(row["record_type"]) in selected_types
            and first_string(row["keyword"]) in selected_keywords
            and first_string(row["source"])
        }

    def reset(
        self,
        record_type: str | None = None,
        sources: set[str] | None = None,
        *,
        clear_occurrences: bool = False,
    ) -> None:
        clauses: list[str] = []
        params: list[Any] = []
        if record_type:
            clauses.append("record_type=?")
            params.append(record_type)
        if sources:
            placeholders = ",".join("?" for _ in sources)
            clauses.append(f"source IN ({placeholders})")
            params.extend(sorted(sources))
        where = f" WHERE {' AND '.join(clauses)}" if clauses else ""
        with self._lock, self._connection:
            self._connection.execute(f"DELETE FROM source_runs{where}", params)
            if clear_occurrences:
                self._connection.execute(f"DELETE FROM occurrences{where}", params)

    def invalidate_stale_runs(
        self,
        record_type: str,
        keyword: str,
        source: str,
        config_fingerprint: str,
    ) -> bool:
        with self._lock:
            stale = self._connection.execute(
                """
                SELECT 1 FROM source_runs
                WHERE record_type=? AND keyword=? AND source=? AND config_fingerprint<>?
                LIMIT 1
                """,
                (record_type, keyword, source, config_fingerprint),
            ).fetchone()
        if stale is None:
            return False
        return True

    def mark_run(
        self,
        record_type: str,
        keyword: str,
        source: str,
        path: str,
        config_fingerprint: str,
        status: str,
        *,
        query_variant: str | None = None,
        next_token: str = "",
        pages: int = 0,
        fetched: int = 0,
        accepted: int = 0,
        duplicates: int = 0,
        updated_records: int = 0,
        conflicting_records: int = 0,
        dropped: int = 0,
        total_hint: int | None = None,
        page_signature: str = "",
        reason: str = "",
        reason_code: str = "",
        category: str = "",
        retryable: bool | None = None,
        retry_at: str = "",
    ) -> None:
        if status not in SOURCE_RUN_STATUSES:
            raise ValueError(f"Unsupported source run status: {status}")
        effective_variant = query_variant or current_query_variant()
        inferred_reason = source_reason_detail(reason)
        effective_reason_code = reason_code or first_string(
            inferred_reason.get("reason_code")
        )
        effective_category = category or first_string(
            inferred_reason.get("category")
        ) or "source_run"
        effective_retryable = (
            bool(inferred_reason.get("retryable"))
            if retryable is None
            else bool(retryable)
        )
        effective_retry_at = retry_at or first_string(inferred_reason.get("retry_at"))
        with self._lock, self._connection:
            self._connection.execute(
                """
                INSERT INTO source_runs (
                    record_type, keyword, source, path, query_variant,
                    config_fingerprint, status, next_token, pages, fetched,
                    accepted, duplicates, updated_records, conflicting_records, dropped,
                    total_hint, page_signature, reason, updated_at,
                    reason_code, category, retryable, retry_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(record_type, keyword, source, path, query_variant) DO UPDATE SET
                    config_fingerprint=excluded.config_fingerprint,
                    status=excluded.status,
                    next_token=excluded.next_token,
                    pages=excluded.pages,
                    fetched=excluded.fetched,
                    accepted=excluded.accepted,
                    duplicates=excluded.duplicates,
                    updated_records=excluded.updated_records,
                    conflicting_records=excluded.conflicting_records,
                    dropped=excluded.dropped,
                    total_hint=excluded.total_hint,
                    page_signature=excluded.page_signature,
                    reason=excluded.reason,
                    reason_code=excluded.reason_code,
                    category=excluded.category,
                    retryable=excluded.retryable,
                    retry_at=excluded.retry_at,
                    updated_at=excluded.updated_at
                """,
                (
                    record_type,
                    keyword,
                    source,
                    path,
                    effective_variant,
                    config_fingerprint,
                    status,
                    next_token,
                    pages,
                    fetched,
                    accepted,
                    duplicates,
                    updated_records,
                    conflicting_records,
                    dropped,
                    total_hint,
                    page_signature,
                    reason,
                    utc_now(),
                    effective_reason_code,
                    effective_category,
                    int(effective_retryable),
                    effective_retry_at or None,
                ),
            )

    def persist_page(
        self,
        record_type: str,
        keyword: str,
        source: str,
        path: str,
        config_fingerprint: str,
        page: SearchPage,
        *,
        page_number: int,
        keyword_index: int,
        source_index: int,
        query_variant: str | None = None,
    ) -> None:
        effective_variant = query_variant or current_query_variant()
        previous = self.get_run(
            record_type,
            keyword,
            source,
            path,
            effective_variant,
        ) or {}
        previous_signature = str(previous.get("page_signature") or "")
        repeated_signature = bool(page.page_signature and previous_signature == page.page_signature)
        status = "complete" if page.exhausted else "running"
        reason = page.reason
        if repeated_signature and not page.exhausted:
            status = "incomplete"
            reason = reason or "repeated_page_signature"
        reason_detail = source_reason_detail(reason)
        inserted = 0
        duplicates = 0
        updated_records = 0
        conflicting_records = 0
        dropped = max(0, int(page.parser_dropped_count))
        fetched = max(len(page.records), int(page.fetched_count or len(page.records)))
        now = utc_now()
        with self._lock, self._connection:
            for record in page.records:
                identity = search_record_identity(record_type, record)
                has_required_identity = bool(identity)
                if not has_required_identity:
                    dropped += 1
                    identity = "dropped:" + hashlib.sha1(
                        json.dumps(search_record_payload(record_type, record), ensure_ascii=False, sort_keys=True).encode("utf-8")
                    ).hexdigest()
                incoming_payload = search_record_payload(record_type, record)
                observation_json, _ = merge_occurrence_provenance_json(
                    "[]",
                    query_variant=effective_variant,
                    path=path,
                    raw_id=first_string(incoming_payload.get("raw_id")),
                    rank=getattr(record, "rank", None),
                    locator_url=first_string(incoming_payload.get("url")),
                    observed_at=now,
                )
                existing_row = self._connection.execute(
                    """
                    SELECT payload_json, query_variants_json, provenance_json
                    FROM occurrences
                    WHERE record_type=? AND identity=? AND keyword=? AND source=?
                    """,
                    (record_type, identity, keyword, source),
                ).fetchone()
                if existing_row is None:
                    self._connection.execute(
                        """
                        INSERT INTO occurrences (
                            record_type, identity, keyword, source, payload_json,
                            keyword_index, source_index, rank_value,
                            query_variants_json, provenance_json, updated_at
                        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                        """,
                        (
                            record_type,
                            identity,
                            keyword,
                            source,
                            json.dumps(incoming_payload, ensure_ascii=False, sort_keys=True),
                            keyword_index,
                            source_index,
                            getattr(record, "rank", None),
                            json.dumps([effective_variant], ensure_ascii=False),
                            observation_json,
                            now,
                        ),
                    )
                    if has_required_identity:
                        inserted += 1
                    continue
                try:
                    existing_payload = json.loads(existing_row["payload_json"])
                except Exception:
                    existing_payload = {}
                if not isinstance(existing_payload, dict):
                    existing_payload = {}
                merged_payload, payload_changed, conflicted = merge_occurrence_payloads(
                    existing_payload,
                    incoming_payload,
                )
                variants_json, variants_changed = merge_query_variant_json(
                    existing_row["query_variants_json"],
                    effective_variant,
                )
                provenance_json, provenance_changed = merge_occurrence_provenance_json(
                    existing_row["provenance_json"],
                    query_variant=effective_variant,
                    path=path,
                    raw_id=first_string(incoming_payload.get("raw_id")),
                    rank=getattr(record, "rank", None),
                    locator_url=first_string(incoming_payload.get("url")),
                    observed_at=now,
                )
                if payload_changed or variants_changed or provenance_changed:
                    self._connection.execute(
                        """
                        UPDATE occurrences
                        SET payload_json=?, query_variants_json=?, provenance_json=?, updated_at=?
                        WHERE record_type=? AND identity=? AND keyword=? AND source=?
                        """,
                        (
                            json.dumps(merged_payload, ensure_ascii=False, sort_keys=True),
                            variants_json,
                            provenance_json,
                            now,
                            record_type,
                            identity,
                            keyword,
                            source,
                        ),
                    )
                    updated_records += 1
                else:
                    duplicates += 1
                if conflicted:
                    conflicting_records += 1
            self._connection.execute(
                """
                INSERT INTO source_runs (
                    record_type, keyword, source, path, query_variant,
                    config_fingerprint, status, next_token, pages, fetched,
                    accepted, duplicates, updated_records, conflicting_records, dropped,
                    total_hint, page_signature, reason, updated_at,
                    reason_code, category, retryable, retry_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(record_type, keyword, source, path, query_variant) DO UPDATE SET
                    config_fingerprint=excluded.config_fingerprint,
                    status=excluded.status,
                    next_token=excluded.next_token,
                    pages=excluded.pages,
                    fetched=source_runs.fetched + excluded.fetched,
                    accepted=source_runs.accepted + excluded.accepted,
                    duplicates=source_runs.duplicates + excluded.duplicates,
                    updated_records=source_runs.updated_records + excluded.updated_records,
                    conflicting_records=source_runs.conflicting_records + excluded.conflicting_records,
                    dropped=source_runs.dropped + excluded.dropped,
                    total_hint=COALESCE(excluded.total_hint, source_runs.total_hint),
                    page_signature=excluded.page_signature,
                    reason=excluded.reason,
                    reason_code=excluded.reason_code,
                    category=excluded.category,
                    retryable=excluded.retryable,
                    retry_at=excluded.retry_at,
                    updated_at=excluded.updated_at
                """,
                (
                    record_type,
                    keyword,
                    source,
                    path,
                    effective_variant,
                    config_fingerprint,
                    status,
                    page.next_token,
                    page_number,
                    fetched,
                    inserted,
                    duplicates,
                    updated_records,
                    conflicting_records,
                    dropped,
                    page.total_hint,
                    page.page_signature,
                    reason,
                    now,
                    first_string(reason_detail.get("reason_code")),
                    first_string(reason_detail.get("category")) or "source_run",
                    int(bool(reason_detail.get("retryable"))),
                    first_string(reason_detail.get("retry_at")) or None,
                ),
            )

    def host_cooldown(self, host: str) -> dict[str, Any] | None:
        normalized_host = host.casefold().strip()
        if not normalized_host:
            return None
        with self._lock:
            row = self._connection.execute(
                "SELECT host, cooldown_until, reason, updated_at FROM host_cooldowns WHERE host=?",
                (normalized_host,),
            ).fetchone()
        return dict(row) if row is not None else None

    def set_host_cooldown(
        self,
        host: str,
        cooldown_until: float,
        reason: str,
    ) -> None:
        normalized_host = host.casefold().strip()
        if not normalized_host:
            return
        with self._lock, self._connection:
            self._connection.execute(
                """
                INSERT INTO host_cooldowns (host, cooldown_until, reason, updated_at)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(host) DO UPDATE SET
                    cooldown_until=MAX(host_cooldowns.cooldown_until, excluded.cooldown_until),
                    reason=excluded.reason,
                    updated_at=excluded.updated_at
                """,
                (
                    normalized_host,
                    max(0.0, float(cooldown_until)),
                    safe_error_text(reason),
                    utc_now(),
                ),
            )

    def get_doi_enrichment_cache(
        self,
        cache_key: str,
        *,
        now: float | None = None,
    ) -> dict[str, Any] | None:
        current = time.time() if now is None else float(now)
        with self._lock:
            row = self._connection.execute(
                """
                SELECT cache_key, normalized_title, source_input,
                       publication_year, first_author, enricher_version,
                       registry_version, registry_schema_version,
                       schema_version, outcome, doi, reason_code, category,
                       retryable, retry_at, updated_at, expires_at
                FROM doi_enrichment_cache
                WHERE cache_key=?
                """,
                (cache_key,),
            ).fetchone()
            if row is None:
                return None
            payload = dict(row)
            current_versions = (
                DOI_ENRICHER_VERSION,
                REGISTRY_VERSION,
                str(REGISTRY_SCHEMA_VERSION),
                str(CANONICAL_SCHEMA_VERSION),
            )
            row_versions = (
                first_string(payload.get("enricher_version")),
                first_string(payload.get("registry_version")),
                first_string(payload.get("registry_schema_version")),
                first_string(payload.get("schema_version")),
            )
            if float(payload.get("expires_at") or 0) <= current or row_versions != current_versions:
                with self._connection:
                    self._connection.execute(
                        "DELETE FROM doi_enrichment_cache WHERE cache_key=?",
                        (cache_key,),
                    )
                return None
        payload["retryable"] = bool(payload.get("retryable"))
        return payload

    def put_doi_enrichment_cache(
        self,
        cache_key: str,
        identity: Mapping[str, Any],
        *,
        outcome: Literal["positive", "negative"],
        doi: str = "",
        reason_code: str,
        category: str = "doi_enrichment",
        retryable: bool = False,
        retry_at: str | None = None,
        ttl_seconds: int | None = None,
        now: float | None = None,
    ) -> None:
        normalized_doi = normalize_doi(doi)
        if outcome == "positive" and not normalized_doi:
            raise ValueError("A positive DOI enrichment cache entry requires a DOI")
        if outcome == "negative" and normalized_doi:
            raise ValueError("A negative DOI enrichment cache entry cannot contain a DOI")
        if retryable:
            raise ValueError("Retryable DOI enrichment failures must not be persisted as cache outcomes")
        updated_at = time.time() if now is None else float(now)
        effective_ttl = int(ttl_seconds or doi_cache_ttl_seconds(outcome))
        if effective_ttl <= 0:
            raise ValueError("DOI enrichment cache TTL must be positive")
        with self._lock, self._connection:
            self._connection.execute(
                """
                INSERT INTO doi_enrichment_cache (
                    cache_key, normalized_title, source_input,
                    publication_year, first_author, enricher_version,
                    registry_version, registry_schema_version,
                    schema_version, outcome, doi, reason_code, category,
                    retryable, retry_at, updated_at, expires_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(cache_key) DO UPDATE SET
                    normalized_title=excluded.normalized_title,
                    source_input=excluded.source_input,
                    publication_year=excluded.publication_year,
                    first_author=excluded.first_author,
                    enricher_version=excluded.enricher_version,
                    registry_version=excluded.registry_version,
                    registry_schema_version=excluded.registry_schema_version,
                    schema_version=excluded.schema_version,
                    outcome=excluded.outcome,
                    doi=excluded.doi,
                    reason_code=excluded.reason_code,
                    category=excluded.category,
                    retryable=excluded.retryable,
                    retry_at=excluded.retry_at,
                    updated_at=excluded.updated_at,
                    expires_at=excluded.expires_at
                """,
                (
                    cache_key,
                    first_string(identity.get("normalized_title")),
                    first_string(identity.get("source_input")),
                    max(0, int(identity.get("publication_year") or 0)),
                    first_string(identity.get("first_author")),
                    first_string(identity.get("enricher_version")) or DOI_ENRICHER_VERSION,
                    first_string(identity.get("registry_version")) or REGISTRY_VERSION,
                    first_string(identity.get("registry_schema_version"))
                    or str(REGISTRY_SCHEMA_VERSION),
                    first_string(identity.get("schema_version"))
                    or str(CANONICAL_SCHEMA_VERSION),
                    outcome,
                    normalized_doi,
                    first_string(reason_code) or "unknown",
                    first_string(category) or "doi_enrichment",
                    int(bool(retryable)),
                    first_string(retry_at) or None,
                    updated_at,
                    updated_at + effective_ttl,
                ),
            )

    def doi_enrichment_cache_summary(
        self,
        *,
        now: float | None = None,
    ) -> dict[str, Any]:
        current = time.time() if now is None else float(now)
        with self._lock:
            rows = self._connection.execute(
                """
                SELECT outcome, reason_code,
                       SUM(CASE WHEN expires_at>? THEN 1 ELSE 0 END) AS active,
                       SUM(CASE WHEN expires_at<=? THEN 1 ELSE 0 END) AS expired
                FROM doi_enrichment_cache
                GROUP BY outcome, reason_code
                ORDER BY outcome, reason_code
                """,
                (current, current),
            ).fetchall()
        entries = [
            {
                "outcome": first_string(row["outcome"]),
                "reason": structured_reason(
                    first_string(row["reason_code"]),
                    category="doi_enrichment",
                ),
                "active": int(row["active"] or 0),
                "expired": int(row["expired"] or 0),
            }
            for row in rows
        ]
        return {
            "enricher_version": DOI_ENRICHER_VERSION,
            "registry_version": REGISTRY_VERSION,
            "schema_version": str(CANONICAL_SCHEMA_VERSION),
            "entries": entries,
            "active": sum(int(entry["active"]) for entry in entries),
            "expired": sum(int(entry["expired"]) for entry in entries),
        }

    def summary(self) -> list[dict[str, Any]]:
        with self._lock:
            rows = self._connection.execute(
                """
                SELECT record_type, keyword, source, path, config_fingerprint,
                       status, next_token, pages, query_variant, fetched, accepted, duplicates, updated_records,
                       conflicting_records, dropped, total_hint, reason,
                       reason_code, category, retryable, retry_at, updated_at
                FROM source_runs
                ORDER BY record_type, keyword, source, path
                """
            ).fetchall()
        return [dict(row) for row in rows]

    def occurrence_payloads(self, record_type: str) -> list[dict[str, Any]]:
        with self._lock:
            rows = self._connection.execute(
                """
                SELECT payload_json, keyword_index, source_index, rank_value
                FROM occurrences
                WHERE record_type=?
                ORDER BY keyword_index, source_index, COALESCE(rank_value, 2147483647), identity
                """,
                (record_type,),
            ).fetchall()
        payloads: list[dict[str, Any]] = []
        for row in rows:
            try:
                payload = json.loads(row["payload_json"])
            except Exception:
                continue
            if not isinstance(payload, dict):
                continue
            payload["keyword_index"] = int(row["keyword_index"] or 0)
            payload["source_index"] = int(row["source_index"] or 0)
            payload["rank"] = row["rank_value"]
            payloads.append(payload)
        return payloads

    def canonical_occurrence_payloads(self, record_type: str) -> list[dict[str, Any]]:
        """Return occurrence-level evidence without collapsing source provenance.

        New checkpoints carry the exact adapter path in ``provenance_json``.
        Older checkpoints only recorded query variants.  For those rows a path
        is recovered only when one and only one accepted source-run path exists;
        otherwise it is deliberately reported as ``unknown``.
        """

        with self._lock:
            rows = self._connection.execute(
                """
                SELECT identity, keyword, source, payload_json, keyword_index,
                       source_index, rank_value, query_variants_json,
                       provenance_json, updated_at
                FROM occurrences
                WHERE record_type=?
                ORDER BY keyword_index, source_index,
                         COALESCE(rank_value, 2147483647), identity
                """,
                (record_type,),
            ).fetchall()
            run_rows = self._connection.execute(
                """
                SELECT keyword, source, query_variant, path, accepted
                FROM source_runs
                WHERE record_type=?
                """,
                (record_type,),
            ).fetchall()
        accepted_paths: dict[tuple[str, str, str], set[str]] = defaultdict(set)
        for run in run_rows:
            if int(run["accepted"] or 0) <= 0:
                continue
            key = (
                first_string(run["keyword"]),
                first_string(run["source"]),
                first_string(run["query_variant"]) or "unknown",
            )
            accepted_paths[key].add(first_string(run["path"]) or "unknown")

        payloads: list[dict[str, Any]] = []
        for row in rows:
            try:
                payload = json.loads(row["payload_json"])
            except Exception:
                continue
            if not isinstance(payload, dict):
                continue
            try:
                raw_variants = json.loads(row["query_variants_json"] or "[]")
            except Exception:
                raw_variants = []
            variants = [
                first_string(value)
                for value in raw_variants
                if first_string(value)
            ] if isinstance(raw_variants, list) else []
            try:
                raw_observations = json.loads(row["provenance_json"] or "[]")
            except Exception:
                raw_observations = []
            observations = [
                dict(value)
                for value in raw_observations
                if isinstance(value, dict)
            ] if isinstance(raw_observations, list) else []
            observed_variants = {
                first_string(value.get("query_variant")) or "unknown"
                for value in observations
            }
            for variant in variants or (["unknown"] if not observations else []):
                normalized_variant = variant or "unknown"
                if normalized_variant in observed_variants:
                    continue
                path_candidates = accepted_paths.get(
                    (
                        first_string(row["keyword"]),
                        first_string(row["source"]),
                        normalized_variant,
                    ),
                    set(),
                )
                observations.append(
                    {
                        "query_variant": normalized_variant,
                        "path": (
                            next(iter(path_candidates))
                            if len(path_candidates) == 1
                            else "unknown"
                        ),
                        "raw_id": first_string(payload.get("raw_id")),
                        "rank": (
                            int(row["rank_value"])
                            if row["rank_value"] is not None
                            else None
                        ),
                        "locator_url": first_string(payload.get("url")),
                        "observed_at": first_string(row["updated_at"]),
                    }
                )
            locator_urls: list[str] = []
            for value in [
                first_string(payload.get("url")),
                first_string(payload.get("landing_url")),
                *(first_string(item.get("locator_url")) for item in observations),
                *(
                    first_string(item.get("raw_id"))
                    for item in observations
                    if normalize_observed_http_url(item.get("raw_id"))
                ),
            ]:
                if value and value not in locator_urls:
                    locator_urls.append(value)
            payload["source"] = first_string(row["source"]) or "unknown"
            payload["keyword"] = first_string(row["keyword"])
            payload["rank"] = (
                int(row["rank_value"])
                if row["rank_value"] is not None
                else payload.get("rank")
            )
            payload["keyword_index"] = int(row["keyword_index"] or 0)
            payload["source_index"] = int(row["source_index"] or 0)
            payload["_occurrence_identity"] = first_string(row["identity"])
            payload["_canonical_locator_urls"] = locator_urls
            payload["_canonical_provenance"] = observations
            payload["_observed_at"] = first_string(row["updated_at"])
            payloads.append(payload)
        return payloads


