class ParentBrowserControl:
    endpoint: str
    browser_name: Literal["chromium", "chrome"]
    target_id: str = ""


PARENT_BROWSER_CONTROLS: dict[int, ParentBrowserControl] = {}
SEARCH_AUTH_CONTROL_STORE: AuthControlStore | None = None
SEARCH_AUTH_CONTROL_STORE_LOCK = threading.Lock()
SEARCH_VERIFICATION_REQUESTS: dict[str, dict[str, Any]] = {}
