@dataclass
class HostRateState:
    tokens: float = 1.0
    last_refill: float = 0.0
    last_request: float = 0.0
    next_allowed: float = 0.0
    cooldown_until_wall: float = 0.0
    persisted_loaded: bool = False
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


@dataclass
class PoliteRateLimiter:
    min_delay: float = field(
        default_factory=lambda: float(os.getenv("LAPS_DELAY_MIN", "-1") or "-1")
    )
    max_delay: float = field(
        default_factory=lambda: float(os.getenv("LAPS_DELAY_MAX", "-1") or "-1")
    )
    api_interval: float = 1.0
    browser_interval: float = 5.0
    scholar_interval: float = 15.0
    burst: float = 1.0
    state_store: SearchStateStore | None = None
    monotonic: Callable[[], float] = time.monotonic
    wall_clock: Callable[[], float] = time.time
    sleeper: Callable[[float], Awaitable[Any]] = asyncio.sleep
    _states: dict[str, HostRateState] = field(default_factory=dict, init=False)
    _overrides: dict[str, Any] = field(default_factory=dict, init=False)
    _legacy_warning_emitted: bool = field(default=False, init=False)

    def __post_init__(self) -> None:
        raw = os.getenv("LAPS_HOST_RATE_OVERRIDES", "").strip()
        if raw:
            try:
                loaded = json.loads(raw)
                if isinstance(loaded, dict):
                    self._overrides = loaded
                else:
                    raise ValueError("root must be an object")
            except Exception as exc:
                raise ValueError(
                    f"LAPS_HOST_RATE_OVERRIDES must be valid JSON: {safe_error_text(str(exc))}"
                ) from exc

    def _legacy_interval(self) -> float | None:
        if self.min_delay < 0 and self.max_delay < 0:
            return None
        if (
            not self._legacy_warning_emitted
            and (
                os.getenv("LAPS_DELAY_MIN", "").strip()
                or os.getenv("LAPS_DELAY_MAX", "").strip()
            )
        ):
            print(
                "Warning: LAPS_DELAY_MIN/MAX are deprecated; use LAPS_HOST_RATE_OVERRIDES.",
                file=sys.stderr,
            )
            self._legacy_warning_emitted = True
        return max(0.0, self.min_delay, self.max_delay)

    def policy(self, host: str, *, kind: str, source: str = "") -> tuple[float, float]:
        normalized_host = host.casefold().strip()
        if source == "Google Scholar" or "scholar.google." in normalized_host:
            interval = self.scholar_interval
        elif kind == "browser":
            interval = self.browser_interval
        else:
            interval = self.api_interval
        burst = self.burst
        legacy_interval = self._legacy_interval()
        if legacy_interval is not None:
            interval = legacy_interval
        override = self._overrides.get(normalized_host)
        if override is None:
            override = self._overrides.get(source)
        if isinstance(override, (int, float)):
            interval = max(0.0, float(override))
        elif isinstance(override, dict):
            raw_interval = override.get(kind, override.get("interval"))
            if isinstance(raw_interval, (int, float)):
                interval = max(0.0, float(raw_interval))
            if isinstance(override.get("burst"), (int, float)):
                burst = max(1.0, float(override["burst"]))
        return interval, burst

    def _state(self, host: str, burst: float) -> HostRateState:
        normalized_host = host.casefold().strip()
        state = self._states.get(normalized_host)
        if state is None:
            now = self.monotonic()
            state = HostRateState(tokens=burst, last_refill=now)
            self._states[normalized_host] = state
        return state

    async def wait(self, host: str, *, kind: str = "api", source: str = "") -> None:
        normalized_host = host.casefold().strip() or "unknown-host"
        interval, burst = self.policy(normalized_host, kind=kind, source=source)
        state = self._state(normalized_host, burst)
        async with state.lock:
            if not state.persisted_loaded and self.state_store is not None:
                persisted = self.state_store.host_cooldown(normalized_host)
                if persisted is not None:
                    state.cooldown_until_wall = max(
                        state.cooldown_until_wall,
                        float(persisted.get("cooldown_until") or 0),
                    )
                state.persisted_loaded = True
            while True:
                now_mono = self.monotonic()
                now_wall = self.wall_clock()
                elapsed = max(0.0, now_mono - state.last_refill)
                if interval <= 0:
                    state.tokens = burst
                else:
                    state.tokens = min(burst, state.tokens + elapsed / interval)
                state.last_refill = now_mono
                cooldown_wait = max(0.0, state.cooldown_until_wall - now_wall)
                token_wait = 0.0
                if state.tokens < 1.0 and interval > 0:
                    token_wait = (1.0 - state.tokens) * interval
                wait_seconds = max(cooldown_wait, token_wait, state.next_allowed - now_mono)
                if wait_seconds <= 0:
                    state.tokens = max(0.0, state.tokens - 1.0)
                    state.last_request = now_mono
                    state.next_allowed = now_mono + interval
                    return
                await self.sleeper(wait_seconds)

    async def register_cooldown(self, host: str, seconds: float, reason: str) -> None:
        normalized_host = host.casefold().strip() or "unknown-host"
        _, burst = self.policy(normalized_host, kind="api")
        state = self._state(normalized_host, burst)
        cooldown_until = self.wall_clock() + max(0.0, float(seconds))
        async with state.lock:
            state.cooldown_until_wall = max(state.cooldown_until_wall, cooldown_until)
        if self.state_store is not None:
            self.state_store.set_host_cooldown(
                normalized_host,
                cooldown_until,
                reason,
            )


async def wait_for_rate_limiter(
    limiter: Any,
    host: str,
    *,
    kind: str,
    source: str,
) -> None:
    try:
        await limiter.wait(host, kind=kind, source=source)
    except TypeError as exc:
        if "unexpected keyword argument" not in str(exc):
            raise
        await limiter.wait(host)


@dataclass(frozen=True)
class HttpAttemptResult:
    response: Any | None = None
    status_code: int = 0
    reason: str = ""
    retry_after_seconds: int = 0
    error_code: str = ""
    reason_code: str = ""
    category: str = "http"
    retryable: bool = False
    retry_at: str = ""
    headers: dict[str, str] = field(default_factory=dict)

    @property
    def ok(self) -> bool:
        return self.response is not None and 200 <= self.status_code < 400

    def reason_detail(self) -> dict[str, Any]:
        return structured_reason(
            self.reason_code or self.error_code or f"http_{self.status_code}",
            category=self.category,
            retryable=self.retryable,
            retry_at=self.retry_at,
        )


@dataclass
class SearchRuntime:
    config: SearchConfig
    client: Any
    skipped_sources: list[SkippedSource]
    degraded_sources: list[DegradedSource]
    browser_disabled_sources: list[BrowserDisabledSource]
    global_sem: asyncio.Semaphore
    restricted_auth_sources: list[RestrictedAuthSource] = field(default_factory=list)
    host_sem_map: dict[str, asyncio.Semaphore] = field(default_factory=dict)
    limiter: PoliteRateLimiter = field(default_factory=PoliteRateLimiter)
    browser_sem: asyncio.Semaphore = field(default_factory=lambda: asyncio.Semaphore(1))
    state_store: SearchStateStore | None = None
    config_fingerprint: str = ""
    allowed_cost_sources: set[str] = field(default_factory=set)
    cost_notice_emitted: set[str] = field(default_factory=set)
    doi_enrichment_cache: dict[str, str] = field(default_factory=dict)
    doi_enrichment_cache_metrics: Counter[str] = field(default_factory=Counter)
    scheduler_metrics: dict[str, dict[str, Any]] = field(default_factory=dict)
    query_anchor_cache: dict[tuple[str, str], str] = field(default_factory=dict)
    # Browser-only observations that are not safe to synthesize.  The Wanfang
    # patent result cards can be re-rendered after a popup/back navigation, so
    # retain a bounded, run-local copy until the page checkpoint is committed.
    observed_locator_cache: dict[tuple[str, str, str], str] = field(
        default_factory=dict
    )
    materializer: IncrementalMaterializer | None = None

    def __post_init__(self) -> None:
        self.limiter.state_store = self.state_store

    def skip(self, source: str, keyword: str | None, reason: str) -> None:
        context = SEARCH_TASK_CONTEXT.get()
        self.skipped_sources.append(
            SkippedSource(
                source=source,
                keyword=keyword,
                reason=reason,
                path=first_string(context.get("checkpoint_path") or context.get("path")),
                query_variant=current_query_variant(),
            )
        )

    def degrade(self, source: str, keyword: str | None, reason: str) -> None:
        context = SEARCH_TASK_CONTEXT.get()
        self.degraded_sources.append(
            DegradedSource(
                source=source,
                keyword=keyword,
                reason=reason,
                path=first_string(context.get("checkpoint_path") or context.get("path")),
                query_variant=current_query_variant(),
            )
        )

    def browser_disabled(self, source: str, keyword: str | None, reason: str) -> None:
        context = SEARCH_TASK_CONTEXT.get()
        self.browser_disabled_sources.append(
            BrowserDisabledSource(
                source=source,
                keyword=keyword,
                reason=reason,
                path=first_string(context.get("checkpoint_path") or context.get("path")),
                query_variant=current_query_variant(),
            )
        )

    def restricted_auth(self, source: str, keyword: str | None, mode: str, status: str, reason: str) -> None:
        context = SEARCH_TASK_CONTEXT.get()
        self.restricted_auth_sources.append(
            RestrictedAuthSource(
                source=source,
                keyword=keyword,
                mode=mode,
                status=status,
                reason=reason,
                path=first_string(context.get("checkpoint_path") or context.get("path")),
                query_variant=current_query_variant(),
            )
        )

    def persist_page(
        self,
        record_type: Literal["literature", "patent"],
        source: str,
        keyword: str,
        path: str,
        page: SearchPage,
        *,
        page_number: int,
        keyword_index: int | None = None,
        source_index: int | None = None,
    ) -> None:
        if self.state_store is None:
            return
        context = SEARCH_TASK_CONTEXT.get()
        if not path:
            path = str(
                context.get("checkpoint_path")
                or context.get("path")
                or "api"
            )
        if keyword_index is None:
            keyword_index = int(context.get("keyword_index") or 0)
        if source_index is None:
            source_index = int(context.get("source_index") or 0)
        self.state_store.persist_page(
            record_type,
            keyword,
            source,
            path,
            self.config_fingerprint,
            page,
            page_number=page_number,
            keyword_index=keyword_index,
            source_index=source_index,
        )
        if self.materializer is not None:
            self.materializer.page_committed()

    def resume_run(self, record_type: Literal["literature", "patent"], source: str, keyword: str, path: str = "") -> dict[str, Any]:
        if self.state_store is None:
            return {}
        context = SEARCH_TASK_CONTEXT.get()
        effective_path = path or str(
            context.get("checkpoint_path")
            or context.get("path")
            or "api"
        )
        return self.state_store.get_run(record_type, keyword, source, effective_path) or {}

    def mark_current_run(
        self,
        record_type: Literal["literature", "patent"],
        source: str,
        keyword: str,
        status: Literal["pending", "running", "complete", "incomplete", "blocked", "failed"],
        reason: str,
        path: str = "",
    ) -> None:
        if self.state_store is None:
            return
        context = SEARCH_TASK_CONTEXT.get()
        effective_path = path or str(
            context.get("checkpoint_path")
            or context.get("path")
            or "api"
        )
        previous = self.state_store.get_run(record_type, keyword, source, effective_path) or {}
        self.state_store.mark_run(
            record_type,
            keyword,
            source,
            effective_path,
            self.config_fingerprint,
            status,
            next_token=str(previous.get("next_token") or ""),
            pages=int(previous.get("pages") or 0),
            fetched=int(previous.get("fetched") or 0),
            accepted=int(previous.get("accepted") or 0),
            duplicates=int(previous.get("duplicates") or 0),
            updated_records=int(previous.get("updated_records") or 0),
            conflicting_records=int(previous.get("conflicting_records") or 0),
            dropped=int(previous.get("dropped") or 0),
            total_hint=previous.get("total_hint"),
            page_signature=str(previous.get("page_signature") or ""),
            reason=reason,
        )

    def get_host_semaphore(self, url: str, source: str) -> asyncio.Semaphore:
        parsed = urllib.parse.urlparse(url)
        host = parsed.netloc or parsed.scheme or source
        if host not in self.host_sem_map:
            per_host_limit = 1 if source in SERIAL_HOST_SOURCES else 2
            self.host_sem_map[host] = asyncio.Semaphore(per_host_limit)
        return self.host_sem_map[host]

    async def request_result(
        self,
        source: str,
        keyword: str | None,
        method: str,
        url: str,
        record_failure: bool = True,
        **kwargs: Any,
    ) -> HttpAttemptResult:
        host_sem = self.get_host_semaphore(url, source)
        host = urllib.parse.urlparse(url).netloc.casefold()
        last_result = HttpAttemptResult(
            reason="unknown request error",
            error_code="network_error",
            reason_code="network_error",
            category="transport",
            retryable=True,
        )
        for attempt in range(1, 4):
            await wait_for_rate_limiter(
                self.limiter,
                host,
                kind="api",
                source=source,
            )
            try:
                async with self.global_sem, host_sem:
                    response = await self.client.request(method, url, **kwargs)
            except Exception as exc:  # httpx is imported lazily by the caller.
                reason = f"{exc.__class__.__name__}: {safe_error_text(str(exc))}"
                backoff_seconds = (2 ** attempt) + random.random()
                last_result = HttpAttemptResult(
                    reason=reason,
                    error_code="network_error",
                    reason_code=f"transport_{exc.__class__.__name__.casefold()}",
                    category="transport",
                    retryable=True,
                    retry_at=retry_at_iso(backoff_seconds),
                )
                if attempt < 3:
                    await asyncio.sleep(backoff_seconds)
                    continue
                if record_failure:
                    self.skip(source, keyword, f"request failed after retries: {reason}")
                return last_result
            status_code = int(response.status_code)
            retry_after = response_retry_after_seconds(response)
            selected_headers = {
                name.casefold(): first_string(response.headers.get(name))
                for name in (
                    "Retry-After",
                    "X-RateLimit-Limit",
                    "X-RateLimit-Remaining",
                    "X-RateLimit-Reset",
                )
                if first_string(response.headers.get(name))
            }
            result = HttpAttemptResult(
                response=response,
                status_code=status_code,
                reason=f"HTTP {status_code}",
                retry_after_seconds=retry_after,
                error_code=(
                    "rate_limited"
                    if status_code == 429
                    else "upstream_transient"
                    if status_code in {408, 425, 500, 502, 503, 504}
                    else ""
                ),
                reason_code=f"http_{status_code}",
                category="http",
                retryable=status_code
                in {408, 425, 429, 500, 502, 503, 504},
                retry_at=retry_at_iso(
                    retry_after
                    or (
                        DEFAULT_TRANSIENT_RETRY_SECONDS
                        if status_code in {408, 425, 429, 500, 502, 503, 504}
                        else 0
                    )
                ),
                headers=selected_headers,
            )
            if status_code == 429:
                cooldown = retry_after or min(300, 2 ** attempt)
                await self.limiter.register_cooldown(
                    host,
                    cooldown,
                    f"HTTP 429 retry_after_seconds={cooldown}",
                )
                last_result = HttpAttemptResult(
                    response=response,
                    status_code=status_code,
                    reason=f"HTTP 429 retry_after_seconds={cooldown}",
                    retry_after_seconds=cooldown,
                    error_code="rate_limited",
                    reason_code="http_429_rate_limited",
                    category="rate_limit",
                    retryable=True,
                    retry_at=retry_at_iso(cooldown),
                    headers=selected_headers,
                )
                if retry_after > 60 or attempt >= 3:
                    if record_failure:
                        self.skip(source, keyword, f"request deferred by server: {last_result.reason}")
                    return last_result
                continue
            if status_code in {502, 503, 504} and attempt < 3:
                last_result = result
                await asyncio.sleep((2 ** attempt) + random.random())
                continue
            if status_code >= 400:
                if record_failure:
                    self.skip(source, keyword, f"HTTP {status_code}")
                return result
            return result
        if record_failure:
            self.skip(source, keyword, f"request failed after retries: {last_result.reason}")
        return last_result

    async def request(self, source: str, keyword: str | None, method: str, url: str, record_failure: bool = True, **kwargs: Any) -> Any | None:
        result = await self.request_result(
            source,
            keyword,
            method,
            url,
            record_failure=record_failure,
            **kwargs,
        )
        return result.response if result.ok else None


def safe_error_text(value: str) -> str:
    text = value or ""
    for secret_name, secret in API_CONFIG_VALUES.items():
        if secret_name in NON_SECRET_CONFIG_KEYS:
            continue
        if secret:
            text = text.replace(secret, f"<{secret_name}>")
    for secret_name in API_CONFIG_KEYS:
        if secret_name in NON_SECRET_CONFIG_KEYS:
            continue
        secret = os.getenv(secret_name)
        if secret:
            text = text.replace(secret, f"<{secret_name}>")
    try:
        secrets_to_mask = read_api_user_config(include_empty=True) | read_raw_api_user_config()
        for secret_name, secret in secrets_to_mask.items():
            if secret_name in NON_SECRET_CONFIG_KEYS:
                continue
            if secret:
                text = text.replace(secret, f"<{secret_name}>")
    except Exception:
        pass
    try:
        runtime_path = get_runtime_config_path()
        if runtime_path.exists():
            loaded = json.loads(runtime_path.read_text(encoding="utf-8-sig"))
            if isinstance(loaded, dict):
                for key in (
                    "account",
                    "password",
                    "uyanip_account",
                    "uyanip_password",
                ):
                    secret = str(loaded.get(key) or "")
                    if secret:
                        text = text.replace(secret, f"<runtime_config_{key}>")
    except Exception:
        pass
    auth_state = str(AUTH_STATE_DIR)
    if auth_state:
        text = text.replace(auth_state, "<auth_state_path>")
    return text


def env_value(*names: str) -> str:
    for name in names:
        if name in API_CONFIG_KEY_SET:
            value = API_CONFIG_VALUES.get(name, "").strip()
            if value:
                return value
            continue
        value = os.getenv(name, "").strip()
        if value:
            return value
    return ""


def has_any_key(keys: tuple[str, ...]) -> bool:
    return any(env_value(key) for key in keys)


def required_key_configured(key: str) -> bool:
    if key in {"CLARIVATE_API_KEY", "WOS_API_KEY"}:
        return bool(env_value("CLARIVATE_API_KEY", "WOS_API_KEY"))
    if key in {"NCBI_API_KEY", "PUBMED_API_KEY"}:
        return bool(env_value("NCBI_API_KEY", "PUBMED_API_KEY"))
    return bool(env_value(key))


def missing_required_keys(policy: SourceAuthPolicy) -> list[str]:
    missing: list[str] = []
    for key in policy.required_keys:
        if required_key_configured(key):
            continue
        if key == "CLARIVATE_API_KEY":
            missing.append("CLARIVATE_API_KEY/WOS_API_KEY")
        else:
            missing.append(key)
    return missing


def read_named_environment(name: str) -> str:
    value = os.getenv(name, "").strip()
    if value or os.name != "nt":
        return value
    try:
        import winreg

        locations = (
            (winreg.HKEY_CURRENT_USER, r"Environment"),
            (winreg.HKEY_LOCAL_MACHINE, r"SYSTEM\CurrentControlSet\Control\Session Manager\Environment"),
        )
        for root, subkey in locations:
            try:
                with winreg.OpenKey(root, subkey) as handle:
                    raw, _ = winreg.QueryValueEx(handle, name)
            except OSError:
                continue
            value = str(raw or "").strip()
            if value:
                return os.path.expandvars(value)
    except Exception:
        return ""
    return ""


def get_api_config_path(required: bool = True) -> Path | None:
    configured = read_named_environment(API_CONFIG_PATH_ENV)
    if not configured:
        if required:
            raise ValueError(f"{API_CONFIG_PATH_ENV} must point to the API key JSON file.")
        return None
    path = Path(configured).expanduser().resolve()
    if path.exists() and path.is_dir():
        raise ValueError(f"{API_CONFIG_PATH_ENV} must point to a JSON file, not a directory: {path}")
    return path


def api_config_template() -> dict[str, str]:
    return {key: "" for key in API_CONFIG_KEYS}


def migrate_legacy_api_config_values(raw_config: dict[str, str]) -> dict[str, str]:
    cleaned = api_config_template()
    for key, value in raw_config.items():
        if key in API_CONFIG_KEY_SET and value is not None:
            cleaned[str(key)] = str(value)
    legacy_lens = str(raw_config.get("LENS_API_KEY") or "")
    if legacy_lens:
        if not cleaned.get("LENS_Scholarly_API_KEY"):
            cleaned["LENS_Scholarly_API_KEY"] = legacy_lens
        if not cleaned.get("LENS_Patents_API_KEY"):
            cleaned["LENS_Patents_API_KEY"] = legacy_lens
    return cleaned


def read_raw_api_user_config() -> dict[str, str]:
    path = get_api_config_path(required=False)
    if path is None:
        return {}
    if not path.exists():
        return {}
    with path.open("r", encoding="utf-8") as handle:
        loaded = json.load(handle)
    if not isinstance(loaded, dict):
        raise ValueError(f"API user config must be a JSON object: {path}")
    allowed = API_CONFIG_KEY_SET | LEGACY_API_CONFIG_KEY_SET
    return {str(k): str(v) for k, v in loaded.items() if k in allowed and v is not None}


def read_api_user_config(include_empty: bool = False) -> dict[str, str]:
    cleaned = migrate_legacy_api_config_values(read_raw_api_user_config())
    if include_empty:
        return cleaned
    return {key: value for key, value in cleaned.items() if value}


def chmod_user_config(path: Path) -> None:
    if os.name != "nt" and path.exists():
        path.chmod(0o600)


def write_api_user_config(config: dict[str, str]) -> Path:
    path = get_api_config_path(required=True)
    assert path is not None
    path.parent.mkdir(parents=True, exist_ok=True)
    cleaned = api_config_template()
    for key, value in config.items():
        if key in API_CONFIG_KEY_SET and value is not None:
            cleaned[key] = str(value)
    path.write_text(json.dumps(cleaned, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    chmod_user_config(path)
    return path


def init_api_user_config(force: bool = False) -> tuple[Path, bool]:
    path = get_api_config_path(required=True)
    assert path is not None
    if path.exists() and not force:
        existing = read_api_user_config(include_empty=True)
        write_api_user_config(existing)
        chmod_user_config(path)
        return path, False
    write_api_user_config(api_config_template())
    return path, True


def parse_simple_env_file(path: Path, allowed_keys: set[str] | None = None) -> dict[str, str]:
    values: dict[str, str] = {}
    if not path.exists():
        return values
    allowed = allowed_keys if allowed_keys is not None else API_CONFIG_KEY_SET
    for raw_line in path.read_text(encoding="utf-8").splitlines():
        line = raw_line.strip()
        if not line or line.startswith("#") or "=" not in line:
            continue
        key, value = line.split("=", 1)
        key = key.strip()
        value = value.strip()
        if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
            value = value[1:-1]
        if key in allowed:
            values[key] = value
    return values


def load_project_dotenv_into_env() -> list[str]:
    applied: list[str] = []
    for key, value in parse_simple_env_file(PROJECT_ROOT / ".env", allowed_keys=API_CONFIG_PATH_ENV_KEYS).items():
        if key not in os.environ:
            os.environ[key] = value
            applied.append(key)
    return applied


def apply_compat_env_aliases() -> list[str]:
    applied: list[str] = []
    for alias, canonical in API_KEY_COMPAT_ALIASES.items():
        alias_value = env_value(alias)
        if alias_value and not env_value(canonical):
            API_CONFIG_VALUES[canonical] = alias_value
            applied.append(canonical)
    return applied


def load_api_user_config_into_env() -> list[str]:
    applied: list[str] = []
    API_CONFIG_VALUES.clear()
    APPLIED_FROM_USER_API_CONFIG.clear()
    for key, value in read_api_user_config().items():
        if value:
            API_CONFIG_VALUES[key] = value
            APPLIED_FROM_USER_API_CONFIG.add(key)
            applied.append(key)
            if key == "GOOGLE_APPLICATION_CREDENTIALS" and not os.getenv(key):
                os.environ[key] = value
    for alias, canonical in API_KEY_COMPAT_ALIASES.items():
        if alias in API_CONFIG_VALUES and canonical not in API_CONFIG_VALUES:
            API_CONFIG_VALUES[canonical] = API_CONFIG_VALUES[alias]
            APPLIED_FROM_USER_API_CONFIG.add(canonical)
            applied.append(canonical)
    applied.extend(apply_compat_env_aliases())
    return applied


def assert_api_config_key(key: str) -> None:
    if key not in API_CONFIG_KEY_SET:
        raise ValueError(f"Unsupported config key: {key}. Use `config keys` to view supported keys.")


def parse_config_assignment(args: list[str]) -> tuple[str, str]:
    if not args:
        raise ValueError("Missing KEY/VALUE assignment.")
    if "=" in args[0]:
        key, value = args[0].split("=", 1)
    elif len(args) >= 2:
        key, value = args[0], " ".join(args[1:])
    else:
        raise ValueError("Expected `config set KEY VALUE` or `config set KEY=VALUE`.")
    key = key.strip()
    assert_api_config_key(key)
    return key, value.strip()


def mask_config_value(key: str, value: str) -> str:
    del key
    if not value:
        return ""
    if "@" in value:
        local, domain = value.split("@", 1)
        return f"{local[:2]}***@{domain}"
    if len(value) <= 8:
        return "***"
    return f"{value[:4]}...{value[-4:]}"


def list_api_config_entries(include_missing: bool = False, raw: bool = False) -> list[dict[str, str | bool]]:
    user_config = read_api_user_config(include_empty=True)
    config_path = get_api_config_path(required=False)
    config_source = f"{API_CONFIG_PATH_ENV}:{config_path}" if config_path else "missing"
    entries: list[dict[str, str | bool]] = []
    for key in API_CONFIG_KEYS:
        if API_CONFIG_VALUES.get(key):
            source = config_source
            value = API_CONFIG_VALUES[key]
            configured = True
        elif key in user_config and user_config[key]:
            source = config_source
            value = user_config[key]
            configured = True
        else:
            source = "missing"
            value = ""
            configured = False
        if configured or include_missing:
            entries.append({"key": key, "configured": configured, "source": source, "value": value if raw else mask_config_value(key, value)})
    return entries


def json_print(payload: Any) -> None:
    print(json.dumps(payload, ensure_ascii=False, indent=2))


def parse_keywords(raw: str) -> list[str]:
    parts = re.split(r"[，,]", raw or "")
    keywords: list[str] = []
    seen: set[str] = set()
    for part in parts:
        kw = part.strip()
        if not kw:
            continue
        key = kw.casefold()
        if key not in seen:
            keywords.append(kw)
            seen.add(key)
    return keywords


def read_keywords_file(path: Path) -> list[str]:
    if not path.exists():
        raise FileNotFoundError(f"Keywords file not found: {path}")
    values: list[str] = []
    for line in path.read_text(encoding="utf-8-sig").splitlines():
        values.extend(parse_keywords(line))
    return values


def merge_keywords(*groups: list[str]) -> list[str]:
    merged: list[str] = []
    seen: set[str] = set()
    for group in groups:
        for keyword in group:
            key = keyword.casefold()
            if keyword and key not in seen:
                merged.append(keyword)
                seen.add(key)
    return merged


def safe_batch_name(value: str) -> str:
    normalized = unicodedata.normalize("NFKC", value or "")
    normalized = re.sub(r'[<>:"/\\|?*\x00-\x1f]+', "_", normalized)
    normalized = re.sub(r"\s+", "_", normalized).strip(" ._")
    reserved = {"CON", "PRN", "AUX", "NUL", *(f"COM{i}" for i in range(1, 10)), *(f"LPT{i}" for i in range(1, 10))}
    if not normalized or normalized.upper() in reserved:
        normalized = "keywords"
    return normalized[:100]


def batch_name_from_keywords(keywords: list[str]) -> str:
    joined = "__".join(keywords)
    digest = hashlib.sha1(joined.encode("utf-8")).hexdigest()[:10]
    head = safe_batch_name("__".join(keywords[:4]))
    return f"{head}__{digest}"


def metadata_batch_root(batch_name: str | None = None, metadata_root: Path | None = None) -> Path:
    if metadata_root is not None:
        return metadata_root
    if batch_name:
        return OUTPUT_ROOT / safe_batch_name(batch_name)
    return OUTPUT_ROOT


def pdf_batch_root(batch_name: str | None = None, pdf_root: Path | None = None) -> Path:
    if pdf_root is not None:
        return pdf_root
    if batch_name:
        return PDF_ROOT / safe_batch_name(batch_name)
    return PDF_ROOT


def normalize_doi(doi: str | None) -> str:
    """Use the canonical v2 DOI parser everywhere in the search runtime."""

    return normalize_contract_doi(doi)


def normalize_observed_http_url(url: Any) -> str:
    """Normalize only syntax; do not promote a landing page to a PDF."""

    value = html.unescape(first_string(url)).strip()
    if not value:
        return ""
    try:
        parsed = urllib.parse.urlsplit(value)
    except ValueError:
        return ""
    scheme = parsed.scheme.casefold()
    if scheme not in {"http", "https"} or not parsed.hostname:
        return ""
    return urllib.parse.urlunsplit(
        (scheme, parsed.netloc.casefold(), parsed.path, parsed.query, "")
    )


def normalize_literature_pdf_url(url: str | None) -> str:
    value = html.unescape(str(url or "")).strip()
    if not value:
        return ""
    try:
        parsed = urllib.parse.urlsplit(value)
    except ValueError:
        return ""
    scheme = parsed.scheme.casefold()
    if scheme not in {"http", "https"} or not parsed.netloc:
        return ""
    path = urllib.parse.unquote(parsed.path or "").casefold()
    host = (parsed.hostname or "").casefold()
    query_pairs = urllib.parse.parse_qsl(parsed.query, keep_blank_values=True)
    decoded_query = " ".join(
        f"{urllib.parse.unquote_plus(key)}={urllib.parse.unquote_plus(item)}"
        for key, item in query_pairs
    ).casefold()
    path_evidence = (
        path.endswith(".pdf")
        or ".pdf/" in path
        or "/pdf/" in path
        or path.endswith("/pdf")
        or "/article-pdf" in path
        or "/download/pdf" in path
        or "/pdfft" in path
        or path.endswith(".full.pdf")
    )
    query_evidence = (
        ".pdf" in decoded_query
        or bool(
            re.search(
                r"(?:^|\s)(?:format|type|content-type|download)=pdf(?:\s|$)",
                decoded_query,
            )
        )
    )
    wanfang_download_parts = [part for part in path.split("/") if part]
    wanfang_path_evidence = bool(
        not parsed.query
        and (
            (
                host == "oss.wanfangdata.com.cn"
                and path.startswith("/file/download/")
                and path.endswith(".aspx")
            )
            or (
                host == "f.wanfangdata.com.cn"
                and len(wanfang_download_parts) == 4
                and wanfang_download_parts[:2] == ["download", "pc"]
                and wanfang_download_parts[2]
                in {"periodical", "thesis", "conference", "nstr"}
                and bool(
                    re.fullmatch(
                        r"[a-z0-9._-]+",
                        wanfang_download_parts[3],
                    )
                )
            )
        )
    )
    if not path_evidence and not query_evidence and not wanfang_path_evidence:
        return ""
    normalized_netloc = parsed.netloc.casefold()
    return urllib.parse.urlunsplit(
        (scheme, normalized_netloc, parsed.path, parsed.query, "")
    )


def stable_literature_pdf_url(url: str | None) -> str:
    normalized = normalize_literature_pdf_url(url)
    if not normalized:
        return ""
    volatile_keys = {
        "access_token",
        "auth",
        "authorization",
        "awsaccesskeyid",
        "expires",
        "googleaccessid",
        "jwt",
        "key-pair-id",
        "policy",
        "session",
        "sessionid",
        "signature",
        "sig",
        "ticket",
        "token",
        "x-amz-credential",
        "x-amz-security-token",
        "x-amz-signature",
        "x-goog-credential",
        "x-goog-expires",
        "x-goog-signature",
    }
    query_keys = {
        key.casefold()
        for key, _ in urllib.parse.parse_qsl(
            urllib.parse.urlsplit(normalized).query,
            keep_blank_values=True,
        )
    }
    return "" if volatile_keys.intersection(query_keys) else normalized


def first_observed_pdf_url(*values: Any) -> str:
    url_keys = (
        "pdf_url",
        "pdfUrl",
        "pdf",
        "downloadUrl",
        "download_url",
        "fullTextUrl",
        "fullText",
        "fulltext",
        "full_text",
        "full_text_url",
        "contentUrl",
        "content_url",
        "URL",
        "url",
        "urls",
        "@href",
        "href",
        "value",
    )

    def visit(value: Any) -> str:
        if value is None:
            return ""
        if isinstance(value, str):
            return normalize_literature_pdf_url(value)
        if isinstance(value, (list, tuple)):
            for item in value:
                candidate = visit(item)
                if candidate:
                    return candidate
            return ""
        if isinstance(value, dict):
            for key in url_keys:
                if key not in value:
                    continue
                candidate = visit(value.get(key))
                if candidate:
                    return candidate
        return ""

    for value in values:
        candidate = visit(value)
        if candidate:
            return candidate
    return ""


def first_observed_landing_url(*values: Any) -> str:
    """Select an observed non-PDF HTTP URL without constructing one."""

    url_keys = (
        "landing_page_url",
        "landingPageUrl",
        "document_url",
        "detail_url",
        "fullTextUrl",
        "URL",
        "url",
        "href",
        "@href",
        "value",
    )

    def visit(value: Any) -> str:
        if isinstance(value, str):
            normalized = normalize_observed_http_url(value)
            return normalized if normalized and not normalize_literature_pdf_url(normalized) else ""
        if isinstance(value, (list, tuple)):
            for item in value:
                candidate = visit(item)
                if candidate:
                    return candidate
            return ""
        if isinstance(value, Mapping):
            for key in url_keys:
                if key in value:
                    candidate = visit(value.get(key))
                    if candidate:
                        return candidate
        return ""

    for value in values:
        candidate = visit(value)
        if candidate:
            return candidate
    return ""


DOI_PATTERN = re.compile(r"\b10\.\d{4,9}/[^\s\"'<>]+", re.IGNORECASE)


def unwrap_google_redirect_url(url: str | None) -> str:
    value = (url or "").strip()
    if not value:
        return ""
    try:
        parsed = urllib.parse.urlsplit(value)
    except ValueError:
        return value
    if parsed.path == "/url" or parsed.netloc.casefold().endswith(".google.com") or parsed.netloc.casefold() == "google.com":
        query = urllib.parse.parse_qs(parsed.query)
        for key in ("q", "url"):
            target = first_string(query.get(key))
            if target:
                return target
    return value


def clean_extracted_doi(value: str | None) -> str:
    text = html.unescape(urllib.parse.unquote(value or "")).strip()
    text = re.sub(r"^https?://(?:dx\.)?doi\.org/", "", text, flags=re.IGNORECASE)
    text = re.sub(r"^doi:\s*", "", text, flags=re.IGNORECASE)
    text = re.split(r"[?#]", text, maxsplit=1)[0]
    text = text.strip().strip("<>[]{}()")
    text = text.rstrip(".,;:")
    return normalize_doi(text)


def extract_doi_from_url(url: str | None) -> str:
    value = unwrap_google_redirect_url(url)
    if not value:
        return ""
    try:
        parsed = urllib.parse.urlsplit(value)
    except ValueError:
        return ""
    if parsed.netloc.casefold() in {"doi.org", "dx.doi.org"}:
        return clean_extracted_doi(parsed.path.lstrip("/"))
    return ""


def extract_doi_from_values(*values: Any) -> str:
    for value in values:
        text = html.unescape(urllib.parse.unquote(first_string(value)))
        if not text:
            continue
        doi = extract_doi_from_url(text)
        if doi:
            return doi
        match = DOI_PATTERN.search(text)
        if match:
            doi = clean_extracted_doi(match.group(0))
            if doi:
                return doi
    return ""


def normalize_title(title: str | None) -> str:
    if not title:
        return ""
    value = unicodedata.normalize("NFKC", title)
    value = value.casefold()
    value = re.sub(r"[^\w\s]", " ", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


def normalize_patent_name(name: str | None) -> str:
    if not name:
        return ""
    value = unicodedata.normalize("NFKC", name)
    value = value.casefold()
    value = re.sub(r"[^\w\s]", " ", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


def normalize_school(value: str) -> str:
    return re.sub(r"\s+", "", value or "").casefold()


def normalize_institution_name(value: Any) -> str:
    text = unicodedata.normalize("NFKC", str(value or "")).replace("\u00a0", " ")
    text = re.sub(r"\s+", " ", text).strip(" \t\r\n,;:")
    return re.sub(r"\s*([()])\s*", r"\1", text).casefold()


def normalize_school_aliases(value: Any) -> tuple[str, ...]:
    if isinstance(value, str):
        values: Iterable[Any] = (value,)
    elif isinstance(value, (list, tuple, set, frozenset)):
        values = value
    else:
        values = ()
    output: list[str] = []
    seen: set[str] = set()
    for item in values:
        label = re.sub(r"\s+", " ", str(item or "")).strip()
        normalized = normalize_institution_name(label)
        if normalized and normalized not in seen:
            seen.add(normalized)
            output.append(label)
    return tuple(output)


def exact_institution_labels(
    school: str,
    school_aliases: Iterable[str] = (),
) -> tuple[str, ...]:
    configured = re.sub(r"\s+", " ", str(school or "")).strip()
    if not configured:
        return ()
    labels = [configured, *normalize_school_aliases(tuple(school_aliases))]
    output: list[str] = []
    seen: set[str] = set()
    for label in labels:
        normalized = normalize_institution_name(label)
        if normalized and normalized not in seen:
            seen.add(normalized)
            output.append(label)
    return tuple(output)


def institution_name_matches_exact(
    candidate: Any,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    normalized_candidate = normalize_institution_name(candidate)
    return bool(
        normalized_candidate
        and normalized_candidate in {
            normalize_institution_name(label)
            for label in exact_institution_labels(school, school_aliases)
        }
    )


def institution_authorization_name_matches(
    candidate: Any,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    aliases = tuple(school_aliases)
    if institution_name_matches_exact(candidate, school, aliases):
        return True
    candidate_tokens = re.findall(
        r"[a-z0-9]+",
        normalize_institution_name(candidate),
    )
    if not candidate_tokens:
        return False
    for label in exact_institution_labels(school, aliases):
        configured_tokens = re.findall(
            r"[a-z0-9]+",
            normalize_institution_name(label),
        )
        if len(candidate_tokens) != len(configured_tokens):
            continue
        if all(
            candidate_token == configured_token
            or (
                len(candidate_token) >= 4
                and configured_token.startswith(candidate_token)
            )
            for candidate_token, configured_token in zip(
                candidate_tokens,
                configured_tokens,
            )
        ):
            return True
    return False


def configured_institution_is_xiamen(
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    configured = {
        normalize_institution_name(label)
        for label in exact_institution_labels(school, school_aliases)
    }
    return bool(
        configured
        & {
            normalize_institution_name("Xiamen University"),
            normalize_institution_name("厦门大学"),
        }
    )


def preferred_carsi_institution_query(
    school: str,
    school_aliases: Iterable[str] = (),
) -> str:
    labels = exact_institution_labels(school, school_aliases)
    return next(
        (
            label
            for label in labels
            if any("\u4e00" <= character <= "\u9fff" for character in label)
        ),
        labels[0] if labels else "",
    )


def policy_auth_entries(
    source: str,
    policy: SourceAccessPolicy,
) -> tuple[InstitutionAuthEntry, ...]:
    if policy.auth_entries:
        return policy.auth_entries
    url = policy.auth_entry_url or policy.web_search_url or literature_search_path_map.get(source) or ""
    return (InstitutionAuthEntry("default_institution", url),) if url else ()


def auth_entry_cooldown_seconds() -> int:
    return min(86400, env_seconds("LAPS_AUTH_ENTRY_COOLDOWN_SECONDS", 1800, 60))


def is_carsi_url(value: str | None) -> bool:
    host = (urllib.parse.urlsplit(value or "").hostname or "").casefold()
    return host == "carsi.edu.cn" or host.endswith(".carsi.edu.cn")


def safe_slug(value: str) -> str:
    normalized = unicodedata.normalize("NFKC", value or "").casefold()
    slug = re.sub(r"[^a-z0-9._-]+", "_", normalized).strip("._-")
    return slug[:80] or "default"


def source_auth_state_scope(source: str, policy: SourceAccessPolicy | None = None) -> str:
    selected_policy = policy or literature_source_auth_policy.get(source) or patent_source_auth_policy.get(source)
    configured_scope = selected_policy.auth_state_scope if selected_policy is not None else ""
    return safe_slug(configured_scope or source)


def normalized_search_record_type(value: str | None = None) -> Literal["literature", "patent"]:
    selected = first_string(value).casefold()
    return "patent" if selected == "patent" else "literature"


def current_search_record_type() -> Literal["literature", "patent"]:
    return normalized_search_record_type(
        first_string(SEARCH_TASK_CONTEXT.get().get("record_type"))
    )


def canonical_source_for_auth_scope(
    auth_state_scope: str,
    record_type: Literal["literature", "patent"],
) -> str:
    expected_scope = safe_slug(auth_state_scope)
    source_map = (
        patents_search_path_map
        if record_type == "patent"
        else literature_search_path_map
    )
    policy_map = (
        patent_source_auth_policy
        if record_type == "patent"
        else literature_source_auth_policy
    )
    for candidate in source_map:
        policy = policy_map.get(candidate)
        if policy is not None and source_auth_state_scope(candidate, policy) == expected_scope:
            return candidate
    return ""


def canonical_literature_source_for_auth_scope(auth_state_scope: str) -> str:
    return canonical_source_for_auth_scope(auth_state_scope, "literature")


def auth_state_path(config: SearchConfig, source: str, policy: SourceAccessPolicy | None = None) -> Path:
    mode = source_restricted_access_mode(config, source, policy)
    path_part = safe_slug(mode)
    school_part = (
        safe_slug(normalize_school(config.school))
        if mode == "institution"
        else "personal"
    )
    scope_part = source_auth_state_scope(source, policy)
    return AUTH_STATE_DIR / path_part / school_part / f"{scope_part}.json"


def auth_state_attestation_path(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy | None = None,
) -> Path:
    state_path = auth_state_path(config, source, policy)
    return state_path.with_name(f"{state_path.stem}.attestation.json")


def auth_state_confirmation_url(source: str, policy: SourceAccessPolicy) -> str:
    return first_string(
        policy.web_search_url
        or policy.auth_entry_url
        or literature_search_path_map.get(source)
        or patents_search_path_map.get(source)
    )


def auth_state_service_host(source: str, policy: SourceAccessPolicy) -> str:
    if source_auth_state_scope(source, policy) == "cnki":
        return "cnki.net"
    return (urllib.parse.urlsplit(auth_state_confirmation_url(source, policy)).hostname or "").casefold()


def auth_state_scope_identity(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    state_path: Path,
) -> tuple[str, str]:
    scope = source_auth_state_scope(source, policy)
    mode = source_restricted_access_mode(config, source, policy)
    principal_digest = search_challenge_principal_digest(config, source, mode)
    shared_scope = bool(policy.auth_state_scope)
    return (
        auth_scope_key(
            auth_mode=mode,
            principal_digest=principal_digest,
            auth_state_scope=scope,
            channel=source,
            state_path_digest=hashlib.sha256(
                str(state_path.resolve()).encode("utf-8")
            ).hexdigest(),
            shared_scope=shared_scope,
        ),
        principal_digest,
    )


def effective_auth_state_scope_identity(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    state_path: Path,
) -> tuple[str, str, str]:
    scope_key, principal_digest = auth_state_scope_identity(
        config,
        source,
        policy,
        state_path,
    )
    mode = (
        "site_personal"
        if source == UYANIP_SOURCE or policy.runtime_personal_credential_keys
        else source_restricted_access_mode(config, source, policy)
    )
    if mode == "site_personal":
        scope_key = auth_scope_key(
            auth_mode=mode,
            principal_digest=principal_digest,
            auth_state_scope=source_auth_state_scope(source, policy),
            shared_scope=True,
        )
    return scope_key, principal_digest, mode


def auth_state_service_host_matches(expected_host: str, current_host: str) -> bool:
    expected = first_string(expected_host).casefold().strip(".")
    current = first_string(current_host).casefold().strip(".")
    if not expected or not current:
        return False
    if expected == "cnki.net":
        return current == expected or current.endswith(f".{expected}")
    return current == expected


def auth_state_file_sha256(path: Path) -> str:
    digest = hashlib.sha256()
    with path.open("rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def auth_state_attestation_ttl_seconds() -> int:
    try:
        configured = int(
            os.getenv(
                "LAPS_AUTH_STATE_ATTESTATION_TTL_SECONDS",
                str(AUTH_STATE_ATTESTATION_DEFAULT_TTL_SECONDS),
            )
        )
    except ValueError:
        configured = AUTH_STATE_ATTESTATION_DEFAULT_TTL_SECONDS
    return max(
        AUTH_STATE_ATTESTATION_MIN_TTL_SECONDS,
        min(AUTH_STATE_ATTESTATION_MAX_TTL_SECONDS, configured),
    )


def auth_state_attestation_kind_from_control_reason(reason: str) -> str:
    normalized = first_string(reason).casefold()
    if normalized.endswith("_institution_marker"):
        return "exact_institution_marker"
    if normalized.endswith("_sso_round_trip"):
        return "sso_round_trip"
    return ""


def save_auth_state_attestation(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    state_path: Path,
    confirmation_kind: str,
    *,
    staged_state_path: Path | None = None,
) -> tuple[bool, str]:
    kind = first_string(confirmation_kind).casefold()
    if kind not in AUTH_STATE_ATTESTATION_CONFIRMATION_KINDS:
        return False, "auth_state_attestation_confirmation_kind_invalid"
    service_host = auth_state_service_host(source, policy)
    scope_key, principal_digest, mode = effective_auth_state_scope_identity(
        config,
        source,
        policy,
        state_path,
    )
    candidate_state = staged_state_path or state_path
    if (
        candidate_state.is_symlink()
        or not candidate_state.is_file()
        or not service_host
        or mode not in {"institution", "personal", "site_personal"}
    ):
        return False, "auth_state_attestation_prerequisite_missing"
    lease_context = AUTH_SCOPE_LEASE_CONTEXT.get()
    owner_token = first_string(lease_context.get("owner_token"))
    operation_id = first_string(lease_context.get("operation_id"))
    active_scope_key = first_string(lease_context.get("scope_key"))
    store = search_auth_control_store()
    if (
        active_scope_key != scope_key
        or not owner_token
        or not operation_id
        or not store.owns_active_scope_lease(
            scope_key,
            owner_token=owner_token,
            operation_id=operation_id,
        )
    ):
        return False, "auth_scope_lease_missing"
    token = uuid.uuid4().hex
    staged_state = state_path.with_name(f".{state_path.name}.{token}.tmp")
    try:
        if staged_state_path is None:
            shutil.copy2(state_path, staged_state)
        else:
            staged_state = staged_state_path
        payload = build_auth_state_attestation_v2(
            state_path=staged_state,
            generation_id=str(uuid.uuid4()),
            auth_state_scope=source_auth_state_scope(source, policy),
            auth_mode=mode,
            principal_digest=principal_digest,
            confirmation_kind=kind,
            service_host=service_host,
            browser_name="chromium",
            headful_required=os.getenv("LAPS_AUTH_INTERACTIVE", "0") == "1",
            producer_component="search",
            producer_operation_id=operation_id,
            ttl_seconds=auth_state_attestation_ttl_seconds(),
        )
    except (OSError, ValueError) as exc:
        staged_state.unlink(missing_ok=True)
        return False, str(exc)
    target = auth_state_attestation_path(config, source, policy)
    target.parent.mkdir(parents=True, exist_ok=True)
    temporary = target.with_name(f".{target.name}.{token}.tmp")
    try:
        temporary.write_text(json.dumps(payload, ensure_ascii=True, indent=2) + "\n", encoding="utf-8")
    except OSError as exc:
        staged_state.unlink(missing_ok=True)
        temporary.unlink(missing_ok=True)
        return False, f"auth_state_attestation_write_failed:{exc.__class__.__name__}"
    committed, commit_reason = store.publish_auth_generation(
        scope_key,
        payload,
        staged_state_path=staged_state,
        target_state_path=state_path,
        staged_attestation_path=temporary,
        target_attestation_path=target,
        owner_token=owner_token,
        operation_id=operation_id,
    )
    if not committed:
        staged_state.unlink(missing_ok=True)
        temporary.unlink(missing_ok=True)
        return False, commit_reason
    chmod_user_config(state_path)
    chmod_user_config(target)
    return True, "auth_state_attestation_saved"


async def persist_search_auth_context_state(
    context: Any,
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    confirmation_kind: str,
) -> tuple[bool, str]:
    """Stage browser state, then publish it only while holding its scope lease."""

    target_state = auth_state_path(config, source, policy)
    target_state.parent.mkdir(parents=True, exist_ok=True)
    staged_state = target_state.with_name(
        f".{target_state.name}.{uuid.uuid4().hex}.capture.tmp"
    )
    try:
        await context.storage_state(path=str(staged_state))
        chmod_user_config(staged_state)
    except Exception as exc:
        staged_state.unlink(missing_ok=True)
        return False, f"auth_state_stage_failed:{exc.__class__.__name__}"

    scope_key, _principal_digest, auth_mode = effective_auth_state_scope_identity(
        config,
        source,
        policy,
        target_state,
    )
    store = search_auth_control_store()
    current = AUTH_SCOPE_LEASE_CONTEXT.get()
    current_owner = first_string(current.get("owner_token"))
    current_operation = first_string(current.get("operation_id"))
    if (
        first_string(current.get("scope_key")) == scope_key
        and current_owner
        and current_operation
        and await asyncio.to_thread(
            store.owns_active_scope_lease,
            scope_key,
            owner_token=current_owner,
            operation_id=current_operation,
        )
    ):
        try:
            return save_auth_state_attestation(
                config,
                source,
                policy,
                target_state,
                confirmation_kind,
                staged_state_path=staged_state,
            )
        finally:
            staged_state.unlink(missing_ok=True)

    owner_token = uuid.uuid4().hex
    operation_id = (
        first_string(SEARCH_TASK_CONTEXT.get().get("config_fingerprint"))
        or uuid.uuid4().hex
    )
    deadline = time.monotonic() + verification_hook_timeout_seconds(
        "auth_challenge"
    )
    lease = await asyncio.to_thread(
        store.wait_for_scope_lease,
        scope_key,
        owner_token=owner_token,
        operation_id=operation_id,
        deadline=deadline,
    )
    if not lease.acquired:
        staged_state.unlink(missing_ok=True)
        return False, lease.reason_code or "auth_scope_lease_timeout"
    context_token = AUTH_SCOPE_LEASE_CONTEXT.set(
        {
            "scope_key": scope_key,
            "owner_token": owner_token,
            "operation_id": operation_id,
            "auth_mode": auth_mode,
        }
    )
    try:
        return save_auth_state_attestation(
            config,
            source,
            policy,
            target_state,
            confirmation_kind,
            staged_state_path=staged_state,
        )
    finally:
        AUTH_SCOPE_LEASE_CONTEXT.reset(context_token)
        staged_state.unlink(missing_ok=True)
        await asyncio.to_thread(
            store.release_scope_lease,
            scope_key,
            owner_token=owner_token,
        )


def load_auth_state_attestation(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
) -> tuple[dict[str, Any] | None, str]:
    path = auth_state_attestation_path(config, source, policy)
    if not path.is_file():
        return None, "auth_state_attestation_missing"
    try:
        loaded = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError):
        return None, "auth_state_attestation_invalid"
    if not isinstance(loaded, dict) or set(loaded) != AUTH_STATE_ATTESTATION_FIELDS:
        return None, "auth_state_attestation_invalid"
    return loaded, ""


def validate_auth_state_attestation_metadata(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    state_path: Path,
    payload: dict[str, Any],
    current_url: str,
    *,
    now: datetime | None = None,
) -> tuple[bool, str]:
    expected_scope = source_auth_state_scope(source, policy)
    expected_mode = (
        "site_personal"
        if source == UYANIP_SOURCE or policy.runtime_personal_credential_keys
        else source_restricted_access_mode(config, source, policy)
    )
    expected_host = auth_state_service_host(source, policy)
    current_host = (urllib.parse.urlsplit(current_url or "").hostname or "").casefold()
    if not auth_state_service_host_matches(expected_host, current_host):
        return False, "auth_state_attestation_scope_or_host_mismatch"
    scope_key, principal_digest = auth_state_scope_identity(
        config,
        source,
        policy,
        state_path,
    )
    if expected_mode == "site_personal":
        scope_key = auth_scope_key(
            auth_mode=expected_mode,
            principal_digest=principal_digest,
            auth_state_scope=expected_scope,
            shared_scope=True,
        )
    validation = validate_auth_state_attestation_v2(
        payload,
        state_path,
        expected_scope=expected_scope,
        expected_auth_mode=expected_mode,
        expected_principal_digest=principal_digest,
        expected_service_host=expected_host,
        scope_key=scope_key,
        store=search_auth_control_store(),
        now=now,
    )
    return validation.valid, validation.reason_code


def classify_saved_auth_state_for_reuse(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    state_path: Path,
    confirmation_url: str,
) -> tuple[str, str]:
    """Classify a saved state before it is ever loaded into a browser context.

    Only a state with no v2 sidecar is a legacy seed.  Once a v2 sidecar
    exists, any sidecar/state/generation mismatch is a rejected v2 state and
    must not be silently re-signed through the seed upgrade path.
    """

    if state_path.is_symlink() or not state_path.is_file():
        return "unavailable", "auth_state_attestation_prerequisite_missing"
    payload, reason = load_auth_state_attestation(config, source, policy)
    if payload is None:
        if reason == "auth_state_attestation_missing":
            return "legacy_seed", "auth_state_legacy_seed_unattested"
        return "rejected_v2", reason or "auth_state_attestation_invalid"
    valid, validation_reason = validate_auth_state_attestation_metadata(
        config,
        source,
        policy,
        state_path,
        payload,
        confirmation_url,
    )
    if not valid:
        return "rejected_v2", validation_reason
    return "valid_v2", validation_reason


async def confirm_saved_auth_state_attestation(
    page: Any,
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    state_path: Path,
) -> tuple[bool, str]:
    payload, reason = load_auth_state_attestation(config, source, policy)
    if payload is None:
        return False, reason
    metadata_valid, reason = validate_auth_state_attestation_metadata(
        config,
        source,
        policy,
        state_path,
        payload,
        first_string(getattr(page, "url", "")),
    )
    if not metadata_valid:
        return False, reason
    body = await page_body_text(page)
    if await page_has_visible_password_input(page):
        return False, "auth_state_attestation_password_required"
    if auth_body_has_blocking_failure(body) or institutional_agreement_non_auth_page(
        body,
        first_string(getattr(page, "url", "")),
    ):
        return False, "auth_state_attestation_access_blocked"
    if body_has_verification_challenge(body):
        return False, "auth_state_attestation_challenge_present"
    return True, "saved_state_attested_sso_round_trip"


def normalize_browser_name(value: Any, default: str = "") -> str:
    normalized = first_string(value).casefold()
    if normalized in SUPPORTED_BROWSER_NAMES:
        return normalized
    return default if default in SUPPORTED_BROWSER_NAMES else ""


def auth_browser_transport_path(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy | None = None,
) -> Path:
    state_path = auth_state_path(config, source, policy)
    return state_path.with_name(f"{state_path.stem}.browser.json")


def parse_auth_browser_transport(payload: Any) -> AuthBrowserTransport | None:
    if not isinstance(payload, dict) or payload.get("schema") != AUTH_BROWSER_TRANSPORT_SCHEMA:
        return None
    browser_name = normalize_browser_name(payload.get("browser_name"))
    headful_required = payload.get("headful_required")
    if not browser_name or not isinstance(headful_required, bool):
        return None
    return AuthBrowserTransport(
        browser_name=browser_name,
        headful_required=headful_required,
    )


def load_auth_browser_transport(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy | None = None,
) -> tuple[AuthBrowserTransport | None, str]:
    path = auth_browser_transport_path(config, source, policy)
    if not path.is_file():
        return None, ""
    try:
        transport = parse_auth_browser_transport(
            json.loads(path.read_text(encoding="utf-8-sig"))
        )
    except Exception:
        transport = None
    return (
        (transport, "")
        if transport is not None
        else (None, "auth_state_browser_transport_invalid")
    )


def save_auth_browser_transport(
    config: SearchConfig,
    source: str,
    browser_name: str,
    headful_required: bool,
    policy: SourceAccessPolicy | None = None,
) -> Path | None:
    normalized_browser = normalize_browser_name(browser_name)
    if not normalized_browser:
        return None
    path = auth_browser_transport_path(config, source, policy)
    path.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "schema": AUTH_BROWSER_TRANSPORT_SCHEMA,
        "browser_name": normalized_browser,
        "headful_required": bool(headful_required),
    }
    path.write_text(
        json.dumps(payload, ensure_ascii=True, indent=2) + "\n",
        encoding="utf-8",
    )
    chmod_user_config(path)
    return path


def configured_institution_identity_digest(config: SearchConfig) -> str:
    normalized = sorted(
        {
            " ".join(unicodedata.normalize("NFKC", value).casefold().split())
            for value in (config.school, *config.school_aliases)
            if first_string(value)
        }
    )
    if not normalized:
        return ""
    return hashlib.sha256(
        json.dumps(normalized, ensure_ascii=False).encode("utf-8")
    ).hexdigest()


def ordinary_chrome_external_session_path(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy | None = None,
    record_type: Literal["literature", "patent"] | None = None,
) -> Path:
    state_path = auth_state_path(config, source, policy)
    selected_record_type = record_type or current_search_record_type()
    return state_path.with_name(
        f"{state_path.stem}.{selected_record_type}.external_session.json"
    )


def ordinary_chrome_external_snapshot_dir(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy | None = None,
    record_type: Literal["literature", "patent"] | None = None,
) -> Path:
    state_path = auth_state_path(config, source, policy)
    selected_record_type = record_type or current_search_record_type()
    return state_path.with_name(
        f"{state_path.stem}.{selected_record_type}.external_snapshots"
    )


def ordinary_chrome_external_session_ttl_seconds() -> int:
    try:
        configured = int(
            os.getenv(
                "LAPS_ORDINARY_CHROME_EXTERNAL_SESSION_TTL_SECONDS",
                str(ORDINARY_CHROME_EXTERNAL_SESSION_DEFAULT_TTL_SECONDS),
            )
        )
    except ValueError:
        configured = ORDINARY_CHROME_EXTERNAL_SESSION_DEFAULT_TTL_SECONDS
    return max(
        60,
        min(ORDINARY_CHROME_EXTERNAL_SESSION_MAX_TTL_SECONDS, configured),
    )


def ordinary_chrome_external_keyword_digest(keyword: str) -> str:
    normalized = " ".join(unicodedata.normalize("NFKC", keyword).split())
    return hashlib.sha256(normalized.encode("utf-8")).hexdigest()


def ordinary_chrome_external_snapshot_cache_key(
    auth_state_scope: str,
    record_type: Literal["literature", "patent"],
    keyword: str,
) -> str:
    material = (
        f"{safe_slug(auth_state_scope)}|{record_type}|"
        f"{ordinary_chrome_external_keyword_digest(keyword)}"
    )
    return hashlib.sha256(material.encode("ascii")).hexdigest()[:32]


def ordinary_chrome_external_session_sidecar_fields() -> frozenset[str]:
    return frozenset(
        {
            "schema",
            "record_type",
            "auth_state_scope",
            "auth_mode",
            "service_host",
            "institution_identity_digest",
            "browser_transport",
            "browser_profile_label",
            "confirmed_at",
            "event_id",
            "source",
            "keyword_sha256",
            "snapshot_cache_key",
            "snapshot_page_count",
            "exhausted",
        }
    )


def save_ordinary_chrome_external_session(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    keyword: str,
    event_id: str,
    snapshots: list[dict[str, Any]],
    record_type: Literal["literature", "patent"] | None = None,
) -> tuple[bool, str]:
    if not snapshots or not keyword or not event_id:
        return False, "ordinary_chrome_external_session_prerequisite_missing"
    selected_record_type = record_type or current_search_record_type()
    scope = source_auth_state_scope(source, policy)
    cache_key = ordinary_chrome_external_snapshot_cache_key(
        scope,
        selected_record_type,
        keyword,
    )
    snapshot_dir = ordinary_chrome_external_snapshot_dir(
        config,
        source,
        policy,
        selected_record_type,
    )
    snapshot_dir.mkdir(parents=True, exist_ok=True)
    cached_paths: list[Path] = []
    try:
        for index, snapshot in enumerate(snapshots, start=1):
            target = snapshot_dir / f"{cache_key}.{index:04d}.json"
            payload = {
                "schema": "laps_sanitized_search_snapshot_v1",
                **snapshot,
                "search_record_type": selected_record_type,
            }
            temporary = target.with_name(f"{target.name}.tmp")
            temporary.write_text(
                json.dumps(payload, ensure_ascii=False, indent=2) + "\n",
                encoding="utf-8",
            )
            os.replace(temporary, target)
            chmod_user_config(target)
            cached_paths.append(target)
    except OSError as exc:
        for path in cached_paths:
            path.unlink(missing_ok=True)
        return False, f"ordinary_chrome_external_snapshot_cache_failed:{exc.__class__.__name__}"

    last_snapshot = snapshots[-1]
    sidecar = {
        "schema": ORDINARY_CHROME_EXTERNAL_SESSION_SIDECAR_SCHEMA,
        "record_type": selected_record_type,
        "auth_state_scope": scope,
        "auth_mode": source_restricted_access_mode(config, source, policy),
        "service_host": auth_state_service_host(source, policy),
        "institution_identity_digest": configured_institution_identity_digest(config),
        "browser_transport": ORDINARY_CHROME_EXTERNAL_SESSION_TRANSPORT,
        "browser_profile_label": "selected_profile",
        "confirmed_at": datetime.now(timezone.utc).isoformat().replace("+00:00", "Z"),
        "event_id": event_id,
        "source": source,
        "keyword_sha256": ordinary_chrome_external_keyword_digest(keyword),
        "snapshot_cache_key": cache_key,
        "snapshot_page_count": len(cached_paths),
        "exhausted": bool(
            last_snapshot.get("explicit_no_results")
            or (
                not first_string(last_snapshot.get("next_url"))
                and not bool(last_snapshot.get("has_next_control"))
            )
        ),
    }
    target = ordinary_chrome_external_session_path(
        config,
        source,
        policy,
        selected_record_type,
    )
    target.parent.mkdir(parents=True, exist_ok=True)
    temporary = target.with_name(f"{target.name}.tmp")
    try:
        temporary.write_text(
            json.dumps(sidecar, ensure_ascii=True, indent=2) + "\n",
            encoding="utf-8",
        )
        os.replace(temporary, target)
        chmod_user_config(target)
    except OSError as exc:
        temporary.unlink(missing_ok=True)
        return False, f"ordinary_chrome_external_session_write_failed:{exc.__class__.__name__}"
    return True, "ordinary_chrome_external_session_saved"


def load_ordinary_chrome_external_session(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    keyword: str,
    *,
    record_type: Literal["literature", "patent"] | None = None,
    now: datetime | None = None,
) -> tuple[list[dict[str, Any]] | None, str]:
    selected_record_type = record_type or current_search_record_type()
    path = ordinary_chrome_external_session_path(
        config,
        source,
        policy,
        selected_record_type,
    )
    if not path.is_file():
        return None, "ordinary_chrome_external_session_missing"
    try:
        loaded = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, json.JSONDecodeError):
        return None, "ordinary_chrome_external_session_invalid"
    if (
        not isinstance(loaded, dict)
        or set(loaded) != ordinary_chrome_external_session_sidecar_fields()
        or loaded.get("schema") != ORDINARY_CHROME_EXTERNAL_SESSION_SIDECAR_SCHEMA
    ):
        return None, "ordinary_chrome_external_session_invalid"
    expected_scope = source_auth_state_scope(source, policy)
    if (
        first_string(loaded.get("auth_state_scope")) != expected_scope
        or first_string(loaded.get("record_type")) != selected_record_type
        or first_string(loaded.get("auth_mode"))
        != source_restricted_access_mode(config, source, policy)
        or first_string(loaded.get("service_host")) != auth_state_service_host(source, policy)
        or first_string(loaded.get("institution_identity_digest"))
        != configured_institution_identity_digest(config)
        or first_string(loaded.get("browser_transport"))
        != ORDINARY_CHROME_EXTERNAL_SESSION_TRANSPORT
        or first_string(loaded.get("keyword_sha256"))
        != ordinary_chrome_external_keyword_digest(keyword)
    ):
        return None, "ordinary_chrome_external_session_scope_mismatch"
    confirmed_at_text = first_string(loaded.get("confirmed_at"))
    if confirmed_at_text.endswith("Z"):
        confirmed_at_text = confirmed_at_text[:-1] + "+00:00"
    try:
        confirmed_at = datetime.fromisoformat(confirmed_at_text)
    except ValueError:
        return None, "ordinary_chrome_external_session_invalid"
    selected_now = now or datetime.now(timezone.utc)
    if confirmed_at.tzinfo is None or selected_now.tzinfo is None:
        return None, "ordinary_chrome_external_session_invalid"
    age = (
        selected_now.astimezone(timezone.utc)
        - confirmed_at.astimezone(timezone.utc)
    ).total_seconds()
    if age < -300 or age > ordinary_chrome_external_session_ttl_seconds():
        return None, "ordinary_chrome_external_session_expired"
    try:
        page_count = int(loaded.get("snapshot_page_count") or 0)
    except (TypeError, ValueError):
        return None, "ordinary_chrome_external_session_invalid"
    if not 1 <= page_count <= 100:
        return None, "ordinary_chrome_external_session_invalid"
    cache_key = first_string(loaded.get("snapshot_cache_key"))
    source_for_snapshot = first_string(loaded.get("source"))
    canonical_source = canonical_source_for_auth_scope(
        expected_scope,
        selected_record_type,
    )
    if not canonical_source or source_for_snapshot != canonical_source:
        return None, "ordinary_chrome_external_session_provenance_invalid"
    if source == canonical_source:
        return None, "ordinary_chrome_external_session_live_revalidation_required"
    event_id = first_string(loaded.get("event_id"))
    snapshots: list[dict[str, Any]] = []
    snapshot_dir = ordinary_chrome_external_snapshot_dir(
        config,
        source,
        policy,
        selected_record_type,
    )
    for index in range(1, page_count + 1):
        snapshot = load_sanitized_search_snapshot(
            str(snapshot_dir / f"{cache_key}.{index:04d}.json"),
            expected_source=source_for_snapshot,
            expected_keyword=keyword,
            expected_event_id=event_id,
            expected_auth_state_scope=expected_scope,
            expected_record_type=selected_record_type,
            require_managed_path=True,
        )
        if snapshot is None:
            return None, "ordinary_chrome_external_snapshot_cache_invalid"
        snapshots.append(snapshot)
    return snapshots, "ordinary_chrome_external_session_snapshot_reusable"


def ensure_project_structure(project_root: Path = PROJECT_ROOT) -> None:
    tools_dir = project_root / "tools"
    for path in (
        project_root / "scripts",
        tools_dir,
        tools_dir / ".venv",
        tools_dir / "ms-playwright",
        tools_dir / "run_logs",
        tools_dir / "auth_state",
        project_root / "literature_and_patents_metadata_list" / "literature_metadata_list",
        project_root / "literature_and_patents_metadata_list" / "patents_metadata_list",
    ):
        path.mkdir(parents=True, exist_ok=True)


def get_runtime_config_path() -> Path:
    for env_name in RUNTIME_CONFIG_ENV_NAMES:
        configured = read_named_environment(env_name)
        if configured:
            path = Path(configured).expanduser().resolve()
            if path.exists() and path.is_dir():
                raise ValueError(f"{env_name} must point to a JSON file, not a directory: {path}")
            return path
    return CONFIG_PATH


def ensure_config_file(config_path: Path | None = None) -> Path:
    config_path = config_path or get_runtime_config_path()
    config_path.parent.mkdir(parents=True, exist_ok=True)
    return config_path


def load_config(config_path: Path | None = None) -> dict[str, Any]:
    config_path = ensure_config_file(config_path)
    if not config_path.exists():
        return dict(DEFAULT_CONFIG)
    with config_path.open("r", encoding="utf-8-sig") as handle:
        loaded = json.load(handle)
    merged = DEFAULT_CONFIG | {k: v for k, v in loaded.items() if k in DEFAULT_CONFIG}
    return merged


def validate_config(config: dict[str, Any]) -> SearchConfig:
    try:
        thread_num = int(config.get("thread_num", DEFAULT_CONFIG["thread_num"]))
    except (TypeError, ValueError):
        thread_num = DEFAULT_CONFIG["thread_num"]
    thread_num = max(1, thread_num)
    raw_path = str(config.get("path", "institution") or "")
    normalized_path = raw_path.strip().casefold()
    valid_path = normalized_path in {"institution", "personal"}
    path = normalized_path if valid_path else raw_path
    return SearchConfig(
        thread_num=thread_num,
        path=path,
        school=str(config.get("school", "") or ""),
        account=str(config.get("account", "") or ""),
        password=str(config.get("password", "") or ""),
        valid_path=valid_path,
        school_aliases=normalize_school_aliases(config.get("school_aliases")),
        uyanip_account=str(config.get("uyanip_account", "") or ""),
        uyanip_password=str(config.get("uyanip_password", "") or ""),
    )


def source_personal_credentials(
    config: SearchConfig,
    policy: SourceAccessPolicy,
) -> tuple[str, str]:
    keys = policy.runtime_personal_credential_keys
    if len(keys) != 2:
        return "", ""
    return (
        first_string(getattr(config, keys[0], "")),
        first_string(getattr(config, keys[1], "")),
    )


def source_restricted_access_mode(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy | None = None,
) -> Literal["none", "institution", "personal", "invalid"]:
    selected_policy = (
        policy
        or literature_source_auth_policy.get(source)
        or patent_source_auth_policy.get(source)
    )
    if selected_policy is not None and selected_policy.runtime_personal_credential_keys:
        account, password = source_personal_credentials(config, selected_policy)
        return "personal" if account and password else "none"
    return restricted_access_mode(config)


def config_file_revision(path: Path | None) -> str:
    if path is None:
        return "unconfigured"
    try:
        stat = path.stat()
    except OSError:
        state = "missing"
        stat_payload: dict[str, Any] = {}
    else:
        state = "present"
        digest = hashlib.sha256()
        try:
            with path.open("rb") as handle:
                for block in iter(lambda: handle.read(1024 * 1024), b""):
                    digest.update(block)
            content_sha256 = digest.hexdigest()
        except OSError:
            state = "unreadable"
            content_sha256 = ""
        stat_payload = {
            "mtime_ns": int(stat.st_mtime_ns),
            "size": int(stat.st_size),
            # A digest is revision evidence, never the file contents.  It also
            # invalidates a checkpoint when a credential file is atomically
            # replaced while preserving size and timestamp.
            "content_sha256": content_sha256,
        }
    payload = {
        "path_digest": hashlib.sha256(str(path).encode("utf-8")).hexdigest(),
        "state": state,
        **stat_payload,
    }
    return hashlib.sha256(
        json.dumps(payload, sort_keys=True).encode("utf-8")
    ).hexdigest()


def runtime_config_revision() -> str:
    return config_file_revision(get_runtime_config_path())


def api_config_revision() -> str:
    return config_file_revision(get_api_config_path(required=False))


def should_use_restricted_access(config: SearchConfig | dict[str, Any]) -> bool:
    if isinstance(config, dict):
        config = validate_config(config)
    if not config.valid_path or not config.account or not config.password:
        return False
    if config.path == "institution":
        return bool(config.school.strip())
    if config.path == "personal":
        return True
    return False


def restricted_access_mode(config: SearchConfig | dict[str, Any]) -> Literal["none", "institution", "personal", "invalid"]:
    if isinstance(config, dict):
        config = validate_config(config)
    if not config.valid_path:
        return "invalid"
    if not should_use_restricted_access(config):
        return "none"
    if config.path == "institution":
        return "institution"
    if config.path == "personal":
        return "personal"
    return "invalid"


def restricted_web_fallback_enabled(config: SearchConfig | dict[str, Any]) -> bool:
    if isinstance(config, dict):
        config = validate_config(config)
    return should_use_restricted_access(config) and os.getenv("LAPS_ENABLE_RESTRICTED_WEB_FALLBACK", "1") == "1"


def search_adapter_contract_revision() -> str:
    """Hash fields that change checkpoint compatibility, independent of secrets."""

    payload = [
        {
            "record_type": spec.record_type,
            "order": spec.order,
            "display_name": spec.display_name,
            "nominal_endpoint": spec.nominal_endpoint,
            "endpoint": spec.endpoint,
            "actual_adapter": spec.actual_adapter,
            "parser": spec.parser,
            "paths": spec.paths,
            "pagination": spec.pagination,
            "query_fields": spec.query_fields,
            "auth_scope": spec.auth_scope,
            "fallback_resolver": spec.fallback_resolver,
            "fallback_auth_scope": spec.fallback_auth_scope,
        }
        for spec in (*LITERATURE_SEARCH_SPECS, *PATENT_SEARCH_SPECS)
    ]
    return hashlib.sha256(
        json.dumps(payload, ensure_ascii=True, sort_keys=True).encode("utf-8")
    ).hexdigest()


def search_config_fingerprint(
    config: SearchConfig,
    page_size: int | None = None,
) -> str:
    institution_labels = sorted(
        normalize_institution_name(label)
        for label in exact_institution_labels(config.school, config.school_aliases)
    )
    credential_revision_material = {
        "api": {
            key: hashlib.sha256(str(value).encode("utf-8")).hexdigest()
            for key, value in sorted(API_CONFIG_VALUES.items())
            if value
        },
        "runtime": {
            key: hashlib.sha256(str(value).encode("utf-8")).hexdigest()
            for key, value in (
                ("account", config.account),
                ("password", config.password),
                ("uyanip_account", config.uyanip_account),
                ("uyanip_password", config.uyanip_password),
            )
            if value
        },
    }
    payload = {
        "search_semantics_version": "coverage_variants_path_isolation_merge_v4",
        "registry_version": REGISTRY_VERSION,
        "registry_schema_version": REGISTRY_SCHEMA_VERSION,
        "canonical_schema_version": CANONICAL_SCHEMA_VERSION,
        "search_adapter_contract_revision": search_adapter_contract_revision(),
        "page_size": int(page_size) if page_size is not None else None,
        "configured_api_keys": sorted(key for key, value in API_CONFIG_VALUES.items() if value),
        "credential_revision": hashlib.sha256(
            json.dumps(
                credential_revision_material,
                ensure_ascii=True,
                sort_keys=True,
            ).encode("utf-8")
        ).hexdigest(),
        "runtime_config_revision": runtime_config_revision(),
        "api_config_revision": api_config_revision(),
        "runtime_mode": restricted_access_mode(config),
        "school_configured": bool(config.school.strip()),
        "institution_identity_digest": hashlib.sha256(
            json.dumps(institution_labels, ensure_ascii=True).encode("utf-8")
        ).hexdigest(),
        "account_configured": bool(config.account.strip()),
        "password_configured": bool(config.password.strip()),
        "restricted_web_enabled": restricted_web_fallback_enabled(config),
        "uyanip_credentials_configured": bool(
            config.uyanip_account.strip() and config.uyanip_password
        ),
    }
    return hashlib.sha256(json.dumps(payload, sort_keys=True).encode("utf-8")).hexdigest()


def venv_python_path(venv_dir: Path = VENV_DIR) -> Path:
    if os.name == "nt":
        return venv_dir / "Scripts" / "python.exe"
    return venv_dir / "bin" / "python"


def python_has_required_imports(py: Path) -> bool:
    code = (
        "import playwright.async_api, httpx, pandas, bs4, lxml, dateutil, "
        "tenacity, tqdm, feedparser, xmltodict, pydantic, orjson, pypdf, "
        "google.cloud.bigquery, zeep"
    )
    try:
        result = subprocess.run([str(py), "-c", code], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    except OSError:
        return False
    return result.returncode == 0


def running_in_tools_venv() -> bool:
    try:
        return VENV_DIR.resolve() in Path(sys.executable).resolve().parents or Path(sys.prefix).resolve() == VENV_DIR.resolve()
    except OSError:
        return False


def chromium_installed() -> bool:
    if not PLAYWRIGHT_DIR.exists():
        return False
    names = {"chrome.exe", "chrome", "chromium", "headless_shell.exe", "headless_shell"}
    return any(path.name in names for path in PLAYWRIGHT_DIR.rglob("*"))


def load_async_playwright() -> Any:
    os.environ.setdefault("PLAYWRIGHT_BROWSERS_PATH", str(PLAYWRIGHT_DIR))
    return importlib.import_module("playwright.async_api").async_playwright


def local_chrome_executable() -> Path | None:
    configured = first_string(
        os.getenv("LAPS_CHROME_EXECUTABLE")
        or os.getenv("CODEX_HOOK_CHROME_EXECUTABLE")
    )
    candidates: list[Path] = [Path(configured).expanduser()] if configured else []
    if not configured:
        for command in ("chrome", "chrome.exe", "google-chrome", "google-chrome-stable"):
            found = shutil.which(command)
            if found:
                candidates.append(Path(found))
        for env_name, suffix in (
            ("PROGRAMFILES", r"Google\Chrome\Application\chrome.exe"),
            ("PROGRAMFILES(X86)", r"Google\Chrome\Application\chrome.exe"),
            ("LOCALAPPDATA", r"Google\Chrome\Application\chrome.exe"),
        ):
            base = first_string(os.getenv(env_name))
            if base:
                candidates.append(Path(base) / suffix)
    seen: set[str] = set()
    for candidate in candidates:
        key = str(candidate).casefold()
        if key in seen:
            continue
        seen.add(key)
        try:
            if candidate.is_file():
                return candidate.resolve()
        except OSError:
            continue
    return None


async def launch_named_browser(
    browser_type: Any,
    browser_name: str,
    *,
    headless: bool,
) -> tuple[Any | None, str]:
    normalized_browser = normalize_browser_name(browser_name, "chromium")
    cdp_port = available_loopback_port()
    launch_kwargs: dict[str, Any] = {
        "headless": headless,
        "args": [
            "--remote-debugging-address=127.0.0.1",
            f"--remote-debugging-port={cdp_port}",
        ],
    }
    if normalized_browser == "chromium":
        bundled_path = Path(first_string(getattr(browser_type, "executable_path", "")))
        if bundled_path.is_file():
            launch_kwargs["executable_path"] = str(bundled_path)
    else:
        chrome_path = local_chrome_executable()
        if chrome_path is None:
            return None, "local_chrome_not_found"
        launch_kwargs["executable_path"] = str(chrome_path)
    try:
        browser = await browser_type.launch(**launch_kwargs)
        register_parent_browser_control(
            browser,
            f"http://127.0.0.1:{cdp_port}",
            normalized_browser,
        )
        return browser, ""
    except Exception as exc:
        return None, f"{normalized_browser}_launch_failed:{exc.__class__.__name__}"


async def close_origin_before_browser_switch(browser: Any, context: Any) -> None:
    try:
        await context.close()
    except Exception:
        pass
    try:
        await browser.close()
    except Exception:
        pass


async def parent_browser_switch_cooldown(browser: Any, context: Any) -> None:
    await close_origin_before_browser_switch(browser, context)
    cooldown_seconds = verification_browser_fallback_cooldown_seconds()
    if cooldown_seconds > 0:
        await asyncio.sleep(float(cooldown_seconds))


async def replace_browser_context_from_storage_state(
    browser_type: Any,
    browser: Any,
    context: Any,
    state_path: str,
    browser_name: str,
    context_kwargs: dict[str, Any] | None = None,
    *,
    origin_already_closed: bool = False,
) -> tuple[Any | None, Any | None, str]:
    replacement_browser, launch_error = await launch_named_browser(
        browser_type,
        browser_name,
        headless=False,
    )
    if replacement_browser is None:
        return None, None, launch_error or "auth_state_browser_unavailable"
    try:
        replacement_context = await replacement_browser.new_context(
            **((context_kwargs or {}) | {"storage_state": state_path})
        )
    except Exception as exc:
        try:
            await replacement_browser.close()
        except Exception:
            pass
        return None, None, f"auth_state_context_failed:{exc.__class__.__name__}"
    if not origin_already_closed:
        await close_origin_before_browser_switch(browser, context)
    return replacement_browser, replacement_context, ""


def playwright_page_is_open(page: Any) -> bool:
    if page is None:
        return False
    try:
        return not bool(page.is_closed())
    except Exception:
        return True


async def page_after_parent_browser_handoff(
    context: Any,
    preferred_page: Any,
    final_url: str,
) -> Any | None:
    try:
        pages = [
            candidate
            for candidate in list(context.pages)
            if playwright_page_is_open(candidate)
        ]
    except Exception:
        pages = []
    expected_url = first_string(final_url)
    if expected_url:
        for candidate in reversed(pages):
            if first_string(getattr(candidate, "url", "")) == expected_url:
                return candidate
    if playwright_page_is_open(preferred_page):
        return preferred_page
    return pages[-1] if pages else None


async def close_browser_context_pages(
    context: Any,
    keep_page: Any | None = None,
) -> None:
    try:
        pages = list(context.pages)
    except Exception:
        pages = []
    for candidate in pages:
        if candidate is keep_page:
            continue
        if not playwright_page_is_open(candidate):
            continue
        try:
            await candidate.close()
        except Exception:
            pass


async def fresh_browser_context_page(
    context: Any,
    target_url: str,
) -> Any:
    page = await context.new_page()
    await close_browser_context_pages(context, keep_page=page)
    if target_url:
        await page.goto(
            target_url,
            wait_until="domcontentloaded",
            timeout=30000,
        )
    return page


async def prepare_browser_context_handoff_page(context: Any) -> Any | None:
    try:
        return await fresh_browser_context_page(context, "")
    except Exception:
        try:
            pages = [
                candidate
                for candidate in list(context.pages)
                if playwright_page_is_open(candidate)
            ]
        except Exception:
            pages = []
        return pages[-1] if pages else None


async def browser_context_navigation_page(context: Any) -> Any:
    try:
        pages = [
            candidate
            for candidate in list(context.pages)
            if playwright_page_is_open(candidate)
        ]
    except Exception:
        pages = []
    for candidate in reversed(pages):
        if first_string(getattr(candidate, "url", "")).casefold() in {
            "",
            "about:blank",
        }:
            await close_browser_context_pages(context, keep_page=candidate)
            return candidate
    return await fresh_browser_context_page(context, "")


async def apply_browser_control_transition(
    browser_type: Any,
    browser: Any,
    context: Any,
    page: Any,
    control: SearchChallengeControlResult,
    target_url: str,
    context_kwargs: dict[str, Any] | None = None,
    *,
    allow_missing_state: bool = False,
) -> BrowserControlTransitionResult:
    if control.same_browser_handoff:
        if control.switch_browser_to:
            return BrowserControlTransitionResult(
                browser,
                context,
                page,
                error="invalid_same_browser_switch_response",
            )
        controlled_page = await page_after_parent_browser_handoff(
            context,
            page,
            control.final_url,
        )
        if controlled_page is None:
            return BrowserControlTransitionResult(
                browser,
                context,
                page,
                error="parent_browser_controlled_page_missing",
            )
        registered = parent_browser_control_for_browser(browser)
        selected_browser = normalize_browser_name(
            control.browser_name
            or (registered.browser_name if registered is not None else ""),
            "chromium",
        )
        return BrowserControlTransitionResult(
            browser,
            context,
            controlled_page,
            mode="same_browser",
            browser_name=selected_browser,
        )

    state_path = storage_state_is_usable(control.storage_state_path)
    if not state_path:
        if allow_missing_state and not control.switch_browser_to:
            if target_url:
                try:
                    await page.goto(
                        target_url,
                        wait_until="domcontentloaded",
                        timeout=30000,
                    )
                except Exception as exc:
                    return BrowserControlTransitionResult(
                        browser,
                        context,
                        page,
                        mode="same_page",
                        error=(
                            "browser_handoff_navigation_failed:"
                            f"{exc.__class__.__name__}"
                        ),
                    )
            registered = parent_browser_control_for_browser(browser)
            return BrowserControlTransitionResult(
                browser,
                context,
                page,
                mode="same_page",
                browser_name=(
                    registered.browser_name if registered is not None else ""
                ),
            )
        return BrowserControlTransitionResult(
            browser,
            context,
            page,
            error="external_auth_state_missing",
        )
    switch_browser = normalize_browser_name(control.switch_browser_to)
    if control.switch_browser_to and switch_browser != "chrome":
        return BrowserControlTransitionResult(
            browser,
            context,
            page,
            error="unsupported_parent_browser_switch",
        )
    registered = parent_browser_control_for_browser(browser)
    current_browser_name = normalize_browser_name(
        registered.browser_name if registered is not None else control.browser_name
    )
    if switch_browser and current_browser_name != "chromium":
        return BrowserControlTransitionResult(
            browser,
            context,
            page,
            error="parent_browser_switch_requires_chromium_origin",
        )
    selected_browser = switch_browser or normalize_browser_name(
        control.browser_name,
        "chromium",
    )
    if not switch_browser and not control.browser_name:
        try:
            await context.close()
        except Exception:
            pass
        try:
            replacement_context = await browser.new_context(
                **((context_kwargs or {}) | {"storage_state": state_path})
            )
        except Exception as exc:
            return BrowserControlTransitionResult(
                browser,
                None,
                page,
                error=f"auth_state_context_failed:{exc.__class__.__name__}",
            )
        registered = parent_browser_control_for_browser(browser)
        restored_browser_name = (
            registered.browser_name if registered is not None else ""
        )
        replacement_page = await replacement_context.new_page()
        if target_url:
            try:
                await replacement_page.goto(
                    target_url,
                    wait_until="domcontentloaded",
                    timeout=30000,
                )
            except Exception as exc:
                return BrowserControlTransitionResult(
                    browser,
                    replacement_context,
                    replacement_page,
                    mode="restored_context",
                    browser_name=restored_browser_name,
                    error=(
                        "browser_handoff_navigation_failed:"
                        f"{exc.__class__.__name__}"
                    ),
                )
        return BrowserControlTransitionResult(
            browser,
            replacement_context,
            replacement_page,
            mode="restored_context",
            browser_name=restored_browser_name,
        )
    if switch_browser and local_chrome_executable() is None:
        return BrowserControlTransitionResult(
            browser,
            context,
            page,
            error="auth_state_browser_unavailable:local_chrome_not_found",
        )
    origin_already_closed = False
    if switch_browser:
        await parent_browser_switch_cooldown(browser, context)
        origin_already_closed = True
    replacement_browser, replacement_context, launch_error = (
        await replace_browser_context_from_storage_state(
            browser_type,
            browser,
            context,
            state_path,
            selected_browser,
            context_kwargs,
            origin_already_closed=origin_already_closed,
        )
    )
    if replacement_browser is None or replacement_context is None:
        return BrowserControlTransitionResult(
            browser,
            context,
            page,
            error=f"auth_state_browser_unavailable:{launch_error}",
        )
    replacement_page = await replacement_context.new_page()
    if target_url:
        try:
            await replacement_page.goto(
                target_url,
                wait_until="domcontentloaded",
                timeout=30000,
            )
        except Exception as exc:
            return BrowserControlTransitionResult(
                replacement_browser,
                replacement_context,
                replacement_page,
                mode="switch_browser" if switch_browser else "restored_browser",
                browser_name=selected_browser,
                error=f"browser_handoff_navigation_failed:{exc.__class__.__name__}",
            )
    return BrowserControlTransitionResult(
        replacement_browser,
        replacement_context,
        replacement_page,
        mode="switch_browser" if switch_browser else "restored_browser",
        browser_name=selected_browser,
    )


def load_google_bigquery() -> Any:
    return importlib.import_module("google.cloud.bigquery")


class EnvironmentBootstrapError(RuntimeError):
    def __init__(self, reason: str, message: str, command: list[str] | None = None) -> None:
        super().__init__(message)
        self.reason = reason
        self.command = command or []


def env_seconds(name: str, default: int, minimum: int = 1) -> int:
    try:
        return max(minimum, int(os.getenv(name, str(default))))
    except ValueError:
        return default


def verification_browser_fallback_cooldown_seconds() -> int:
    return env_seconds(
        "LAPS_VERIFICATION_BROWSER_FALLBACK_COOLDOWN_SECONDS",
        30,
        0,
    )


def environment_command_timeout_seconds() -> int:
    return env_seconds("LAPS_ENV_COMMAND_TIMEOUT_SECONDS", DEFAULT_ENV_COMMAND_TIMEOUT_SECONDS, 1)


def environment_lock_timeout_seconds() -> int:
    return env_seconds("LAPS_ENV_LOCK_TIMEOUT_SECONDS", DEFAULT_ENV_LOCK_TIMEOUT_SECONDS, 1)


def environment_lock_path() -> Path:
    return TOOLS_DIR / ENV_BOOTSTRAP_LOCK_NAME


def process_is_running(pid: int) -> bool:
    if pid <= 0:
        return False
    if os.name == "nt":
        try:
            import ctypes

            handle = ctypes.windll.kernel32.OpenProcess(0x1000, False, pid)
            if handle:
                ctypes.windll.kernel32.CloseHandle(handle)
                return True
            return False
        except Exception:
            return True
    try:
        os.kill(pid, 0)
        return True
    except OSError:
        return False
    except Exception:
        return True


def environment_lock_owner_running(lock_path: Path) -> bool:
    try:
        raw = lock_path.read_text(encoding="utf-8-sig")
        payload = json.loads(raw) if raw else {}
        return process_is_running(int(payload.get("pid") or 0))
    except Exception:
        return False


def acquire_environment_bootstrap_lock() -> tuple[Path, str]:
    TOOLS_DIR.mkdir(parents=True, exist_ok=True)
    lock_path = environment_lock_path()
    token = f"{os.getpid()}-{time.time_ns()}"
    timeout_seconds = environment_lock_timeout_seconds()
    deadline = time.monotonic() + timeout_seconds
    logged_wait = False
    while True:
        try:
            fd = os.open(str(lock_path), os.O_CREAT | os.O_EXCL | os.O_WRONLY)
            with os.fdopen(fd, "w", encoding="utf-8") as handle:
                json.dump({"pid": os.getpid(), "token": token, "created_at": datetime.now(timezone.utc).isoformat(timespec="seconds")}, handle)
            return lock_path, token
        except FileExistsError:
            try:
                age = time.time() - lock_path.stat().st_mtime if lock_path.exists() else 0.0
            except OSError:
                continue
            if age > timeout_seconds and not environment_lock_owner_running(lock_path):
                print(f"Removing stale environment bootstrap lock after {age:.1f} seconds: {lock_path}", file=sys.stderr)
                try:
                    lock_path.unlink()
                    continue
                except OSError:
                    pass
            if time.monotonic() >= deadline:
                raise EnvironmentBootstrapError(
                    "environment_bootstrap_lock_timeout",
                    f"Timed out waiting for environment bootstrap lock after {timeout_seconds} seconds: {lock_path}",
                )
            if not logged_wait:
                print(f"Waiting for environment bootstrap lock: {lock_path}", file=sys.stderr)
                logged_wait = True
            time.sleep(min(1.0, max(0.2, deadline - time.monotonic())))
        except OSError as exc:
            raise EnvironmentBootstrapError(
                "environment_bootstrap_lock_failed",
                f"Unable to create environment bootstrap lock {lock_path}: {exc}",
            ) from exc


def release_environment_bootstrap_lock(lock_path: Path, token: str) -> None:
    try:
        raw = lock_path.read_text(encoding="utf-8-sig") if lock_path.exists() else ""
        payload = json.loads(raw) if raw else {}
        if payload.get("token") == token:
            lock_path.unlink()
    except Exception as exc:
        print(f"Unable to release environment bootstrap lock {lock_path}: {exc}", file=sys.stderr)


def environment_process_group_kwargs() -> dict[str, Any]:
    if os.name == "nt":
        return {"creationflags": subprocess.CREATE_NEW_PROCESS_GROUP}
    return {"start_new_session": True}


def terminate_environment_process_tree(process: subprocess.Popen[Any]) -> None:
    if process.poll() is not None:
        return
    if os.name == "nt":
        try:
            subprocess.run(
                ["taskkill", "/F", "/T", "/PID", str(process.pid)],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                timeout=10,
            )
        except Exception as exc:
            print(f"Unable to terminate environment process tree {process.pid}: {exc}", file=sys.stderr)
    else:
        try:
            import signal

            os.killpg(process.pid, signal.SIGTERM)
        except Exception as exc:
            print(f"Unable to terminate environment process group {process.pid}: {exc}", file=sys.stderr)
        try:
            process.wait(timeout=5)
        except Exception:
            try:
                import signal

                os.killpg(process.pid, signal.SIGKILL)
            except Exception:
                pass
    try:
        process.wait(timeout=10)
    except Exception:
        pass


def run_subprocess(args: list[str], env: dict[str, str]) -> None:
    timeout_seconds = environment_command_timeout_seconds()
    command_preview = " ".join(args[:4])
    try:
        process = subprocess.Popen(args, env=env, **environment_process_group_kwargs())
    except subprocess.TimeoutExpired as exc:
        raise EnvironmentBootstrapError(
            "environment_bootstrap_timeout",
            f"Environment setup command timed out after {timeout_seconds} seconds: {command_preview}",
            args,
        ) from exc
    except OSError as exc:
        raise EnvironmentBootstrapError(
            "environment_bootstrap_failed",
            f"Environment setup command could not start: {command_preview}: {exc}",
            args,
        ) from exc
    try:
        process.communicate(timeout=timeout_seconds)
    except subprocess.TimeoutExpired as exc:
        terminate_environment_process_tree(process)
        raise EnvironmentBootstrapError(
            "environment_bootstrap_timeout",
            f"Environment setup command timed out after {timeout_seconds} seconds: {command_preview}",
            args,
        ) from exc
    if process.returncode != 0:
        raise EnvironmentBootstrapError(
            "environment_bootstrap_failed",
            f"Environment setup command failed with exit code {process.returncode}: {command_preview}",
            args,
        )


def restart_with_venv_python(py: Path, env: dict[str, str]) -> None:
    args = [str(py), str(SCRIPT_PATH), *sys.argv[1:]]
    if os.name != "nt":
        os.execve(str(py), args, env)
    raise SystemExit(subprocess.call(args, env=env))


def ensure_tools_environment() -> dict[str, Any]:
    """Prepare the canonical tools runtime and restart under it when needed."""

    try:
        report = shared_environment.check_environment(PROJECT_ROOT)
        if not shared_environment.required_environment_ready(report):
            report = shared_environment.prepare_environment(
                PROJECT_ROOT,
                command_timeout_seconds=environment_command_timeout_seconds(),
                lock_timeout_seconds=environment_lock_timeout_seconds(),
            )
        if not shared_environment.required_environment_ready(report):
            raise EnvironmentBootstrapError(
                "environment_bootstrap_failed",
                "The canonical tools runtime is still incomplete after preparation.",
            )
        env = shared_environment.runtime_environment(PROJECT_ROOT)
    except shared_environment.EnvironmentBootstrapError as exc:
        raise EnvironmentBootstrapError(exc.reason, str(exc), list(exc.command)) from exc

    os.environ.update(env)
    py = venv_python_path()
    if not shared_environment.running_in_tools_venv(PROJECT_ROOT):
        restart_with_venv_python(py, env)
    return report


def contact_email() -> str | None:
    return env_value("CONTACT_EMAIL", "CROSSREF_MAILTO", "NCBI_EMAIL") or None


def ncbi_tool() -> str:
    return os.getenv("NCBI_TOOL", "literature-and-patents-search-skills").strip()


def user_agent() -> str:
    email = contact_email()
    suffix = f"; contact={email}" if email else ""
    return f"literature-and-patents-search-skills/1.0 (metadata retrieval{suffix})"


def build_httpx_client() -> Any:
    import httpx

    headers = {
        "User-Agent": user_agent(),
        "Accept": "application/json, application/xml;q=0.9, text/xml;q=0.8, */*;q=0.5",
        "Accept-Language": "en-US,en;q=0.9,zh-CN;q=0.8,zh;q=0.7",
    }
    return httpx.AsyncClient(timeout=httpx.Timeout(30.0), follow_redirects=True, headers=headers, trust_env=True)


def first_string(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, list):
        for item in value:
            text = first_string(item)
            if text:
                return text
        return ""
    if isinstance(value, dict):
        for key in ("value", "text", "name", "title"):
            if key in value:
                text = first_string(value[key])
                if text:
                    return text
        return ""
    return str(value).strip()


def parse_year(value: Any) -> int | None:
    if value is None:
        return None
    if isinstance(value, int):
        return value if 1000 <= value <= 9999 else None
    if isinstance(value, float):
        return parse_year(int(value))
    text = str(value)
    match = re.search(r"(18|19|20|21)\d{2}", text)
    if not match:
        return None
    return int(match.group(0))


def parse_int(value: Any) -> int | None:
    try:
        return int(str(value).replace(",", "").strip())
    except (TypeError, ValueError):
        return None


def author_name(author: dict[str, Any]) -> str:
    if not isinstance(author, dict):
        return str(author)
    if author.get("display_name"):
        return str(author["display_name"]).strip()
    if author.get("fullName"):
        return str(author["fullName"]).strip()
    given = str(author.get("given", "") or author.get("firstName", "") or "").strip()
    family = str(author.get("family", "") or author.get("lastName", "") or "").strip()
    name = " ".join(part for part in (given, family) if part).strip()
    return name or first_string(author)


def clean_people(values: Any) -> list[str]:
    if not values:
        return []
    if isinstance(values, str):
        return [part.strip() for part in re.split(r";|,\s*(?=[A-Z][a-z]+(?:\s|$))", values) if part.strip()]
    if isinstance(values, dict):
        values = [values]
    names: list[str] = []
    for value in values:
        if isinstance(value, dict):
            name = author_name(value)
        else:
            name = str(value).strip()
        if name and name not in names:
            names.append(name)
    return names


def literature_key(record: LiteratureRecord) -> str:
    doi = normalize_doi(record.doi)
    if doi:
        return f"doi:{doi}"
    pdf_url = normalize_literature_pdf_url(record.url)
    if pdf_url:
        return f"pdf_url:{pdf_url}"
    first_author = normalize_title(record.authors[0]) if record.authors else ""
    return f"title:{normalize_title(record.title)}|year:{record.year or ''}|author:{first_author}"


def patent_key(record: PatentRecord) -> str:
    publication = normalize_publication_number(record.publication_number)
    if publication:
        return f"publication_number:{publication}"
    normalized_url = normalize_resume_url(record.url)
    if normalized_url:
        return f"url:{normalized_url}"
    name = normalize_patent_name(record.patent_name)
    if name:
        return f"name:{name}"
    return ""


def lit_sort_key(record: LiteratureRecord) -> tuple[Any, ...]:
    return (record.keyword_index, record.source_index, record.rank if record.rank is not None else 10**9, normalize_title(record.title))


def patent_sort_key(record: PatentRecord) -> tuple[Any, ...]:
    return (record.keyword_index, record.source_index, record.rank if record.rank is not None else 10**9, normalize_patent_name(record.patent_name))


def merge_literature_record_fields(primary: LiteratureRecord, duplicate: LiteratureRecord) -> None:
    if not normalize_doi(primary.doi) and normalize_doi(duplicate.doi):
        primary.doi = normalize_doi(duplicate.doi)
    if not primary.title and duplicate.title:
        primary.title = duplicate.title
    if not primary.authors and duplicate.authors:
        primary.authors = list(duplicate.authors)
    if not primary.year and duplicate.year:
        primary.year = duplicate.year
    if not primary.journal and duplicate.journal:
        primary.journal = duplicate.journal
    if not normalize_literature_pdf_url(primary.url):
        primary.url = normalize_literature_pdf_url(duplicate.url) or None
    if not primary.raw_id and duplicate.raw_id:
        primary.raw_id = duplicate.raw_id
    for kind, value in duplicate.identifiers.items():
        if first_string(kind) and first_string(value) and kind not in primary.identifiers:
            primary.identifiers[kind] = value
    if not normalize_observed_http_url(primary.landing_url):
        primary.landing_url = normalize_observed_http_url(duplicate.landing_url) or None


def dedupe_literature_records(records: list[LiteratureRecord]) -> list[LiteratureRecord]:
    entries: list[LiteratureRecord] = []
    parents: list[int] = []
    by_doi: dict[str, int] = {}
    by_pdf_url: dict[str, int] = {}

    def find(index: int) -> int:
        while parents[index] != index:
            parents[index] = parents[parents[index]]
            index = parents[index]
        return index

    for record in sorted(records, key=lit_sort_key):
        record.doi = normalize_doi(record.doi) or None
        record.url = normalize_literature_pdf_url(record.url) or None
        record.landing_url = normalize_observed_http_url(record.landing_url) or None
        doi = normalize_doi(record.doi)
        pdf_url = normalize_literature_pdf_url(record.url)
        matches = {
            find(index)
            for index in (
                by_doi.get(doi) if doi else None,
                by_pdf_url.get(pdf_url) if pdf_url else None,
            )
            if index is not None
        }
        if not matches:
            primary_index = len(entries)
            entries.append(record)
            parents.append(primary_index)
        else:
            primary_index = min(matches)
            for duplicate_index in sorted(matches - {primary_index}):
                duplicate_index = find(duplicate_index)
                if duplicate_index == primary_index:
                    continue
                merge_literature_record_fields(
                    entries[primary_index],
                    entries[duplicate_index],
                )
                parents[duplicate_index] = primary_index
            merge_literature_record_fields(entries[primary_index], record)
        primary = entries[find(primary_index)]
        primary_doi = normalize_doi(primary.doi)
        primary_pdf_url = normalize_literature_pdf_url(primary.url)
        if primary_doi:
            by_doi[primary_doi] = find(primary_index)
        if primary_pdf_url:
            by_pdf_url[primary_pdf_url] = find(primary_index)
    return [record for index, record in enumerate(entries) if find(index) == index]


def literature_has_required_doi(record: LiteratureRecord) -> bool:
    return bool(normalize_doi(record.doi))


def literature_has_required_locator(record: LiteratureRecord) -> bool:
    return bool(
        normalize_doi(record.doi)
        or stable_literature_pdf_url(record.url)
    )


def split_literature_records_by_required_locator(
    records: list[LiteratureRecord],
) -> tuple[list[LiteratureRecord], list[LiteratureRecord]]:
    valid: list[LiteratureRecord] = []
    dropped: list[LiteratureRecord] = []
    for record in records:
        record.doi = normalize_doi(record.doi) or None
        record.url = normalize_literature_pdf_url(record.url) or None
        if literature_has_required_locator(record):
            valid.append(record)
        else:
            dropped.append(record)
    return valid, dropped


def dropped_literature_summary(records: list[LiteratureRecord]) -> dict[str, Any]:
    by_source = Counter(record.source or "unknown" for record in records)
    by_keyword = Counter(record.keyword or "unknown" for record in records)
    return {
        "count": len(records),
        "reason": "missing_required_doi_and_stable_pdf_url",
        "by_source": dict(sorted(by_source.items())),
        "by_keyword": dict(sorted(by_keyword.items())),
    }


def literature_locator_summary(records: list[LiteratureRecord]) -> dict[str, int]:
    doi_only = 0
    pdf_url_only = 0
    doi_and_pdf_url = 0
    for record in records:
        has_doi = bool(normalize_doi(record.doi))
        has_pdf_url = bool(stable_literature_pdf_url(record.url))
        if has_doi and has_pdf_url:
            doi_and_pdf_url += 1
        elif has_doi:
            doi_only += 1
        elif has_pdf_url:
            pdf_url_only += 1
    return {
        "doi_only": doi_only,
        "pdf_url_only": pdf_url_only,
        "doi_and_pdf_url": doi_and_pdf_url,
    }


def patent_has_required_locator(record: PatentRecord) -> bool:
    return bool(
        normalize_publication_number(record.publication_number)
        or normalize_resume_url(record.url)
    )


def patent_has_required_url(record: PatentRecord) -> bool:
    """Compatibility alias for the v2 publication-number-or-URL rule."""
    return patent_has_required_locator(record)


def split_patent_records_by_required_locator(
    records: list[PatentRecord],
) -> tuple[list[PatentRecord], list[PatentRecord]]:
    valid: list[PatentRecord] = []
    dropped: list[PatentRecord] = []
    for record in records:
        record.publication_number = (
            normalize_publication_number(record.publication_number) or None
        )
        if patent_has_required_locator(record):
            valid.append(record)
        else:
            dropped.append(record)
    return valid, dropped


def split_patent_records_by_required_url(
    records: list[PatentRecord],
) -> tuple[list[PatentRecord], list[PatentRecord]]:
    """Compatibility alias for split_patent_records_by_required_locator()."""
    return split_patent_records_by_required_locator(records)


def dropped_patent_summary(records: list[PatentRecord]) -> dict[str, Any]:
    by_source = Counter(record.source or "unknown" for record in records)
    by_keyword = Counter(record.keyword or "unknown" for record in records)
    return {
        "count": len(records),
        "reason": "missing_required_publication_number_and_url",
        "by_source": dict(sorted(by_source.items())),
        "by_keyword": dict(sorted(by_keyword.items())),
    }


def patent_missing_url_report_summary(
    records: list[PatentRecord],
    source_runs: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    summary = dropped_patent_summary(records)
    parser_rejected_by_source: Counter[str] = Counter()
    parser_rejected_by_keyword: Counter[str] = Counter()
    for run in source_runs or []:
        if (
            first_string(run.get("record_type")) != "patent"
            or first_string(run.get("source")) != CNKI_SOURCE
        ):
            continue
        count = max(0, int(run.get("dropped") or 0))
        if not count:
            continue
        parser_rejected_by_source[CNKI_SOURCE] += count
        parser_rejected_by_keyword[first_string(run.get("keyword")) or "unknown"] += count
    parser_rejected_count = sum(parser_rejected_by_source.values())
    by_source = Counter(summary["by_source"])
    by_keyword = Counter(summary["by_keyword"])
    by_source.update(parser_rejected_by_source)
    by_keyword.update(parser_rejected_by_keyword)
    return {
        **summary,
        "count": int(summary["count"]) + parser_rejected_count,
        "parser_rejected_count": parser_rejected_count,
        "by_source": dict(sorted(by_source.items())),
        "by_keyword": dict(sorted(by_keyword.items())),
    }


def merge_patent_record_fields(primary: PatentRecord, duplicate: PatentRecord) -> None:
    if not primary.patent_name and duplicate.patent_name:
        primary.patent_name = duplicate.patent_name
    if not primary.authors and duplicate.authors:
        primary.authors = list(duplicate.authors)
    if not primary.year and duplicate.year:
        primary.year = duplicate.year
    if not normalize_resume_url(primary.url) and normalize_resume_url(duplicate.url):
        primary.url = duplicate.url
    if not normalize_publication_number(primary.publication_number):
        primary.publication_number = (
            normalize_publication_number(duplicate.publication_number) or None
        )
    if not primary.applicants and duplicate.applicants:
        primary.applicants = list(duplicate.applicants)
    if not primary.database and duplicate.database:
        primary.database = duplicate.database
    if not primary.application_date and duplicate.application_date:
        primary.application_date = duplicate.application_date
    if not primary.publication_date and duplicate.publication_date:
        primary.publication_date = duplicate.publication_date
    if not primary.raw_id and duplicate.raw_id:
        primary.raw_id = duplicate.raw_id


def dedupe_patent_records(records: list[PatentRecord]) -> list[PatentRecord]:
    entries: list[PatentRecord] = []
    parents: list[int] = []
    by_publication_number: dict[str, int] = {}
    by_url: dict[str, int] = {}

    def find(index: int) -> int:
        while parents[index] != index:
            parents[index] = parents[parents[index]]
            index = parents[index]
        return index

    for record in sorted(records, key=patent_sort_key):
        publication_number = normalize_publication_number(record.publication_number)
        normalized_url = normalize_resume_url(record.url)
        record.publication_number = publication_number or None
        if not publication_number and not normalized_url:
            continue
        matches: set[int] = set()
        if publication_number and publication_number in by_publication_number:
            matches.add(find(by_publication_number[publication_number]))
        if normalized_url and normalized_url in by_url:
            url_match = find(by_url[normalized_url])
            existing_publication = normalize_publication_number(
                entries[url_match].publication_number
            )
            if (
                not publication_number
                or not existing_publication
                or publication_number == existing_publication
            ):
                matches.add(url_match)
        if not matches:
            primary_index = len(entries)
            entries.append(record)
            parents.append(primary_index)
        else:
            primary_index = min(matches)
            for duplicate_index in sorted(matches - {primary_index}):
                duplicate_index = find(duplicate_index)
                if duplicate_index == primary_index:
                    continue
                merge_patent_record_fields(
                    entries[primary_index],
                    entries[duplicate_index],
                )
                parents[duplicate_index] = primary_index
            merge_patent_record_fields(entries[primary_index], record)
        primary_index = find(primary_index)
        primary = entries[primary_index]
        primary_publication = normalize_publication_number(primary.publication_number)
        primary_url = normalize_resume_url(primary.url)
        if primary_publication:
            primary.publication_number = primary_publication
            by_publication_number[primary_publication] = primary_index
        if primary_url:
            existing_url_index = by_url.get(primary_url)
            if existing_url_index is None:
                by_url[primary_url] = primary_index
            else:
                existing_url_root = find(existing_url_index)
                existing_publication = normalize_publication_number(
                    entries[existing_url_root].publication_number
                )
                if not (
                    existing_publication
                    and primary_publication
                    and existing_publication != primary_publication
                ):
                    by_url[primary_url] = primary_index
    return [record for index, record in enumerate(entries) if find(index) == index]


def literature_rows(records: list[LiteratureRecord]) -> list[dict[str, Any]]:
    return [
        {
            "title": record.title or "",
            "authors": "; ".join(record.authors),
            "year": record.year or "",
            "journal": record.journal or "",
            "doi": normalize_doi(record.doi),
            "source": record.source,
            "keyword": record.keyword,
            "url": normalize_literature_pdf_url(record.url),
            "raw_id": record.raw_id or "",
        }
        for record in records
    ]


def patent_rows(records: list[PatentRecord]) -> list[dict[str, Any]]:
    return [
        {
            "patent_name": record.patent_name or "",
            "authors": "; ".join(record.authors),
            "year": record.year or "",
            "url": record.url or "",
            "source": record.source,
            "keyword": record.keyword,
            "publication_number": normalize_publication_number(
                record.publication_number
            ),
            "raw_id": record.raw_id or "",
        }
        for record in records
    ]


def records_to_dataframes(literature_records: list[LiteratureRecord], patent_records: list[PatentRecord]) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    return literature_rows(literature_records), patent_rows(patent_records)


def write_csv(path: Path, columns: list[str], rows: list[dict[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("w", encoding="utf-8-sig", newline="") as handle:
        writer = csv.DictWriter(handle, fieldnames=columns, extrasaction="ignore")
        writer.writeheader()
        writer.writerows(rows)


def write_csv_atomic(
    path: Path,
    columns: list[str],
    rows: list[dict[str, Any]],
) -> tuple[bool, str]:
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_name(
        f".{path.name}.{os.getpid()}.{threading.get_ident()}.tmp"
    )
    try:
        with temporary.open("w", encoding="utf-8-sig", newline="") as handle:
            writer = csv.DictWriter(handle, fieldnames=columns, extrasaction="ignore")
            writer.writeheader()
            writer.writerows(rows)
        os.replace(temporary, path)
        return True, ""
    except OSError as exc:
        return False, safe_error_text(f"{exc.__class__.__name__}: {exc}")
    finally:
        try:
            temporary.unlink(missing_ok=True)
        except OSError:
            pass


def write_json_atomic(path: Path, payload: dict[str, Any]) -> tuple[bool, str]:
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_name(
        f".{path.name}.{os.getpid()}.{threading.get_ident()}.tmp"
    )
    try:
        temporary.write_text(
            json.dumps(payload, ensure_ascii=False, indent=2) + "\n",
            encoding="utf-8",
        )
        os.replace(temporary, path)
        return True, ""
    except OSError as exc:
        return False, safe_error_text(f"{exc.__class__.__name__}: {exc}")
    finally:
        try:
            temporary.unlink(missing_ok=True)
        except OSError:
            pass


def read_csv_rows(path: Path) -> list[dict[str, str]]:
    if not path.exists() or path.stat().st_size == 0:
        return []
    with path.open("r", encoding="utf-8-sig", newline="") as handle:
        return [dict(row) for row in csv.DictReader(handle)]


def parse_people(value: str | None) -> list[str]:
    return [part.strip() for part in re.split(r";|\n", value or "") if part.strip()]


def read_literature_records(
    path: Path,
    migration_stats: dict[str, int] | None = None,
) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for row in read_csv_rows(path):
        records.append(
            LiteratureRecord(
                title=str(row.get("title") or ""),
                authors=parse_people(row.get("authors")),
                year=parse_year(row.get("year")),
                journal=str(row.get("journal") or ""),
                doi=normalize_doi(row.get("doi")),
                url=normalize_migrated_literature_pdf_url(
                    row.get("url"),
                    migration_stats,
                )
                or None,
                source=str(row.get("source") or "existing_metadata"),
                keyword=str(row.get("keyword") or ""),
                raw_id=str(row.get("raw_id") or ""),
            )
        )
    return records


def read_patent_records(path: Path) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    for row in read_csv_rows(path):
        records.append(
            PatentRecord(
                patent_name=str(row.get("patent_name") or ""),
                authors=parse_people(row.get("authors")),
                year=parse_year(row.get("year")),
                url=str(row.get("url") or ""),
                source=str(row.get("source") or "existing_metadata"),
                keyword=str(row.get("keyword") or ""),
                raw_id=str(row.get("raw_id") or ""),
                publication_number=normalize_publication_number(
                    row.get("publication_number")
                )
                or None,
            )
        )
    return records


def output_paths(project_root: Path = PROJECT_ROOT, batch_name: str | None = None, metadata_root: Path | None = None) -> tuple[Path, Path]:
    root = metadata_batch_root(batch_name, metadata_root) if project_root == PROJECT_ROOT else project_root / "literature_and_patents_metadata_list"
    return (
        root / "literature_metadata_list" / "literature_metadata_list.csv",
        root / "patents_metadata_list" / "patents_metadata_list.csv",
    )


def search_status_path(batch_name: str | None = None, metadata_root: Path | None = None) -> Path:
    return metadata_batch_root(batch_name, metadata_root) / "search_run_report.json"


def workflow_status_path(
    batch_name: str | None = None,
    metadata_root: Path | None = None,
) -> Path:
    return metadata_batch_root(batch_name, metadata_root) / WORKFLOW_RUN_REPORT_FILENAME


def search_state_path(batch_name: str | None = None, metadata_root: Path | None = None) -> Path:
    return metadata_batch_root(batch_name, metadata_root) / "search_state.sqlite3"


def search_progress_path(batch_name: str | None = None, metadata_root: Path | None = None) -> Path:
    return metadata_batch_root(batch_name, metadata_root) / "search_progress.json"


def write_outputs(
    literature_records: list[LiteratureRecord],
    patent_records: list[PatentRecord],
    project_root: Path = PROJECT_ROOT,
    batch_name: str | None = None,
    metadata_root: Path | None = None,
) -> tuple[Path, Path]:
    literature_path, patent_path = output_paths(project_root, batch_name, metadata_root)
    lit_rows, pat_rows = records_to_dataframes(literature_records, patent_records)
    for path, columns, rows in (
        (literature_path, LITERATURE_COLUMNS, lit_rows),
        (patent_path, PATENT_COLUMNS, pat_rows),
    ):
        ok, reason = write_csv_atomic(path, columns, rows)
        if not ok:
            print(
                f"Warning: CSV atomic replacement failed for {path.name}: {reason}",
                file=sys.stderr,
            )
    return literature_path.resolve(), patent_path.resolve()


def canonical_v2_paths(
    batch_name: str | None = None,
    metadata_root: Path | None = None,
) -> tuple[Path, Path, Path, Path]:
    root = metadata_batch_root(batch_name, metadata_root)
    return (
        root / LITERATURE_RECORDS_V2_FILENAME,
        root / PATENT_RECORDS_V2_FILENAME,
        root / HANDOFF_MANIFEST_V2_FILENAME,
        root / CANONICAL_DATABASE_V2_FILENAME,
    )


def _canonical_auth_scope(
    record_type: str,
    source: str,
    *,
    path: str = "",
) -> str:
    specs = (
        LITERATURE_SEARCH_SPECS
        if record_type == "literature"
        else PATENT_SEARCH_SPECS
    )
    spec = next(
        (item for item in specs if item.display_name == source),
        None,
    )
    if spec is None:
        return "unknown"
    if first_string(path) == "enrichment" and first_string(
        spec.fallback_auth_scope
    ):
        return first_string(spec.fallback_auth_scope)
    return first_string(spec.auth_scope) or "unknown"


def _canonical_http_url(record_type: str, value: Any) -> str:
    raw = first_string(value)
    if not raw:
        return ""
    normalized = normalize_observed_http_url(raw)
    try:
        parsed = urllib.parse.urlsplit(normalized)
    except ValueError:
        return ""
    if parsed.scheme.casefold() not in {"http", "https"} or not parsed.hostname:
        return ""
    return normalized


def _canonical_locator_kind(
    record_type: str,
    url: str,
    source: str = "",
) -> str:
    if record_type == "literature":
        return "direct_pdf" if normalize_literature_pdf_url(url) else "landing"
    parsed = urllib.parse.urlsplit(url)
    query = {
        key.casefold(): value.casefold()
        for key, value in urllib.parse.parse_qsl(
            parsed.query,
            keep_blank_values=True,
        )
    }
    if (
        parsed.path.casefold().endswith(".pdf")
        or query.get("format") == "pdf"
        or query.get("type") == "pdf"
    ):
        return "direct_pdf"
    # ODP search results are metadata query surfaces, not a patent-document
    # landing page.  Preserve the observed URL, but do not overstate its
    # locator capability in the v2 handoff.
    if (
        source == "USPTO Open Data Portal"
        and (parsed.hostname or "").casefold() == "data.uspto.gov"
        and "/patent/file-wrapper/search/results" in parsed.path.casefold()
    ):
        return "metadata_search"
    return "landing"


def _canonical_locator_stability(kind: str, url: str) -> str:
    if kind != "direct_pdf":
        return "unknown"
    volatile_keys = {
        "access_token",
        "auth",
        "authorization",
        "awsaccesskeyid",
        "expires",
        "googleaccessid",
        "jwt",
        "key-pair-id",
        "policy",
        "session",
        "sessionid",
        "signature",
        "sig",
        "ticket",
        "token",
        "x-amz-credential",
        "x-amz-security-token",
        "x-amz-signature",
        "x-goog-credential",
        "x-goog-expires",
        "x-goog-signature",
    }
    query_keys = {
        key.casefold()
        for key, _ in urllib.parse.parse_qsl(
            urllib.parse.urlsplit(url).query,
            keep_blank_values=True,
        )
    }
    return "unknown" if volatile_keys.intersection(query_keys) else "stable"


def _canonical_metadata(record_type: str, payload: Mapping[str, Any]) -> dict[str, Any]:
    title = first_string(
        payload.get("title")
        if record_type == "literature"
        else payload.get("patent_name") or payload.get("title")
    )
    metadata: dict[str, Any] = {}
    if title:
        metadata["title"] = title
        if record_type == "patent":
            metadata["patent_name"] = title
    authors = clean_people(payload.get("authors"))
    if authors:
        metadata["authors"] = authors
    year = parse_year(payload.get("year"))
    if year is not None:
        metadata["year"] = year
    if record_type == "literature":
        journal = first_string(payload.get("journal"))
        if journal:
            metadata["journal"] = journal
    else:
        applicants = clean_people(payload.get("applicants"))
        if applicants:
            metadata["applicants"] = applicants
        for key in ("database", "application_date", "publication_date"):
            value = first_string(payload.get(key))
            if value:
                metadata[key] = value
    return metadata


def _canonical_literature_identifiers(
    payload: Mapping[str, Any],
    source: str,
    raw_ids: Iterable[str],
) -> list[tuple[str, str]]:
    """Return only typed identifiers observed in the provider payload."""

    aliases = {
        "arxiv": "arxiv_id",
        "arxiv_id": "arxiv_id",
        "pmid": "pmid",
        "pubmed": "pmid",
        "pmcid": "pmcid",
        "pmc": "pmcid",
    }
    candidates: list[tuple[str, str]] = []
    explicit = payload.get("identifiers")
    if isinstance(explicit, Mapping):
        values = explicit.items()
    elif isinstance(explicit, (list, tuple)):
        values = (
            (
                first_string(item.get("type") or item.get("identifier_type")),
                first_string(item.get("value")),
            )
            for item in explicit
            if isinstance(item, Mapping)
        )
    else:
        values = ()
    for raw_kind, raw_value in values:
        kind = aliases.get(first_string(raw_kind).casefold())
        value = first_string(raw_value)
        if kind and value:
            candidates.append((kind, value))

    raw_values = [first_string(value) for value in raw_ids if first_string(value)]
    if source == "arXiv API" and not any(kind == "arxiv_id" for kind, _ in candidates):
        for raw_id in raw_values:
            parsed = urllib.parse.urlsplit(raw_id)
            value = (parsed.path.rstrip("/").rsplit("/", 1)[-1] if parsed.scheme else raw_id)
            value = re.sub(r"v\d+$", "", value, flags=re.IGNORECASE)
            if value:
                candidates.append(("arxiv_id", value))
                break
    if source == "PMC (PubMed Central)" and not any(
        kind == "pmcid" for kind, _ in candidates
    ):
        for raw_id in raw_values:
            value = re.sub(r"^PMC", "", raw_id, flags=re.IGNORECASE)
            if value.isdigit():
                candidates.append(("pmcid", f"PMC{value}"))
                break
    if source == "PubMed" and not any(kind == "pmid" for kind, _ in candidates):
        for raw_id in raw_values:
            if raw_id.isdigit():
                candidates.append(("pmid", raw_id))
                break

    result: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for kind, value in candidates:
        normalized_value = first_string(value)
        parsed_identifier_url = urllib.parse.urlsplit(normalized_value)
        if parsed_identifier_url.scheme in {"http", "https"}:
            normalized_value = parsed_identifier_url.path.rstrip("/").rsplit("/", 1)[-1]
        if kind == "pmcid":
            normalized_value = normalized_value.upper()
            if normalized_value.isdigit():
                normalized_value = f"PMC{normalized_value}"
        elif kind == "pmid":
            pmid_match = re.search(r"\d+", normalized_value)
            normalized_value = pmid_match.group(0) if pmid_match else ""
        elif kind == "arxiv_id":
            normalized_value = re.sub(
                r"v\d+$", "", normalized_value, flags=re.IGNORECASE
            )
        marker = (kind, normalized_value.casefold())
        if normalized_value and marker not in seen:
            result.append((kind, normalized_value))
            seen.add(marker)
    return result


def canonical_record_from_search_payload(
    record_type: Literal["literature", "patent"],
    payload: Mapping[str, Any],
) -> CanonicalRecord:
    """Convert one observed search result without guessing unavailable fields."""

    source = first_string(payload.get("source")) or "unknown"
    keyword = first_string(payload.get("keyword"))
    raw_observations = payload.get("_canonical_provenance")
    observations = [
        dict(item)
        for item in raw_observations
        if isinstance(item, Mapping)
    ] if isinstance(raw_observations, (list, tuple)) else []
    if not observations:
        observations = [
            {
                "query_variant": "unknown",
                "path": "unknown",
                "raw_id": first_string(payload.get("raw_id")),
                "rank": payload.get("rank"),
                "locator_url": first_string(payload.get("url")),
                "observed_at": first_string(payload.get("_observed_at")),
            }
        ]

    provenance: list[Provenance] = []
    raw_ids: list[str] = []
    for observation in observations:
        raw_id = first_string(observation.get("raw_id"))
        if raw_id and raw_id not in raw_ids:
            raw_ids.append(raw_id)
        raw_rank = observation.get("rank")
        try:
            rank = int(raw_rank) if raw_rank not in (None, "") else None
        except (TypeError, ValueError):
            rank = None
        candidate = Provenance(
            source=source,
            keyword=keyword,
            query_variant=(
                first_string(observation.get("query_variant")) or "unknown"
            ),
            rank=rank,
            path=first_string(observation.get("path")) or "unknown",
            raw_id=raw_id,
        )
        marker = (
            candidate.source,
            candidate.keyword,
            candidate.query_variant,
            candidate.rank,
            candidate.path,
            candidate.raw_id,
        )
        if marker not in {
            (
                item.source,
                item.keyword,
                item.query_variant,
                item.rank,
                item.path,
                item.raw_id,
            )
            for item in provenance
        }:
            provenance.append(candidate)
    payload_raw_id = first_string(payload.get("raw_id"))
    if payload_raw_id and payload_raw_id not in raw_ids:
        raw_ids.append(payload_raw_id)

    identifiers: list[Identifier] = []
    if record_type == "literature":
        doi = normalize_doi(first_string(payload.get("doi")))
        if doi:
            identifiers.append(Identifier("doi", doi, source, primary=True))
        for kind, value in _canonical_literature_identifiers(
            payload,
            source,
            raw_ids,
        ):
            identifiers.append(
                Identifier(
                    kind,
                    value,
                    source,
                    primary=not identifiers,
                )
            )
    else:
        publication_number = normalize_publication_number(
            payload.get("publication_number")
        )
        if publication_number:
            identifiers.append(
                Identifier(
                    "publication_number",
                    publication_number,
                    source,
                    primary=True,
                )
            )
    identifiers.extend(
        Identifier("raw_id", raw_id, source)
        for raw_id in raw_ids
    )

    locator_candidates: list[str] = []
    raw_locator_values = payload.get("_canonical_locator_urls")
    values = (
        list(raw_locator_values)
        if isinstance(raw_locator_values, (list, tuple))
        else []
    )
    values.append(payload.get("url"))
    values.append(payload.get("landing_url"))
    values.extend(item.get("locator_url") for item in observations)
    values.extend(raw_id for raw_id in raw_ids if normalize_observed_http_url(raw_id))
    for value in values:
        normalized = _canonical_http_url(record_type, value)
        if normalized and normalized not in locator_candidates:
            locator_candidates.append(normalized)
    observed_at_by_url: dict[str, str] = {}
    observed_path_by_url: dict[str, str] = {}
    for observation in observations:
        normalized = _canonical_http_url(
            record_type,
            observation.get("locator_url"),
        )
        if normalized and normalized not in observed_at_by_url:
            observed_at_by_url[normalized] = first_string(
                observation.get("observed_at")
            )
        if normalized and normalized not in observed_path_by_url:
            observed_path_by_url[normalized] = first_string(
                observation.get("path")
            )
    locators: list[Locator] = []
    for url in locator_candidates:
        kind = _canonical_locator_kind(record_type, url, source)
        locators.append(
            Locator(
                kind=kind,
                url=url,
                source=source,
                auth_scope=_canonical_auth_scope(
                    record_type,
                    source,
                    path=observed_path_by_url.get(url, ""),
                ),
                stability=_canonical_locator_stability(kind, url),
                observed_at=(
                    observed_at_by_url.get(url)
                    or first_string(payload.get("_observed_at"))
                ),
            )
        )
    return make_canonical_record(
        record_type,
        _canonical_metadata(record_type, payload),
        identifiers=identifiers,
        locators=locators,
        provenance=provenance,
    )


def canonical_record_from_search_record(
    record: LiteratureRecord | PatentRecord,
) -> CanonicalRecord:
    record_type: Literal["literature", "patent"] = (
        "literature" if isinstance(record, LiteratureRecord) else "patent"
    )
    return canonical_record_from_search_payload(
        record_type,
        search_record_payload(record_type, record),
    )


def canonical_records_from_state_store(
    store: SearchStateStore,
) -> list[CanonicalRecord]:
    records: list[CanonicalRecord] = []
    for record_type in ("literature", "patent"):
        records.extend(
            canonical_record_from_search_payload(record_type, payload)
            for payload in store.canonical_occurrence_payloads(record_type)
        )
    return records


def _canonical_strong_values(record: CanonicalRecord) -> set[tuple[str, str]]:
    expected_types = (
        {"doi", "pmid", "pmcid", "arxiv_id"}
        if record.record_type == "literature"
        else {"publication_number"}
    )
    return {
        (item.identifier_type.casefold(), item.normalized_value)
        for item in record.identifiers
        if item.identifier_type.casefold() in expected_types
        and item.normalized_value
    }


def _canonical_merge_tokens(record: CanonicalRecord) -> set[str]:
    tokens = {f"record_id:{record.record_id}"}
    for identifier in record.identifiers:
        normalized = identifier.normalized_value
        kind = identifier.identifier_type.casefold()
        if not normalized:
            continue
        if kind in {
            "doi",
            "pmid",
            "pmcid",
            "arxiv_id",
            "publication_number",
        }:
            tokens.add(f"strong:{kind}:{normalized}")
        elif kind == "raw_id":
            tokens.add(
                f"scoped_raw:{identifier.source.casefold()}:{normalized}"
            )
    for locator in record.locators:
        if record.record_type == "patent" or (
            locator.kind.casefold() in {"direct_pdf", "pdf"}
            and locator.stability.casefold() == "stable"
        ):
            tokens.add(f"locator:{locator.normalized_url}")
    return tokens


def _json_marker(value: Any) -> str:
    return json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)


def _merge_canonical_component(
    component: list[CanonicalRecord],
) -> CanonicalRecord:
    first = component[0]
    metadata = dict(first.metadata)
    observed_metadata: list[dict[str, Any]] = []
    observed_markers: set[str] = set()
    for record in component:
        marker = _json_marker(record.metadata)
        if marker not in observed_markers:
            observed_markers.add(marker)
            observed_metadata.append(
                {
                    "sources": sorted(
                        {item.source for item in record.provenance}
                    ) or ["unknown"],
                    "value": record.metadata,
                }
            )
        for key, value in record.metadata.items():
            if key not in metadata or metadata[key] in (None, "", [], {}):
                metadata[key] = value
    if len(observed_metadata) > 1:
        metadata["observed_metadata"] = observed_metadata

    identifiers_by_key: dict[tuple[str, str, str], Identifier] = {}
    for record in component:
        for item in record.identifiers:
            key = (
                item.identifier_type.casefold(),
                item.normalized_value,
                item.source,
            )
            previous = identifiers_by_key.get(key)
            if previous is None or (item.primary and not previous.primary):
                identifiers_by_key[key] = item
    locators_by_key: dict[tuple[str, str, str, str], Locator] = {}
    for record in component:
        for item in record.locators:
            key = (
                item.kind.casefold(),
                item.normalized_url,
                item.source,
                item.auth_scope,
            )
            previous = locators_by_key.get(key)
            if previous is None or (
                item.stability == "stable" and previous.stability != "stable"
            ):
                locators_by_key[key] = item
    provenance_by_key: dict[
        tuple[str, str, str, int | None, str, str],
        Provenance,
    ] = {}
    for record in component:
        for item in record.provenance:
            key = (
                item.source,
                item.keyword,
                item.query_variant,
                item.rank,
                item.path,
                item.raw_id,
            )
            provenance_by_key.setdefault(key, item)
    return make_canonical_record(
        first.record_type,
        metadata,
        identifiers=list(identifiers_by_key.values()),
        locators=list(locators_by_key.values()),
        provenance=list(provenance_by_key.values()),
    )


def merge_canonical_search_records(
    records: Iterable[CanonicalRecord],
) -> tuple[list[CanonicalRecord], dict[str, str]]:
    candidates = list(records)
    if not candidates:
        return [], {}
    parents = list(range(len(candidates)))
    strong_values = [set(_canonical_strong_values(item)) for item in candidates]

    def find(index: int) -> int:
        while parents[index] != index:
            parents[index] = parents[parents[index]]
            index = parents[index]
        return index

    def union(left: int, right: int) -> bool:
        left_root = find(left)
        right_root = find(right)
        if left_root == right_root:
            return True
        if candidates[left_root].record_type != candidates[right_root].record_type:
            return False
        left_strong = strong_values[left_root]
        right_strong = strong_values[right_root]
        combined_strong = left_strong | right_strong
        identity_priority = (
            ("doi", "pmcid", "pmid", "arxiv_id")
            if candidates[left_root].record_type == "literature"
            else ("publication_number",)
        )
        # Compare the highest-priority identifier kind observed by both
        # components.  Agreement on one DOI is authoritative even when a
        # secondary PMID was supplied inconsistently by different sources;
        # all observed identifiers and provenance are retained after merge.
        # Conflicting DOIs/publication numbers still prevent a merge.
        for kind in identity_priority:
            left_values = {value for item_kind, value in left_strong if item_kind == kind}
            right_values = {value for item_kind, value in right_strong if item_kind == kind}
            if not left_values or not right_values:
                continue
            if (
                len(left_values) != 1
                or len(right_values) != 1
                or left_values != right_values
            ):
                return False
            break
        if right_root < left_root:
            left_root, right_root = right_root, left_root
        parents[right_root] = left_root
        strong_values[left_root] = combined_strong
        return True

    token_owner: dict[tuple[str, str], int] = {}
    for index, record in enumerate(candidates):
        for token in sorted(_canonical_merge_tokens(record)):
            scoped_token = (record.record_type, token)
            owner = token_owner.get(scoped_token)
            if owner is None:
                token_owner[scoped_token] = index
            elif union(index, owner):
                token_owner[scoped_token] = find(index)

    components: dict[int, list[CanonicalRecord]] = defaultdict(list)
    component_first_index: dict[int, int] = {}
    for index, record in enumerate(candidates):
        root = find(index)
        components[root].append(record)
        component_first_index[root] = min(
            component_first_index.get(root, index),
            index,
        )
    merged: list[CanonicalRecord] = []
    aliases: dict[str, str] = {}
    for root in sorted(components, key=component_first_index.get):
        record = _merge_canonical_component(components[root])
        merged.append(record)
        for original in components[root]:
            if original.record_id != record.record_id:
                aliases[original.record_id] = record.record_id
    merged.sort(key=lambda item: (item.record_type, item.record_id))
    return merged, aliases


def materialize_v2_handoff(
    canonical_candidates: Iterable[CanonicalRecord],
    *,
    batch_name: str | None,
    metadata_root: Path | None,
    search_status: str,
    legacy_literature_count: int,
    legacy_patent_count: int,
) -> dict[str, Any]:
    literature_path, patent_path, manifest_path, database_path = canonical_v2_paths(
        batch_name,
        metadata_root,
    )
    candidates = tuple(canonical_candidates)
    candidate_types: dict[str, str] = {}
    for candidate in candidates:
        previous_type = candidate_types.setdefault(
            candidate.record_id,
            candidate.record_type,
        )
        if previous_type != candidate.record_type:
            raise ValueError(
                "handoff_alias_type_mismatch: one record_id was observed "
                "under multiple record types"
            )
    merged, aliases = merge_canonical_search_records(candidates)
    current_ids = {record.record_id for record in merged}
    target_types = {record.record_id: record.record_type for record in merged}
    persisted_aliases = {
        alias: target
        for alias, target in sorted(aliases.items())
        if alias not in current_ids and target in current_ids
    }
    typed_aliases: dict[str, dict[str, str]] = {
        "literature": {},
        "patent": {},
    }
    for alias, target in persisted_aliases.items():
        alias_type = candidate_types.get(alias)
        target_type = target_types.get(target)
        if alias_type not in typed_aliases or alias_type != target_type:
            raise ValueError(
                f"handoff_alias_type_mismatch: {alias!r} -> {target!r}"
            )
        typed_aliases[alias_type][alias] = target
    return write_handoff_bundle(
        records=merged,
        aliases_by_type=typed_aliases,
        literature_path=literature_path,
        patent_path=patent_path,
        manifest_path=manifest_path,
        database_path=database_path,
        search_status=search_status,
        legacy_literature_count=legacy_literature_count,
        legacy_patent_count=legacy_patent_count,
        registry_schema_version=REGISTRY_SCHEMA_VERSION,
        registry_version=REGISTRY_VERSION,
    )


@dataclass
class IncrementalMaterializer:
    state_store: SearchStateStore
    batch_name: str | None
    metadata_root: Path | None
    baseline_literature: list[LiteratureRecord]
    baseline_patents: list[PatentRecord]
    every_pages: int = 10
    every_seconds: int = 60
    enabled: bool = True
    _lock: asyncio.Lock = field(default_factory=asyncio.Lock, init=False)
    _pages_since_flush: int = field(default=0, init=False)
    _last_flush_monotonic: float = field(default_factory=time.monotonic, init=False)
    _timer_task: asyncio.Task[Any] | None = field(default=None, init=False)
    _flush_task: asyncio.Task[Any] | None = field(default=None, init=False)

    def page_committed(self) -> None:
        if not self.enabled:
            return
        self._pages_since_flush += 1
        try:
            loop = asyncio.get_running_loop()
        except RuntimeError:
            return
        if self._pages_since_flush >= self.every_pages:
            if self._flush_task is None or self._flush_task.done():
                self._flush_task = loop.create_task(self.flush())
            return
        if self._timer_task is None or self._timer_task.done():
            self._timer_task = loop.create_task(self._flush_after_interval())

    async def _flush_after_interval(self) -> None:
        remaining = max(
            0.0,
            self.every_seconds - (time.monotonic() - self._last_flush_monotonic),
        )
        await asyncio.sleep(remaining)
        if self._pages_since_flush:
            await self.flush()

    def _materialize_sync(self, run_status: str) -> tuple[int, int, list[str]]:
        migration_stats: dict[str, int] = {}
        literature_candidates = [
            *self.baseline_literature,
            *literature_records_from_state(
                self.state_store,
                migration_stats=migration_stats,
            ),
        ]
        patent_candidates = [
            *self.baseline_patents,
            *patent_records_from_state(self.state_store),
        ]
        literature_with_locator, _ = split_literature_records_by_required_locator(
            literature_candidates
        )
        patents_with_url, _ = split_patent_records_by_required_url(patent_candidates)
        literature_records = dedupe_literature_records(literature_with_locator)
        patent_records = dedupe_patent_records(patents_with_url)
        literature_path, patent_path = output_paths(
            batch_name=self.batch_name,
            metadata_root=self.metadata_root,
        )
        warnings: list[str] = []
        for path, columns, rows in (
            (literature_path, LITERATURE_COLUMNS, literature_rows(literature_records)),
            (patent_path, PATENT_COLUMNS, patent_rows(patent_records)),
        ):
            ok, reason = write_csv_atomic(path, columns, rows)
            if not ok:
                warnings.append(f"atomic_replace_failed:{path.name}:{reason}")
        source_runs = self.state_store.summary()
        progress = {
            "schema": "laps_search_progress_v1",
            "run_status": run_status,
            "materialized_at": utc_now(),
            "literature_count": len(literature_records),
            "patent_count": len(patent_records),
            "committed_pages": sum(int(run.get("pages") or 0) for run in source_runs),
            "source_runs": source_runs,
            "warnings": warnings,
        }
        ok, reason = write_json_atomic(
            search_progress_path(self.batch_name, self.metadata_root),
            progress,
        )
        if not ok:
            warnings.append(f"progress_write_failed:{reason}")
        return len(literature_records), len(patent_records), warnings

    async def flush(
        self,
        *,
        force: bool = False,
        run_status: str = "running",
    ) -> None:
        if not self.enabled and not force:
            return
        async with self._lock:
            if not force and self._pages_since_flush <= 0:
                return
            self._pages_since_flush = 0
            self._last_flush_monotonic = time.monotonic()
            _, _, warnings = await asyncio.to_thread(
                self._materialize_sync,
                run_status,
            )
            for warning in warnings:
                print(f"Warning: incremental materialization {warning}", file=sys.stderr)

    async def final_flush(self, run_status: str = "completed") -> None:
        if self._timer_task is not None and not self._timer_task.done():
            self._timer_task.cancel()
        if self._flush_task is not None and not self._flush_task.done():
            await self._flush_task
        await self.flush(force=True, run_status=run_status)


def validate_source_policies() -> None:
    checks = [
        ("literature policy", set(literature_search_path_map), set(literature_source_auth_policy)),
        ("patent policy", set(patents_search_path_map), set(patent_source_auth_policy)),
        ("literature adapter", set(literature_search_path_map), set(LITERATURE_SOURCE_ADAPTERS)),
        ("patent adapter", set(patents_search_path_map), set(PATENT_SOURCE_ADAPTERS)),
        ("literature query profile", set(literature_search_path_map), set(LITERATURE_QUERY_PROFILES)),
        ("patent query profile", set(patents_search_path_map), set(PATENT_QUERY_PROFILES)),
    ]
    problems: list[str] = []
    for label, expected, actual in checks:
        missing = sorted(expected - actual)
        extra = sorted(actual - expected)
        if missing or extra:
            problems.append(f"{label} source policy mismatch; missing={missing}; extra={extra}")
    if problems:
        raise RuntimeError("; ".join(problems))
    for record_type, specs, endpoint_map, adapters in (
        (
            "literature",
            LITERATURE_SEARCH_SPECS,
            literature_search_path_map,
            LITERATURE_SOURCE_ADAPTERS,
        ),
        (
            "patent",
            PATENT_SEARCH_SPECS,
            patents_search_path_map,
            PATENT_SOURCE_ADAPTERS,
        ),
    ):
        expected_names = tuple(spec.display_name for spec in specs)
        if tuple(endpoint_map) != expected_names or tuple(adapters) != expected_names:
            raise RuntimeError(
                f"{record_type} runtime order drifted from shared registry"
            )
        for spec in specs:
            adapter = adapters[spec.display_name]
            actual_runner_name = getattr(adapter.runner, "__name__", "")
            if (
                endpoint_map[spec.display_name] != spec.endpoint
                or adapter.parser_name != spec.parser
                or adapter.paths != spec.paths
                or adapter.pagination != spec.pagination
                or actual_runner_name != spec.actual_adapter
            ):
                raise RuntimeError(
                    f"{record_type} runtime adapter drifted from shared registry: "
                    f"{spec.display_name}"
                )
    generic_parsers = [
        adapter.source
        for adapter in [*LITERATURE_SOURCE_ADAPTERS.values(), *PATENT_SOURCE_ADAPTERS.values()]
        if not adapter.parser_name or adapter.parser_name == "parse_generic_search_results"
    ]
    if generic_parsers:
        raise RuntimeError(f"source adapters require dedicated parser names: {sorted(generic_parsers)}")
    missing_query_variants = sorted(
        f"{adapter.record_type}:{adapter.source}"
        for adapter in [*LITERATURE_SOURCE_ADAPTERS.values(), *PATENT_SOURCE_ADAPTERS.values()]
        if not effective_query_variants(adapter)
    )
    if missing_query_variants:
        raise RuntimeError(
            f"source adapters require at least one coverage query variant: {missing_query_variants}"
        )
    invalid_browser_controllers = sorted(
        adapter.source
        for adapter in [*LITERATURE_SOURCE_ADAPTERS.values(), *PATENT_SOURCE_ADAPTERS.values()]
        if BROWSER_ADAPTER_PATHS.intersection(adapter.paths)
        and adapter.browser_escalation_controller
        != COMMON_BROWSER_ESCALATION_CONTROLLER
    )
    if invalid_browser_controllers:
        raise RuntimeError(
            "browser source adapters require the common verification controller: "
            f"{invalid_browser_controllers}"
        )
    missing_auth_scopes = sorted(
        f"{record_type}:{source}"
        for record_type, policy_map in (
            ("literature", literature_source_auth_policy),
            ("patent", patent_source_auth_policy),
        )
        for source, policy in policy_map.items()
        if policy.institutional_web_allowed and not policy.auth_state_scope.strip()
    )
    missing_restricted_adapters = sorted(
        f"{record_type}:{source}"
        for record_type, policy_map, adapters in (
            ("literature", literature_source_auth_policy, LITERATURE_SOURCE_ADAPTERS),
            ("patent", patent_source_auth_policy, PATENT_SOURCE_ADAPTERS),
        )
        for source, policy in policy_map.items()
        if policy.institutional_web_allowed
        and (
            source not in adapters
            or adapters[source].restricted_browser_runner is None
        )
    )
    missing_personal_auth_scopes = sorted(
        f"{record_type}:{source}"
        for record_type, policy_map in (
            ("literature", literature_source_auth_policy),
            ("patent", patent_source_auth_policy),
        )
        for source, policy in policy_map.items()
        if policy.runtime_personal_credential_keys
        and not policy.auth_state_scope.strip()
    )
    missing_personal_auth_adapters = sorted(
        f"{record_type}:{source}"
        for record_type, policy_map, adapters in (
            ("literature", literature_source_auth_policy, LITERATURE_SOURCE_ADAPTERS),
            ("patent", patent_source_auth_policy, PATENT_SOURCE_ADAPTERS),
        )
        for source, policy in policy_map.items()
        if policy.runtime_personal_credential_keys
        and (
            source not in adapters
            or adapters[source].restricted_browser_runner is None
        )
    )
    if missing_auth_scopes:
        raise RuntimeError(
            "institutional sources require auth_state_scope: "
            f"{missing_auth_scopes}"
        )
    if missing_restricted_adapters:
        raise RuntimeError(
            "institutional sources require restricted browser adapters: "
            f"{missing_restricted_adapters}"
        )
    if missing_personal_auth_scopes:
        raise RuntimeError(
            "site-personal sources require auth_state_scope: "
            f"{missing_personal_auth_scopes}"
        )
    if missing_personal_auth_adapters:
        raise RuntimeError(
            "site-personal sources require restricted browser adapters: "
            f"{missing_personal_auth_adapters}"
        )


def source_names_by_kind(policy_map: dict[str, SourceAuthPolicy], kind: AuthKind) -> list[str]:
    return [source for source, policy in policy_map.items() if policy.api_kind == kind]


def required_source_configured(source: str, policy: SourceAuthPolicy, *, is_patent: bool) -> bool:
    if is_patent and source == "Google BigQuery":
        return has_google_adc()
    return not missing_required_keys(policy)


def configured_required_sources(policy_map: dict[str, SourceAuthPolicy], *, is_patent: bool) -> list[str]:
    return [source for source, policy in policy_map.items() if policy.api_kind == "required_config" and required_source_configured(source, policy, is_patent=is_patent)]


def missing_required_sources(policy_map: dict[str, SourceAuthPolicy], *, is_patent: bool) -> list[str]:
    return [source for source, policy in policy_map.items() if policy.api_kind == "required_config" and not required_source_configured(source, policy, is_patent=is_patent)]


def canonical_optional_missing(key: str) -> bool:
    if key in {"CONTACT_EMAIL", "CROSSREF_MAILTO", "NCBI_EMAIL"}:
        return not env_value("CONTACT_EMAIL", "CROSSREF_MAILTO", "NCBI_EMAIL")
    if key in {"NCBI_API_KEY", "PUBMED_API_KEY"}:
        return not env_value("NCBI_API_KEY", "PUBMED_API_KEY")
    if key in {"CLARIVATE_API_KEY", "WOS_API_KEY"}:
        return not env_value("CLARIVATE_API_KEY", "WOS_API_KEY")
    return not env_value(key)


def collect_missing_required_keys(policy_map: dict[str, SourceAuthPolicy], *, is_patent: bool) -> list[str]:
    missing: list[str] = []
    for source, policy in policy_map.items():
        if policy.api_kind != "required_config":
            continue
        if is_patent and source == "Google BigQuery":
            if not has_google_adc() and "GOOGLE_APPLICATION_CREDENTIALS" not in missing:
                missing.append("GOOGLE_APPLICATION_CREDENTIALS")
            continue
        for key in policy.required_keys:
            if required_key_configured(key):
                continue
            display_key = "CLARIVATE_API_KEY/WOS_API_KEY" if key == "CLARIVATE_API_KEY" else key
            if display_key not in missing:
                missing.append(display_key)
    return missing


def collect_missing_optional_keys(policy_map: dict[str, SourceAuthPolicy]) -> list[str]:
    missing: list[str] = []
    for policy in policy_map.values():
        for key in policy.optional_keys:
            if canonical_optional_missing(key) and key not in missing:
                missing.append(key)
    return missing


def configured_optional_keys(policy_map: dict[str, SourceAuthPolicy]) -> list[str]:
    configured: list[str] = []
    for policy in policy_map.values():
        for key in policy.optional_keys:
            if not canonical_optional_missing(key) and key not in configured:
                configured.append(key)
    return configured


def policy_allows_restricted_access(policy: SourceAuthPolicy, config: SearchConfig) -> bool:
    if os.getenv("LAPS_ENABLE_RESTRICTED_WEB_FALLBACK", "1") != "1":
        return False
    if policy.runtime_personal_credential_keys:
        account, password = source_personal_credentials(config, policy)
        return bool(account and password and policy.personal_web_allowed)
    if not restricted_web_fallback_enabled(config):
        return False
    if config.path == "institution":
        return policy.institutional_web_allowed
    if config.path == "personal":
        return policy.personal_web_allowed
    return False


def build_access_plan(config: SearchConfig, source: str, policy: SourceAuthPolicy, keyword: str, *, is_patent: bool = False) -> AccessPlan:
    del keyword
    if policy.api_kind == "no_config":
        return AccessPlan("api", "public/no-config endpoint")
    if policy.api_kind == "optional_config":
        missing = tuple(key for key in policy.optional_keys if canonical_optional_missing(key))
        if missing:
            return AccessPlan("api_degraded", f"optional credential(s) not configured: {'/'.join(missing)}; continuing with anonymous/degraded access", missing)
        return AccessPlan("api", "configured optional credential(s) available")
    if policy.api_kind == "required_config":
        if is_patent and source == "Google BigQuery" and has_google_adc():
            return AccessPlan("api", "Google application-default credentials available")
        missing = tuple(missing_required_keys(policy))
        if not missing:
            return AccessPlan("api", "required credential(s) configured")
        if policy_allows_restricted_access(policy, config):
            return AccessPlan("restricted_browser", f"missing required credential(s): {'/'.join(missing)}; using permitted restricted web fallback", missing)
        if is_patent and source == "Google BigQuery":
            return AccessPlan("skip", "missing required credential(s): GOOGLE_APPLICATION_CREDENTIALS", missing)
        return AccessPlan("skip", f"missing required credential(s): {'/'.join(missing)} and no permitted restricted web fallback", missing)
    if policy.api_kind == "none":
        browser_enabled = os.getenv("LAPS_ENABLE_BROWSER_FALLBACK", "0") == "1"
        if policy.public_browser_allowed and (policy.browser_default_enabled or browser_enabled):
            return AccessPlan("public_browser", "public browser path preferred before restricted authentication")
        if policy_allows_restricted_access(policy, config):
            return AccessPlan("restricted_browser", "public browser path disabled; using permitted restricted web fallback")
        return AccessPlan("browser_disabled", "browser fallback disabled by default; no API key is required")
    return AccessPlan("unimplemented", "source access mode is not implemented; no missing API key is assumed")


def restricted_web_fallback_sources(policy_map: dict[str, SourceAuthPolicy], config: SearchConfig) -> list[str]:
    return [source for source, policy in policy_map.items() if policy_allows_restricted_access(policy, config)]


def browser_disabled_source_names(policy_map: dict[str, SourceAuthPolicy], config: SearchConfig, *, is_patent: bool) -> list[str]:
    names: list[str] = []
    for source, policy in policy_map.items():
        if build_access_plan(config, source, policy, "*", is_patent=is_patent).route == "browser_disabled":
            names.append(source)
    return names


def build_source_capability_report(config: SearchConfig | None = None) -> dict[str, Any]:
    if config is None:
        config = validate_config(load_config())
    runtime_config_path = get_runtime_config_path()
    literature_browser_disabled = browser_disabled_source_names(literature_source_auth_policy, config, is_patent=False)
    patent_browser_disabled = browser_disabled_source_names(patent_source_auth_policy, config, is_patent=True)
    literature_restricted_sources = restricted_web_fallback_sources(
        literature_source_auth_policy,
        config,
    )
    patent_restricted_sources = restricted_web_fallback_sources(
        patent_source_auth_policy,
        config,
    )
    missing_required_api_keys = sorted(set(collect_missing_required_keys(literature_source_auth_policy, is_patent=False) + collect_missing_required_keys(patent_source_auth_policy, is_patent=True)))
    missing_optional_keys = sorted(set(collect_missing_optional_keys(literature_source_auth_policy) + collect_missing_optional_keys(patent_source_auth_policy)))
    return {
        "runtime_config_path": str(runtime_config_path),
        "runtime_config_exists": runtime_config_path.exists(),
        "restricted_web_available": restricted_web_fallback_enabled(config),
        "restricted_access_mode": restricted_access_mode(config),
        "school_configured": bool(config.school.strip()),
        "account_configured": bool(config.account.strip()),
        "password_configured": bool(config.password.strip()),
        "uyanip_account_configured": bool(config.uyanip_account.strip()),
        "uyanip_password_configured": bool(config.uyanip_password),
        "institutional_web_fallback_enabled": config.path == "institution" and restricted_web_fallback_enabled(config),
        "personal_web_fallback_enabled": config.path == "personal" and restricted_web_fallback_enabled(config),
        "no_config_sources": source_names_by_kind(literature_source_auth_policy, "no_config") + source_names_by_kind(patent_source_auth_policy, "no_config"),
        "optional_config_sources": source_names_by_kind(literature_source_auth_policy, "optional_config") + source_names_by_kind(patent_source_auth_policy, "optional_config"),
        "required_config_sources": source_names_by_kind(literature_source_auth_policy, "required_config") + source_names_by_kind(patent_source_auth_policy, "required_config"),
        "restricted_web_fallback_sources": [
            *literature_restricted_sources,
            *patent_restricted_sources,
        ],
        "browser_disabled_sources": literature_browser_disabled + patent_browser_disabled,
        "configured_required_api_sources": configured_required_sources(literature_source_auth_policy, is_patent=False) + configured_required_sources(patent_source_auth_policy, is_patent=True),
        "missing_required_api_keys": missing_required_api_keys,
        "missing_optional_keys": missing_optional_keys,
        "literature": {
            "no_config_sources": source_names_by_kind(literature_source_auth_policy, "no_config"),
            "optional_config_sources": source_names_by_kind(literature_source_auth_policy, "optional_config"),
            "required_config_sources": source_names_by_kind(literature_source_auth_policy, "required_config"),
            "restricted_web_fallback_sources": literature_restricted_sources,
            "browser_disabled_sources": literature_browser_disabled,
            "configured_required_sources": configured_required_sources(literature_source_auth_policy, is_patent=False),
            "missing_required_sources": missing_required_sources(literature_source_auth_policy, is_patent=False),
            "configured_optional_keys": configured_optional_keys(literature_source_auth_policy),
            "missing_optional_keys": collect_missing_optional_keys(literature_source_auth_policy),
            "missing_required_keys": collect_missing_required_keys(literature_source_auth_policy, is_patent=False),
        },
        "patents": {
            "no_config_sources": source_names_by_kind(patent_source_auth_policy, "no_config"),
            "optional_config_sources": source_names_by_kind(patent_source_auth_policy, "optional_config"),
            "required_config_sources": source_names_by_kind(patent_source_auth_policy, "required_config"),
            "restricted_web_fallback_sources": patent_restricted_sources,
            "browser_disabled_sources": patent_browser_disabled,
            "configured_required_sources": configured_required_sources(patent_source_auth_policy, is_patent=True),
            "missing_required_sources": missing_required_sources(patent_source_auth_policy, is_patent=True),
            "configured_optional_keys": configured_optional_keys(patent_source_auth_policy),
            "missing_optional_keys": collect_missing_optional_keys(patent_source_auth_policy),
            "missing_required_keys": collect_missing_required_keys(patent_source_auth_policy, is_patent=True),
        },
    }


def apply_access_plan(runtime: SearchRuntime, source: str, keyword: str, plan: AccessPlan) -> bool:
    if plan.route == "skip":
        runtime.skip(source, keyword, plan.reason)
        return False
    if plan.route == "browser_disabled":
        runtime.browser_disabled(source, keyword, plan.reason)
        return False
    if plan.route == "unimplemented":
        runtime.browser_disabled(source, keyword, plan.reason)
        return False
    if plan.route == "api_degraded":
        runtime.degrade(source, keyword, plan.reason)
    return True


def apply_source_auth_preflight(runtime: SearchRuntime, source: str, keyword: str, policy: SourceAuthPolicy, *, is_patent: bool) -> bool:
    return apply_access_plan(runtime, source, keyword, build_access_plan(runtime.config, source, policy, keyword, is_patent=is_patent))


def handle_config_command(args: list[str]) -> int:
    if not args:
        json_print({"ok": False, "error": "Missing config command."})
        return 2
    command = args[0]
    rest = args[1:]
    try:
        if command == "init":
            path, created = init_api_user_config(force="--force" in rest)
            json_print({"ok": True, "path": str(path), "created": created})
            return 0
        if command == "path":
            path = get_api_config_path(required=False)
            print(path or "")
            return 0
        if command == "keys":
            json_print(list(API_CONFIG_KEYS))
            return 0
        if command == "env-template":
            json_print(api_config_template())
            return 0
        if command == "set":
            key, value = parse_config_assignment(rest)
            config = read_api_user_config(include_empty=True)
            config[key] = value
            path = write_api_user_config(config)
            API_CONFIG_VALUES[key] = value
            apply_compat_env_aliases()
            json_print({"ok": True, "path": str(path), "key": key, "value": mask_config_value(key, value)})
            return 0
        if command == "get":
            raw = "--raw" in rest
            keys = [arg for arg in rest if arg != "--raw"]
            if not keys:
                raise ValueError("Missing KEY.")
            key = keys[0]
            assert_api_config_key(key)
            entries = {entry["key"]: entry for entry in list_api_config_entries(include_missing=True, raw=raw)}
            json_print(entries[key])
            return 0
        if command == "unset":
            if not rest:
                raise ValueError("Missing KEY.")
            key = rest[0]
            assert_api_config_key(key)
            config = read_api_user_config(include_empty=True)
            existed = bool(config.get(key))
            config[key] = ""
            API_CONFIG_VALUES.pop(key, None)
            path = write_api_user_config(config)
            json_print({"ok": True, "path": str(path), "unset": key, "existed": existed})
            return 0
        if command == "list":
            json_print(list_api_config_entries(include_missing="--include-missing" in rest, raw="--raw" in rest))
            return 0
        if command == "doctor":
            load_project_dotenv_into_env()
            load_api_user_config_into_env()
            entries = list_api_config_entries(include_missing=True, raw=False)
            runtime_config = validate_config(load_config())
            json_print({
                "ok": True,
                "config_path": str(get_api_config_path(required=False) or ""),
                "config_path_env": API_CONFIG_PATH_ENV,
                "config_path_configured": get_api_config_path(required=False) is not None,
                "runtime_config_path": str(get_runtime_config_path()),
                "runtime_config_env": list(RUNTIME_CONFIG_ENV_NAMES),
                "runtime_config_exists": get_runtime_config_path().exists(),
                "configured_count": sum(1 for entry in entries if entry["configured"]),
                "missing_count": sum(1 for entry in entries if not entry["configured"]),
                "entries": entries,
                "source_capability": build_source_capability_report(runtime_config),
                "smoke_test_command": "python scripts/literature_and_patents_search_scripts.py config doctor",
                "smoke_test_network": "no network access; checks user config, environment variables, source capability, and missing required/optional credential separation",
            })
            return 0
        if command == "import-env":
            if not rest:
                raise ValueError("Missing PATH.")
            imported = parse_simple_env_file(Path(rest[0]).expanduser())
            config = read_api_user_config()
            config.update(imported)
            path = write_api_user_config(config)
            json_print({"ok": True, "path": str(path), "imported": sorted(imported), "count": len(imported)})
            return 0
        raise ValueError(f"Unsupported config command: {command}")
    except Exception as exc:
        json_print({"ok": False, "error": safe_error_text(str(exc))})
        return 2


def source_page_size(requested: int, maximum: int, minimum: int = 1) -> int:
    return min(max(minimum, int(requested)), maximum)


def normalized_search_phrase(keyword: str) -> str:
    return " ".join(first_string(keyword).split())


def quoted_search_phrase(keyword: str, *, tokenize_punctuation: bool = False) -> str:
    value = normalized_search_phrase(keyword)
    if tokenize_punctuation:
        value = " ".join(re.findall(r"[^\W_]+", unicodedata.normalize("NFKC", value).casefold()))
    escaped = value.replace("\\", "\\\\").replace('"', '\\"')
    return f'"{escaped}"'


def keyword_phrase_matches(keyword: str, *values: Any) -> bool:
    def tokens(value: Any) -> list[str]:
        normalized = unicodedata.normalize("NFKC", first_string(value)).casefold()
        return re.findall(r"[^\W_]+", normalized)

    expected = tokens(keyword)
    if not expected:
        return False
    needle = " ".join(expected)
    for value in values:
        haystack = " ".join(tokens(value))
        if needle and f" {needle} " in f" {haystack} ":
            return True
    return False


def apply_task_indices(records: list[LiteratureRecord] | list[PatentRecord]) -> None:
    context = SEARCH_TASK_CONTEXT.get()
    keyword_index = int(context.get("keyword_index") or 0)
    source_index = int(context.get("source_index") or 0)
    for record in records:
        record.keyword_index = keyword_index
        record.source_index = source_index


def persist_search_page(
    runtime: SearchRuntime,
    record_type: Literal["literature", "patent"],
    source: str,
    keyword: str,
    records: list[LiteratureRecord] | list[PatentRecord],
    *,
    next_token: str,
    exhausted: bool,
    page_number: int,
    total_hint: int | None = None,
    reason: str = "",
    raw_count: int | None = None,
    page_signature: str = "",
) -> None:
    apply_task_indices(records)
    page = SearchPage(
        records=list(records),
        next_token=next_token,
        exhausted=exhausted,
        total_hint=total_hint,
        page_signature=page_signature or search_page_signature(records, next_token),
        reason=reason,
        fetched_count=raw_count,
        parser_dropped_count=max(0, int(raw_count or len(records)) - len(records)),
    )
    runtime.persist_page(record_type, source, keyword, "", page, page_number=page_number)
    task_context = SEARCH_TASK_CONTEXT.get()
    if isinstance(task_context, dict):
        # The next request is the only cursor a later challenge response may
        # resume.  Keep it in the task-local binding context even when the
        # provider paginates by POST/XHR and the visible URL never changes.
        task_context["cursor_token"] = str(next_token or "")


def resumed_page_state(runtime: SearchRuntime, record_type: Literal["literature", "patent"], source: str, keyword: str, default_token: str) -> tuple[str, int]:
    run = runtime.resume_run(record_type, source, keyword)
    cursor = str(run.get("next_token") or default_token)
    task_context = SEARCH_TASK_CONTEXT.get()
    if isinstance(task_context, dict):
        task_context["cursor_token"] = cursor
    return cursor, int(run.get("pages") or 0)


def high_confidence_doi_match(record: LiteratureRecord, candidate: LiteratureRecord) -> bool:
    if not normalize_doi(candidate.doi):
        return False
    if normalize_title(record.title) != normalize_title(candidate.title):
        return False
    if record.year and candidate.year and abs(record.year - candidate.year) > 1:
        return False
    if record.authors and candidate.authors:
        expected = normalize_title(record.authors[0]).split()
        actual = normalize_title(candidate.authors[0]).split()
        if expected and actual and expected[-1] != actual[-1]:
            return False
    return True


async def resolve_doi_by_metadata(runtime: SearchRuntime, source: str, keyword: str, record: LiteratureRecord) -> str:
    normalized_title = normalize_title(record.title)
    if not normalized_title:
        return ""
    cache_metrics = getattr(runtime, "doi_enrichment_cache_metrics", None)
    if cache_metrics is None:
        cache_metrics = Counter()
        runtime.doi_enrichment_cache_metrics = cache_metrics
    state_store = getattr(runtime, "state_store", None)

    async def request_enricher(
        provider_source: str,
        url: str,
        params: Mapping[str, Any],
    ) -> HttpAttemptResult:
        request_result = getattr(runtime, "request_result", None)
        if callable(request_result):
            return await request_result(
                provider_source,
                keyword,
                "GET",
                url,
                params=dict(params),
                record_failure=False,
            )
        response = await runtime.request(
            provider_source,
            keyword,
            "GET",
            url,
            params=dict(params),
            record_failure=False,
        )
        if response is None:
            return HttpAttemptResult(
                status_code=404,
                reason="legacy runtime returned no enrichment response",
                error_code="legacy_empty",
            )
        return HttpAttemptResult(
            response=response,
            status_code=int(getattr(response, "status_code", 200) or 200),
            reason="legacy runtime enrichment response",
        )
    normalized_first_author = ""
    if record.authors:
        author_tokens = normalize_title(record.authors[0]).split()
        normalized_first_author = author_tokens[-1] if author_tokens else ""
    cache_key, cache_identity = doi_enrichment_cache_identity(
        normalized_title=normalized_title,
        source_input=source,
        publication_year=int(record.year or 0),
        first_author=normalized_first_author,
    )
    if cache_key in runtime.doi_enrichment_cache:
        cached = runtime.doi_enrichment_cache[cache_key]
        cache_metrics[
            "memory_positive_hit" if cached else "memory_negative_hit"
        ] += 1
        return cached
    if state_store is not None:
        cached_entry = state_store.get_doi_enrichment_cache(cache_key)
        if cached_entry is not None:
            cached = normalize_doi(cached_entry.get("doi"))
            runtime.doi_enrichment_cache[cache_key] = cached
            cache_metrics[
                "persistent_positive_hit"
                if cached_entry.get("outcome") == "positive"
                else "persistent_negative_hit"
            ] += 1
            return cached
    cache_metrics["miss"] += 1

    def persist_cache(outcome: Literal["positive", "negative"], doi: str, reason_code: str) -> str:
        normalized = normalize_doi(doi)
        runtime.doi_enrichment_cache[cache_key] = normalized
        cache_metrics[f"{outcome}_write"] += 1
        if state_store is not None:
            state_store.put_doi_enrichment_cache(
                cache_key,
                cache_identity,
                outcome=outcome,
                doi=normalized,
                reason_code=reason_code,
                ttl_seconds=doi_cache_ttl_seconds(outcome),
            )
        return normalized

    authoritative_no_match = True
    transient_failure = False
    params: dict[str, Any] = {"query.bibliographic": record.title, "rows": 5}
    if contact_email():
        params["mailto"] = contact_email()
    crossref_attempt = await request_enricher(
        "Crossref API",
        "https://api.crossref.org/works",
        params,
    )
    if crossref_attempt.ok:
        try:
            for candidate in parse_crossref_works(
                crossref_attempt.response.json(),
                source,
                keyword,
            ):
                if high_confidence_doi_match(record, candidate):
                    return persist_cache(
                        "positive",
                        normalize_doi(candidate.doi),
                        "doi_resolved_crossref",
                    )
        except Exception:
            authoritative_no_match = False
            cache_metrics["parse_error_not_cached"] += 1
    else:
        if crossref_attempt.error_code != "legacy_empty":
            authoritative_no_match = False
            if transient_http_attempt(crossref_attempt):
                transient_failure = True
    openalex_params: dict[str, Any] = {
        "search.exact": quoted_search_phrase(record.title),
        "per-page": 5,
    }
    openalex_key = env_value("OPENALEX_API_KEY")
    if openalex_key:
        openalex_params["api_key"] = openalex_key
    if contact_email():
        openalex_params["mailto"] = contact_email()
    openalex_attempt = await request_enricher(
        "OpenAlex API",
        "https://api.openalex.org/works",
        openalex_params,
    )
    if openalex_attempt.ok:
        try:
            for candidate in parse_openalex_works(
                openalex_attempt.response.json(),
                source,
                keyword,
            ):
                if high_confidence_doi_match(record, candidate):
                    return persist_cache(
                        "positive",
                        normalize_doi(candidate.doi),
                        "doi_resolved_openalex",
                    )
        except Exception:
            authoritative_no_match = False
            cache_metrics["parse_error_not_cached"] += 1
    else:
        if openalex_attempt.error_code != "legacy_empty":
            authoritative_no_match = False
            if transient_http_attempt(openalex_attempt):
                transient_failure = True
    if authoritative_no_match:
        persist_cache("negative", "", "no_high_confidence_doi_match")
    elif transient_failure:
        cache_metrics["transient_not_cached"] += 1
    else:
        cache_metrics["indeterminate_not_cached"] += 1
    return ""


async def enrich_missing_dois(runtime: SearchRuntime, source: str, keyword: str, records: list[LiteratureRecord]) -> None:
    for record in records:
        if normalize_doi(record.doi):
            continue
        doi = await resolve_doi_by_metadata(runtime, source, keyword, record)
        if doi:
            record.doi = doi


def parse_openalex_works(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("results", []), start=1):
        title = first_string(item.get("title") or item.get("display_name"))
        authors = [first_string(auth.get("author", {}).get("display_name")) for auth in item.get("authorships", []) if isinstance(auth, dict)]
        location = item.get("primary_location") or {}
        source_obj = location.get("source") or {}
        journal = first_string(source_obj.get("display_name") or item.get("host_venue", {}).get("display_name"))
        observed_ids = item.get("ids") if isinstance(item.get("ids"), Mapping) else {}
        typed_identifiers = {
            kind: first_string(observed_ids.get(key))
            for kind, key in (
                ("pmid", "pmid"),
                ("pmcid", "pmcid"),
                ("arxiv_id", "arxiv"),
            )
            if first_string(observed_ids.get(key))
        }
        pdf_url = first_observed_pdf_url(
            (item.get("best_oa_location") or {}).get("pdf_url")
            if isinstance(item.get("best_oa_location"), dict)
            else None,
            location.get("pdf_url") if isinstance(location, dict) else None,
            [
                candidate.get("pdf_url")
                for candidate in (item.get("locations") or [])
                if isinstance(candidate, dict)
            ],
        )
        records.append(
            LiteratureRecord(
                title=title,
                authors=[author for author in authors if author],
                year=parse_year(item.get("publication_year")),
                journal=journal or None,
                doi=first_string(item.get("doi")),
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=first_string(item.get("id")),
                identifiers=typed_identifiers,
                landing_url=first_observed_landing_url(
                    location.get("landing_page_url") if isinstance(location, Mapping) else None,
                    item.get("id"),
                )
                or None,
            )
        )
    return [record for record in records if record.title]


async def search_openalex(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int, query_override: str | None = None) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 100)
    cursor, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "*")
    api_key = env_value("OPENALEX_API_KEY")
    if not api_key:
        runtime.degrade(source, keyword, "OPENALEX_API_KEY not configured; trying anonymous/degraded OpenAlex access")
    records: list[LiteratureRecord] = []
    seen_tokens: set[str] = set()
    while cursor and cursor not in seen_tokens:
        seen_tokens.add(cursor)
        params: dict[str, Any] = {"per-page": page_size, "cursor": cursor}
        if query_override:
            params["search"] = query_override
        else:
            params["search.exact"] = quoted_search_phrase(keyword)
        if api_key:
            params["api_key"] = api_key
        if contact_email():
            params["mailto"] = contact_email()
        response = await runtime.request(source, keyword, "GET", url, params=params, record_failure=bool(api_key))
        if response is None:
            if not api_key:
                runtime.degrade(source, keyword, "OpenAlex anonymous request failed; configure OPENALEX_API_KEY for stable production access")
            if completed_pages:
                failure_reason = latest_source_reason(runtime, source, keyword)
                retry_after = retry_after_seconds_from_text(failure_reason)
                reason = (
                    f"rate_limit_exceeded_after_partial_results:retry_after_seconds={retry_after}"
                    if "http 429" in failure_reason.casefold() and retry_after
                    else "request_failed_after_partial_results"
                )
                runtime.mark_current_run("literature", source, keyword, "incomplete", reason)
            return records
        try:
            data = response.json()
            page_records = parse_openalex_works(data, source, keyword, len(records))
            next_cursor = first_string((data.get("meta") or {}).get("next_cursor"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "openalex_schema_error")
            return records
        exhausted = not data.get("results") or not next_cursor
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else next_cursor,
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=parse_int((data.get("meta") or {}).get("count")),
        )
        records.extend(page_records)
        if exhausted:
            break
        if next_cursor in seen_tokens:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_cursor")
            break
        cursor = next_cursor
    return records


def parse_crossref_works(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    items = (data.get("message") or {}).get("items", [])
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(items, start=1):
        date_parts = (
            item.get("published-print", {}).get("date-parts")
            or item.get("published-online", {}).get("date-parts")
            or item.get("published", {}).get("date-parts")
            or item.get("issued", {}).get("date-parts")
            or []
        )
        year = date_parts[0][0] if date_parts and date_parts[0] else None
        pdf_url = first_observed_pdf_url(item.get("link"))
        records.append(
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("author", [])),
                year=parse_year(year),
                journal=first_string(item.get("container-title")) or None,
                doi=first_string(item.get("DOI")),
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=first_string(item.get("DOI")),
            )
        )
    return [record for record in records if record.title]


def crossref_title_anchor_terms(keyword: str) -> list[str]:
    normalized = unicodedata.normalize("NFKC", normalized_search_phrase(keyword)).casefold()
    terms: list[str] = []
    for term in re.findall(r"[^\W_]+", normalized):
        if len(term) < 3 or term in terms:
            continue
        terms.append(term)
    return terms or ([normalized] if normalized else [])


async def select_crossref_title_anchor(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
) -> str:
    cache_key = (source, normalized_search_phrase(keyword).casefold())
    cached = runtime.query_anchor_cache.get(cache_key)
    if cached:
        return cached
    terms = crossref_title_anchor_terms(keyword)
    if len(terms) <= 1:
        anchor = first_string(terms) or normalized_search_phrase(keyword)
        runtime.query_anchor_cache[cache_key] = anchor
        return anchor
    candidates: list[tuple[int, int, str]] = []
    for index, term in enumerate(terms):
        params: dict[str, Any] = {"query.title": term, "rows": 0}
        if contact_email():
            params["mailto"] = contact_email()
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            params=params,
            record_failure=False,
        )
        if response is None:
            continue
        try:
            total = parse_int((response.json().get("message") or {}).get("total-results"))
        except Exception:
            continue
        if total is not None:
            candidates.append((total, index, term))
    anchor = min(candidates)[2] if candidates else normalized_search_phrase(keyword)
    runtime.query_anchor_cache[cache_key] = anchor
    return anchor


def crossref_raw_page_signature(items: list[Any]) -> str:
    identities = [
        (
            first_string(item.get("DOI")),
            first_string(item.get("title")),
        )
        for item in items
        if isinstance(item, dict)
    ]
    return hashlib.sha1(json.dumps(identities, ensure_ascii=False).encode("utf-8")).hexdigest()


async def search_crossref(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 1000)
    cursor, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "*")
    if not contact_email():
        runtime.degrade(source, keyword, "CONTACT_EMAIL/CROSSREF_MAILTO not configured; using Crossref public pool")
    anchor = await select_crossref_title_anchor(runtime, source, url, keyword)
    records: list[LiteratureRecord] = []
    seen_pages: set[str] = set()
    while cursor:
        params = {
            "query.title": anchor,
            "rows": page_size,
            "cursor": cursor,
            "select": "DOI,title,author,published-print,published-online,published,container-title,URL,link,issued",
        }
        if contact_email():
            params["mailto"] = contact_email()
        response = await runtime.request(source, keyword, "GET", url, params=params)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            message = data.get("message") or {}
            raw_items = message.get("items", [])
            parsed_records = parse_crossref_works(data, source, keyword, len(records))
            page_records = [
                record for record in parsed_records
                if keyword_phrase_matches(keyword, record.title)
            ]
            next_cursor = first_string(message.get("next-cursor"))
            raw_signature = crossref_raw_page_signature(raw_items)
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "crossref_schema_error")
            return records
        if raw_signature in seen_pages and raw_items:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_page_signature")
            break
        seen_pages.add(raw_signature)
        exhausted = len(raw_items) < page_size
        missing_cursor = bool(raw_items) and not exhausted and not next_cursor
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else (next_cursor or cursor),
            exhausted=exhausted and not missing_cursor,
            page_number=completed_pages,
            total_hint=parse_int(message.get("total-results")),
            raw_count=len(raw_items),
            reason="missing_next_cursor_before_exhaustion" if missing_cursor else "",
            page_signature=raw_signature,
        )
        records.extend(page_records)
        if missing_cursor:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "missing_next_cursor_before_exhaustion")
            break
        if exhausted:
            break
        cursor = next_cursor
    return records


def parse_semantic_scholar_api(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("data", []), start=1):
        external = item.get("externalIds") or {}
        journal = item.get("journal") or {}
        records.append(
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("authors", [])),
                year=parse_year(item.get("year") or item.get("publicationDate")),
                journal=first_string(journal.get("name") if isinstance(journal, dict) else journal) or first_string(item.get("venue")) or None,
                doi=first_string(external.get("DOI")),
                url=first_observed_pdf_url(item.get("openAccessPdf")) or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=first_string(item.get("paperId") or external.get("CorpusId")),
            )
        )
    return [record for record in records if record.title]


async def search_semantic_scholar_api(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    del limit
    endpoint = url.rstrip("/") + "/bulk"
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "")
    headers: dict[str, str] = {}
    if env_value("SEMANTIC_SCHOLAR_API_KEY"):
        headers["x-api-key"] = env_value("SEMANTIC_SCHOLAR_API_KEY")
    else:
        runtime.degrade(source, keyword, "SEMANTIC_SCHOLAR_API_KEY not configured; using anonymous metadata search")
    records: list[LiteratureRecord] = []
    seen_tokens: set[str] = set()
    while token not in seen_tokens:
        seen_tokens.add(token)
        params = {
            "query": quoted_search_phrase(keyword, tokenize_punctuation=True),
            "fields": "title,authors,year,venue,journal,externalIds,url,openAccessPdf,publicationDate",
        }
        if token:
            params["token"] = token
        response = await runtime.request(source, keyword, "GET", endpoint, params=params, headers=headers or None)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("data", [])
            page_records = parse_semantic_scholar_api(data, source, keyword, len(records))
            total = parse_int(data.get("total"))
            next_token = first_string(data.get("token"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "semantic_scholar_schema_error")
            return records
        exhausted = not raw_items or not next_token
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else next_token,
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=total,
        )
        records.extend(page_records)
        if exhausted:
            break
        if next_token in seen_tokens:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_cursor")
            break
        token = next_token
    return records


def parse_arxiv_atom(text: str, source: str, keyword: str, rank_start: int = 0) -> tuple[list[LiteratureRecord], int | None, int]:
    root = ET.fromstring(text)
    ns = {
        "a": "http://www.w3.org/2005/Atom",
        "opensearch": "http://a9.com/-/spec/opensearch/1.1/",
        "arxiv": "http://arxiv.org/schemas/atom",
    }
    entries = root.findall("a:entry", ns)
    records: list[LiteratureRecord] = []
    for offset, entry in enumerate(entries, start=1):
        title = first_string(entry.findtext("a:title", default="", namespaces=ns))
        authors = [first_string(node.findtext("a:name", default="", namespaces=ns)) for node in entry.findall("a:author", ns)]
        raw_id = first_string(entry.findtext("a:id", default="", namespaces=ns))
        arxiv_id = re.sub(
            r"v\d+$",
            "",
            urllib.parse.urlsplit(raw_id).path.rstrip("/").rsplit("/", 1)[-1],
            flags=re.IGNORECASE,
        )
        doi = first_string(entry.findtext("arxiv:doi", default="", namespaces=ns))
        journal = first_string(entry.findtext("arxiv:journal_ref", default="", namespaces=ns))
        published = first_string(entry.findtext("a:published", default="", namespaces=ns))
        pdf_url = first_observed_pdf_url(
            [
                link.get("href")
                for link in entry.findall("a:link", ns)
                if "pdf"
                in " ".join(
                    first_string(link.get(attribute))
                    for attribute in ("title", "type", "rel")
                ).casefold()
            ]
        )
        records.append(
            LiteratureRecord(
                title=title,
                authors=authors,
                year=parse_year(published),
                journal=journal or "arXiv",
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=raw_id,
                identifiers={"arxiv_id": arxiv_id} if arxiv_id else {},
                landing_url=raw_id or None,
            )
        )
    total = parse_int(root.findtext("opensearch:totalResults", default="", namespaces=ns))
    return [record for record in records if record.title], total, len(entries)


async def search_arxiv(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 2000)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    start = parse_int(token) or 0
    records: list[LiteratureRecord] = []
    while True:
        params = {
            "search_query": f"all:{quoted_search_phrase(keyword)}",
            "start": start,
            "max_results": page_size,
        }
        response = await runtime.request(source, keyword, "GET", url, params=params)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            page_records, total, raw_count = parse_arxiv_atom(response.text, source, keyword, len(records))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "arxiv_atom_schema_error")
            return records
        next_start = start + raw_count
        exhausted = raw_count == 0 or (total is not None and next_start >= total) or raw_count < page_size
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else str(next_start),
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=total,
        )
        records.extend(page_records)
        if exhausted:
            break
        if next_start <= start:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        start = next_start
    return records


def parse_ncbi_esummary(data: dict[str, Any], source: str, keyword: str, db: str, rank_start: int = 0) -> list[LiteratureRecord]:
    result = data.get("result", {})
    records: list[LiteratureRecord] = []
    for offset, uid in enumerate(result.get("uids", []), start=1):
        item = result.get(uid, {})
        doi = ""
        typed_identifiers: dict[str, str] = {
            "pmcid" if db == "pmc" else "pmid": (
                f"PMC{uid}" if db == "pmc" and not str(uid).upper().startswith("PMC") else str(uid)
            )
        }
        for article_id in item.get("articleids", []):
            identifier_type = first_string(article_id.get("idtype")).casefold()
            identifier_value = first_string(article_id.get("value"))
            if identifier_type == "doi":
                doi = first_string(article_id.get("value"))
            elif identifier_type in {"pmid", "pubmed"} and identifier_value:
                typed_identifiers["pmid"] = identifier_value
            elif identifier_type in {"pmcid", "pmc"} and identifier_value:
                typed_identifiers["pmcid"] = identifier_value
        pdf_url = first_observed_pdf_url(
            item.get("pdf_url"),
            item.get("fullTextUrlList"),
        )
        records.append(
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("authors", [])),
                year=parse_year(item.get("pubdate") or item.get("epubdate")),
                journal=first_string(item.get("fulljournalname") or item.get("source")) or None,
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=uid,
                identifiers=typed_identifiers,
            )
        )
    return [record for record in records if record.title]


def parse_pmc_esummary(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return parse_ncbi_esummary(data, source, keyword, "pmc", rank_start)


def parse_pubmed_esummary(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return parse_ncbi_esummary(data, source, keyword, "pubmed", rank_start)


async def search_pubmed_or_pmc(runtime: SearchRuntime, source: str, keyword: str, limit: int, db: str) -> list[LiteratureRecord]:
    base = "https://eutils.ncbi.nlm.nih.gov/entrez/eutils"
    page_size = source_page_size(limit, 10000)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    retstart = parse_int(token) or 0
    ncbi_key = env_value("NCBI_API_KEY", "PUBMED_API_KEY")
    if not ncbi_key:
        runtime.degrade(source, keyword, "NCBI_API_KEY/PUBMED_API_KEY not configured; using lower-rate anonymous NCBI E-utilities access")
    records: list[LiteratureRecord] = []
    while True:
        params: dict[str, Any] = {
            "db": db,
            "term": f"{quoted_search_phrase(keyword)}[Title/Abstract]",
            "retmode": "json",
            "retmax": page_size,
            "retstart": retstart,
        }
        if ncbi_key:
            params["api_key"] = ncbi_key
        if contact_email():
            params["email"] = contact_email()
        if ncbi_tool():
            params["tool"] = ncbi_tool()
        response = await runtime.request(source, keyword, "GET", f"{base}/esearch.fcgi", params=params)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            search_result = response.json().get("esearchresult", {})
            ids = search_result.get("idlist", [])
            total = parse_int(search_result.get("count"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "ncbi_esearch_schema_error")
            return records
        page_records: list[LiteratureRecord] = []
        if ids:
            for chunk_start in range(0, len(ids), 500):
                id_chunk = ids[chunk_start : chunk_start + 500]
                summary_params: dict[str, Any] = {
                    "db": db,
                    "id": ",".join(id_chunk),
                    "retmode": "json",
                }
                if ncbi_key:
                    summary_params["api_key"] = ncbi_key
                if contact_email():
                    summary_params["email"] = contact_email()
                if ncbi_tool():
                    summary_params["tool"] = ncbi_tool()
                summary_response = await runtime.request(
                    source,
                    keyword,
                    "POST",
                    f"{base}/esummary.fcgi",
                    data=summary_params,
                )
                if summary_response is None:
                    runtime.mark_current_run("literature", source, keyword, "incomplete", "ncbi_esummary_request_failed")
                    return records
                try:
                    summary_data = summary_response.json()
                    if summary_data.get("error"):
                        raise ValueError(first_string(summary_data.get("error")))
                    page_records.extend(
                        parse_ncbi_esummary(
                            summary_data,
                            source,
                            keyword,
                            db,
                            len(records) + len(page_records),
                        )
                    )
                except Exception as exc:
                    runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
                    runtime.mark_current_run("literature", source, keyword, "failed", "ncbi_esummary_schema_error")
                    return records
        next_start = retstart + len(ids)
        exhausted = not ids or (total is not None and next_start >= total) or len(ids) < page_size
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_start), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_start <= retstart:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        retstart = next_start
    return records


def parse_europe_pmc(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    items = data.get("resultList", {}).get("result", [])
    records = [
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("authorString")),
                year=parse_year(item.get("pubYear") or item.get("firstPublicationDate")),
                journal=first_string(item.get("journalTitle") or item.get("bookOrReportDetails")) or None,
                doi=first_string(item.get("doi")) or None,
                url=first_observed_pdf_url(item.get("fullTextUrlList")) or None,
                source=source,
                keyword=keyword,
                rank=rank_start + rank,
                raw_id=first_string(item.get("id")),
                identifiers={
                    kind: first_string(item.get(key))
                    for kind, key in (("pmid", "pmid"), ("pmcid", "pmcid"))
                    if first_string(item.get(key))
                },
                landing_url=first_observed_landing_url(
                    item.get("fullTextUrlList"),
                    item.get("url"),
                )
                or None,
            )
        for rank, item in enumerate(items, start=1)
    ]
    return [record for record in records if record.title]


def parse_biorxiv_europe_pmc(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return parse_europe_pmc(data, source, keyword, rank_start)


async def search_europe_pmc(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
    limit: int,
    query_override: str | None = None,
) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 1000)
    cursor, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "*")
    records: list[LiteratureRecord] = []
    seen_tokens: set[str] = set()
    while cursor and cursor not in seen_tokens:
        seen_tokens.add(cursor)
        params = {
            "query": query_override or quoted_search_phrase(keyword),
            "format": "json",
            "pageSize": page_size,
            "resultType": "core",
            "cursorMark": cursor,
        }
        response = await runtime.request(source, keyword, "GET", url, params=params)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("resultList", {}).get("result", [])
            parser = parse_biorxiv_europe_pmc if source == "bioRxiv / medRxiv" else parse_europe_pmc
            page_records = parser(data, source, keyword, len(records))
            next_cursor = first_string(data.get("nextCursorMark"))
            total = parse_int(data.get("hitCount"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "europe_pmc_schema_error")
            return records
        exhausted = not raw_items or not next_cursor
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else next_cursor, exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_cursor in seen_tokens:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_cursor")
            break
        cursor = next_cursor
    return records


def parse_doaj_articles(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("results", []), start=1):
            bib = item.get("bibjson", {})
            journal = bib.get("journal", {})
            identifiers = bib.get("identifier", []) or []
            doi = ""
            for identifier in identifiers:
                if str(identifier.get("type", "")).lower() == "doi":
                    doi = first_string(identifier.get("id"))
            links = bib.get("link", []) or []
            pdf_url = first_observed_pdf_url(links)
            records.append(
                LiteratureRecord(
                    title=first_string(bib.get("title")),
                    authors=clean_people(bib.get("author", [])),
                    year=parse_year(bib.get("year") or bib.get("month")),
                    journal=first_string(journal.get("title") if isinstance(journal, dict) else journal) or None,
                    doi=doi or None,
                    url=pdf_url or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=first_string(item.get("id")),
                )
            )
    return [record for record in records if record.title]


async def search_doaj(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "1")
    page_number = parse_int(token) or 1
    query = quoted_search_phrase(keyword)
    encoded = urllib.parse.quote(query)
    records: list[LiteratureRecord] = []
    use_path_query = True
    while True:
        params = {"pageSize": page_size, "page": page_number}
        endpoint = f"{url}/{encoded}" if use_path_query else url
        if not use_path_query:
            params["q"] = query
        response = await runtime.request(source, keyword, "GET", endpoint, params=params, record_failure=False)
        if response is None and use_path_query and page_number == 1:
            use_path_query = False
            continue
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            else:
                runtime.skip(source, keyword, "DOAJ request failed")
            return records
        try:
            data = response.json()
            raw_items = data.get("results", [])
            page_records = parse_doaj_articles(data, source, keyword, len(records))
            total = parse_int(data.get("total"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "doaj_schema_error")
            return records
        next_page = page_number + 1
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and page_number * page_size >= total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_page), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        page_number = next_page
    return records


def parse_datacite_dois(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("data", []), start=1):
            attrs = item.get("attributes", {})
            creators = attrs.get("creators", [])
            authors = [first_string(c.get("name") or " ".join([first_string(c.get("givenName")), first_string(c.get("familyName"))])) for c in creators if isinstance(c, dict)]
            publisher = first_string(attrs.get("publisher") or attrs.get("container", {}).get("title"))
            pdf_url = first_observed_pdf_url(
                attrs.get("contentUrl"),
                attrs.get("relatedIdentifiers"),
            )
            records.append(
                LiteratureRecord(
                    title=first_string(attrs.get("titles", [{}])[0].get("title") if attrs.get("titles") else attrs.get("title")),
                    authors=[a for a in authors if a],
                    year=parse_year(attrs.get("publicationYear") or attrs.get("dates")),
                    journal=publisher or None,
                    doi=first_string(attrs.get("doi")),
                    url=pdf_url or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=first_string(item.get("id")),
                )
            )
    return [record for record in records if record.title]


async def search_datacite(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 1000)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "1")
    page_number = parse_int(token) or 1
    records: list[LiteratureRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            params={
                "query": quoted_search_phrase(keyword),
                "page[size]": page_size,
                "page[number]": page_number,
            },
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("data", [])
            page_records = parse_datacite_dois(data, source, keyword, len(records))
            meta = data.get("meta") or {}
            total = parse_int(meta.get("total"))
            next_link = first_string((data.get("links") or {}).get("next"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "datacite_schema_error")
            return records
        next_page = page_number + 1
        exhausted = not raw_items or (not next_link and len(raw_items) < page_size) or (total is not None and page_number * page_size >= total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_page), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        page_number = next_page
    return records


def parse_dblp_hits(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    hits = data.get("result", {}).get("hits", {}).get("hit", [])
    records: list[LiteratureRecord] = []
    for offset, hit in enumerate(hits, start=1):
            info = hit.get("info", {})
            authors = info.get("authors", {}).get("author", [])
            if isinstance(authors, dict):
                authors = [authors]
            records.append(
                LiteratureRecord(
                    title=first_string(info.get("title")),
                    authors=clean_people(authors),
                    year=parse_year(info.get("year")),
                    journal=first_string(info.get("venue")) or None,
                    doi=first_string(info.get("doi")) or None,
                    url=first_observed_pdf_url(
                        info.get("ee"),
                        info.get("url"),
                    )
                    or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=first_string(hit.get("@id") or info.get("key")),
                )
            )
    return [record for record in records if record.title]


async def search_dblp(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 1000)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    offset = parse_int(token) or 0
    records: list[LiteratureRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            params={"q": normalized_search_phrase(keyword), "format": "json", "h": page_size, "f": offset},
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            hits_obj = data.get("result", {}).get("hits", {})
            raw_hits = hits_obj.get("hit", [])
            parsed_records = parse_dblp_hits(data, source, keyword, len(records))
            page_records = [
                record for record in parsed_records
                if keyword_phrase_matches(keyword, record.title)
            ]
            total = parse_int(hits_obj.get("@total"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "dblp_schema_error")
            return records
        next_offset = offset + len(raw_hits)
        exhausted = not raw_hits or len(raw_hits) < page_size or (total is not None and next_offset >= total)
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else str(next_offset),
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=total,
            raw_count=len(raw_hits),
        )
        records.extend(page_records)
        if exhausted:
            break
        if next_offset <= offset:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        offset = next_offset
    return records


def openreview_value(value: Any) -> Any:
    if isinstance(value, dict) and "value" in value:
        return value.get("value")
    return value


def year_from_timestamp_or_value(value: Any) -> int | None:
    numeric = parse_int(value)
    if numeric and numeric > 10_000_000_000:
        try:
            return datetime.fromtimestamp(numeric / 1000, tz=timezone.utc).year
        except (OSError, OverflowError, ValueError):
            pass
    return parse_year(value)


def parse_openreview_notes(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, note in enumerate(data.get("notes", []), start=1):
        content = note.get("content", {}) if isinstance(note.get("content"), dict) else {}
        title = first_string(openreview_value(content.get("title")))
        authors_value = openreview_value(content.get("authors")) or openreview_value(content.get("authorids")) or []
        venue = openreview_value(content.get("venue")) or openreview_value(content.get("venueid")) or note.get("venue")
        direct_doi = openreview_value(content.get("doi")) or openreview_value(content.get("DOI"))
        doi = extract_doi_from_values(direct_doi, json.dumps(content, ensure_ascii=False))
        note_id = first_string(note.get("id") or note.get("forum"))
        observed_pdf_value = first_string(
            openreview_value(content.get("pdf"))
            or openreview_value(content.get("pdf_url"))
        )
        pdf_url = first_observed_pdf_url(
            observed_pdf_value,
            urllib.parse.urljoin("https://openreview.net", observed_pdf_value)
            if observed_pdf_value
            else None,
        )
        records.append(
            LiteratureRecord(
                title=title,
                authors=clean_people(authors_value),
                year=year_from_timestamp_or_value(note.get("pdate") or note.get("odate") or note.get("cdate") or note.get("tcdate")),
                journal=first_string(venue) or "OpenReview",
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=note_id or None,
            )
        )
    return [record for record in records if record.title]


async def search_openreview(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 1000)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    offset = parse_int(token) or 0
    records: list[LiteratureRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            params={"term": quoted_search_phrase(keyword), "limit": page_size, "offset": offset},
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_notes = data.get("notes", [])
            parsed_records = parse_openreview_notes(data, source, keyword, len(records))
            page_records = [
                record for record in parsed_records
                if keyword_phrase_matches(keyword, record.title)
            ]
            total = parse_int(data.get("count") or data.get("total"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "openreview_schema_error")
            return records
        await enrich_missing_dois(runtime, source, keyword, page_records)
        next_offset = offset + len(raw_notes)
        exhausted = not raw_notes or len(raw_notes) < page_size or (total is not None and next_offset >= total)
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else str(next_offset),
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=total,
            raw_count=len(raw_notes),
        )
        records.extend(page_records)
        if exhausted:
            break
        if next_offset <= offset:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        offset = next_offset
    return records


def parse_iacr_eprint(html_text: str, source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text, "html.parser")
    records: list[LiteratureRecord] = []
    seen_ids: set[str] = set()
    for anchor in soup.find_all("a", href=re.compile(r"^/\d{4}/\d+/?$")):
        href = first_string(anchor.get("href"))
        match = re.fullmatch(r"/(\d{4}/\d+)/?", href)
        if not match or match.group(1) in seen_ids:
            continue
        entry_id = match.group(1)
        container = None
        parents = list(anchor.parents)[:8]
        for parent in parents:
            if getattr(parent, "name", "") not in {"div", "li", "article"} or parent.select_one(".papertitle, strong") is None:
                continue
            report_links = parent.find_all("a", href=re.compile(r"^/\d{4}/\d+/?$"))
            if len(report_links) <= 2:
                container = parent
                break
        if container is None:
            for parent in parents:
                sibling = parent.find_next_sibling("div") if hasattr(parent, "find_next_sibling") else None
                if sibling is not None and sibling.select_one(".papertitle, strong") is not None:
                    container = sibling
                    break
        if container is None or container.select_one(".papertitle, strong") is None:
            continue
        title_node = container.select_one(".papertitle, strong")
        authors_node = container.select_one(".summaryauthors, .fst-italic")
        abstract_node = container.select_one(".paper-abstract, .search-abstract")
        title = first_string(title_node.get_text(" ", strip=True) if title_node else "")
        authors_text = first_string(authors_node.get_text(" ", strip=True) if authors_node else "")
        abstract = first_string(abstract_node.get_text(" ", strip=True) if abstract_node else "")
        searchable = f"{title} {authors_text} {abstract}"
        if not keyword_phrase_matches(keyword, searchable):
            continue
        page_url = urllib.parse.urljoin("https://eprint.iacr.org", href)
        observed_links = [
            urllib.parse.urljoin(page_url, first_string(link.get("href")))
            for link in container.find_all("a", href=True)
        ]
        doi = extract_doi_from_values(searchable, *observed_links)
        pdf_url = first_observed_pdf_url(observed_links)
        seen_ids.add(entry_id)
        records.append(
            LiteratureRecord(
                title=title or entry_id,
                authors=clean_people(authors_text.replace(" and ", "; ")),
                year=parse_year(entry_id.split("/", 1)[0]),
                journal="IACR ePrint",
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=page_url,
            )
        )
    return records


def iacr_next_offset(html_text: str) -> int | None:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text, "html.parser")
    for anchor in soup.find_all("a", href=True):
        text = anchor.get_text(" ", strip=True).casefold()
        if text not in {"next", "next >", "next >>", "next »"} and not text.startswith("next"):
            continue
        try:
            query = urllib.parse.parse_qs(urllib.parse.urlsplit(first_string(anchor.get("href"))).query)
        except ValueError:
            continue
        offset = parse_int(first_string(query.get("offset")))
        if offset is not None:
            return offset
    return None


def parse_iacr_rss_records(xml_text: str, source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    from bs4 import BeautifulSoup

    root = ET.fromstring(xml_text)
    records: list[LiteratureRecord] = []
    for item in root.findall(".//item"):
        title = first_string(item.findtext("title", default=""))
        description = first_string(item.findtext("description", default=""))
        if not keyword_phrase_matches(keyword, title, description):
            continue
        link = first_string(item.findtext("link", default=""))
        doi = extract_doi_from_values(title, description, link)
        description_soup = BeautifulSoup(description, "html.parser")
        pdf_url = first_observed_pdf_url(
            [
                urllib.parse.urljoin(link, first_string(anchor.get("href")))
                for anchor in description_soup.select("a[href]")
            ],
            [
                child.get("url")
                for child in list(item)
                if "enclosure" in first_string(child.tag).casefold()
            ],
        )
        records.append(
            LiteratureRecord(
                title=title,
                authors=[],
                year=parse_year(item.findtext("pubDate", default="")),
                journal="IACR ePrint",
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=link,
            )
        )
    return records


def extract_doi_from_landing_html(html_text: str) -> str:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text, "html.parser")
    values: list[Any] = [html_text]
    for meta in soup.select('meta[name*="doi" i], meta[property*="doi" i]'):
        values.append(meta.get("content"))
    for link in soup.select('a[href*="doi.org"], link[href*="doi.org"]'):
        values.append(link.get("href"))
    return extract_doi_from_values(*values)


def extract_pdf_url_from_landing_html(html_text: str, base_url: str) -> str:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    observed_values: list[Any] = []
    for meta in soup.select(
        'meta[name="citation_pdf_url" i], meta[name="pdf_url" i], '
        'meta[property="citation_pdf_url" i], meta[property="pdf_url" i]'
    ):
        observed_values.append(
            urllib.parse.urljoin(base_url, first_string(meta.get("content")))
        )
    for link in soup.select("a[href], link[href]"):
        observed_values.append(
            urllib.parse.urljoin(base_url, first_string(link.get("href")))
        )
    return first_observed_pdf_url(observed_values)


async def search_iacr_rss(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    del limit
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    offset = parse_int(token) or 0
    search_url = "https://eprint.iacr.org/search"
    records: list[LiteratureRecord] = []
    seen_offsets: set[int] = set()
    while offset not in seen_offsets:
        seen_offsets.add(offset)
        params: dict[str, Any] = {"q": keyword}
        if offset:
            params["offset"] = offset
        response = await runtime.request(source, keyword, "GET", search_url, params=params, record_failure=False)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "iacr_search_request_failed_after_partial_results")
                return records
            break
        try:
            page_records = parse_iacr_eprint(response.text, source, keyword, len(records))
            next_offset = iacr_next_offset(response.text)
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "iacr_schema_error")
            return records
        for record in page_records:
            if normalize_doi(record.doi):
                continue
            detail_url = first_string(record.raw_id)
            if not detail_url.startswith(("http://", "https://")):
                continue
            detail = await runtime.request(
                source,
                keyword,
                "GET",
                detail_url,
                record_failure=False,
            )
            if detail is not None:
                record.doi = extract_doi_from_landing_html(detail.text) or None
                if not normalize_doi(record.doi) and not normalize_literature_pdf_url(
                    record.url
                ):
                    record.url = (
                        extract_pdf_url_from_landing_html(
                            detail.text,
                            detail_url,
                        )
                        or None
                    )
        await enrich_missing_dois(runtime, source, keyword, page_records)
        exhausted = next_offset is None
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else str(next_offset),
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=None,
        )
        records.extend(page_records)
        if exhausted:
            return records
        if next_offset in seen_offsets:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            return records
        offset = next_offset

    response = await runtime.request(source, keyword, "GET", url)
    if response is None:
        return records
    try:
        rss_records = parse_iacr_rss_records(response.text, source, keyword, len(records))
    except Exception as exc:
        runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
        runtime.mark_current_run("literature", source, keyword, "failed", "iacr_rss_schema_error")
        return records
    await enrich_missing_dois(runtime, source, keyword, rss_records)
    completed_pages += 1
    persist_search_page(runtime, "literature", source, keyword, rss_records, next_token="", exhausted=False, page_number=completed_pages, reason="rss_archive_is_not_exhaustive")
    runtime.mark_current_run("literature", source, keyword, "incomplete", "rss_archive_is_not_exhaustive")
    return [*records, *rss_records]


async def search_biorxiv_medrxiv(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    # Europe PMC indexes preprints and provides a stable keyword API. ``url``
    # is the executed endpoint from the shared registry, not the nominal
    # bioRxiv provider endpoint.
    return await search_europe_pmc(
        runtime,
        source,
        url,
        keyword,
        limit,
        query_override=f"{quoted_search_phrase(keyword)} AND SRC:PPR",
    )


def parse_chemrxiv_items(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, hit in enumerate(data.get("itemHits", []), start=1):
        item = hit.get("item", {}) if isinstance(hit, dict) else {}
        item_id = first_string(item.get("id") or item.get("legacyId"))
        pdf_url = first_observed_pdf_url(
            item.get("pdfUrl"),
            item.get("downloadUrl"),
            item.get("assets"),
            item.get("files"),
            item.get("vor"),
        )
        records.append(
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("authors")),
                year=parse_year(item.get("publishedDate") or item.get("approvedDate") or item.get("submittedDate")),
                journal="ChemRxiv",
                doi=first_string(item.get("doi")) or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=item_id or None,
            )
        )
    return [record for record in records if record.title]


async def search_chemrxiv(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    page_size = source_page_size(limit, 50)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    skip = parse_int(token) or 0
    records: list[LiteratureRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            params={"term": quoted_search_phrase(keyword), "limit": page_size, "skip": skip},
            record_failure=False,
        )
        if response is None:
            break
        try:
            data = response.json()
        except Exception:
            body = first_string(getattr(response, "text", ""))
            if body_has_verification_challenge(body) or "just a moment" in body.casefold():
                runtime.skip(source, keyword, "security_challenge_required:chemrxiv_public_api")
            break
        raw_hits = data.get("itemHits", [])
        parsed_records = parse_chemrxiv_items(data, source, keyword, len(records))
        page_records = [
            record for record in parsed_records
            if keyword_phrase_matches(keyword, record.title)
        ]
        total = parse_int(data.get("totalCount"))
        next_skip = skip + len(raw_hits)
        exhausted = not raw_hits or len(raw_hits) < page_size or (total is not None and next_skip >= total)
        completed_pages += 1
        persist_search_page(
            runtime,
            "literature",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else str(next_skip),
            exhausted=exhausted,
            page_number=completed_pages,
            total_hint=total,
            raw_count=len(raw_hits),
        )
        records.extend(page_records)
        if exhausted:
            return records
        if next_skip <= skip:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            return records
        skip = next_skip
    runtime.degrade(source, keyword, "ChemRxiv public API unavailable; using OpenAlex enrichment fallback")
    parent_context = SEARCH_TASK_CONTEXT.get()
    fallback_token = SEARCH_TASK_CONTEXT.set(parent_context | {"path": "enrichment"})
    try:
        fallback = await search_openalex(
            runtime,
            source,
            "https://api.openalex.org/works",
            keyword,
            limit,
            query_override=f"{quoted_search_phrase(keyword)} AND chemrxiv",
        )
    finally:
        SEARCH_TASK_CONTEXT.reset(fallback_token)
    for record in fallback:
        record.source = source
        record.keyword = keyword
    if completed_pages:
        runtime.mark_current_run("literature", source, keyword, "incomplete", "chemrxiv_direct_api_interrupted")
    return [*records, *fallback]


def parse_core_works(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return [
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("authors")),
                year=parse_year(item.get("yearPublished") or item.get("publishedDate")),
                journal=first_string(item.get("publisher") or item.get("journals")) or None,
                doi=first_string(item.get("doi")) or None,
                url=first_observed_pdf_url(
                    item.get("downloadUrl"),
                    item.get("sourceFulltextUrls"),
                )
                or None,
                source=source,
                keyword=keyword,
                rank=rank_start + rank,
                raw_id=first_string(item.get("id")),
            )
            for rank, item in enumerate(data.get("results", []), start=1)
            if first_string(item.get("title"))
    ]


async def search_core(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("CORE_API_KEY")
    headers = {"Authorization": f"Bearer {api_key}"} if api_key else None
    if not api_key:
        runtime.degrade(source, keyword, "CORE_API_KEY not configured; CORE source will use anonymous/degraded mode or no-op fallback")
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    offset = parse_int(token) or 0
    records: list[LiteratureRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "POST",
            url,
            headers=headers,
            json={"q": quoted_search_phrase(keyword), "limit": page_size, "offset": offset},
            record_failure=bool(api_key),
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("results", [])
            page_records = parse_core_works(data, source, keyword, len(records))
            total = parse_int(data.get("totalHits") or data.get("total"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "core_schema_error")
            return records
        next_offset = offset + len(raw_items)
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and next_offset >= total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_offset), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_offset <= offset:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        offset = next_offset
    return records


def parse_lens_scholarly(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return [
            LiteratureRecord(
                title=first_string(item.get("title")),
                authors=clean_people(item.get("authors")),
                year=parse_year(item.get("year_published") or item.get("date_published")),
                journal=first_string(item.get("source", {}).get("title") if isinstance(item.get("source"), dict) else item.get("source")) or None,
                doi=first_string(item.get("doi")),
                url=first_observed_pdf_url(
                    item.get("pdf_url"),
                    item.get("full_text_urls"),
                    item.get("url"),
                )
                or None,
                source=source,
                keyword=keyword,
                rank=rank_start + rank,
                raw_id=first_string(item.get("lens_id")),
            )
            for rank, item in enumerate(data.get("data", []), start=1)
            if first_string(item.get("title"))
    ]


async def search_lens_scholarly(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("LENS_Scholarly_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): LENS_Scholarly_API_KEY")
        return []
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "offset:0")
    records: list[LiteratureRecord] = []
    seen_tokens: set[str] = set()
    while token not in seen_tokens:
        seen_tokens.add(token)
        payload: dict[str, Any]
        if token.startswith("scroll:"):
            payload = {"scroll_id": token.removeprefix("scroll:")}
        else:
            offset = parse_int(token.removeprefix("offset:")) or 0
            payload = {
                "query": {
                    "query_string": {
                        "query": quoted_search_phrase(keyword),
                        "fields": ["title", "abstract", "full_text"],
                        "default_operator": "and",
                    }
                },
                "size": page_size,
                "from": offset,
                "include": ["title", "authors", "year_published", "source", "doi", "ids", "external_ids", "lens_id"],
            }
        response = await runtime.request(source, keyword, "POST", url, headers={"Authorization": f"Bearer {api_key}"}, json=payload)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("data", [])
            page_records = parse_lens_scholarly(data, source, keyword, len(records))
            total = parse_int(data.get("total") or (data.get("meta") or {}).get("total"))
            scroll_id = first_string(data.get("scroll_id") or data.get("scrollId"))
            if scroll_id:
                next_token = f"scroll:{scroll_id}"
            else:
                current_offset = parse_int(token.removeprefix("offset:")) or 0
                next_token = f"offset:{current_offset + len(raw_items)}"
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "lens_scholarly_schema_error")
            return records
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and len(records) + len(raw_items) >= total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else next_token, exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_token in seen_tokens:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_cursor")
            break
        token = next_token
    return records


def parse_springerlink(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("records", []), start=1):
            doi = first_string(item.get("doi"))
            records.append(
                LiteratureRecord(
                    title=first_string(item.get("title")),
                    authors=clean_people(item.get("creators")),
                    year=parse_year(item.get("publicationDate")),
                    journal=first_string(item.get("publicationName")) or None,
                    doi=doi or None,
                    url=first_observed_pdf_url(item.get("url")) or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=doi,
                )
            )
    return [record for record in records if record.title]


def parse_springer_alias(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return parse_springerlink(data, source, keyword, rank_start)


async def search_springer(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("SPRINGER_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): SPRINGER_API_KEY")
        return []
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "1")
    start = parse_int(token) or 1
    records: list[LiteratureRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            params={
                "q": quoted_search_phrase(keyword),
                "p": page_size,
                "s": start,
                "api_key": api_key,
            },
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("records", [])
            parser = parse_springer_alias if source == "Springer" else parse_springerlink
            page_records = parser(data, source, keyword, len(records))
            result_meta = data.get("result") or []
            total = parse_int(result_meta[0].get("total")) if result_meta and isinstance(result_meta[0], dict) else None
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "springer_schema_error")
            return records
        next_start = start + len(raw_items)
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and next_start > total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_start), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_start <= start:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        start = next_start
    return records


def elsevier_sciencedirect_pdf_url(item: dict[str, Any]) -> str:
    return first_observed_pdf_url(
        item.get("pdf_url"),
        item.get("link"),
        item.get("prism:url"),
    )


def parse_elsevier_sciencedirect_v2(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    entries = data.get("search-results", {}).get("entry", [])
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(entries, start=1):
        identifier = first_string(item.get("prism:doi") or item.get("dc:identifier"))
        doi = extract_doi_from_values(identifier, item.get("prism:url"), item.get("link"))
        authors = clean_people((item.get("authors") or {}).get("author") if isinstance(item.get("authors"), dict) else item.get("dc:creator"))
        records.append(
            LiteratureRecord(
                title=first_string(item.get("dc:title")),
                authors=authors,
                year=parse_year(item.get("prism:coverDate") or item.get("prism:coverDisplayDate")),
                journal=first_string(item.get("prism:publicationName")) or None,
                doi=doi or None,
                url=elsevier_sciencedirect_pdf_url(item) or None,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=first_string(item.get("eid") or item.get("pii") or item.get("dc:identifier")),
            )
        )
    return [record for record in records if record.title]


async def search_elsevier(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("ELSEVIER_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): ELSEVIER_API_KEY")
        return []
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "0")
    start = parse_int(token) or 0
    headers = {"X-ELS-APIKey": api_key, "Accept": "application/json"}
    if env_value("ELSEVIER_INSTTOKEN"):
        headers["X-ELS-Insttoken"] = env_value("ELSEVIER_INSTTOKEN")
    records: list[LiteratureRecord] = []
    while True:
        if start >= 6000:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "source_result_window_cap:6000")
            break
        params = {
            "query": quoted_search_phrase(keyword),
            "count": page_size,
            "start": start,
            "view": "STANDARD",
            "suppressNavLinks": "false",
        }
        response = await runtime.request(source, keyword, "PUT", url, headers=headers, params=params, record_failure=False)
        if response is None:
            response = await runtime.request(source, keyword, "GET", url, headers=headers, params=params)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            search_results = data.get("search-results", {})
            raw_entries = search_results.get("entry", [])
            page_records = parse_elsevier_sciencedirect_v2(data, source, keyword, len(records))
            total = parse_int(search_results.get("opensearch:totalResults"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "sciencedirect_v2_schema_error")
            return records
        next_start = start + len(raw_entries)
        source_capped = total is not None and total > 6000 and next_start >= 6000
        exhausted = not raw_entries or len(raw_entries) < page_size or (total is not None and next_start >= total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_start), exhausted=exhausted, page_number=completed_pages, total_hint=total, reason="source_result_window_cap:6000" if source_capped else "")
        records.extend(page_records)
        if source_capped:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "source_result_window_cap:6000")
            break
        if exhausted:
            break
        if next_start <= start:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        start = next_start
    return records


def parse_ieee_xplore(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("articles", []), start=1):
            records.append(
                LiteratureRecord(
                    title=first_string(item.get("title")),
                    authors=clean_people(item.get("authors", {}).get("authors") if isinstance(item.get("authors"), dict) else item.get("authors")),
                    year=parse_year(item.get("publication_year")),
                    journal=first_string(item.get("publication_title")) or None,
                    doi=first_string(item.get("doi")) or None,
                    url=first_observed_pdf_url(item.get("pdf_url")) or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=first_string(item.get("article_number")),
                )
            )
    return [record for record in records if record.title]


def provider_error_evidence(response: Any) -> tuple[str, str]:
    if response is None:
        return "", ""
    try:
        payload = response.json()
    except Exception:
        return "", ""
    values: list[str] = []
    codes: list[str] = []

    def visit(value: Any, depth: int = 0) -> None:
        if depth > 4 or len(values) >= 30:
            return
        if isinstance(value, dict):
            for key, child in value.items():
                normalized_key = first_string(key).casefold()
                if normalized_key in {
                    "code",
                    "errorcode",
                    "error_code",
                    "status",
                    "type",
                }:
                    code = first_string(child)
                    if code:
                        codes.append(code[:120])
                if any(
                    marker in normalized_key
                    for marker in ("error", "message", "reason", "detail", "description")
                ):
                    text = first_string(child)
                    if text:
                        values.append(text[:500])
                visit(child, depth + 1)
        elif isinstance(value, list):
            for child in value[:20]:
                visit(child, depth + 1)

    visit(payload)
    return " ".join(values).casefold(), first_string(codes)


def classify_provider_http_attempt(attempt: HttpAttemptResult) -> tuple[str, str]:
    evidence, error_code = provider_error_evidence(attempt.response)
    status_code = attempt.status_code
    invalid_key_markers = (
        "invalid api key",
        "invalid key",
        "api key is invalid",
        "authentication failed",
        "not authenticated",
        "key not found",
    )
    subscription_markers = (
        "subscription",
        "not entitled",
        "entitlement",
        "not licensed",
        "product not enabled",
        "service not subscribed",
    )
    quota_markers = (
        "quota exceeded",
        "daily quota",
        "monthly quota",
        "request limit exceeded",
        "maximum number of requests",
        "usage limit exceeded",
    )
    if status_code == 401 or any(marker in evidence for marker in invalid_key_markers):
        return "api_key_invalid", error_code
    if any(marker in evidence for marker in subscription_markers):
        return "subscription_required", error_code
    if any(marker in evidence for marker in quota_markers):
        return "quota_exhausted", error_code
    if status_code == 429:
        return "rate_limited", error_code
    if status_code in {408, 425, 500, 502, 503, 504}:
        return f"http_{status_code}", error_code
    if status_code == 403:
        return "forbidden_unknown", error_code
    if 200 <= status_code < 300 and (evidence or error_code):
        return "schema_error", error_code
    if status_code >= 400:
        return "forbidden_unknown", error_code
    return "", error_code


def provider_failure_status(category: str) -> str:
    if category in {"api_key_invalid", "subscription_required"}:
        return "blocked"
    if category in {
        "quota_exhausted",
        "rate_limited",
        "forbidden_unknown",
        "http_408",
        "http_425",
        "http_500",
        "http_502",
        "http_503",
        "http_504",
    }:
        return "incomplete"
    return "failed"


async def search_ieee(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("IEEE_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): IEEE_API_KEY")
        return []
    page_size = source_page_size(limit, 200)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "1")
    start_record = parse_int(token) or 1
    records: list[LiteratureRecord] = []
    while True:
        attempt = await runtime.request_result(
            source,
            keyword,
            "GET",
            url,
            params={
                "querytext": quoted_search_phrase(keyword),
                "max_records": page_size,
                "start_record": start_record,
                "apikey": api_key,
                "format": "json",
            },
            record_failure=False,
        )
        if not attempt.ok:
            category, error_code = classify_provider_http_attempt(attempt)
            reason = category or attempt.reason or "ieee_api_request_failed"
            if error_code:
                reason = f"{reason}:error_code={safe_error_text(error_code)}"
            runtime.skip(source, keyword, reason)
            runtime.mark_current_run(
                "literature",
                source,
                keyword,
                provider_failure_status(category),
                reason,
            )
            if completed_pages:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    f"{reason}:after_partial_results",
                )
            return records
        try:
            data = attempt.response.json()
            payload_category, error_code = classify_provider_http_attempt(attempt)
            if payload_category:
                reason = payload_category
                if error_code:
                    reason = f"{reason}:error_code={safe_error_text(error_code)}"
                runtime.skip(source, keyword, reason)
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    provider_failure_status(payload_category),
                    reason,
                )
                return records
            raw_items = data.get("articles", [])
            page_records = parse_ieee_xplore(data, source, keyword, len(records))
            total = parse_int(data.get("total_records"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "ieee_schema_error")
            return records
        next_start = start_record + len(raw_items)
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and next_start > total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_start), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_start <= start_record:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_offset")
            break
        start_record = next_start
    return records


def parse_wos_starter(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(data.get("hits", []), start=1):
            names = item.get("names", {}).get("authors", []) if isinstance(item.get("names"), dict) else []
            records.append(
                LiteratureRecord(
                    title=first_string(item.get("title")),
                    authors=clean_people(names),
                    year=parse_year(item.get("source", {}).get("publishYear") if isinstance(item.get("source"), dict) else None),
                    journal=first_string(item.get("source", {}).get("sourceTitle") if isinstance(item.get("source"), dict) else None) or None,
                    doi=first_string(item.get("identifiers", {}).get("doi") if isinstance(item.get("identifiers"), dict) else None),
                    url=first_observed_pdf_url(item.get("links")) or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=first_string(item.get("uid")),
                )
            )
    return [record for record in records if record.title]


async def search_wos_starter(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("CLARIVATE_API_KEY", "WOS_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): CLARIVATE_API_KEY")
        return []
    page_size = source_page_size(limit, 50)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "1")
    page_number = parse_int(token) or 1
    records: list[LiteratureRecord] = []
    while True:
        attempt = await runtime.request_result(
            source,
            keyword,
            "GET",
            url,
            headers={"X-ApiKey": api_key},
            params={
                "q": f"TS={quoted_search_phrase(keyword)}",
                "limit": page_size,
                "page": page_number,
            },
            record_failure=False,
        )
        if not attempt.ok:
            category, error_code = classify_provider_http_attempt(attempt)
            reason = category or attempt.reason or "wos_api_request_failed"
            if error_code:
                reason = f"{reason}:error_code={safe_error_text(error_code)}"
            runtime.skip(source, keyword, reason)
            runtime.mark_current_run(
                "literature",
                source,
                keyword,
                provider_failure_status(category),
                reason,
            )
            if completed_pages:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    f"{reason}:after_partial_results",
                )
            return records
        try:
            data = attempt.response.json()
            payload_category, error_code = classify_provider_http_attempt(attempt)
            if payload_category:
                reason = payload_category
                if error_code:
                    reason = f"{reason}:error_code={safe_error_text(error_code)}"
                runtime.skip(source, keyword, reason)
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    provider_failure_status(payload_category),
                    reason,
                )
                return records
            raw_hits = data.get("hits", [])
            page_records = parse_wos_starter(data, source, keyword, len(records))
            metadata = data.get("metadata") or {}
            total = parse_int(metadata.get("total") or data.get("total"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "wos_schema_error")
            return records
        next_page = page_number + 1
        exhausted = not raw_hits or len(raw_hits) < page_size or (total is not None and page_number * page_size >= total)
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else str(next_page), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        page_number = next_page
    return records


def openaire_items(data: dict[str, Any]) -> list[dict[str, Any]]:
    items = data.get("results") or data.get("response", {}).get("results", []) or []
    return [item for item in items if isinstance(item, dict)]


def openaire_doi(item: dict[str, Any]) -> str:
    for pid in item.get("pids") or []:
        if not isinstance(pid, dict):
            continue
        scheme = first_string(pid.get("scheme") or pid.get("type")).casefold()
        value = first_string(pid.get("value") or pid.get("pid") or pid.get("id"))
        if "doi" in scheme:
            doi = clean_extracted_doi(value)
            if doi:
                return doi
        doi = extract_doi_from_values(value)
        if doi:
            return doi
    return extract_doi_from_values(*(item.get("originalIds") or []), json.dumps(item.get("instances") or [], ensure_ascii=False))


def openaire_pdf_url(item: dict[str, Any]) -> str:
    return first_observed_pdf_url(
        item.get("instances"),
        item.get("pdf_url"),
        item.get("url"),
    )


def parse_openaire_products(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records: list[LiteratureRecord] = []
    for offset, item in enumerate(openaire_items(data), start=1):
            container = item.get("container") if isinstance(item.get("container"), dict) else {}
            records.append(
                LiteratureRecord(
                    title=first_string(item.get("mainTitle") or item.get("title")),
                    authors=clean_people(item.get("authors") or item.get("creator")),
                    year=parse_year(item.get("publicationDate") or item.get("dateofacceptance")),
                    journal=first_string(container.get("name") or container.get("title") or item.get("publisher") or item.get("journal")) or None,
                    doi=openaire_doi(item) or first_string(item.get("doi")) or None,
                    url=openaire_pdf_url(item) or None,
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=first_string(item.get("id")),
                )
            )
    return [record for record in records if record.title]


async def search_openaire(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    api_key = env_value("OPENAIRE_API_KEY")
    headers = {"Authorization": f"Bearer {api_key}"} if api_key else None
    if not api_key:
        runtime.degrade(source, keyword, "OPENAIRE_API_KEY not configured; trying public OpenAIRE access")
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "literature", source, keyword, "*")
    cursor = token or "*"
    records: list[LiteratureRecord] = []
    seen_cursors: set[str] = set()
    while cursor and cursor not in seen_cursors:
        seen_cursors.add(cursor)
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            headers=(headers or {}) | {"Accept": "application/json"},
            params={
                "search": quoted_search_phrase(keyword),
                "cursor": cursor,
                "pageSize": page_size,
            },
            record_failure=True,
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = openaire_items(data)
            page_records = parse_openaire_products(data, source, keyword, len(records))
            header = data.get("header") or data.get("response", {}).get("header", {}) or {}
            total = parse_int(header.get("numFound") or header.get("total") or header.get("totalResults") or data.get("total"))
            next_cursor = first_string(header.get("nextCursor") or header.get("next_cursor"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("literature", source, keyword, "failed", "openaire_schema_error")
            return records
        exhausted = not raw_items or not next_cursor
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else next_cursor, exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_cursor in seen_cursors:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_cursor")
            break
        cursor = next_cursor
    return records


def build_web_search_url(source: str, policy: SourceAccessPolicy, keyword: str, limit: int) -> str:
    del limit
    query = quoted_search_phrase(keyword)
    if source == "Web of Science Starter API (Clarivate)":
        return "https://www.webofscience.com/wos/woscc/basic-search"
    if source == "Elsevier":
        return "https://www.sciencedirect.com/search?qs=" + urllib.parse.quote(query)
    if source == "IEEE Xplore API":
        return "https://ieeexplore.ieee.org/search/searchresult.jsp?queryText=" + urllib.parse.quote(query)
    if source in {"SpringerLink", "Springer"}:
        return "https://link.springer.com/search?query=" + urllib.parse.quote(query)
    if source == "Nature":
        return "https://www.nature.com/search?q=" + urllib.parse.quote(query)
    if source == "ACS Publications":
        return "https://pubs.acs.org/action/doSearch?AllField=" + urllib.parse.quote(query)
    if source == "RSC Publishing":
        return "https://pubs.rsc.org/search-results?q=" + urllib.parse.quote(query)
    if source == "ACM metadata":
        return "https://dl.acm.org/action/doSearch?AllField=" + urllib.parse.quote(query)
    if source == "Crossref Metadata Search (search.crossref.org)":
        return "https://search.crossref.org/search/works?" + urllib.parse.urlencode({"q": query, "from_ui": "yes"})
    if source == "USENIX":
        encoded_keyword = urllib.parse.quote(keyword, safe="")
        return f"https://www.usenix.org/search/site/{encoded_keyword}?" + urllib.parse.urlencode({"search": query})
    if source == CNKI_SOURCE:
        return CNKI_PATENT_HOME if current_search_record_type() == "patent" else CNKI_HOME
    if source == WANFANG_SOURCE:
        return (
            WANFANG_PATENT_HOME
            if current_search_record_type() == "patent"
            else WANFANG_HOME
        )
    base = policy.web_search_url or literature_search_path_map.get(source, "")
    if not base:
        return ""
    separator = "&" if "?" in base else "?"
    return f"{base}{separator}{urllib.parse.urlencode({policy.web_query_param: query})}"


def normalized_search_query(value: Any) -> str:
    return re.sub(r"\s+", " ", first_string(value).strip().strip('"')).casefold()


def acs_search_query_matches(value: Any, keyword: str) -> bool:
    normalized_value = normalized_search_query(value)
    return bool(
        normalized_value
        and normalized_value == normalized_search_query(keyword)
    )


def acs_url_has_search_query(page: Any, keyword: str) -> bool:
    try:
        query_items = urllib.parse.parse_qs(
            urllib.parse.urlsplit(first_string(page.url)).query,
            keep_blank_values=True,
        )
    except Exception:
        query_items = {}
    for key, values in query_items.items():
        if key.casefold() == "allfield" and any(
            acs_search_query_matches(value, keyword) for value in values
        ):
            return True
    return False


async def acs_page_has_search_query(page: Any, keyword: str) -> bool:
    if acs_url_has_search_query(page, keyword):
        return True
    for selector in ACS_SEARCH_INPUT_SELECTORS:
        try:
            locators = page.locator(selector)
            for index in range(min(await locators.count(), 8)):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=500):
                    continue
                if acs_search_query_matches(
                    await locator.input_value(timeout=1000),
                    keyword,
                ):
                    return True
        except Exception:
            continue
    return False


async def acs_page_has_visible_results(page: Any) -> bool:
    try:
        locators = page.locator(
            WEB_SOURCE_DYNAMIC_READY_SELECTORS["ACS Publications"]
        )
        for index in range(min(await locators.count(), 40)):
            if await locators.nth(index).is_visible(timeout=300):
                return True
    except Exception:
        pass
    return False


async def submit_acs_browser_search(page: Any, keyword: str) -> bool:
    try:
        await page.wait_for_selector(
            ", ".join(ACS_SEARCH_INPUT_SELECTORS),
            state="visible",
            timeout=min(
                60,
                env_seconds("LAPS_ACS_SEARCH_SURFACE_TIMEOUT_SECONDS", 20, 1),
            )
            * 1000,
        )
    except Exception:
        pass
    query = quoted_search_phrase(keyword)
    for selector in ACS_SEARCH_INPUT_SELECTORS:
        try:
            locators = page.locator(selector)
            for index in range(min(await locators.count(), 8)):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=500):
                    continue
                if not acs_search_query_matches(
                    await locator.input_value(timeout=1000),
                    keyword,
                ):
                    await locator.fill(query, timeout=2000)
                await locator.press("Enter", timeout=2000)
                try:
                    await page.wait_for_load_state("domcontentloaded", timeout=10000)
                except Exception:
                    pass
                await page.wait_for_timeout(1000)
                return True
        except Exception:
            continue
    return False


async def classify_acs_search_readiness(
    page: Any,
    body: str = "",
) -> tuple[str, str]:
    current_body = body or await page_body_text(page)
    if body_has_verification_challenge(current_body):
        return "challenge", current_body
    if await acs_page_has_visible_results(page):
        return "records", current_body
    if browser_profile_has_explicit_no_results(
        "ACS Publications",
        current_body,
    ):
        return "explicit_no_results", current_body
    return "pending", current_body


async def wait_for_acs_search_readiness(page: Any) -> tuple[str, str]:
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_ACS_RESULTS_READY_TIMEOUT_SECONDS", 30, 1),
    )
    while True:
        readiness, body = await classify_acs_search_readiness(page)
        if readiness != "pending" or time.monotonic() >= deadline:
            return readiness, body
        try:
            await page.wait_for_timeout(500)
        except Exception:
            return "pending", body


