def parse_usenix_search(html_text: str, base_url: str, source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    records = parse_source_web_html(html_text, base_url, source, keyword, WEB_SOURCE_PARSER_PROFILES[source], rank_start)
    publication_path_markers = ("/presentation/", "/paper/", "/papers/", "/technical-sessions/")
    return [
        record
        for record in records
        if any(
            marker
            in urllib.parse.urlsplit(first_string(record.raw_id)).path.casefold()
            for marker in publication_path_markers
        )
    ]


def parse_cnki_search(
    html_text: str,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> list[LiteratureRecord]:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    profile = WEB_SOURCE_PARSER_PROFILES[source]
    cards: list[Any] = []
    seen_nodes: set[int] = set()
    for selector in profile.cards:
        for node in soup.select(selector):
            node_id = id(node)
            if node_id not in seen_nodes:
                seen_nodes.add(node_id)
                cards.append(node)

    records: list[LiteratureRecord] = []
    seen_details: set[str] = set()
    for card in cards:
        title_node = next(
            (
                candidate
                for selector in profile.titles
                if (candidate := card.select_one(selector)) is not None
            ),
            None,
        )
        if title_node is None:
            continue
        title = first_string(title_node.get_text(" ", strip=True))
        detail_href = first_string(title_node.get("href"))
        detail_url = urllib.parse.urljoin(base_url, detail_href) if detail_href else ""
        if len(title) < 2 or (detail_url and detail_url in seen_details):
            continue

        card_text = first_string(card.get_text(" ", strip=True))
        metadata_text = " ".join(
            first_string(node.get_text(" ", strip=True))
            for selector in profile.metadata
            for node in card.select(selector)
        )
        observed_links = [
            urllib.parse.urljoin(base_url, first_string(link.get("href")))
            for link in card.select("a[href]")
        ]
        observed_pdf_values: list[str] = []
        for node in card.select("a[href], [data-pdf-url], [data-download-url]"):
            label = first_string(node.get_text(" ", strip=True)).casefold()
            candidate = first_string(
                node.get("data-pdf-url")
                or node.get("data-download-url")
                or node.get("href")
            )
            if candidate and ("pdf" in label or "下载" in label or "pdf" in candidate.casefold()):
                observed_pdf_values.append(urllib.parse.urljoin(base_url, candidate))

        doi = extract_doi_from_values(
            card_text,
            metadata_text,
            *observed_links,
        )
        pdf_url = "" if doi else first_observed_pdf_url(observed_pdf_values)
        author_text = first_string(
            " ".join(node.get_text(" ", strip=True) for node in card.select(".author, .authors, td.author"))
        )
        journal_text = first_string(
            " ".join(node.get_text(" ", strip=True) for node in card.select(".source, .journal, td.source"))
        )
        raw_id = detail_url or first_string(card.get("data-id") or card.get("data-key"))
        records.append(
            LiteratureRecord(
                title=title,
                authors=clean_people(author_text),
                year=parse_year(metadata_text or card_text),
                journal=journal_text or None,
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=raw_id or None,
            )
        )
        if detail_url:
            seen_details.add(detail_url)
    return records


def extract_cnki_patent_database_scope(
    html_text: str,
) -> tuple[str, tuple[str, ...]]:
    """Return only the patent resource/database scope observed in the page."""
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    resource_node = soup.select_one("#resource, input[name='resource']")
    dbcode_node = soup.select_one("#dbcode, input[name='dbcode']")
    resource = first_string(
        resource_node.get("value") if resource_node is not None else ""
    ).upper()
    database_codes: list[str] = []

    def append_codes(value: Any) -> None:
        for candidate in re.split(r"[,;\s]+", first_string(value)):
            normalized = candidate.strip().upper()
            if normalized and normalized not in database_codes:
                database_codes.append(normalized)

    append_codes(dbcode_node.get("value") if dbcode_node is not None else "")
    scope_nodes = soup.select(
        "li.cur a[name='classify'][resource], "
        "a[name='classify'][resource='PATENT' i]"
    )
    for node in scope_nodes:
        observed_resource = first_string(node.get("resource")).upper()
        if observed_resource != "PATENT":
            continue
        if not resource:
            resource = observed_resource
        for attribute in ("data-chs", "data-en", "dbcode", "data-dbcode"):
            append_codes(node.get(attribute))
    return resource, tuple(database_codes)


def cnki_patent_detail_url(base_url: str, href: str | None) -> str:
    """Accept a CNKI patent detail URL only when the page actually exposed it."""
    value = first_string(href)
    if not value or value.casefold().startswith(("javascript:", "#")):
        return ""
    candidate = urllib.parse.urljoin(base_url, value)
    try:
        parsed = urllib.parse.urlsplit(candidate)
    except ValueError:
        return ""
    host = (parsed.hostname or "").casefold()
    path = parsed.path.casefold().rstrip("/")
    if (
        parsed.scheme != "https"
        or not (host == "cnki.net" or host.endswith(".cnki.net"))
        or path != "/kcms2/article/abstract"
    ):
        return ""
    return urllib.parse.urlunsplit(
        (parsed.scheme, parsed.netloc, parsed.path, parsed.query, "")
    )


def explicit_cnki_patent_publication_number(card: Any) -> str:
    for attribute in (
        "data-publication-number",
        "data-publication-no",
        "data-pub-number",
        "data-pubno",
    ):
        value = first_string(card.get(attribute))
        if value:
            return value
        node = card.select_one(f"[{attribute}]")
        value = first_string(node.get(attribute) if node is not None else "")
        if value:
            return value
    text = first_string(card.get_text(" ", strip=True))
    match = re.search(
        r"(?:申请公布号|公开[（(]?公告[）)]?号|公开号|publication\s+number)"
        r"\s*[:：]?\s*([A-Z]{2}\s*[A-Z0-9][A-Z0-9.\-/]{4,})",
        text,
        re.IGNORECASE,
    )
    return re.sub(r"\s+", "", match.group(1)).upper() if match else ""


def cnki_patent_observed_dates(card: Any) -> tuple[str, str]:
    """Return observed application/publication dates without inferring missing values."""
    application_date = ""
    publication_date = ""
    unlabeled_dates: list[str] = []
    date_pattern = re.compile(
        r"(?:19|20)\d{2}(?:[-/.年]\d{1,2})?(?:[-/.月]\d{1,2}日?)?"
    )
    for node in card.select("td.date, .date"):
        text = first_string(node.get_text(" ", strip=True))
        match = date_pattern.search(text)
        if not match:
            continue
        observed = (
            match.group(0)
            .replace("年", "-")
            .replace("月", "-")
            .replace("日", "")
            .replace("/", "-")
            .replace(".", "-")
            .rstrip("-")
        )
        lowered = text.casefold()
        if any(marker in lowered for marker in ("申请日", "申请日期", "filing date", "application date")):
            application_date = application_date or observed
        elif any(
            marker in lowered
            for marker in (
                "公开日",
                "公告日",
                "公开日期",
                "发表时间",
                "publication date",
            )
        ):
            publication_date = publication_date or observed
        else:
            unlabeled_dates.append(observed)

    # The CNKI patent result table exposes application date before publication
    # date when the cells are unlabeled. A single date is the displayed
    # publication date; no missing date is synthesized from it.
    if len(unlabeled_dates) >= 2:
        application_date = application_date or unlabeled_dates[0]
        publication_date = publication_date or unlabeled_dates[1]
    elif len(unlabeled_dates) == 1:
        publication_date = publication_date or unlabeled_dates[0]
    return application_date, publication_date


def parse_cnki_patent_search(
    html_text: str,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> list[PatentRecord]:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    profile = PATENT_WEB_SOURCE_PARSER_PROFILES[source]
    cards: list[Any] = []
    seen_nodes: set[int] = set()
    for selector in profile.cards:
        for node in soup.select(selector):
            node_id = id(node)
            if node_id not in seen_nodes:
                seen_nodes.add(node_id)
                cards.append(node)

    records: list[PatentRecord] = []
    seen_urls: set[str] = set()
    for card in cards:
        title_node = next(
            (
                candidate
                for selector in profile.titles
                if (candidate := card.select_one(selector)) is not None
            ),
            None,
        )
        if title_node is None:
            continue
        detail_url = cnki_patent_detail_url(base_url, title_node.get("href"))
        title = first_string(title_node.get_text(" ", strip=True))
        publication_number = explicit_cnki_patent_publication_number(card)
        if (
            (not detail_url and not normalize_publication_number(publication_number))
            or (detail_url and detail_url in seen_urls)
            or len(title) < 2
        ):
            continue

        inventor_node = card.select_one("td.inventor, .inventor")
        inventor_values = (
            [
                first_string(node.get_text(" ", strip=True)).rstrip(";")
                for node in inventor_node.select("a")
                if first_string(node.get_text(" ", strip=True)).rstrip(";")
            ]
            if inventor_node is not None
            else []
        )
        authors = clean_people(
            inventor_values
            or first_string(
                inventor_node.get_text(";", strip=True)
                if inventor_node is not None
                else ""
            )
        )
        applicant_node = card.select_one("td.applicant, .applicant")
        applicants = clean_people(
            [
                first_string(node.get_text(" ", strip=True)).rstrip(";")
                for node in applicant_node.select("a")
                if first_string(node.get_text(" ", strip=True)).rstrip(";")
            ]
            if applicant_node is not None and applicant_node.select("a")
            else first_string(
                applicant_node.get_text(";", strip=True)
                if applicant_node is not None
                else ""
            )
        )
        database_node = card.select_one("td.data, .data")
        database = first_string(
            database_node.get_text(" ", strip=True)
            if database_node is not None
            else ""
        )
        application_date, publication_date = cnki_patent_observed_dates(card)
        year = parse_year(publication_date) or parse_year(application_date)
        if detail_url:
            seen_urls.add(detail_url)
        records.append(
            PatentRecord(
                patent_name=title,
                authors=authors,
                year=year,
                url=detail_url,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=publication_number or detail_url,
                publication_number=publication_number or None,
                applicants=applicants,
                database=database or None,
                application_date=application_date or None,
                publication_date=publication_date or None,
            )
        )
    return records


def cnki_patent_candidate_count(html_text: str) -> int:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    return len(soup.select("table.result-table-list tbody tr td.name a"))


def cnki_patent_verification_resume_url(value: Any) -> str:
    current_url = first_string(value)
    if not current_url or browser_internal_navigation_error_url(current_url):
        return CNKI_PATENT_HOME
    return current_url


WANFANG_EXCLUDED_RESOURCE_MARKERS = ("专利", "标准", "法规")
WANFANG_TRANSIENT_PDF_QUERY_KEYS = frozenset(
    {
        "access_token",
        "auth",
        "authorization",
        "expires",
        "expiry",
        "signature",
        "signed",
        "timestamp",
        "token",
        "ticket",
    }
)


def wanfang_resource_type_from_url(value: Any) -> str:
    path = urllib.parse.urlsplit(first_string(value)).path.casefold()
    for resource_key, resource_label, _ in WANFANG_RESOURCE_PATHS:
        if f"/{resource_key}" in path:
            return resource_label
    return ""


def normalize_wanfang_pdf_url(value: Any, base_url: str = "") -> str:
    observed = urllib.parse.urljoin(base_url, first_string(value))
    normalized = normalize_literature_pdf_url(observed)
    if not normalized:
        try:
            parsed_observed = urllib.parse.urlsplit(observed)
        except ValueError:
            return ""
        observed_host = (parsed_observed.hostname or "").casefold()
        observed_path = parsed_observed.path or ""
        stable_oss_download = (
            parsed_observed.scheme.casefold() in {"http", "https"}
            and observed_host == "oss.wanfangdata.com.cn"
            and observed_path.casefold().startswith("/file/download/")
            and observed_path.casefold().endswith(".aspx")
        )
        download_parts = [part for part in observed_path.split("/") if part]
        stable_fulltext_download = (
            parsed_observed.scheme.casefold() in {"http", "https"}
            and observed_host == "f.wanfangdata.com.cn"
            and len(download_parts) == 4
            and [part.casefold() for part in download_parts[:2]]
            == ["download", "pc"]
            and download_parts[2].casefold()
            in {key for key, _, _ in WANFANG_RESOURCE_PATHS}
            and bool(re.fullmatch(r"[A-Za-z0-9._-]+", download_parts[3]))
            and not parsed_observed.query
        )
        if not stable_oss_download and not stable_fulltext_download:
            return ""
        normalized = urllib.parse.urlunsplit(
            (
                parsed_observed.scheme.casefold(),
                parsed_observed.netloc.casefold(),
                parsed_observed.path,
                parsed_observed.query,
                "",
            )
        )
    query_keys = {
        key.casefold()
        for key, _ in urllib.parse.parse_qsl(
            urllib.parse.urlsplit(normalized).query,
            keep_blank_values=True,
        )
    }
    if query_keys & WANFANG_TRANSIENT_PDF_QUERY_KEYS:
        return ""
    return normalized


def first_observed_wanfang_pdf_url(
    values: Iterable[Any],
    base_url: str,
) -> str:
    for value in values:
        candidate = normalize_wanfang_pdf_url(value, base_url)
        if candidate:
            return candidate
    return ""


def normalize_wanfang_title_text(value: Any) -> str:
    return re.sub(r"\s+", " ", first_string(value)).strip()


def parse_wanfang_search(
    html_text: str,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> list[LiteratureRecord]:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    profile = WEB_SOURCE_PARSER_PROFILES[source]
    resource_type = wanfang_resource_type_from_url(base_url)
    cards: list[Any] = []
    seen_nodes: set[int] = set()
    for selector in profile.cards:
        for node in soup.select(selector):
            node_id = id(node)
            if node_id not in seen_nodes:
                seen_nodes.add(node_id)
                cards.append(node)

    records: list[LiteratureRecord] = []
    seen_details: set[str] = set()
    for card in cards:
        title_node = next(
            (
                candidate
                for selector in profile.titles
                if (candidate := card.select_one(selector)) is not None
            ),
            None,
        )
        if title_node is None:
            continue
        title = normalize_wanfang_title_text(
            title_node.get_text("", strip=False)
        )
        detail_href = first_string(title_node.get("href"))
        detail_url = urllib.parse.urljoin(base_url, detail_href) if detail_href else ""
        if len(title) < 2 or (detail_url and detail_url in seen_details):
            continue

        card_text = first_string(card.get_text(" ", strip=True))
        card_resource_type = first_string(
            card.get("data-resource-type")
            or card.get("data-type")
        )
        if any(marker in card_resource_type for marker in WANFANG_EXCLUDED_RESOURCE_MARKERS):
            continue
        observed_resource_type = card_resource_type or resource_type
        metadata_text = " ".join(
            first_string(node.get_text(" ", strip=True))
            for selector in profile.metadata
            for node in card.select(selector)
        )
        observed_links = [
            urllib.parse.urljoin(base_url, first_string(link.get("href")))
            for link in card.select("a[href], link[href]")
        ]
        doi = extract_doi_from_values(card_text, metadata_text, *observed_links)

        pdf_values: list[str] = []
        if not doi:
            for node in card.select(
                "a[href], link[href], [data-pdf-url], [data-download-url], "
                "[data-fulltext-url], [data-fulltextpath]"
            ):
                label = first_string(node.get_text(" ", strip=True)).casefold()
                candidate = first_string(
                    node.get("data-pdf-url")
                    or node.get("data-download-url")
                    or node.get("data-fulltext-url")
                    or node.get("data-fulltextpath")
                    or node.get("href")
                )
                if candidate and (
                    "pdf" in label
                    or "全文" in label
                    or "下载" in label
                    or normalize_wanfang_pdf_url(candidate, base_url)
                ):
                    pdf_values.append(candidate)
        pdf_url = first_observed_wanfang_pdf_url(pdf_values, base_url) if not doi else ""

        author_text = first_string(
            " ".join(
                dict.fromkeys(
                    first_string(node.get_text(" ", strip=True))
                    for node in card.select(
                        ".author, .authors, .creator, [class*='author' i], "
                        "[data-field='author'], td.author"
                    )
                    if first_string(node.get_text(" ", strip=True))
                )
            )
        )
        container_text = first_string(
            " ".join(
                dict.fromkeys(
                    first_string(node.get_text(" ", strip=True))
                    for node in card.select(
                        ".source, .journal, .degree, .organization, "
                        ".periodical-title, .thesis-title, .conference-title, "
                        ".nstr-title, "
                        "[class*='source' i], [data-field='source'], td.source"
                    )
                    if first_string(node.get_text(" ", strip=True))
                )
            )
        )
        journal = container_text or observed_resource_type
        observed_raw_id_match = re.search(
            r"\b(?:periodical|thesis|conference|nstr)_[A-Za-z0-9][A-Za-z0-9._-]*\b",
            card_text,
            flags=re.IGNORECASE,
        )
        raw_id = detail_url or first_string(
            card.get("data-id")
            or card.get("data-key")
            or card.get("data-doc-id")
        ) or first_string(observed_raw_id_match.group(0) if observed_raw_id_match else "")
        records.append(
            LiteratureRecord(
                title=title,
                authors=clean_people(author_text),
                year=parse_year(metadata_text or card_text),
                journal=journal or None,
                doi=doi or None,
                url=pdf_url or None,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=raw_id or None,
            )
        )
        if detail_url:
            seen_details.add(detail_url)
    return records


def wanfang_patent_detail_url(value: Any, base_url: str = "") -> str:
    """Accept only a Wanfang patent detail URL observed by the browser/page."""
    raw = first_string(value)
    if not raw or raw.casefold().startswith(("javascript:", "#")):
        return ""
    candidate = urllib.parse.urljoin(base_url, raw)
    try:
        parsed = urllib.parse.urlsplit(candidate)
    except ValueError:
        return ""
    path_parts = [part for part in (parsed.path or "").split("/") if part]
    if (
        parsed.scheme.casefold() != "https"
        or (parsed.hostname or "").casefold() != "d.wanfangdata.com.cn"
        or len(path_parts) < 2
        or path_parts[0].casefold() != "patent"
    ):
        return ""
    return urllib.parse.urlunsplit(
        ("https", parsed.netloc.casefold(), parsed.path, parsed.query, "")
    )


def clean_wanfang_patent_people(value: Any) -> list[str]:
    text = re.sub(
        r"^(?:发明人|设计人|申请人|专利权人|申请人/专利权人)\s*[:：]\s*",
        "",
        first_string(value),
        flags=re.IGNORECASE,
    )
    values = [
        part.strip()
        for part in re.split(r"[；;]|,\s*(?=[A-Z][A-Za-z.\- ]+(?:,|$))", text)
        if part.strip()
    ]
    return list(dict.fromkeys(values))


def wanfang_patent_observed_dates(card: Any) -> tuple[str, str]:
    text = first_string(card.get_text(" ", strip=True))
    date_pattern = r"((?:19|20)\d{2}(?:[-/.年]\d{1,2})?(?:[-/.月]\d{1,2}日?)?)"

    def observed(label: str) -> str:
        match = re.search(label + r"\s*[:：]?\s*" + date_pattern, text, re.IGNORECASE)
        if not match:
            return ""
        return (
            match.group(1)
            .replace("年", "-")
            .replace("月", "-")
            .replace("日", "")
            .replace("/", "-")
            .replace(".", "-")
            .rstrip("-")
        )

    application_date = observed(r"(?:申请日|申请日期|filing\s+date|application\s+date)")
    publication_date = observed(r"(?:公开日|公告日|公开日期|publication\s+date)")
    return application_date, publication_date


def explicit_wanfang_patent_publication_number(card: Any) -> str:
    for attribute in (
        "data-publication-number",
        "data-publication-no",
        "data-pub-number",
        "data-pubno",
    ):
        value = first_string(card.get(attribute))
        if value:
            return re.sub(r"\s+", "", value).upper()
    text = first_string(card.get_text(" ", strip=True))
    labeled = re.search(
        r"(?:公开[（(]?公告[）)]?号|公开号|公告号|publication\s+number)"
        r"\s*[:：]?\s*([A-Z]{2}[A-Z0-9][A-Z0-9.\-/_]{4,})",
        text,
        re.IGNORECASE,
    )
    if labeled:
        return re.sub(r"\s+", "", labeled.group(1)).upper()
    for node in card.select(".author-area .t-ML6, .publication-number"):
        value = first_string(node.get_text(" ", strip=True))
        match = re.fullmatch(
            r"([A-Z]{2}[A-Z0-9][A-Z0-9.\-/_]{4,})",
            re.sub(r"\s+", "", value),
            re.IGNORECASE,
        )
        if match:
            return match.group(1).upper()
    return ""


def wanfang_patent_cards(html_text: str) -> list[Any]:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    profile = PATENT_WEB_SOURCE_PARSER_PROFILES[WANFANG_SOURCE]
    cards: list[Any] = []
    seen_nodes: set[int] = set()
    for selector in profile.cards:
        for node in soup.select(selector):
            node_id = id(node)
            if node_id not in seen_nodes:
                seen_nodes.add(node_id)
                cards.append(node)
    return cards


def parse_wanfang_patent_search(
    html_text: str,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> list[PatentRecord]:
    profile = PATENT_WEB_SOURCE_PARSER_PROFILES[source]
    records: list[PatentRecord] = []
    seen_urls: set[str] = set()
    for card in wanfang_patent_cards(html_text):
        title_node = next(
            (
                candidate
                for selector in profile.titles
                if (candidate := card.select_one(selector)) is not None
            ),
            None,
        )
        if title_node is None:
            continue
        title = normalize_wanfang_title_text(title_node.get_text("", strip=False))
        if len(title) < 2:
            continue
        observed_url = first_string(
            card.get("data-observed-detail-url")
            or title_node.get("data-observed-detail-url")
            or title_node.get("href")
        )
        detail_url = wanfang_patent_detail_url(observed_url, base_url)
        if detail_url and detail_url in seen_urls:
            continue
        application_date, publication_date = wanfang_patent_observed_dates(card)
        inventor_text = "；".join(
            first_string(node.get_text(" ", strip=True))
            for node in card.select(
                ".inventor, .inventors, .designer, [class*='inventor' i], "
                "[class*='designer' i]"
            )
            if first_string(node.get_text(" ", strip=True))
        )
        applicant_text = "；".join(
            first_string(node.get_text(" ", strip=True))
            for node in card.select(
                ".applicant, .applicants, .author-area .authors, "
                "[class*='applicant' i]"
            )
            if first_string(node.get_text(" ", strip=True))
        )
        database = first_string(
            next(
                (
                    node.get_text(" ", strip=True)
                    for node in card.select(".database, .essay-type")
                    if first_string(node.get_text(" ", strip=True))
                ),
                "",
            )
        )
        raw_id = first_string(
            card.get("data-doc-id")
            or card.get("data-id")
            or card.get("data-key")
        )
        if not raw_id:
            hidden = card.select_one(".title-id-hidden")
            raw_id = first_string(hidden.get_text(" ", strip=True) if hidden else "")
        records.append(
            PatentRecord(
                patent_name=title,
                authors=clean_wanfang_patent_people(inventor_text),
                year=parse_year(publication_date or application_date),
                url=detail_url,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=raw_id or None,
                publication_number=explicit_wanfang_patent_publication_number(card) or None,
                applicants=clean_wanfang_patent_people(applicant_text),
                database=database or None,
                application_date=application_date or None,
                publication_date=publication_date or None,
            )
        )
        if detail_url:
            seen_urls.add(detail_url)
    return records


def wanfang_patent_candidate_count(html_text: str) -> int:
    return sum(
        1
        for card in wanfang_patent_cards(html_text)
        if card.select_one(".title-area .title") is not None
    )


def wanfang_patent_html_has_next(html_text: str) -> bool:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    for selector in PATENT_WEB_SOURCE_PARSER_PROFILES[WANFANG_SOURCE].next_links:
        for node in soup.select(selector):
            style = first_string(node.get("style")).replace(" ", "").casefold()
            classes = {first_string(value).casefold() for value in node.get("class", [])}
            if "display:none" not in style and not ({"disabled", "occupying"} & classes):
                return True
    return False


def uyanip_patent_detail_url(value: Any, base_url: str = UYANIP_HOME) -> str:
    """Accept only a patent detail URL explicitly observed on a Uyan page/response."""
    raw = first_string(value)
    if not raw or raw.casefold().startswith(("javascript:", "#")):
        return ""
    candidate = urllib.parse.urljoin(base_url, raw)
    try:
        parsed = urllib.parse.urlsplit(candidate)
    except ValueError:
        return ""
    host = (parsed.hostname or "").casefold().strip(".")
    path = parsed.path or ""
    lowered_path = path.casefold().rstrip("/")
    if (
        parsed.scheme.casefold() != "https"
        or not (host == "uyanip.com" or host.endswith(".uyanip.com"))
        or lowered_path in {"", "/"}
        or lowered_path.startswith(
            (
                "/result",
                "/login",
                "/register",
                "/user",
                "/space",
                "/search",
                "/auth",
                "/download",
            )
        )
    ):
        return ""
    path_parts = [part.casefold() for part in path.split("/") if part]
    if "detail" not in path_parts and not (
        path_parts and path_parts[0] == "patent" and len(path_parts) >= 2
    ):
        return ""
    if lowered_path == "/detail":
        query = urllib.parse.parse_qs(parsed.query, keep_blank_values=False)
        if not first_string(query.get("aid", [""])[0]):
            return ""
    return urllib.parse.urlunsplit(
        ("https", parsed.netloc.casefold(), path, parsed.query, "")
    )


def clean_uyanip_patent_people(value: Any) -> list[str]:
    if isinstance(value, list):
        values = [first_string(item) for item in value]
    else:
        text = re.sub(
            r"^(?:发明人|设计人|申请人|专利权人|inventors?|applicants?)\s*[:：]\s*",
            "",
            first_string(value),
            flags=re.IGNORECASE,
        )
        values = re.split(r"[；;]|,(?=\s*[^,]+$)", text)
    return list(dict.fromkeys(item.strip() for item in values if item.strip()))


def normalize_observed_patent_date(value: Any) -> str:
    match = re.search(
        r"(?:19|20)\d{2}(?:[-/.年]\d{1,2})?(?:[-/.月]\d{1,2}日?)?",
        first_string(value),
    )
    if not match:
        return ""
    return (
        match.group(0)
        .replace("年", "-")
        .replace("月", "-")
        .replace("日", "")
        .replace("/", "-")
        .replace(".", "-")
        .rstrip("-")
    )


def explicit_uyanip_publication_number(value: Any) -> str:
    text = first_string(value)
    match = re.search(
        r"(?:公开[（(]?(?:公告|公布)[）)]?号|公开号|公告号|publication\s+number)"
        r"\s*[:：]?\s*([A-Z]{2}[A-Z0-9][A-Z0-9.\-/_]{4,})",
        text,
        re.IGNORECASE,
    )
    return re.sub(r"\s+", "", match.group(1)).upper() if match else ""


def uyanip_label_value(value: Any, labels: tuple[str, ...]) -> str:
    text = first_string(value)
    if not text:
        return ""
    label_pattern = "|".join(re.escape(label) for label in labels)
    boundary_pattern = (
        r"发明人|设计人|申请人|当前权利人|专利权人|"
        r"公开[（(]?(?:公告|公布)[）)]?号|公开[（(]?(?:公告|公布)[）)]?日|"
        r"申请日|IPC分类号|权项数|摘要"
    )
    match = re.search(
        rf"(?:{label_pattern})\s*[:：]\s*(.+?)(?=\s+(?:{boundary_pattern})\s*[:：]|$)",
        text,
        re.IGNORECASE,
    )
    return first_string(match.group(1)) if match else ""


def uyanip_observed_application_id(value: Any) -> str:
    text = first_string(value).strip()
    match = re.fullmatch(r"[A-Z]{2}\d{6,}(?:\.\d+)?", text, re.IGNORECASE)
    return match.group(0).upper() if match else ""


def uyanip_actual_title_node(card: Any, base_url: str) -> Any | None:
    container = card.select_one(".result-ct-info-title")
    if container is None:
        return None
    candidates: list[tuple[int, int, Any]] = []
    for node in container.select("a[href]"):
        text = first_string(node.get_text(" ", strip=True))
        detail_url = uyanip_patent_detail_url(node.get("href"), base_url)
        if not text or not detail_url:
            continue
        is_identifier = bool(uyanip_observed_application_id(text))
        candidates.append((0 if is_identifier else 1, len(text), node))
    return max(candidates, default=(0, 0, None), key=lambda item: item[:2])[2]


def uyanip_stable_observed_detail_url(
    card: Any,
    preferred_url: str,
    base_url: str,
) -> str:
    preferred = uyanip_patent_detail_url(preferred_url, base_url)
    if not preferred:
        return ""
    preferred_parts = urllib.parse.urlsplit(preferred)
    preferred_aid = first_string(
        urllib.parse.parse_qs(preferred_parts.query).get("aid", [""])[0]
    )
    if not preferred_aid:
        return preferred
    candidates: list[str] = []
    for node in card.select("a[href]"):
        candidate = uyanip_patent_detail_url(node.get("href"), base_url)
        if not candidate:
            continue
        parts = urllib.parse.urlsplit(candidate)
        candidate_aid = first_string(
            urllib.parse.parse_qs(parts.query).get("aid", [""])[0]
        )
        if candidate_aid == preferred_aid and candidate not in candidates:
            candidates.append(candidate)
    return min(
        candidates or [preferred],
        key=lambda value: (
            len(urllib.parse.parse_qsl(urllib.parse.urlsplit(value).query)),
            len(value),
        ),
    )


def uyanip_patent_cards(html_text: str) -> list[Any]:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    cards: list[Any] = []
    seen_nodes: set[int] = set()
    for selector in PATENT_WEB_SOURCE_PARSER_PROFILES[UYANIP_SOURCE].cards:
        for node in soup.select(selector):
            node_id = id(node)
            if node_id not in seen_nodes:
                seen_nodes.add(node_id)
                cards.append(node)
    return cards


def parse_uyanip_patent_search(
    html_text: str,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> list[PatentRecord]:
    profile = PATENT_WEB_SOURCE_PARSER_PROFILES[source]
    records: list[PatentRecord] = []
    seen_urls: set[str] = set()
    for card in uyanip_patent_cards(html_text):
        title_node = uyanip_actual_title_node(card, base_url) or next(
            (
                candidate
                for selector in profile.titles
                if (candidate := card.select_one(selector)) is not None
            ),
            None,
        )
        if title_node is None:
            continue
        title = re.sub(
            r"\s+",
            " ",
            first_string(title_node.get_text("", strip=False)),
        ).strip()
        if len(title) < 2:
            continue
        observed_url = first_string(
            card.get("data-observed-detail-url")
            or card.get("data-detail-url")
            or title_node.get("data-observed-detail-url")
            or title_node.get("data-detail-url")
            or title_node.get("href")
        )
        detail_url = uyanip_stable_observed_detail_url(card, observed_url, base_url)
        if detail_url and detail_url in seen_urls:
            continue
        card_text = first_string(card.get_text(" ", strip=True))
        inventor_text = "；".join(
            first_string(node.get_text(" ", strip=True))
            for node in card.select(".inventor, .inventors, [class*='inventor' i]")
            if first_string(node.get_text(" ", strip=True))
        )
        if not inventor_text:
            inventor_text = uyanip_label_value(card_text, ("发明人", "设计人"))
        applicant_text = "；".join(
            first_string(node.get_text(" ", strip=True))
            for node in card.select(
                ".result-curapplicant, .applicant, .applicants, [class*='applicant' i]"
            )
            if first_string(node.get_text(" ", strip=True))
        )
        if not applicant_text:
            applicant_text = uyanip_label_value(
                card_text,
                ("申请人", "当前权利人", "专利权人"),
            )
        application_text = " ".join(
            first_string(node.get_text(" ", strip=True))
            for node in card.select(
                ".application-date, [class*='application-date' i], "
                "[data-field='applicationDate']"
            )
        )
        publication_text = " ".join(
            first_string(node.get_text(" ", strip=True))
            for node in card.select(
                ".publication-date, [class*='publication-date' i], "
                "[data-field='publicationDate']"
            )
        )
        if not application_text:
            application_text = uyanip_label_value(card_text, ("申请日",))
        if not publication_text:
            publication_text = uyanip_label_value(
                card_text,
                ("公开(公布)日", "公开（公布）日", "公开日", "公告日"),
            )
        application_date = normalize_observed_patent_date(application_text)
        publication_date = normalize_observed_patent_date(publication_text)
        publication_number = explicit_uyanip_publication_number(card_text)
        raw_id = first_string(
            card.get("data-id")
            or card.get("data-key")
            or card.get("data-doc-id")
        )
        if not raw_id:
            title_container = card.select_one(".result-ct-info-title")
            if title_container is not None:
                raw_id = next(
                    (
                        observed_id
                        for node in title_container.select("a")
                        if (
                            observed_id := uyanip_observed_application_id(
                                node.get_text(" ", strip=True)
                            )
                        )
                    ),
                    "",
                )
        database = first_string(
            next(
                (
                    node.get_text(" ", strip=True)
                    for node in card.select(".database, [class*='database' i]")
                    if first_string(node.get_text(" ", strip=True))
                ),
                "",
            )
        )
        if not database:
            database_match = re.search(r"[\[【](发明专利|实用新型|外观设计)[\]】]", card_text)
            database = database_match.group(1) if database_match else ""
        records.append(
            PatentRecord(
                patent_name=title,
                authors=clean_uyanip_patent_people(inventor_text),
                year=parse_year(publication_date or application_date),
                url=detail_url,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=raw_id or None,
                publication_number=publication_number or None,
                applicants=clean_uyanip_patent_people(applicant_text),
                database=database or None,
                application_date=application_date or None,
                publication_date=publication_date or None,
            )
        )
        if detail_url:
            seen_urls.add(detail_url)
    return records


def uyanip_dict_value(record: dict[str, Any], *names: str) -> Any:
    expected = {name.casefold() for name in names}
    for key, value in record.items():
        if first_string(key).casefold() in expected:
            return value
    return None


def uyanip_xhr_record_dicts(payload: Any) -> list[dict[str, Any]]:
    if not isinstance(payload, dict):
        return []
    title_keys = {
        "title",
        "patentname",
        "patent_name",
        "name",
        "ti",
    }
    for key in ("records", "items", "results", "list", "content", "rows", "hits"):
        value = uyanip_dict_value(payload, key)
        if isinstance(value, list):
            candidates = [item for item in value if isinstance(item, dict)]
            if any(
                title_keys.intersection(
                    first_string(candidate_key).casefold()
                    for candidate_key in item
                )
                for item in candidates
            ):
                return candidates
    for value in payload.values():
        if isinstance(value, dict):
            candidates = uyanip_xhr_record_dicts(value)
            if candidates:
                return candidates
    return []


def uyanip_xhr_url(record: dict[str, Any], base_url: str) -> str:
    values: list[Any] = [
        uyanip_dict_value(
            record,
            "detailUrl",
            "detail_url",
            "url",
            "href",
            "link",
            "patentUrl",
        )
    ]
    links = uyanip_dict_value(record, "links")
    if isinstance(links, list):
        for link in links:
            if isinstance(link, dict):
                values.append(
                    uyanip_dict_value(link, "href", "url", "link", "detailUrl")
                )
            else:
                values.append(link)
    for value in values:
        detail_url = uyanip_patent_detail_url(value, base_url)
        if detail_url:
            return detail_url
    return ""


def uyanip_xhr_pagination(payload: Any, record_count: int) -> tuple[str, bool]:
    if not isinstance(payload, dict):
        return "", not record_count
    containers = [payload]
    containers.extend(value for value in payload.values() if isinstance(value, dict))
    for container in containers:
        page_raw = uyanip_dict_value(container, "page", "pageNum", "pageNumber", "current")
        size_raw = uyanip_dict_value(container, "pageSize", "size", "limit")
        total_raw = uyanip_dict_value(container, "total", "totalCount", "count")
        try:
            page = int(page_raw)
            page_size = int(size_raw)
            total = int(total_raw)
        except (TypeError, ValueError):
            continue
        if page >= 1 and page_size >= 1 and total >= 0:
            exhausted = page * page_size >= total
            return ("" if exhausted else f"page:{page + 1}"), exhausted
    return "", not record_count


def parse_uyanip_patent_xhr(
    payload: Any,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> tuple[list[PatentRecord], str, bool]:
    records: list[PatentRecord] = []
    seen_urls: set[str] = set()
    for item in uyanip_xhr_record_dicts(payload):
        title = first_string(
            uyanip_dict_value(
                item,
                "title",
                "patentName",
                "patent_name",
                "name",
                "ti",
            )
        )
        if len(title.strip()) < 2:
            continue
        detail_url = uyanip_xhr_url(item, base_url)
        if detail_url and detail_url in seen_urls:
            continue
        publication_number = first_string(
            uyanip_dict_value(
                item,
                "publicationNumber",
                "publication_number",
                "publicationNo",
                "pubNo",
            )
        )
        application_date = normalize_observed_patent_date(
            uyanip_dict_value(item, "applicationDate", "application_date", "filingDate")
        )
        publication_date = normalize_observed_patent_date(
            uyanip_dict_value(item, "publicationDate", "publication_date", "pubDate")
        )
        records.append(
            PatentRecord(
                patent_name=title.strip(),
                authors=clean_uyanip_patent_people(
                    uyanip_dict_value(item, "inventors", "inventor", "authors")
                ),
                year=parse_year(publication_date or application_date),
                url=detail_url,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=first_string(
                    uyanip_dict_value(item, "id", "rawId", "raw_id", "patentId")
                )
                or None,
                publication_number=publication_number or None,
                applicants=clean_uyanip_patent_people(
                    uyanip_dict_value(item, "applicants", "applicant", "assignees")
                ),
                database=first_string(
                    uyanip_dict_value(item, "database", "sourceDatabase", "db")
                )
                or None,
                application_date=application_date or None,
                publication_date=publication_date or None,
            )
        )
        if detail_url:
            seen_urls.add(detail_url)
    next_token, exhausted = uyanip_xhr_pagination(payload, len(records))
    return records, next_token, exhausted


def uyanip_patent_html_has_next(html_text: str) -> bool:
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text or "", "html.parser")
    current_page = 0
    active = soup.select_one(".page a.active")
    if active is not None:
        current_page = parse_int(active.get_text(" ", strip=True)) or 0
    if current_page:
        for node in soup.select(".page a"):
            candidate_page = parse_int(node.get_text(" ", strip=True)) or 0
            if candidate_page > current_page:
                return True
    for selector in PATENT_WEB_SOURCE_PARSER_PROFILES[UYANIP_SOURCE].next_links:
        for node in soup.select(selector):
            classes = {first_string(value).casefold() for value in node.get("class", [])}
            if "disabled" not in classes and node.get("disabled") is None:
                return True
    return False


def uyanip_login_required_html(html_text: str) -> bool:
    lowered = first_string(html_text).casefold()
    has_login_surface = any(
        marker in lowered
        for marker in (
            'id="login-open"',
            "id='login-open'",
            'id="pop-login"',
            'name="password"',
            "请输入您的手机号或邮箱",
            "请输入您的账号",
        )
    )
    has_registration_marker = "免费注册" in lowered or "/register" in lowered
    return has_login_surface and has_registration_marker


def parse_restricted_provider_search(html_text: str, base_url: str, source: str, keyword: str, rank_start: int = 0) -> list[LiteratureRecord]:
    return parse_source_web_html(html_text, base_url, source, keyword, WEB_SOURCE_PARSER_PROFILES[source], rank_start)


