CODEX_CHROME_SETUP_PENDING_STATES = {
    "chrome_plugin_install_required",
    "chrome_plugin_connect_required",
    "full_cdp_enable_required",
    "preflight_unavailable",
}
SEARCH_CHALLENGE_FORBIDDEN_ACTIONS = (
    "Do not use proxy pools, IP rotation, third-party CAPTCHA services, token forgery, or hidden anti-bot script injection.",
    "Do not read or export browser cookies, passwords, local storage, profile databases, API keys, or account passwords.",
    "Do not submit one-time secrets such as SMS, email, OTP, or QR confirmations unless the authorized user has supplied that value for this exact flow.",
    "Do not continue high-frequency retries after access_denied, rate_limit, or cooldown classifications.",
)


def body_has_verification_challenge(body: str) -> bool:
    lowered = body.casefold()
    return any(marker in lowered for marker in VERIFICATION_CHALLENGE_MARKERS)


def verification_events_root() -> Path:
    configured = os.getenv("CODEX_HOOK_DIR", "").strip()
    if configured:
        return Path(configured).expanduser().resolve()
    return TOOLS_DIR / "codex_hooks" / "events"


def search_auth_control_store() -> AuthControlStore:
    global SEARCH_AUTH_CONTROL_STORE
    with SEARCH_AUTH_CONTROL_STORE_LOCK:
        if SEARCH_AUTH_CONTROL_STORE is None:
            SEARCH_AUTH_CONTROL_STORE = AuthControlStore(
                AUTH_STATE_DIR / "auth_control.sqlite3"
            )
        return SEARCH_AUTH_CONTROL_STORE


def search_challenge_principal_digest(
    config: SearchConfig | None,
    source: str,
    auth_mode: str,
) -> str:
    if config is None or auth_mode == "public":
        principal = "public"
    elif source == UYANIP_SOURCE or auth_mode == "site_personal":
        policy = patent_source_auth_policy.get(source)
        account, _password = source_personal_credentials(config, policy) if policy else ("", "")
        principal = account or "site-personal-anonymous"
    elif config.path == "institution":
        principal = config.school or config.account or "institution-anonymous"
    else:
        principal = config.account or "personal-anonymous"
    return search_auth_control_store().principal_digest(principal)


def search_verification_url_allowed(value: str) -> bool:
    return shared_outbound_http_url_allowed(value)


def verification_manual_timeout_seconds() -> int:
    try:
        fallback = os.getenv("LAPS_AUTH_MANUAL_TIMEOUT_SECONDS", "60")
        return max(10, int(os.getenv("LAPS_VERIFICATION_MANUAL_TIMEOUT_SECONDS", fallback)))
    except Exception:
        return 60


def codex_chrome_control_disabled() -> bool:
    mode = os.getenv("LAPS_CODEX_CHROME_CONTROL_MODE", "").strip().casefold()
    if mode in {"off", "disabled", "declined", "false", "0"}:
        return True
    legacy = os.getenv("LAPS_CODEX_EXTENSION_CONTROL_ENABLED")
    return legacy is not None and legacy.strip().casefold() not in {
        "1",
        "true",
        "yes",
        "on",
    }


def codex_chrome_preflight_state_for_budget() -> str:
    if codex_chrome_control_disabled():
        return "codex_chrome_control_declined"
    return (
        os.getenv("LAPS_CODEX_CHROME_PREFLIGHT_STATE", "")
        .strip()
        .casefold()
        .replace("-", "_")
    ) or "preflight_unavailable"


def codex_chrome_setup_parent_budget_seconds() -> int:
    state = codex_chrome_preflight_state_for_budget()
    confirmation = env_seconds(
        "LAPS_CODEX_CHROME_SETUP_CONFIRM_TIMEOUT_SECONDS", 300, 1
    )
    scan = env_seconds("LAPS_CODEX_CHROME_SETUP_SCAN_TIMEOUT_SECONDS", 1800, 1)
    stage_budget = confirmation + scan
    if state in {
        "chrome_plugin_install_required",
        "chrome_plugin_connect_required",
        "preflight_unavailable",
    }:
        connect_settle = env_seconds(
            "LAPS_CODEX_CHROME_CONNECT_SETTLE_SECONDS", 3, 1
        )
        return stage_budget * 2 + connect_settle
    if state == "full_cdp_enable_required":
        return stage_budget
    return 0


def codex_chrome_handoff_confirmation_parent_budget_seconds() -> int:
    return 0


def codex_chrome_extension_may_run() -> bool:
    state = codex_chrome_preflight_state_for_budget()
    return state == "ready" or state in CODEX_CHROME_SETUP_PENDING_STATES


def external_handoff_parent_budget_seconds() -> int:
    if not codex_chrome_extension_may_run():
        return 0
    return env_seconds("LAPS_EXTERNAL_HANDOFF_TIMEOUT_SECONDS", 900, 1)


def source_deadline_remaining_seconds() -> int | None:
    raw = os.getenv("LAPS_SOURCE_DEADLINE_EPOCH_SECONDS", "").strip()
    if not raw:
        return None
    try:
        return max(0, int(float(raw) - time.time()))
    except ValueError:
        return None


def verification_hook_timeout_seconds(event: str = "search_challenge") -> int:
    event_specific = (
        ("LAPS_AUTH_CONTROL_HOOK_TIMEOUT_SECONDS",)
        if event == "auth_challenge"
        else ("LAPS_SEARCH_CHALLENGE_HOOK_TIMEOUT_SECONDS", "LAPS_SECURITY_CHALLENGE_HOOK_TIMEOUT_SECONDS")
    )
    for name in (*event_specific, "LAPS_HOOK_TOTAL_TIMEOUT_SECONDS"):
        value = os.getenv(name, "").strip()
        if not value:
            continue
        try:
            return max(1, int(value))
        except ValueError:
            continue
    chromium_seconds = env_seconds("LAPS_CHROMIUM_CONTROL_TIMEOUT_SECONDS", 60, 10)
    chrome_seconds = env_seconds("LAPS_CHROME_CONTROL_TIMEOUT_SECONDS", 180, 10)
    manual_seconds = verification_manual_timeout_seconds()
    chrome_enabled = os.getenv("CODEX_HOOK_DISABLE_CHROME_FALLBACK", "").strip().casefold() not in {"1", "true", "yes", "on"}
    fallback_cooldown_seconds = env_seconds(
        "LAPS_VERIFICATION_BROWSER_FALLBACK_COOLDOWN_SECONDS",
        30,
        0,
    )
    stable_control_seconds = env_seconds(
        "LAPS_VERIFICATION_CONTROL_STABLE_SECONDS",
        15,
        0,
    )
    post_action_wait_seconds = env_seconds(
        "LAPS_VERIFICATION_POST_ACTION_WAIT_SECONDS",
        180,
        0,
    )
    chromium_navigation_seconds = min(chromium_seconds, 30)
    chrome_navigation_seconds = min(chrome_seconds, 30)
    normal_path_budget = (
        chromium_navigation_seconds
        + chromium_seconds
        + (chrome_navigation_seconds + chrome_seconds if chrome_enabled else 0)
        + (fallback_cooldown_seconds if chrome_enabled else 0)
        + manual_seconds
        + 15
    )
    chromium_interaction_budget = (
        chromium_navigation_seconds
        + stable_control_seconds
        + post_action_wait_seconds
        + 15
    )
    chrome_interaction_budget = 0
    if chrome_enabled:
        chrome_interaction_budget = (
            chromium_navigation_seconds
            + chromium_seconds
            + manual_seconds
            + fallback_cooldown_seconds
            + chrome_navigation_seconds
            + stable_control_seconds
            + post_action_wait_seconds
            + 15
        )
    setup_budget = codex_chrome_setup_parent_budget_seconds()
    extension_budget = (
        env_seconds("LAPS_CODEX_EXTENSION_CONTROL_TIMEOUT_SECONDS", 180, 1)
        if codex_chrome_extension_may_run()
        else 0
    )
    calculated = max(
        normal_path_budget,
        chromium_interaction_budget,
        chrome_interaction_budget,
    ) + setup_budget + max(
        extension_budget,
        external_handoff_parent_budget_seconds(),
    )
    parent_remaining = source_deadline_remaining_seconds()
    if parent_remaining is None:
        return calculated
    return max(1, min(calculated, max(1, parent_remaining - 5)))


def split_hook_command(command: str) -> list[str]:
    value = command.strip()
    if not value:
        return []
    candidate = Path(value.strip('"')).expanduser()
    if candidate.exists():
        resolved = str(candidate.resolve())
        return [sys.executable, resolved] if candidate.suffix.casefold() == ".py" else [resolved]
    parts = shlex.split(value, posix=os.name != "nt")
    return [part.strip('"') for part in parts if part.strip('"')]


def bundled_verification_hook_path() -> Path:
    return TOOLS_DIR / "codex_hooks" / "codex_external_control_hook.py"


def browser_escalation_policy_contract() -> dict[str, Any]:
    return {
        "schema": BROWSER_ESCALATION_POLICY_SCHEMA,
        "layers": list(BROWSER_ESCALATION_LAYERS),
        "order_locked": True,
        "advance_on": [
            "verification_loop",
            "timeout",
            "transport_failure",
            "unsupported_browser",
        ],
        "final_failure_action": "cooldown_current_source",
        "channel_order_unchanged": True,
    }


def control_authorization_contract() -> dict[str, Any]:
    return {
        "schema": BROWSER_CONTROL_AUTHORIZATION_SCHEMA,
        "scope": "literature_and_patent_browser_workflow",
        "preauthorized_action_classes": list(BROWSER_CONTROL_ACTION_CLASSES),
        "verification_action_budget": 1,
        "event_bound": True,
        "requires_unique_visible_target": True,
        "refresh_or_repeat_forbidden": True,
        "user_completed_first_is_accepted": True,
        "user_held_one_time_secrets_remain_user_provided": True,
        "host_enforced_confirmation_may_still_apply": True,
    }


def verification_hook_uses_bundled_controller(command: list[str]) -> bool:
    expected = bundled_verification_hook_path()
    try:
        expected = expected.resolve()
    except OSError:
        return False
    for part in command:
        try:
            candidate = Path(part).expanduser()
            if candidate.suffix.casefold() == ".py" and candidate.resolve() == expected:
                return True
        except (OSError, ValueError):
            continue
    return False


def verification_hook_command(event: str = "search_challenge") -> list[str]:
    if event == "auth_challenge":
        names = ("LAPS_AUTH_CONTROL_HOOK", "LAPS_LOGIN_HOOK_COMMAND", "LAPS_SEARCH_CHALLENGE_HOOK", "LAPS_SECURITY_CHALLENGE_HOOK", "LAPS_CHALLENGE_HOOK_COMMAND")
    else:
        names = ("LAPS_SEARCH_CHALLENGE_HOOK", "LAPS_SECURITY_CHALLENGE_HOOK", "LAPS_CHALLENGE_HOOK_COMMAND")
    for name in names:
        command = split_hook_command(os.getenv(name, ""))
        if command:
            return command
    default_hook = bundled_verification_hook_path()
    if default_hook.exists():
        return [sys.executable, str(default_hook)]
    return []


def sanitize_url_for_search_hook(value: str | None) -> str:
    text = (value or "").strip()
    if not text:
        return ""
    try:
        parsed = urllib.parse.urlsplit(text)
        if parsed.scheme and parsed.netloc:
            safe_query_parts = []
            for key, raw_value in urllib.parse.parse_qsl(parsed.query, keep_blank_values=True):
                lowered_key = key.casefold()
                if any(token in lowered_key for token in ("token", "session", "cookie", "password", "credential", "authorization", "code", "key", "secret")):
                    continue
                safe_query_parts.append((key, raw_value))
            return urllib.parse.urlunsplit((parsed.scheme, parsed.netloc, parsed.path, urllib.parse.urlencode(safe_query_parts), ""))
    except ValueError:
        pass
    return text.split("?", 1)[0].split("#", 1)[0][:500]


def verification_event_id(source: str, event: str) -> str:
    digest_basis = f"{event}|{source}|{time.time()}|{os.getpid()}|{random.random()}"
    digest = hashlib.sha1(digest_basis.encode("utf-8")).hexdigest()[:12]
    return f"{datetime.now().strftime('%Y%m%d_%H%M%S')}_{safe_slug(event)}_{safe_slug(source)}_{digest}"


def search_challenge_artifact_paths(event_id: str) -> dict[str, Path]:
    root = verification_events_root()
    return {
        "screenshot": root / "screenshots" / f"{event_id}.png",
        "hook_screenshot": root / "screenshots" / f"{event_id}.hook.png",
        "storage_state": root / "auth_states" / f"{event_id}.storage_state.json",
        "response": root / "responses" / f"{event_id}.json",
    }


def classify_search_challenge(text: str, reason: str = "", url: str = "") -> str:
    lowered = " ".join((text or "", reason or "", url or "")).casefold()
    if any(token in lowered for token in ("mfa", "multi-factor", "two-factor", "verification code", "otp", "短信验证码", "邮箱验证码", "邮箱验证", "二次验证", "扫码确认")):
        return "mfa_required"
    if any(token in lowered for token in ("recaptcha", "hcaptcha", "captcha", "验证码", "slide to verify", "drag the slider", "滑块", "拖动滑块")):
        return "captcha_required"
    if any(token in lowered for token in ("verify you are human", "verify human", "are you a robot", "robot verification", "robot check", "unusual traffic", "automated queries", "异常流量", "稍后重新发送请求", "google.com/sorry", "/sorry/", "机器人验证", "我不是机器人")):
        return "robot_check"
    if any(token in lowered for token in ("cloudflare", "security check", "安全验证", "you have been blocked", "there was a problem providing the content you requested")) or re.search(r"(?<![a-z0-9])waf(?![a-z0-9])", lowered):
        return "cloudflare_or_waf"
    if any(token in lowered for token in ("access denied", "forbidden", "not authorized", "unauthorized", "permission denied")):
        return "access_denied"
    reason_value = (reason or "").strip().casefold()
    lowered_url = (url or "").casefold()
    if reason_value == "institution_login" or any(
        token in lowered_url for token in ("/login", "/signin", "/wayf", "/saml", "authserver")
    ):
        return "institution_login"
    return "unknown_verification"


def normalize_search_challenge_action(value: str) -> str:
    action = (value or "").strip().casefold()
    aliases = {
        "resolved": "retry",
        "continue": "retry",
        "try_again": "retry",
        "switch": "skip",
        "switch_source": "skip",
        "next": "skip",
        "unable": "unhandled",
        "failed": "unhandled",
    }
    return aliases.get(action, action if action in SEARCH_CHALLENGE_ACTIONS else "unhandled")


def parse_search_challenge_response(
    loaded: dict[str, Any],
    *,
    request: Mapping[str, Any] | None = None,
    allow_legacy_sync: bool = True,
    consume: bool = True,
) -> SearchChallengeControlResult:
    if loaded.get("_protocol_error"):
        return SearchChallengeControlResult(
            action="unhandled",
            reason=str(loaded.get("_protocol_error") or "challenge_response_unbound"),
            protocol_request=dict(request or {}),
        )
    selected_request = dict(request or {})
    if not selected_request:
        with SEARCH_VERIFICATION_REQUESTS_LOCK:
            selected_request = dict(
                SEARCH_VERIFICATION_REQUESTS.get(
                    str(loaded.get("event_id") or "")
                )
                or {}
            )
    legacy_sync = loaded.get("schema") != "laps_verification_response_v2"
    if not legacy_sync:
        if not selected_request:
            return SearchChallengeControlResult(
                action="unhandled",
                reason="challenge_response_unbound",
            )
        validation = validate_verification_response(
            selected_request,
            loaded,
            controlled_roots=(verification_events_root(), AUTH_STATE_DIR),
            url_validator=search_verification_url_allowed,
            replay_store=search_auth_control_store(),
            consume=consume and str(loaded.get("action") or "") != "manual_pending",
        )
        if not validation.valid or not isinstance(validation.payload, dict):
            return SearchChallengeControlResult(
                action="unhandled",
                reason=validation.reason_code,
                protocol_request=selected_request,
            )
        loaded = validation.payload
        evidence = loaded.get("evidence") if isinstance(loaded.get("evidence"), Mapping) else {}
    else:
        if not allow_legacy_sync:
            return SearchChallengeControlResult(
                action="unhandled",
                reason="challenge_response_unbound",
                protocol_request=selected_request,
            )
        evidence = loaded
    raw_snapshot_paths = evidence.get("sanitized_search_snapshot_paths")
    snapshot_paths = (
        [str(value or "").strip() for value in raw_snapshot_paths]
        if isinstance(raw_snapshot_paths, list)
        else []
    )
    singular_snapshot = str(
        evidence.get("sanitized_search_snapshot_path") or ""
    ).strip()
    if singular_snapshot and singular_snapshot not in snapshot_paths:
        snapshot_paths.insert(0, singular_snapshot)
    attestation = evidence.get("external_session_attestation")
    capability_attestation = evidence.get("capability_attestation")
    return SearchChallengeControlResult(
        action=normalize_search_challenge_action(str(loaded.get("action") or "")),
        reason=str(loaded.get("reason") or loaded.get("reason_code") or ""),
        storage_state_path=str(evidence.get("storage_state_path") or ""),
        final_url=str(evidence.get("final_url") or ""),
        sanitized_search_snapshot_path=singular_snapshot,
        browser_name=normalize_browser_name(loaded.get("browser_name")),
        same_browser_handoff=bool(loaded.get("same_browser_handoff")),
        switch_browser_to=normalize_browser_name(loaded.get("switch_browser_to")),
        preflight_state=str(loaded.get("preflight_state") or ""),
        external_browser_session=evidence.get("external_browser_session") is True,
        browser_transport=str(evidence.get("browser_transport") or ""),
        external_session_attestation=(
            dict(attestation) if isinstance(attestation, dict) else {}
        ),
        capability_attestation=(
            dict(capability_attestation)
            if isinstance(capability_attestation, dict)
            else {}
        ),
        sanitized_search_snapshot_paths=tuple(
            value for value in snapshot_paths if value
        ),
        protocol_request=selected_request,
        legacy_sync=legacy_sync,
    )


def search_challenge_response_event_id(loaded: dict[str, Any]) -> str:
    direct = str(loaded.get("event_id") or "").strip()
    if direct:
        return direct
    for key in (
        "external_session_attestation",
        "challenge_action_authorization",
        "challenge_action_confirmation",
    ):
        nested = loaded.get(key)
        if isinstance(nested, dict):
            candidate = str(nested.get("event_id") or "").strip()
            if candidate:
                return candidate
    return ""


def search_challenge_response_matches_event(
    loaded: dict[str, Any],
    event_id: str,
) -> bool:
    expected = str(event_id or "").strip()
    return bool(
        expected
        and search_challenge_response_event_id(loaded) == expected
    )


async def wait_for_search_challenge_response(
    event_id: str,
    timeout_seconds: int,
    request: Mapping[str, Any] | None = None,
) -> dict[str, Any] | None:
    root = verification_events_root()
    if request is None:
        with SEARCH_VERIFICATION_REQUESTS_LOCK:
            request = dict(SEARCH_VERIFICATION_REQUESTS.get(event_id) or {})
    if not request:
        return {"_protocol_error": "challenge_response_unbound"}
    deadline = time.monotonic() + max(0, timeout_seconds)
    while time.monotonic() < deadline:
        read_result = await asyncio.to_thread(
            read_verification_response,
            root / "responses",
            request,
        )
        if read_result.payload is not None:
            return read_result.payload
        if read_result.reason_code != "challenge_response_missing":
            response_sha, responded_at = await asyncio.to_thread(
                verification_file_audit_evidence,
                read_result.path,
            )
            await asyncio.to_thread(
                search_auth_control_store().mark_verification_rejected,
                request,
                read_result.reason_code,
                response_sha256=response_sha,
                responded_at=responded_at,
            )
            return {"_protocol_error": read_result.reason_code}
        await asyncio.sleep(0.5)
    await asyncio.to_thread(
        search_auth_control_store().mark_verification_expired,
        request,
        "challenge_response_timeout",
    )
    return None


async def wait_if_search_manual_pending(control: SearchChallengeControlResult, event_id: str) -> SearchChallengeControlResult:
    if control.action != "manual_pending":
        return control
    if control.legacy_sync:
        return SearchChallengeControlResult(
            action="unhandled",
            reason="challenge_response_unbound",
            protocol_request=control.protocol_request,
            legacy_sync=True,
        )
    setup_state = control.preflight_state or (
        control.reason
        if control.reason in CODEX_CHROME_SETUP_PENDING_STATES
        else ""
    )
    if setup_state in CODEX_CHROME_SETUP_PENDING_STATES or control.reason == "codex_chrome_capability_check_required":
        normalized_state = setup_state or "preflight_unavailable"
        return SearchChallengeControlResult(
            action="unhandled",
            reason=f"codex_chrome_setup_required:{normalized_state}",
            storage_state_path=control.storage_state_path,
            final_url=control.final_url,
            sanitized_search_snapshot_path=control.sanitized_search_snapshot_path,
            browser_name=control.browser_name,
            same_browser_handoff=control.same_browser_handoff,
            switch_browser_to=control.switch_browser_to,
            preflight_state=normalized_state,
            external_browser_session=control.external_browser_session,
            browser_transport=control.browser_transport,
            external_session_attestation=dict(
                control.external_session_attestation
            ),
            capability_attestation=dict(control.capability_attestation),
            sanitized_search_snapshot_paths=(
                control.sanitized_search_snapshot_paths
            ),
        )
    loaded = await wait_for_search_challenge_response(
        event_id,
        verification_manual_timeout_seconds(),
        control.protocol_request,
    )
    if loaded is None:
        return SearchChallengeControlResult(
            "unhandled",
            control.reason or "challenge_response_timeout",
            control.storage_state_path,
            control.final_url,
            control.sanitized_search_snapshot_path,
        )
    return parse_search_challenge_response(
        loaded,
        request=control.protocol_request,
        allow_legacy_sync=False,
        consume=True,
    )


async def capture_search_challenge_screenshot(page: Any, path: Path) -> str:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        await page.screenshot(path=str(path), full_page=True)
        return str(path)
    except Exception:
        return ""


async def export_current_browser_storage_state(page: Any, path: Path) -> str:
    try:
        path.parent.mkdir(parents=True, exist_ok=True)
        await page.context.storage_state(path=str(path))
        if os.name != "nt":
            path.chmod(0o600)
        return storage_state_is_usable(str(path))
    except Exception:
        return ""


def storage_state_is_usable(path_value: str) -> str:
    if not path_value:
        return ""
    try:
        path = Path(path_value).expanduser().resolve()
        if not path.exists() or not path.is_file():
            return ""
        loaded = json.loads(path.read_text(encoding="utf-8"))
        if isinstance(loaded, dict) and ("cookies" in loaded or "origins" in loaded):
            return str(path)
    except Exception:
        return ""
    return ""


def resolved_path_is_within(path: Path, parent: Path) -> bool:
    try:
        path.resolve().relative_to(parent.resolve())
        return True
    except (OSError, ValueError):
        return False


def snapshot_url_is_valid_for_source(
    value: str,
    source: str,
    record_type: Literal["literature", "patent"] = "literature",
) -> bool:
    sanitized = sanitize_url_for_search_hook(value)
    try:
        parsed = urllib.parse.urlsplit(sanitized)
    except ValueError:
        return False
    if parsed.scheme.casefold() != "https" or not parsed.hostname:
        return False
    if not source:
        return True
    source_map = (
        patents_search_path_map
        if record_type == "patent"
        else literature_search_path_map
    )
    policy_map = (
        patent_source_auth_policy
        if record_type == "patent"
        else literature_source_auth_policy
    )
    policy = policy_map.get(source)
    candidate_urls = (
        policy.web_search_url if policy is not None else "",
        policy.auth_entry_url if policy is not None else "",
        source_map.get(source, ""),
    )
    expected_hosts = {
        (urllib.parse.urlsplit(candidate).hostname or "").casefold().removeprefix("www.")
        for candidate in candidate_urls
        if candidate
    }
    expected_hosts.discard("")
    actual_host = parsed.hostname.casefold().removeprefix("www.")
    return bool(
        expected_hosts
        and any(
            actual_host == expected
            or actual_host.endswith(f".{expected}")
            or expected.endswith(f".{actual_host}")
            for expected in expected_hosts
        )
    )


def load_sanitized_search_snapshot(
    path_value: str,
    *,
    expected_source: str = "",
    expected_keyword: str = "",
    expected_event_id: str = "",
    expected_auth_state_scope: str = "",
    expected_record_type: Literal["literature", "patent"] | None = None,
    require_managed_path: bool = False,
) -> dict[str, Any] | None:
    if not path_value:
        return None
    try:
        path = Path(path_value).expanduser().resolve()
        if require_managed_path and not any(
            resolved_path_is_within(path, root)
            for root in (verification_events_root() / "search_snapshots", AUTH_STATE_DIR)
        ):
            return None
        if not path.is_file() or path.stat().st_size > 25 * 1024 * 1024:
            return None
        loaded = json.loads(path.read_text(encoding="utf-8-sig"))
        if not isinstance(loaded, dict) or loaded.get("schema") != "laps_sanitized_search_snapshot_v1":
            return None
        html_text = loaded.get("html")
        if not isinstance(html_text, str) or not html_text.strip():
            return None
        if re.search(
            r"<(?:script|style|form|input|textarea|select|button|iframe|object|embed)\b",
            html_text,
            re.IGNORECASE,
        ):
            return None
        if expected_source and first_string(loaded.get("source")) != expected_source:
            return None
        if expected_keyword and first_string(loaded.get("keyword")) != expected_keyword:
            return None
        if expected_event_id and first_string(loaded.get("event_id")) != expected_event_id:
            return None
        if (
            expected_auth_state_scope
            and first_string(loaded.get("auth_state_scope"))
            != expected_auth_state_scope
        ):
            return None
        loaded_record_type = normalized_search_record_type(
            first_string(loaded.get("search_record_type"))
        )
        if (
            expected_record_type is not None
            and first_string(loaded.get("search_record_type"))
            != expected_record_type
        ):
            return None
        final_url = sanitize_url_for_search_hook(first_string(loaded.get("final_url")))
        if not snapshot_url_is_valid_for_source(
            final_url,
            expected_source,
            loaded_record_type,
        ):
            return None
        next_url = sanitize_url_for_search_hook(first_string(loaded.get("next_url")))
        if next_url and not snapshot_url_is_valid_for_source(
            next_url,
            expected_source,
            loaded_record_type,
        ):
            return None
        return {
            "event_id": str(loaded.get("event_id") or ""),
            "source": str(loaded.get("source") or ""),
            "keyword": str(loaded.get("keyword") or ""),
            "auth_state_scope": str(loaded.get("auth_state_scope") or ""),
            "search_record_type": loaded_record_type,
            "page_number": max(1, int(loaded.get("page_number") or 1)),
            "html": html_text,
            "final_url": final_url,
            "next_url": next_url,
            "has_next_control": bool(loaded.get("has_next_control")),
            "explicit_no_results": bool(loaded.get("explicit_no_results")),
        }
    except Exception:
        return None


def ordinary_chrome_capability_attestation_valid(
    attestation: dict[str, Any],
) -> bool:
    return bool(
        attestation.get("ordinary_chrome_extension_connected") is True
        and attestation.get("full_cdp_access") is True
        and first_string(attestation.get("readonly_cdp_probe_method"))
        == "Page.getFrameTree"
        and attestation.get("readonly_cdp_probe_succeeded") is True
    )


def validate_ordinary_chrome_external_search_resume(
    control: SearchChallengeControlResult,
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
    keyword: str,
) -> tuple[list[dict[str, Any]] | None, str]:
    record_type = current_search_record_type()
    if (
        not control.external_browser_session
        or control.browser_transport
        != ORDINARY_CHROME_EXTERNAL_SESSION_TRANSPORT
        or control.same_browser_handoff
        or control.storage_state_path
    ):
        return None, "ordinary_chrome_external_session_transport_invalid"
    if not ordinary_chrome_capability_attestation_valid(
        control.capability_attestation
    ):
        return None, "ordinary_chrome_external_session_capability_invalid"
    attestation = control.external_session_attestation
    event_id = first_string(attestation.get("event_id"))
    expected_scope = source_auth_state_scope(source, policy)
    if (
        attestation.get("schema")
        != ORDINARY_CHROME_EXTERNAL_SESSION_ATTESTATION_SCHEMA
        or attestation.get("authenticated") is not True
        or first_string(attestation.get("source")) != source
        or first_string(attestation.get("auth_state_scope")) != expected_scope
        or first_string(attestation.get("institution_identity_digest"))
        != configured_institution_identity_digest(config)
        or not event_id
    ):
        return None, "ordinary_chrome_external_session_attestation_invalid"
    paths = list(control.sanitized_search_snapshot_paths)
    if control.sanitized_search_snapshot_path:
        if control.sanitized_search_snapshot_path not in paths:
            paths.insert(0, control.sanitized_search_snapshot_path)
    if not paths:
        return None, "ordinary_chrome_external_session_snapshot_required"
    snapshots: list[dict[str, Any]] = []
    seen_pages: set[int] = set()
    for path_value in paths:
        snapshot = load_sanitized_search_snapshot(
            path_value,
            expected_source=source,
            expected_keyword=keyword,
            expected_event_id=event_id,
            expected_auth_state_scope=expected_scope,
            expected_record_type=record_type,
            require_managed_path=True,
        )
        if snapshot is None:
            return None, "ordinary_chrome_external_session_snapshot_invalid"
        page_number = int(snapshot.get("page_number") or 1)
        if page_number in seen_pages:
            return None, "ordinary_chrome_external_session_duplicate_page"
        seen_pages.add(page_number)
        snapshots.append(snapshot)
    snapshots.sort(key=lambda value: int(value.get("page_number") or 1))
    saved, reason = save_ordinary_chrome_external_session(
        config,
        source,
        policy,
        keyword,
        event_id,
        snapshots,
        record_type,
    )
    if not saved:
        return None, reason
    return snapshots, "ordinary_chrome_external_session_valid"


def build_search_challenge_payload(
    *,
    event_id: str,
    source: str,
    keyword: str,
    reason: str,
    current_url: str,
    body: str,
    screenshot_path: str,
    storage_state_path: str,
    response_path: str,
    seed_storage_state_path: str = "",
    hook_screenshot_path: str = "",
    event: str = "search_challenge",
    config: SearchConfig | None = None,
    success_markers: list[str] | None = None,
    auth_entry_id: str = "",
    auth_entry_mode: AuthEntryMode = "institution",
    control_mode: str = "",
    parent_browser_control: ParentBrowserControl | None = None,
    trusted_bundled_hook: bool = False,
) -> dict[str, Any]:
    sanitized_current_url = sanitize_url_for_search_hook(current_url)
    is_auth = event == "auth_challenge"
    search_record_type = current_search_record_type()
    source_policy = (
        patent_source_auth_policy.get(source)
        if search_record_type == "patent"
        else literature_source_auth_policy.get(source)
    )
    task_path = first_string(SEARCH_TASK_CONTEXT.get().get("path"))
    handoff_uses_restricted_state = is_auth or task_path == "restricted_browser"
    timeout_seconds = verification_hook_timeout_seconds(event)
    payload: dict[str, Any] = {
        "event": event,
        "event_id": event_id,
        "challenge_type": classify_search_challenge(body, reason, current_url),
        "source": source,
        "channel": source,
        "auth_state_scope": (
            source_auth_state_scope(source, source_policy)
            if source_policy is not None and handoff_uses_restricted_state
            else ""
        ),
        "auth_entry_id": auth_entry_id if is_auth else "",
        "auth_entry_mode": auth_entry_mode if is_auth else "",
        "control_mode": control_mode,
        "keyword": keyword,
        "reason": reason,
        "record_type": "authentication" if is_auth else "search",
        "search_record_type": search_record_type,
        "title": keyword,
        "url": sanitized_current_url,
        "current_url": sanitized_current_url,
        "candidate_url": sanitized_current_url,
        "entry_url": sanitized_current_url,
        "access_mode": "restricted_browser" if is_auth else "search_public_browser",
        "timeout_seconds": timeout_seconds,
        "manual_wait_seconds": verification_manual_timeout_seconds(),
        "response_path": response_path,
        "keep_browser_open": True,
        "codex_extension_control_enabled": True,
        "ordinary_chrome_preapproved": os.getenv(
            "LAPS_ORDINARY_CHROME_PREAUTHORIZED", "1"
        ).strip().casefold()
        in {"1", "true", "yes", "on"},
        "computer_use_preapproved": os.getenv(
            "LAPS_CODEX_WINDOWS_CONTROL_PREAUTHORIZED", "1"
        ).strip().casefold()
        in {"1", "true", "yes", "on"},
        "browser_escalation_policy": browser_escalation_policy_contract(),
        "control_authorization": control_authorization_contract(),
        "external_handoff_timeout_seconds": external_handoff_parent_budget_seconds(),
        "automation_level": os.getenv("LAPS_VERIFICATION_AUTOMATION_LEVEL", "assist").strip() or "assist",
        "browser_preference": os.getenv("LAPS_EXTERNAL_CONTROL_BROWSER", os.getenv("CODEX_HOOK_BROWSER_CHANNEL", "chromium")).strip() or "chromium",
        "browser_profile_path": str(verification_events_root() / "browser_profiles"),
        "screenshot_path": screenshot_path,
        "hook_screenshot_path": hook_screenshot_path,
        "storage_state_path": storage_state_path,
        "success_markers": success_markers or (["log out", "logout", "sign out", "signed in", "institutional access", "access provided by"] if is_auth else [source, "Search Results", "Results", "搜索结果"]),
        "forbidden_actions": list(SEARCH_CHALLENGE_FORBIDDEN_ACTIONS),
        "created_at": utc_now(),
        "expected_stdout_json": {
            "action": "retry|skip|cooldown|manual_pending|unhandled",
            "storage_state_path": "optional Playwright storage_state JSON after browser verification",
            "final_url": "optional final browser URL",
            "sanitized_search_snapshot_path": "optional sanitized public result-card snapshot JSON",
            "reason": "optional explanation",
            "same_browser_handoff": "true only when the hook controlled the parent-owned browser",
            "switch_browser_to": "optional bounded browser fallback request",
            "external_browser_session": "true only for independently owned ordinary Chrome/CDP",
            "browser_transport": ORDINARY_CHROME_EXTERNAL_SESSION_TRANSPORT,
            "external_session_attestation": "required for ordinary Chrome auth retry",
            "sanitized_search_snapshot_paths": "required for ordinary Chrome search continuation",
        },
    }
    if parent_browser_control is not None:
        payload.update(
            {
                "parent_browser_cdp_endpoint": parent_browser_control.endpoint,
                "parent_browser_target_id": parent_browser_control.target_id,
                "parent_browser_name": parent_browser_control.browser_name,
            }
        )
    if seed_storage_state_path:
        payload["seed_storage_state_path"] = seed_storage_state_path
    profile = (
        PATENT_WEB_SOURCE_PARSER_PROFILES.get(source)
        if search_record_type == "patent"
        else WEB_SOURCE_PARSER_PROFILES.get(source)
    )
    if profile is not None:
        payload["result_card_selectors"] = list(profile.cards)
        payload["next_page_selectors"] = list(profile.next_links)
        payload["resume_action_selectors"] = list(
            PATENT_WEB_SOURCE_RESUME_ACTION_SELECTORS.get(source, ())
            if search_record_type == "patent"
            else WEB_SOURCE_RESUME_ACTION_SELECTORS.get(source, ())
        )
        payload["search_surface_selectors"] = list(
            PATENT_WEB_SOURCE_SEARCH_SURFACE_SELECTORS.get(source, ())
            if search_record_type == "patent"
            else WEB_SOURCE_SEARCH_SURFACE_SELECTORS.get(source, ())
        )
        payload["no_result_markers"] = list(
            PATENT_WEB_SOURCE_NO_RESULT_MARKERS.get(
                source,
                ("no results found", "0 results"),
            )
            if search_record_type == "patent"
            else WEB_SOURCE_NO_RESULT_MARKERS.get(
                source,
                ("no results found", "0 results"),
            )
        )
    if source == CNKI_SOURCE and search_record_type == "literature":
        payload["result_detail_enrichment"] = {
            "schema": "laps_browser_result_detail_enrichment_v1",
            "mode": "observed_page_metadata_only",
            "detail_link_selectors": list(
                WEB_SOURCE_PARSER_PROFILES[CNKI_SOURCE].titles
            ),
            "locator_priority": ["doi", "direct_pdf"],
            "stop_when_observed": "doi_or_direct_pdf",
            "doi_must_be_explicit": True,
            "pdf_must_be_direct_response_or_explicit_direct_link": True,
            "landing_or_order_url_is_not_pdf": True,
            "title_based_doi_inference_forbidden": True,
            "snapshot_embedding": {
                "doi_class": "doi",
                "direct_pdf_anchor_class": "direct-pdf",
            },
            "production_logout_forbidden": True,
            "test_logout_requires_explicit_test_mode": True,
        }
    if source == CNKI_SOURCE and search_record_type == "patent":
        payload["result_patent_enrichment"] = {
            "schema": "laps_browser_patent_result_enrichment_v1",
            "mode": "observed_page_metadata_only",
            "detail_link_selectors": list(
                PATENT_WEB_SOURCE_PARSER_PROFILES[CNKI_SOURCE].titles
            ),
            "detail_url_must_be_observed": True,
            "publication_number_must_be_explicit": True,
            "search_author_or_order_url_is_not_detail": True,
            "constructed_patent_url_forbidden": True,
            "production_logout_forbidden": True,
            "test_logout_requires_explicit_test_mode": True,
        }
    if source == WANFANG_SOURCE and search_record_type == "patent":
        payload["result_patent_enrichment"] = {
            "schema": "laps_browser_patent_result_enrichment_v1",
            "mode": "observed_popup_url_only",
            "detail_link_selectors": list(
                PATENT_WEB_SOURCE_PARSER_PROFILES[WANFANG_SOURCE].titles
            ),
            "detail_url_must_be_observed": True,
            "accepted_detail_host": "d.wanfangdata.com.cn",
            "accepted_detail_path_prefix": "/patent/",
            "snapshot_detail_attribute": "data-observed-detail-url",
            "publication_number_must_be_explicit": True,
            "hidden_identifier_is_not_a_detail_url": True,
            "constructed_patent_url_forbidden": True,
            "production_logout_forbidden": True,
            "test_logout_requires_explicit_test_mode": True,
        }
    if source == UYANIP_SOURCE and search_record_type == "patent":
        payload["result_patent_enrichment"] = {
            "schema": "laps_browser_patent_result_enrichment_v1",
            "mode": "observed_page_or_xhr_detail_url_only",
            "detail_link_selectors": list(
                PATENT_WEB_SOURCE_PARSER_PROFILES[UYANIP_SOURCE].titles
            ),
            "detail_url_must_be_observed": True,
            "accepted_detail_hosts": ["uyanip.com", "www.uyanip.com"],
            "search_or_account_url_is_not_detail": True,
            "constructed_patent_url_forbidden": True,
        }
    if is_auth and keyword:
        if source_policy is not None:
            resume_url = first_string(SEARCH_TASK_CONTEXT.get().get("resume_url"))
            payload["source_search_url"] = sanitize_url_for_search_hook(
                resume_url
                or build_web_search_url(source, source_policy, keyword, 1)
            )
    if config is not None:
        payload["school"] = config.school
        payload["school_aliases"] = list(config.school_aliases)
        if is_auth:
            if (
                source == UYANIP_SOURCE
                and source_policy is not None
                and source_policy.runtime_personal_credential_keys
            ):
                uyanip_account, uyanip_password = source_personal_credentials(
                    config,
                    source_policy,
                )
                payload["runtime_auth_values_available"] = bool(
                    uyanip_account and uyanip_password
                )
                payload["credential_scope"] = "site_personal"
                payload["credential_allowed_hosts"] = [
                    "uyanip.com",
                    "api.duyandb.com",
                ]
            else:
                payload["runtime_auth_values_available"] = bool(
                    config.account and config.password
                )
    raw_url_allowed = any(
        os.getenv(name, "").strip().casefold() in {"1", "true", "yes", "on"}
        for name in ("LAPS_SEARCH_CHALLENGE_HOOK_ALLOW_RAW_URL", "LAPS_AUTH_CONTROL_HOOK_ALLOW_RAW_URL")
    )
    if raw_url_allowed:
        payload["raw_current_url"] = current_url
        payload["raw_candidate_url"] = current_url
        payload["raw_url"] = current_url
        payload["raw_entry_url"] = current_url
    custom_hook_credentials_allowed = os.getenv(
        "LAPS_AUTH_CONTROL_HOOK_ALLOW_CREDENTIALS", ""
    ).strip().casefold() in {"1", "true", "yes", "on"}
    if is_auth and config is not None and (
        trusted_bundled_hook or custom_hook_credentials_allowed
    ):
        if (
            source == UYANIP_SOURCE
            and source_policy is not None
            and source_policy.runtime_personal_credential_keys
        ):
            account, password = source_personal_credentials(config, source_policy)
            current_host = (
                urllib.parse.urlsplit(current_url or "").hostname or ""
            ).casefold()
            if (
                account
                and password
                and (
                    current_host == "uyanip.com"
                    or current_host.endswith(".uyanip.com")
                    or current_host == "api.duyandb.com"
                )
            ):
                payload["raw_account"] = account
                payload["raw_password"] = password
        elif config.account and config.password:
            payload["raw_account"] = config.account
            payload["raw_password"] = config.password
    task_context = dict(SEARCH_TASK_CONTEXT.get())
    query_variant = first_string(task_context.get("query_variant")) or "default"
    query_text = first_string(task_context.get("query_text")) or keyword
    checkpoint_path = first_string(
        task_context.get("checkpoint_path") or task_context.get("path")
    ) or "browser"
    config_fingerprint = first_string(task_context.get("config_fingerprint"))
    checkpoint_cursor = first_string(task_context.get("cursor_token"))
    if not checkpoint_cursor:
        checkpoint_cursor = first_string(task_context.get("resume_url")) or current_url
    # ``current_url`` is the page that the parent will actually resume.  A
    # checkpoint cursor may be an opaque token or page number and is bound
    # independently below rather than being mislabelled as a URL.
    resume_url = current_url or first_string(task_context.get("resume_url"))
    search_job_payload = {
        "config_fingerprint": config_fingerprint,
        "record_type": search_record_type,
        "source": source,
        "keyword_digest": value_digest(keyword),
        "query_variant": query_variant,
        "checkpoint_path": checkpoint_path,
    }
    search_job_id = hashlib.sha256(
        json.dumps(
            search_job_payload,
            ensure_ascii=False,
            sort_keys=True,
            separators=(",", ":"),
        ).encode("utf-8")
    ).hexdigest()
    selected_auth_mode = (
        "site_personal"
        if source == UYANIP_SOURCE or auth_entry_mode == "site_personal"
        else (config.path if config is not None else "institution")
        if is_auth
        else "public"
    )
    request = build_verification_request(
        event=event,
        event_id=event_id,
        producer="search",
        binding={
            "run_id": "",
            "search_job_id": search_job_id,
            "auth_check_id": auth_entry_id or event_id if is_auth else "",
            "record_id": "",
            "record_type": search_record_type,
            "source": source,
            "planned_channel": source,
            "auth_state_scope": str(payload.get("auth_state_scope") or ""),
            "auth_mode": selected_auth_mode,
            "principal_digest": search_challenge_principal_digest(
                config,
                source,
                selected_auth_mode,
            ),
            "access_mode": str(payload.get("access_mode") or ""),
            "query_variant": query_variant,
            "query_digest": value_digest(query_text),
            "cursor_digest": value_digest(checkpoint_cursor),
            "candidate_id": "",
        },
        ttl_seconds=max(1, int(timeout_seconds)),
        public_fields=payload,
        challenge_url=current_url,
        resume_url=resume_url,
    )
    with SEARCH_VERIFICATION_REQUESTS_LOCK:
        SEARCH_VERIFICATION_REQUESTS[event_id] = request
    return request


def run_search_challenge_hook(command: list[str], payload: dict[str, Any], timeout_seconds: int) -> SearchChallengeControlResult:
    try:
        completed = subprocess.run(
            command,
            input=json.dumps(payload, ensure_ascii=False),
            text=True,
            capture_output=True,
            timeout=timeout_seconds,
        )
    except subprocess.TimeoutExpired:
        return SearchChallengeControlResult("unhandled", "hook_timeout")
    except Exception as exc:
        return SearchChallengeControlResult("unhandled", f"hook_failed:{exc.__class__.__name__}")
    if completed.returncode != 0:
        return SearchChallengeControlResult("unhandled", f"hook_exit_{completed.returncode}")
    stdout = (completed.stdout or "").strip()
    if not stdout:
        return SearchChallengeControlResult("unhandled", "hook_empty_stdout")
    try:
        loaded = json.loads(stdout)
    except Exception:
        return SearchChallengeControlResult("unhandled", "hook_non_json_stdout")
    if not isinstance(loaded, dict):
        return SearchChallengeControlResult("unhandled", "hook_invalid_json")
    return parse_search_challenge_response(
        loaded,
        request=payload,
        allow_legacy_sync=not verification_hook_uses_bundled_controller(command),
        consume=True,
    )


async def verification_control(
    page: Any,
    source: str,
    keyword: str,
    current_url: str,
    body: str,
    *,
    event: str = "search_challenge",
    reason: str = "security_challenge_required",
    config: SearchConfig | None = None,
    success_markers: list[str] | None = None,
    auth_entry_id: str = "",
    auth_entry_mode: AuthEntryMode = "institution",
    control_mode: str = "",
) -> SearchChallengeControlResult:
    command = verification_hook_command(event)
    if not command:
        return SearchChallengeControlResult("unhandled", "verification_hook_not_available")
    event_id = verification_event_id(source, event)
    artifacts = search_challenge_artifact_paths(event_id)
    for path in artifacts.values():
        path.parent.mkdir(parents=True, exist_ok=True)
    screenshot_path = await capture_search_challenge_screenshot(page, artifacts["screenshot"])
    seed_storage_state_path = await export_current_browser_storage_state(page, artifacts["storage_state"])
    parent_browser_control = await parent_browser_control_for_page(page)
    payload = build_search_challenge_payload(
        event_id=event_id,
        source=source,
        keyword=keyword,
        reason=reason,
        current_url=current_url,
        body=body,
        screenshot_path=screenshot_path,
        storage_state_path=str(artifacts["storage_state"]),
        response_path=str(artifacts["response"]),
        seed_storage_state_path=seed_storage_state_path,
        hook_screenshot_path=str(artifacts["hook_screenshot"]),
        event=event,
        config=config,
        success_markers=success_markers,
        auth_entry_id=auth_entry_id,
        auth_entry_mode=auth_entry_mode,
        control_mode=control_mode,
        parent_browser_control=parent_browser_control,
        trusted_bundled_hook=verification_hook_uses_bundled_controller(command),
    )
    registered, registration_reason = search_auth_control_store().register_verification_request(
        payload
    )
    if not registered:
        return SearchChallengeControlResult(
            "unhandled",
            registration_reason,
            protocol_request=payload,
        )
    control = await asyncio.to_thread(run_search_challenge_hook, command, payload, verification_hook_timeout_seconds(event))
    return await wait_if_search_manual_pending(control, event_id)


async def complete_bounded_chrome_handoff(
    browser_type: Any,
    transition: BrowserControlTransitionResult,
    control: SearchChallengeControlResult,
    source: str,
    keyword: str,
    config: SearchConfig,
    *,
    event: str = "search_challenge",
    context_kwargs: dict[str, Any] | None = None,
    success_markers: list[str] | None = None,
    auth_entry_id: str = "",
    auth_entry_mode: AuthEntryMode = "institution",
    control_mode: str = "",
) -> tuple[
    BrowserControlTransitionResult,
    SearchChallengeControlResult,
    str,
]:
    if transition.mode != "switch_browser":
        return transition, control, ""
    settle_seconds = env_seconds(
        "LAPS_BROWSER_SWITCH_COMPONENT_SETTLE_SECONDS",
        5,
        0,
    )
    settle_deadline = time.monotonic() + settle_seconds
    body = ""
    while True:
        body = await page_body_text(transition.page)
        if await web_page_needs_verification_control(
            source,
            transition.page,
            0,
            body,
        ):
            break
        if time.monotonic() >= settle_deadline:
            break
        try:
            await transition.page.wait_for_timeout(250)
        except Exception:
            break
    current_url = first_string(getattr(transition.page, "url", ""))
    chrome_control = await verification_control(
        transition.page,
        source,
        keyword,
        current_url,
        body,
        event=event,
        reason=classify_search_challenge(body, url=current_url),
        config=config,
        success_markers=success_markers,
        auth_entry_id=auth_entry_id,
        auth_entry_mode=auth_entry_mode,
        control_mode=control_mode,
    )
    if (
        chrome_control.action == "retry"
        and chrome_control.external_browser_session
        and chrome_control.browser_transport
        == ORDINARY_CHROME_EXTERNAL_SESSION_TRANSPORT
        and not chrome_control.same_browser_handoff
    ):
        return transition, chrome_control, ""
    if (
        chrome_control.action != "retry"
        or chrome_control.switch_browser_to
        or not chrome_control.same_browser_handoff
    ):
        return (
            transition,
            chrome_control,
            "chrome_parent_handoff_failed:"
            f"{chrome_control.reason or chrome_control.action}",
        )
    chrome_transition = await apply_browser_control_transition(
        browser_type,
        transition.browser,
        transition.context,
        transition.page,
        chrome_control,
        "",
        context_kwargs,
    )
    if chrome_transition.error or chrome_transition.mode != "same_browser":
        return (
            chrome_transition,
            chrome_control,
            chrome_transition.error or "chrome_same_browser_handoff_missing",
        )
    return chrome_transition, chrome_control, ""


async def handle_search_verification_challenge(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    browser_type: Any,
    browser: Any,
    context: Any,
    page: Any,
    page_url: str,
    body: str,
    context_kwargs: dict[str, Any],
    *,
    control_reason: str = "security_challenge_required",
) -> tuple[bool, Any, Any, Any]:
    SEARCH_CHALLENGE_SNAPSHOT.set(None)
    control = await verification_control(
        page,
        source,
        keyword,
        page_url,
        body,
        reason=control_reason,
        config=runtime.config,
    )
    if control.action != "retry":
        runtime.skip(source, keyword, f"search_challenge_unresolved:{control.reason or control.action}")
        return False, browser, context, page
    if (
        control.external_browser_session
        and SEARCH_TASK_CONTEXT.get().get("path") == "restricted_browser"
    ):
        accepted, reason = accept_ordinary_chrome_external_result(
            runtime,
            source,
            control,
        )
        if not accepted:
            runtime.skip(
                source,
                keyword,
                f"search_challenge_unresolved:{reason}",
            )
            return False, browser, context, page
        external_resume = EXTERNAL_BROWSER_SEARCH_RESUME.get()
        if isinstance(external_resume, dict):
            snapshots = external_resume.get("snapshots")
            if isinstance(snapshots, list) and snapshots:
                SEARCH_CHALLENGE_SNAPSHOT.set(snapshots[0])
        return True, browser, context, page
    snapshot = load_sanitized_search_snapshot(control.sanitized_search_snapshot_path)
    if snapshot is not None:
        SEARCH_CHALLENGE_SNAPSHOT.set(snapshot)
    target_url = page_url
    transition = await apply_browser_control_transition(
        browser_type,
        browser,
        context,
        page,
        control,
        target_url,
        context_kwargs,
        allow_missing_state=True,
    )
    if transition.error:
        runtime.skip(
            source,
            keyword,
            f"search_challenge_unresolved:{transition.error}",
        )
        return False, transition.browser, transition.context, transition.page
    initial_transition_mode = transition.mode
    transition, control, chrome_error = await complete_bounded_chrome_handoff(
        browser_type,
        transition,
        control,
        source,
        keyword,
        runtime.config,
        context_kwargs=context_kwargs,
    )
    if chrome_error:
        runtime.skip(
            source,
            keyword,
            f"search_challenge_unresolved:{chrome_error}",
        )
        return False, transition.browser, transition.context, transition.page
    if (
        control.external_browser_session
        and SEARCH_TASK_CONTEXT.get().get("path") == "restricted_browser"
    ):
        accepted, reason = accept_ordinary_chrome_external_result(
            runtime,
            source,
            control,
        )
        if not accepted:
            runtime.skip(
                source,
                keyword,
                f"search_challenge_unresolved:{reason}",
            )
            return False, transition.browser, transition.context, transition.page
        external_resume = EXTERNAL_BROWSER_SEARCH_RESUME.get()
        if isinstance(external_resume, dict):
            snapshots = external_resume.get("snapshots")
            if isinstance(snapshots, list) and snapshots:
                SEARCH_CHALLENGE_SNAPSHOT.set(snapshots[0])
        return True, transition.browser, transition.context, transition.page
    browser, context, page = (
        transition.browser,
        transition.context,
        transition.page,
    )
    active_browser_name = transition.browser_name
    chrome_snapshot = load_sanitized_search_snapshot(
        control.sanitized_search_snapshot_path
    )
    if chrome_snapshot is not None:
        snapshot = chrome_snapshot
        SEARCH_CHALLENGE_SNAPSHOT.set(snapshot)
    if initial_transition_mode in {"same_browser", "switch_browser"}:
        page = await fresh_browser_context_page(context, target_url)
    if source == "Web of Science Starter API (Clarivate)" and urllib.parse.urlsplit(
        first_string(page.url)
    ).path.casefold().endswith("/wos/woscc/basic-search"):
        resumed_page = await submit_wos_basic_search(page, keyword)
        if resumed_page is None:
            runtime.skip(source, keyword, "search_challenge_retry_wos_form_not_ready")
            return False, browser, context, page
        page = resumed_page
    deadline = time.monotonic() + env_seconds("LAPS_SEARCH_CHALLENGE_POST_RETRY_SECONDS", 10, 1)
    new_body = ""
    remaining_challenge = "unknown_verification"
    while time.monotonic() < deadline:
        try:
            new_body = await page.locator("body").inner_text(timeout=5000)
        except Exception:
            new_body = ""
        remaining_challenge = classify_search_challenge(
            new_body,
            url=first_string(page.url),
        )
        active_verification = await page_has_active_verification_challenge(
            page,
            source=source,
            body=new_body,
        )
        if not active_verification and remaining_challenge != "institution_login":
            break
        await page.wait_for_timeout(500)
    active_verification = await page_has_active_verification_challenge(
        page,
        source=source,
        body=new_body,
    )
    if active_verification or remaining_challenge == "institution_login":
        if snapshot is None:
            runtime.skip(source, keyword, f"search_challenge_unresolved:{control.reason or 'challenge_still_present'}")
            return False, browser, context, page
    if SEARCH_TASK_CONTEXT.get().get("path") == "restricted_browser":
        try:
            record_type = current_search_record_type()
            policy = (
                patent_source_auth_policy.get(source)
                if record_type == "patent"
                else literature_source_auth_policy.get(source)
            )
            if policy is not None:
                persisted, persist_reason = await persist_search_auth_context_state(
                    context,
                    runtime.config,
                    source,
                    policy,
                    "challenge_recovered",
                )
                if not persisted:
                    runtime.skip(
                        source,
                        keyword,
                        f"search_challenge_auth_state_not_published:{persist_reason}",
                    )
                    return False, browser, context, page
            if active_browser_name:
                save_auth_browser_transport(
                    runtime.config,
                    source,
                    active_browser_name,
                    True,
                )
        except Exception:
            pass
    return True, browser, context, page


def google_scholar_authors_from_meta(meta: str) -> list[str]:
    parts = [part.strip() for part in re.split(r"\s+-\s+", meta or "") if part.strip()]
    if not parts:
        return []
    return [part.strip() for part in parts[0].split(",") if part.strip()]


def google_scholar_journal_from_meta(meta: str) -> str | None:
    parts = [part.strip() for part in re.split(r"\s+-\s+", meta or "") if part.strip()]
    if len(parts) < 2:
        return None
    journal = re.sub(r"\b(18|19|20|21)\d{2}\b", "", parts[1]).strip(" ,;-")
    return journal or None


def google_scholar_record_url(links: list[dict[str, Any]]) -> str:
    for link in links:
        role = first_string(link.get("role")).casefold()
        href = unwrap_google_redirect_url(first_string(link.get("href")))
        if href and role == "title":
            return href
    for link in links:
        href = unwrap_google_redirect_url(first_string(link.get("href")))
        if href:
            return href
    return ""


def parse_google_scholar_item(item: dict[str, Any], source: str, keyword: str, rank: int) -> LiteratureRecord | None:
    links = item.get("links") if isinstance(item.get("links"), list) else []
    title = first_string(item.get("title"))
    meta = first_string(item.get("meta"))
    snippet = first_string(item.get("snippet"))
    values: list[Any] = [title, meta, snippet]
    for link in links:
        if isinstance(link, dict):
            values.extend([link.get("text"), link.get("href"), unwrap_google_redirect_url(first_string(link.get("href")))])
    doi = extract_doi_from_values(*values)
    observed_links = [
        unwrap_google_redirect_url(first_string(link.get("href")))
        for link in links
        if isinstance(link, dict)
    ]
    pdf_url = first_observed_pdf_url(observed_links)
    record_url = google_scholar_record_url([link for link in links if isinstance(link, dict)])
    if not title:
        title = first_string(next((link.get("text") for link in links if isinstance(link, dict) and first_string(link.get("text"))), ""))
    title = title or doi or pdf_url or record_url
    if not title:
        return None
    return LiteratureRecord(
        title=title,
        authors=google_scholar_authors_from_meta(meta),
        year=parse_year(meta),
        journal=google_scholar_journal_from_meta(meta),
        doi=doi or None,
        url=pdf_url or None,
        source=source,
        keyword=keyword,
        rank=rank,
        raw_id=doi or record_url or None,
    )


async def extract_google_scholar_page_items(page: Any) -> list[dict[str, Any]]:
    return await page.evaluate(
        """() => {
            const rawCards = Array.from(document.querySelectorAll('div.gs_r.gs_or, div.gs_r'));
            const seen = new Set();
            const cards = rawCards.filter((card) => {
                if (!card || seen.has(card)) return false;
                seen.add(card);
                return true;
            });
            return cards.map((card, i) => {
                const titleAnchor = card.querySelector('.gs_rt a, h3 a');
                const titleText = (titleAnchor?.innerText || card.querySelector('.gs_rt, h3')?.innerText || '').trim();
                const meta = (card.querySelector('.gs_a')?.innerText || '').trim();
                const snippet = (card.querySelector('.gs_rs')?.innerText || '').trim();
                const links = Array.from(card.querySelectorAll('a')).map((a) => {
                    let role = 'other';
                    if (a === titleAnchor) role = 'title';
                    if (a.closest('.gs_or_ggsm')) role = 'side';
                    if (a.closest('.gs_fl')) role = 'footer';
                    return {
                        text: (a.innerText || '').trim(),
                        href: a.href || '',
                        role
                    };
                }).filter((link) => link.href || link.text);
                return {title: titleText, meta, snippet, links, rank: i + 1};
            }).filter((item) => item.title || item.links.length);
        }"""
    )


async def google_next_page_url(page: Any) -> str:
    return first_string(
        await page.evaluate(
            """() => {
                const links = Array.from(document.querySelectorAll('a'));
                const next = links.find((a) => {
                    const aria = (a.getAttribute('aria-label') || '').trim().toLowerCase();
                    const text = (a.innerText || '').trim().toLowerCase();
                    return a.id === 'pnnext' || aria === 'next' || text === 'next' || text === '下一页';
                });
                return next ? next.href : '';
            }"""
        )
    )


def google_scholar_no_results(body: str) -> bool:
    lowered = body.casefold()
    return any(
        marker in lowered
        for marker in (
            "did not match any articles",
            "your search did not match any articles",
            "no articles found",
            "未找到任何文章",
            "没有找到相关文章",
        )
    )


def google_scholar_storage_state_path() -> Path:
    return USER_CONFIG_DIR / "browser_state" / "google_scholar.json"


def google_scholar_storage_state_usable() -> Path | None:
    path = google_scholar_storage_state_path()
    if not path.exists() or not path.is_file():
        return None
    ttl = env_seconds(
        "LAPS_GOOGLE_SCHOLAR_STATE_TTL_SECONDS",
        24 * 60 * 60,
        60,
    )
    try:
        age = max(0.0, time.time() - path.stat().st_mtime)
    except OSError:
        return None
    if age > ttl:
        try:
            path.unlink()
        except OSError:
            pass
        return None
    return path


def invalidate_google_scholar_storage_state() -> None:
    try:
        google_scholar_storage_state_path().unlink(missing_ok=True)
    except OSError:
        pass


async def search_google_scholar(runtime: SearchRuntime, source: str, policy: SourceAccessPolicy, keyword: str, limit: int) -> list[LiteratureRecord]:
    query_url = build_web_search_url(source, policy, keyword, limit)
    if not query_url:
        runtime.browser_disabled(source, keyword, "Google Scholar has no configured search URL")
        return []
    records: list[LiteratureRecord] = []
    resume_url, completed_pages = resumed_page_state(runtime, "literature", source, keyword, query_url)
    seen_pages: set[str] = set()
    try:
        async_playwright = load_async_playwright()

        async with runtime.browser_sem:
            async with async_playwright() as pw:
                browser = await pw.chromium.launch(headless=True)
                context_kwargs: dict[str, Any] = {}
                saved_state = google_scholar_storage_state_usable()
                if saved_state is not None:
                    context_kwargs["storage_state"] = str(saved_state)
                context = await browser.new_context(**context_kwargs)
                page = await context.new_page()
                page_url = resume_url or query_url
                while page_url and page_url not in seen_pages:
                    seen_pages.add(page_url)
                    scholar_host = urllib.parse.urlparse(page_url).netloc
                    await wait_for_rate_limiter(
                        runtime.limiter,
                        scholar_host,
                        kind="browser",
                        source=source,
                    )
                    await page.goto(page_url, wait_until="domcontentloaded", timeout=30000)
                    try:
                        await page.wait_for_selector("div.gs_r, #gs_res_ccl_mid, form[action*='/sorry/']", timeout=10000)
                    except Exception:
                        pass
                    body = await page.locator("body").inner_text(timeout=10000)
                    if body_has_verification_challenge(body):
                        if saved_state is not None:
                            invalidate_google_scholar_storage_state()
                            saved_state = None
                            context_kwargs.pop("storage_state", None)
                        resolved, browser, context, page = await handle_search_verification_challenge(runtime, source, keyword, pw.chromium, browser, context, page, page_url, body, context_kwargs)
                        if not resolved:
                            await runtime.limiter.register_cooldown(
                                scholar_host,
                                env_seconds(
                                    "LAPS_GOOGLE_SCHOLAR_CHALLENGE_COOLDOWN_SECONDS",
                                    300,
                                    30,
                                ),
                                "google_scholar_challenge_unresolved",
                            )
                            runtime.mark_current_run("literature", source, keyword, "incomplete", "search_challenge_unresolved")
                            break
                        await page.wait_for_timeout(1000)
                        body = await page.locator("body").inner_text(timeout=10000)
                        if body_has_verification_challenge(body) or classify_search_challenge(body, url=first_string(page.url)) in {
                            "captcha_required",
                            "mfa_required",
                            "robot_check",
                            "cloudflare_or_waf",
                            "access_denied",
                            "institution_login",
                        }:
                            runtime.skip(source, keyword, "search_challenge_unresolved:challenge_still_present_after_retry")
                            await runtime.limiter.register_cooldown(
                                scholar_host,
                                env_seconds(
                                    "LAPS_GOOGLE_SCHOLAR_CHALLENGE_COOLDOWN_SECONDS",
                                    300,
                                    30,
                                ),
                                "google_scholar_challenge_still_present",
                            )
                            runtime.mark_current_run("literature", source, keyword, "incomplete", "search_challenge_unresolved")
                            break
                        state_path = google_scholar_storage_state_path()
                        state_path.parent.mkdir(parents=True, exist_ok=True)
                        await context.storage_state(path=str(state_path))
                        chmod_user_config(state_path)
                        saved_state = state_path
                    page_records: list[LiteratureRecord] = []
                    for item in await extract_google_scholar_page_items(page):
                        record = parse_google_scholar_item(item, source, keyword, len(records) + 1)
                        if record is None:
                            continue
                        page_records.append(record)
                    if not page_records and not google_scholar_no_results(body):
                        runtime.skip(source, keyword, "Google Scholar dedicated parser found no result cards on a non-empty page")
                        runtime.mark_current_run("literature", source, keyword, "incomplete", "google_scholar_results_not_detected")
                        break
                    await enrich_missing_dois(runtime, source, keyword, page_records)
                    next_url = await google_next_page_url(page)
                    exhausted = not next_url
                    completed_pages += 1
                    persist_search_page(
                        runtime,
                        "literature",
                        source,
                        keyword,
                        page_records,
                        next_token="" if exhausted else next_url,
                        exhausted=exhausted,
                        page_number=completed_pages,
                        reason="coverage_scope:source_visible" if exhausted else "",
                    )
                    records.extend(page_records)
                    if exhausted:
                        break
                    if next_url in seen_pages:
                        runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_page_url")
                        break
                    page_url = next_url
                await browser.close()
        return records
    except Exception as exc:
        runtime.skip(source, keyword, f"Google Scholar browser parse failed: {safe_error_text(str(exc))}")
        if completed_pages:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "browser_failed_after_partial_results")
        return records


