def institutional_agreement_non_auth_page(body: str, final_url: str) -> bool:
    lowered = " ".join((body or "", final_url or "")).casefold()
    return any(
        marker in lowered
        for marker in (
            "acsopenscience.org/institutions/institutional-open-access-agreements",
            "springernature.com/gp/open-science/oa-agreements",
            "acs institutional open access agreements",
            "paying for oa apcs through your institution",
        )
    )


def auth_body_has_blocking_failure(body: str) -> bool:
    lowered = (body or "").casefold()
    return any(marker in lowered for marker in AUTH_EXPLICIT_ACCESS_FAILURE_MARKERS) or classify_search_challenge(
        body
    ) == "mfa_required"


def institution_text_contains_exact_school(
    body: str,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    normalized_body = unicodedata.normalize("NFKC", str(body or ""))
    segments = [segment.strip() for segment in re.split(r"[\r\n|•]+", normalized_body) if segment.strip()]
    return any(
        institution_name_matches_exact(segment, school, school_aliases)
        for segment in segments
    )


def institution_access_pattern_contains_exact_school(
    body: str,
    school: str,
    school_aliases: Iterable[str],
    patterns: Iterable[str],
) -> bool:
    if not school.strip():
        return False
    normalized = unicodedata.normalize("NFKC", str(body or ""))
    for pattern in patterns:
        for match in re.finditer(pattern, normalized, flags=re.IGNORECASE):
            candidate = str(match.groupdict().get("school") or "").strip(" \t,;:.")
            if candidate and institution_name_matches_exact(candidate, school, school_aliases):
                return True
    return False


def access_provided_by_text_contains_exact_school(
    body: str,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    if not school.strip():
        return False
    normalized = unicodedata.normalize("NFKC", str(body or ""))
    for match in re.finditer(
        r"access\s+provided\s+by\s*:?\s*([^\r\n|•]+)",
        normalized,
        flags=re.IGNORECASE,
    ):
        candidate = re.split(
            r"\s+(?:sign\s+out|log\s*out|logout|sign\s+in|log\s+in)\b",
            match.group(1),
            maxsplit=1,
            flags=re.IGNORECASE,
        )[0].strip(" \t,;:")
        if institution_authorization_name_matches(
            candidate,
            school,
            school_aliases,
        ):
            return True
    return False


def elsevier_institution_marker_matches_exact_school(
    value: Any,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    candidate = unicodedata.normalize("NFKC", first_string(value)).strip()
    if institution_name_matches_exact(candidate, school, school_aliases):
        return True
    for pattern in (
        r"^\[\s*(?P<school>[^\[\]]+?)\s*\]\s*institutional\s+access\s*$",
        r"^(?P<school>.+?)\s+institutional\s+access\s*$",
    ):
        match = re.fullmatch(pattern, candidate, flags=re.IGNORECASE)
        if match and institution_name_matches_exact(
            match.group("school"),
            school,
            school_aliases,
        ):
            return True
    return False


def institution_sso_round_trip_marker(
    body: str,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    return bool(
        school.strip()
        and institution_text_contains_exact_school(body, school, school_aliases)
        and not body_has_verification_challenge(body)
        and not auth_body_has_blocking_failure(body)
    )


def imported_sso_state_has_no_failure_marker(body: str, final_url: str) -> bool:
    return bool(
        not institutional_agreement_non_auth_page(body, final_url)
        and not body_has_verification_challenge(body)
        and not auth_body_has_blocking_failure(body)
    )


