def configured_institution_display_name_matches(
    candidate: Any,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    if institution_authorization_name_matches(candidate, school, school_aliases):
        return True
    if not configured_institution_is_xiamen(school, school_aliases):
        return False
    return normalize_institution_name(candidate) in {
        normalize_institution_name("Xiamen University"),
        normalize_institution_name("厦门大学"),
    }


def cnki_institution_name_matches(
    candidate: Any,
    school: str,
    school_aliases: Iterable[str] = (),
) -> bool:
    return configured_institution_display_name_matches(
        candidate,
        school,
        school_aliases,
    )


async def cnki_active_verification_challenge(page: Any) -> bool:
    current_url = first_string(getattr(page, "url", ""))
    parsed = urllib.parse.urlsplit(current_url)
    if parsed.hostname and parsed.hostname.casefold().endswith("cnki.net") and "/verify/" in parsed.path.casefold():
        return True
    selectors = (
        "#tcaptcha_transform_dy",
        "#tCaptchaDyMainWrap",
        "iframe[src*='captcha' i]",
        "iframe[src*='challenge' i]",
        "iframe[title*='验证']",
        "[class*='captcha' i][class*='show' i]",
        "#challenge-running",
        ".cf-challenge",
        "[data-testid*='challenge' i]",
    )
    for selector in selectors:
        try:
            locators = page.locator(selector)
            for index in range(min(await locators.count(), 12)):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=300):
                    continue
                box = await locator.bounding_box(timeout=500)
                if not box or box["width"] < 20 or box["height"] < 20:
                    continue
                if box["x"] + box["width"] <= 0 or box["y"] + box["height"] <= 0:
                    continue
                opacity = await locator.evaluate(
                    "element => Number.parseFloat(getComputedStyle(element).opacity || '1')"
                )
                if float(opacity or 0) > 0.05:
                    return True
        except Exception:
            continue
    return False


async def wanfang_login_surface_visible(page: Any) -> bool:
    try:
        locators = page.locator(
            "iframe#anxs-8qwe-login[src*='my.wanfangdata.com.cn'], "
            "iframe[src*='fsso.wanfangdata.com.cn']"
        )
        for index in range(min(await locators.count(), 8)):
            locator = locators.nth(index)
            if not await locator.is_visible(timeout=300):
                continue
            box = await locator.bounding_box(timeout=500)
            if box and box["width"] >= 100 and box["height"] >= 100:
                return True
    except Exception:
        pass
    parsed = urllib.parse.urlsplit(first_string(getattr(page, "url", "")))
    host = (parsed.hostname or "").casefold()
    path = (parsed.path or "").casefold()
    return bool(
        host in {"my.wanfangdata.com.cn", "fsso.wanfangdata.com.cn"}
        and any(marker in path for marker in ("/auth/", "/login", "/wayf"))
    )


def wanfang_personal_login_text(text: Any) -> bool:
    normalized = first_string(text).casefold()
    return bool(
        "个人密码登录" in normalized
        and any(
            marker in normalized
            for marker in ("请输入用户名/邮箱/手机号", "短信登录", "扫码登录")
        )
    )


async def wanfang_personal_login_surface_visible(page: Any) -> bool:
    for frame in getattr(page, "frames", []):
        if frame == getattr(page, "main_frame", None):
            continue
        try:
            text = await frame.locator("body").inner_text(timeout=500)
        except Exception:
            continue
        if wanfang_personal_login_text(text):
            return True
    return False


async def attempt_wanfang_nstr_online_read(page: Any) -> str:
    if await wanfang_personal_login_surface_visible(page):
        return "personal_account_required"
    try:
        controls = page.locator(".onlineRead.buttonItem:visible")
        if await controls.count() != 1:
            return ""
        await controls.first.click(timeout=3000)
    except Exception:
        return ""
    deadline = time.monotonic() + 5
    while time.monotonic() < deadline:
        if await wanfang_personal_login_surface_visible(page):
            return "personal_account_required"
        try:
            await page.wait_for_timeout(250)
        except Exception:
            break
    return ""


