class WosDetailDoiParser(HTMLParser):
    def __init__(self) -> None:
        super().__init__(convert_charrefs=True)
        self.values: list[str] = []
        self.capture_depth = 0

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        attributes = {name.casefold(): first_string(value) for name, value in attrs}
        name = attributes.get("name", "").casefold()
        prop = attributes.get("property", "").casefold()
        if tag.casefold() == "meta" and (name in {"citation_doi", "dc.identifier"} or "doi" in prop):
            self.values.append(attributes.get("content", ""))
        href = attributes.get("href", "")
        if tag.casefold() in {"a", "link"} and "doi.org" in href.casefold():
            self.values.append(href)
        doi_marker = " ".join(
            (attributes.get("data-ta", ""), attributes.get("data-testid", ""))
        ).casefold()
        if self.capture_depth:
            self.capture_depth += 1
        elif "doi" in doi_marker:
            self.capture_depth = 1

    def handle_endtag(self, tag: str) -> None:
        del tag
        if self.capture_depth:
            self.capture_depth -= 1

    def handle_data(self, data: str) -> None:
        if self.capture_depth and data.strip():
            self.values.append(data)


def extract_wos_detail_doi(html_text: str, body_text: str = "") -> str:
    parser = WosDetailDoiParser()
    try:
        parser.feed(html_text or "")
    except Exception:
        pass
    return extract_doi_from_values(*parser.values, body_text)


async def enrich_wos_browser_details(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    context: Any,
    records: list[LiteratureRecord],
) -> None:
    timeout_seconds = min(60, env_seconds("LAPS_WOS_DETAIL_TIMEOUT_SECONDS", 20, 1))
    for record in records:
        if normalize_doi(record.doi):
            continue
        detail_url = first_string(record.raw_id)
        if not detail_url.startswith(("http://", "https://")):
            continue
        detail_page = None
        try:
            await wait_for_rate_limiter(
                runtime.limiter,
                urllib.parse.urlparse(detail_url).netloc,
                kind="browser",
                source=source,
            )
            detail_page = await context.new_page()
            response = await detail_page.goto(
                detail_url,
                wait_until="domcontentloaded",
                timeout=timeout_seconds * 1000,
            )
            response_status = int(response.status) if response is not None else 0
            if response_status >= 400:
                runtime.skip(source, keyword, f"WOS full-record returned HTTP {response_status}")
                continue
            deadline = time.monotonic() + timeout_seconds
            while time.monotonic() < deadline:
                body = await page_body_text(detail_page)
                if body_has_verification_challenge(body):
                    runtime.skip(source, keyword, "WOS full-record requires renewed verification")
                    return
                try:
                    html_text = await detail_page.content()
                except Exception:
                    html_text = ""
                doi = extract_wos_detail_doi(html_text, body)
                if doi:
                    record.doi = doi
                    break
                pdf_url = extract_pdf_url_from_landing_html(
                    html_text,
                    detail_url,
                )
                if pdf_url:
                    record.url = pdf_url
                    break
                await detail_page.wait_for_timeout(500)
        except Exception as exc:
            runtime.skip(source, keyword, f"WOS full-record DOI enrichment failed: {safe_error_text(str(exc))}")
        finally:
            if detail_page is not None:
                try:
                    await detail_page.close()
                except Exception:
                    pass


async def submit_wos_basic_search(page: Any, keyword: str) -> Any | None:
    current_path = urllib.parse.urlsplit(first_string(getattr(page, "url", ""))).path.casefold()
    if not current_path.endswith("/wos/woscc/basic-search"):
        return None
    try:
        await page.wait_for_selector("input[data-ta='search-criteria-input']", timeout=10000)
    except Exception:
        return None
    await dismiss_browser_cookie_banners(page)
    query_locator = page.locator("input[data-ta='search-criteria-input']").first
    try:
        if await query_locator.count() == 0 or not await query_locator.is_visible(timeout=500):
            return None
        await query_locator.click(timeout=3000)
        await query_locator.fill("", timeout=3000)
        await query_locator.press_sequentially(quoted_search_phrase(keyword), delay=20, timeout=10000)
        await page.wait_for_timeout(500)
    except Exception:
        return None
    run_search = page.locator("button[data-ta='run-search']").first
    try:
        known_page_ids = {id(candidate) for candidate in page.context.pages}
    except Exception:
        known_page_ids = {id(page)}
    try:
        if await run_search.count() == 0 or not await run_search.is_visible(timeout=500):
            return None
        for _ in range(20):
            if await run_search.is_enabled(timeout=500):
                break
            await page.wait_for_timeout(250)
        else:
            return None
    except Exception:
        return None
    await dismiss_browser_cookie_banners(page)
    try:
        await run_search.click(timeout=3000)
    except Exception:
        await dismiss_browser_cookie_banners(page)
        try:
            await run_search.click(timeout=3000)
        except Exception:
            return None
    result_page = page
    ready_selector = WEB_SOURCE_DYNAMIC_READY_SELECTORS["Web of Science Starter API (Clarivate)"]
    ready_attempts = min(60, env_seconds("LAPS_WOS_SEARCH_READY_TIMEOUT_SECONDS", 30, 1)) * 2
    for attempt in range(ready_attempts):
        try:
            new_pages = [candidate for candidate in page.context.pages if id(candidate) not in known_page_ids]
        except Exception:
            new_pages = []
        if new_pages:
            result_page = new_pages[-1]
        result_path = urllib.parse.urlsplit(first_string(getattr(result_page, "url", ""))).path.casefold()
        if result_path and not result_path.endswith("/wos/woscc/basic-search"):
            break
        try:
            if await result_page.locator(ready_selector).count() > 0:
                break
        except Exception:
            pass
        if attempt % 2 == 1:
            body = await page_body_text(result_page)
            if browser_profile_has_explicit_no_results("Web of Science Starter API (Clarivate)", body):
                break
        try:
            await result_page.wait_for_timeout(500)
        except Exception:
            break
    try:
        await result_page.wait_for_load_state("domcontentloaded", timeout=15000)
    except Exception:
        pass
    try:
        await result_page.wait_for_timeout(1000)
    except Exception:
        pass
    return result_page


def cnki_home_search_surface(final_url: str) -> bool:
    parsed = urllib.parse.urlsplit(first_string(final_url))
    return bool(
        (parsed.hostname or "").casefold() == "www.cnki.net"
        and (parsed.path or "/").rstrip("/") == ""
    )


def browser_internal_navigation_error_url(final_url: str) -> bool:
    lowered = first_string(final_url).casefold()
    return lowered.startswith("chrome-error://") or lowered.startswith(
        "about:neterror"
    )


def cnki_navigation_request_target(candidate_url: str) -> bool:
    parsed = urllib.parse.urlsplit(first_string(candidate_url))
    if (parsed.hostname or "").casefold() != "kns.cnki.net":
        return False
    path = (parsed.path or "").casefold()
    return path.startswith("/starter") or path.startswith("/kns8s/")


async def submit_cnki_browser_search(page: Any, keyword: str) -> Any | None:
    CNKI_SEARCH_NAVIGATION_TARGET.set("")
    if not cnki_home_search_surface(first_string(getattr(page, "url", ""))):
        return page
    if await cnki_active_verification_challenge(page):
        return page
    input_selectors = WEB_SOURCE_SEARCH_SURFACE_SELECTORS[CNKI_SOURCE]
    query_locator = None
    for selector in input_selectors:
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                query_locator = candidate
                break
        except Exception:
            continue
    if query_locator is None:
        return None
    try:
        await query_locator.click(timeout=3000)
        await query_locator.fill("", timeout=3000)
        await query_locator.press_sequentially(keyword, delay=25, timeout=15000)
    except Exception:
        return None

    try:
        known_page_ids = {id(candidate) for candidate in page.context.pages}
    except Exception:
        known_page_ids = {id(page)}
    observed_navigation = {"url": ""}

    def remember_navigation(request: Any) -> None:
        try:
            if (
                request.is_navigation_request()
                and cnki_navigation_request_target(first_string(request.url))
            ):
                observed_navigation["url"] = first_string(request.url)
        except Exception:
            pass

    try:
        page.context.on("request", remember_navigation)
    except Exception:
        pass

    def finish(result_page: Any) -> Any:
        CNKI_SEARCH_NAVIGATION_TARGET.set(observed_navigation["url"])
        try:
            page.context.remove_listener("request", remember_navigation)
        except Exception:
            pass
        return result_page

    submitted = await click_first_visible_async(
        page,
        (
            ".search-btn",
            "button.search-btn",
            "button:has-text('检索')",
            "input[type='submit'][value='检索']",
        ),
    )
    if not submitted:
        try:
            await query_locator.press("Enter", timeout=3000)
            submitted = True
        except Exception:
            return finish(None)
    if not submitted:
        return finish(None)

    result_page = page
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_CNKI_SEARCH_READY_TIMEOUT_SECONDS", 45, 1),
    )
    while time.monotonic() < deadline:
        try:
            new_pages = [
                candidate
                for candidate in page.context.pages
                if id(candidate) not in known_page_ids and not candidate.is_closed()
            ]
        except Exception:
            new_pages = []
        if new_pages:
            result_page = new_pages[-1]
        if browser_internal_navigation_error_url(
            first_string(getattr(result_page, "url", ""))
        ):
            return finish(result_page)
        if await cnki_active_verification_challenge(result_page):
            return finish(result_page)
        try:
            if await result_page.locator(
                WEB_SOURCE_DYNAMIC_READY_SELECTORS[CNKI_SOURCE]
            ).count() > 0:
                return finish(result_page)
        except Exception:
            pass
        body = await page_body_text(result_page)
        if browser_profile_has_explicit_no_results(CNKI_SOURCE, body):
            return finish(result_page)
        try:
            await result_page.wait_for_timeout(500)
        except Exception:
            break
    return finish(result_page)


async def classify_cnki_search_readiness(page: Any) -> tuple[str, str]:
    body = await page_body_text(page)
    if browser_internal_navigation_error_url(
        first_string(getattr(page, "url", ""))
    ):
        return "navigation_error", body
    if await cnki_active_verification_challenge(page):
        return "challenge", body
    try:
        if await page.locator(WEB_SOURCE_DYNAMIC_READY_SELECTORS[CNKI_SOURCE]).count() > 0:
            return "records", body
    except Exception:
        pass
    if browser_profile_has_explicit_no_results(CNKI_SOURCE, body):
        return "explicit_no_results", body
    return "pending", body


def wanfang_resource_search_surface(final_url: str) -> bool:
    parsed = urllib.parse.urlsplit(first_string(final_url))
    if (parsed.hostname or "").casefold() != "c.wanfangdata.com.cn":
        return False
    normalized_path = (parsed.path or "/").rstrip("/")
    return any(
        normalized_path == f"/{resource_key}"
        for resource_key, _, _ in WANFANG_RESOURCE_PATHS
    )


def wanfang_result_search_surface(final_url: str) -> bool:
    parsed = urllib.parse.urlsplit(first_string(final_url))
    if (parsed.hostname or "").casefold() != "s.wanfangdata.com.cn":
        return False
    normalized_path = (parsed.path or "/").rstrip("/")
    if not any(
        normalized_path == f"/{resource_key}"
        for resource_key, _, _ in WANFANG_RESOURCE_PATHS
    ):
        return False
    return bool(first_string(urllib.parse.parse_qs(parsed.query).get("q", [""])[0]))


async def submit_wanfang_browser_search(page: Any, keyword: str) -> Any | None:
    if not wanfang_resource_search_surface(
        first_string(getattr(page, "url", ""))
    ):
        return page
    if (
        await wanfang_active_verification_challenge(page)
        or await wanfang_login_surface_visible(page)
    ):
        return page
    query_locator = None
    for selector in WEB_SOURCE_SEARCH_SURFACE_SELECTORS[WANFANG_SOURCE]:
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                query_locator = candidate
                break
        except Exception:
            continue
    if query_locator is None:
        return None
    try:
        await query_locator.click(timeout=3000)
        await query_locator.fill("", timeout=3000)
        await query_locator.press_sequentially(keyword, delay=25, timeout=15000)
    except Exception:
        return None

    try:
        known_page_ids = {id(candidate) for candidate in page.context.pages}
    except Exception:
        known_page_ids = {id(page)}

    submitted = await click_first_visible_async(
        page,
        (
            ".search-button:not(.search-button-expand)",
            "button.search-button:not(.search-button-expand)",
            "button:has-text('搜论文')",
            "button:has-text('检索')",
        ),
    )
    if not submitted:
        try:
            await query_locator.press("Enter", timeout=3000)
            submitted = True
        except Exception:
            return None
    if not submitted:
        return None

    result_page = page
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_WANFANG_SEARCH_READY_TIMEOUT_SECONDS", 45, 1),
    )
    stable_signature = ""
    stable_since: float | None = None
    result_surface_since: float | None = None
    result_url_reloaded = False
    stable_seconds = min(
        10,
        env_seconds("LAPS_WANFANG_RESULT_STABLE_SECONDS", 2, 1),
    )
    while time.monotonic() < deadline:
        try:
            new_pages = [
                candidate
                for candidate in page.context.pages
                if id(candidate) not in known_page_ids and not candidate.is_closed()
            ]
        except Exception:
            new_pages = []
        for candidate in reversed(new_pages):
            candidate_url = first_string(getattr(candidate, "url", ""))
            if wanfang_result_search_surface(candidate_url):
                result_page = candidate
                break
        if (
            await wanfang_active_verification_challenge(result_page)
            or await wanfang_login_surface_visible(result_page)
        ):
            return result_page
        if not wanfang_result_search_surface(
            first_string(getattr(result_page, "url", ""))
        ):
            result_surface_since = None
            try:
                await result_page.wait_for_timeout(250)
            except Exception:
                break
            continue
        if result_surface_since is None:
            result_surface_since = time.monotonic()
        try:
            card_locator = result_page.locator(
                WEB_SOURCE_DYNAMIC_READY_SELECTORS[WANFANG_SOURCE]
            )
            if await card_locator.count() > 0:
                title_values = await result_page.locator(
                    ".normal-list .title-area .title"
                ).all_inner_texts()
                signature = hashlib.sha256(
                    "\n".join(
                        re.sub(r"\s+", " ", first_string(value)).strip()
                        for value in title_values[:20]
                    ).encode("utf-8", errors="ignore")
                ).hexdigest()
                if signature and signature == stable_signature:
                    if stable_since is not None and time.monotonic() - stable_since >= stable_seconds:
                        return result_page
                else:
                    stable_signature = signature
                    stable_since = time.monotonic()
        except Exception:
            pass
        body = await page_body_text(result_page)
        if browser_profile_has_explicit_no_results(WANFANG_SOURCE, body):
            return result_page
        if (
            not result_url_reloaded
            and result_surface_since is not None
            and time.monotonic() - result_surface_since >= 5
        ):
            observed_result_url = first_string(getattr(result_page, "url", ""))
            try:
                await result_page.goto(
                    observed_result_url,
                    wait_until="domcontentloaded",
                    timeout=min(30000, max(1000, int((deadline - time.monotonic()) * 1000))),
                )
            except Exception:
                pass
            result_url_reloaded = True
            result_surface_since = time.monotonic()
            stable_signature = ""
            stable_since = None
        try:
            await result_page.wait_for_timeout(500)
        except Exception:
            break
    return result_page


async def classify_wanfang_search_readiness(page: Any) -> tuple[str, str]:
    body = await page_body_text(page)
    current_url = first_string(getattr(page, "url", ""))
    if browser_internal_navigation_error_url(
        current_url
    ):
        return "navigation_error", body
    if await wanfang_active_verification_challenge(page):
        return "challenge", body
    if await wanfang_login_surface_visible(page):
        return "institution_login", body
    current_host = (
        urllib.parse.urlsplit(current_url).hostname or ""
    ).casefold()
    if (
        current_host.endswith("wanfangdata.com.cn")
        and not wanfang_result_search_surface(current_url)
    ):
        return "pending", body
    try:
        if await page.locator(
            WEB_SOURCE_DYNAMIC_READY_SELECTORS[WANFANG_SOURCE]
        ).count() > 0:
            return "records", body
    except Exception:
        pass
    if browser_profile_has_explicit_no_results(WANFANG_SOURCE, body):
        return "explicit_no_results", body
    return "pending", body


async def search_profiled_browser_pages(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    browser_type: Any,
    browser: Any,
    context: Any,
    query_url: str,
) -> tuple[list[LiteratureRecord], Any, Any]:
    profile = WEB_SOURCE_PARSER_PROFILES.get(source)
    parser = WEB_SOURCE_HTML_PARSERS.get(source)
    if profile is None or parser is None:
        runtime.skip(source, keyword, "dedicated web parser is not registered")
        return [], browser, context
    external_resume = EXTERNAL_BROWSER_SEARCH_RESUME.get()
    if (
        isinstance(external_resume, dict)
        and first_string(external_resume.get("source")) == source
        and first_string(external_resume.get("keyword")) == keyword
        and isinstance(external_resume.get("snapshots"), list)
    ):
        EXTERNAL_BROWSER_SEARCH_RESUME.set(None)
        external_records: list[LiteratureRecord] = []
        _, completed_pages = resumed_page_state(
            runtime,
            "literature",
            source,
            keyword,
            query_url,
        )
        snapshots = list(external_resume["snapshots"])
        for offset, snapshot in enumerate(snapshots, start=1):
            html_text = first_string(snapshot.get("html"))
            parse_base_url = first_string(snapshot.get("final_url")) or query_url
            page_records = parser(
                html_text,
                parse_base_url,
                source,
                keyword,
                len(external_records),
            )
            await enrich_browser_records(
                runtime,
                source,
                keyword,
                page_records,
            )
            next_url = first_string(snapshot.get("next_url"))
            has_next_control = bool(snapshot.get("has_next_control"))
            explicit_no_results = bool(snapshot.get("explicit_no_results"))
            exhausted = explicit_no_results or (
                not next_url and not has_next_control
            )
            persist_search_page(
                runtime,
                "literature",
                source,
                keyword,
                page_records,
                next_token="" if exhausted else next_url,
                exhausted=exhausted,
                page_number=completed_pages + offset,
            )
            external_records.extend(page_records)
            if not page_records and not explicit_no_results:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    "ordinary_chrome_external_snapshot_parser_empty",
                )
                runtime.skip(
                    source,
                    keyword,
                    "ordinary Chrome snapshot contained no dedicated-parser result cards",
                )
                return external_records, browser, context
        last_snapshot = snapshots[-1]
        if (
            first_string(last_snapshot.get("next_url"))
            or bool(last_snapshot.get("has_next_control"))
        ):
            runtime.mark_current_run(
                "literature",
                source,
                keyword,
                "incomplete",
                "ordinary_chrome_external_pagination_pending",
            )
        runtime.restricted_auth(
            source,
            keyword,
            runtime.config.path,
            "success",
            (
                "ordinary_chrome_external_session_metadata_parsed:"
                f"{len(external_records)} records"
            ),
        )
        return external_records, browser, context
    resume_url, completed_pages = resumed_page_state(runtime, "literature", source, keyword, query_url)
    page_url = resume_url or query_url
    seen_pages: set[str] = set()
    records: list[LiteratureRecord] = []
    product_authorization_attempted = False
    page = await browser_context_navigation_page(context)
    while page_url and page_url not in seen_pages:
        SEARCH_CHALLENGE_SNAPSHOT.set(None)
        snapshot: dict[str, Any] | None = None
        seen_pages.add(page_url)
        await wait_for_rate_limiter(
            runtime.limiter,
            urllib.parse.urlparse(page_url).netloc,
            kind="browser",
            source=source,
        )
        navigation_timed_out = False
        try:
            response = await page.goto(
                page_url,
                wait_until="domcontentloaded",
                timeout=30000,
            )
        except Exception as exc:
            if exc.__class__.__name__ != "TimeoutError":
                raise
            response = None
            navigation_timed_out = True
        response_status = int(response.status) if response is not None else 0
        await dismiss_browser_cookie_banners(page)
        if source == "Web of Science Starter API (Clarivate)" and urllib.parse.urlsplit(
            first_string(page.url)
        ).path.casefold().endswith("/wos/woscc/basic-search"):
            result_page = await submit_wos_basic_search(page, keyword)
            if result_page is None:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "wos_search_form_not_ready")
                runtime.skip(source, keyword, "Web of Science dedicated search form could not be submitted")
                return records, browser, context
            page = result_page
        ieee_readiness = ""
        if source == "IEEE Xplore API":
            ieee_readiness, body = await wait_for_ieee_results_readiness(page)
        else:
            try:
                body = await page.locator("body").inner_text(timeout=10000)
            except Exception:
                body = ""
        wanfang_login_required = bool(
            source == WANFANG_SOURCE
            and await wanfang_login_surface_visible(page)
        )
        if (
            SEARCH_TASK_CONTEXT.get().get("path") == "restricted_browser"
            and (
                restricted_search_authorization_needed(
                    body,
                    first_string(page.url),
                )
                or wanfang_login_required
            )
        ):
            if product_authorization_attempted:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    "restricted_product_authorization_still_present",
                )
                runtime.skip(source, keyword, "restricted product authorization remained after one recovery attempt")
                return records, browser, context
            product_authorization_attempted = True
            recovered, browser, context, page, body, response_status = await recover_restricted_search_authorization(
                runtime,
                source,
                keyword,
                browser_type,
                browser,
                context,
                page,
                page_url,
                body,
            )
            if not recovered:
                runtime.skip(source, keyword, "restricted product authorization could not be completed")
                return records, browser, context
        if await web_page_needs_verification_control(
            source,
            page,
            response_status,
            body,
        ):
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                browser_type,
                browser,
                context,
                page,
                page_url,
                body,
                {},
            )
            if not resolved:
                runtime.mark_current_run("literature", source, keyword, "incomplete", "search_challenge_unresolved")
                return records, browser, context
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            response_status = 0
            if source == "IEEE Xplore API" and snapshot is None:
                ieee_readiness, body = await wait_for_ieee_results_readiness(page)
            else:
                body = await page_body_text(page)
        elif response_status >= 400:
            runtime.mark_current_run("literature", source, keyword, "incomplete", f"web_http_{response_status}")
            runtime.skip(source, keyword, f"web page returned HTTP {response_status}")
            return records, browser, context
        if source == CNKI_SOURCE and snapshot is None and cnki_home_search_surface(
            first_string(getattr(page, "url", ""))
        ):
            result_page = await submit_cnki_browser_search(page, keyword)
            if result_page is None:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    "cnki_search_form_not_ready",
                )
                runtime.skip(source, keyword, "CNKI dedicated search form could not be submitted")
                return records, browser, context
            page = result_page
        if (
            source == WANFANG_SOURCE
            and snapshot is None
            and wanfang_resource_search_surface(
                first_string(getattr(page, "url", ""))
            )
        ):
            result_page = await submit_wanfang_browser_search(page, keyword)
            if result_page is None:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    "wanfang_search_form_not_ready",
                )
                runtime.skip(
                    source,
                    keyword,
                    "Wanfang dedicated search form could not be submitted",
                )
                return records, browser, context
            page = result_page
            wanfang_readiness, body = await classify_wanfang_search_readiness(page)
            if wanfang_readiness == "institution_login":
                if SEARCH_TASK_CONTEXT.get().get("path") != "restricted_browser":
                    runtime.mark_current_run(
                        "literature",
                        source,
                        keyword,
                        "blocked",
                        "wanfang_institution_login_required",
                    )
                    runtime.skip(
                        source,
                        keyword,
                        "Wanfang search requires institution authentication",
                    )
                    return records, browser, context
                recovered, browser, context, page, body, response_status = (
                    await recover_restricted_search_authorization(
                        runtime,
                        source,
                        keyword,
                        browser_type,
                        browser,
                        context,
                        page,
                        page_url,
                        body,
                    )
                )
                if not recovered:
                    return records, browser, context
                result_page = await submit_wanfang_browser_search(page, keyword)
                if result_page is None:
                    runtime.mark_current_run(
                        "literature",
                        source,
                        keyword,
                        "incomplete",
                        "wanfang_search_form_not_ready_after_auth",
                    )
                    return records, browser, context
                page = result_page
                wanfang_readiness, body = await classify_wanfang_search_readiness(page)
            if wanfang_readiness in {"challenge", "navigation_error"}:
                challenge_url = first_string(getattr(page, "url", "")) or page_url
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    browser_type,
                    browser,
                    context,
                    page,
                    challenge_url,
                    body,
                    {},
                )
                if not resolved:
                    runtime.mark_current_run(
                        "literature",
                        source,
                        keyword,
                        "incomplete",
                        "wanfang_search_challenge_unresolved",
                    )
                    return records, browser, context
                snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
                if snapshot is None:
                    wanfang_readiness, body = await classify_wanfang_search_readiness(page)
            if snapshot is None and wanfang_readiness not in {
                "records",
                "explicit_no_results",
            }:
                registered_browser = parent_browser_control_for_browser(browser)
                active_browser_name = normalize_browser_name(
                    registered_browser.browser_name
                    if registered_browser is not None
                    else "",
                    "chromium",
                )
                if (
                    wanfang_readiness == "pending"
                    and active_browser_name == "chrome"
                ):
                    resolved, browser, context, page = (
                        await handle_search_verification_challenge(
                            runtime,
                            source,
                            keyword,
                            browser_type,
                            browser,
                            context,
                            page,
                            first_string(getattr(page, "url", "")) or page_url,
                            body,
                            {},
                            control_reason=(
                                "browser_internal_navigation_error:"
                                "wanfang_search_results_not_ready"
                            ),
                        )
                    )
                    if resolved:
                        snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
                        if snapshot is None:
                            wanfang_readiness, body = (
                                await classify_wanfang_search_readiness(page)
                            )
                if snapshot is None and wanfang_readiness not in {
                    "records",
                    "explicit_no_results",
                }:
                    runtime.mark_current_run(
                        "literature",
                        source,
                        keyword,
                        "incomplete",
                        "wanfang_search_results_not_ready",
                    )
                    runtime.skip(
                        source,
                        keyword,
                        "Wanfang search did not reach result cards or an explicit zero-result state",
                    )
                    return records, browser, context
        if source == CNKI_SOURCE and snapshot is None:
            cnki_readiness, body = await classify_cnki_search_readiness(page)
            if cnki_readiness in {"challenge", "navigation_error"}:
                challenge_url = first_string(getattr(page, "url", "")) or page_url
                if cnki_readiness == "navigation_error":
                    challenge_url = (
                        CNKI_SEARCH_NAVIGATION_TARGET.get()
                        or challenge_url
                    )
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    browser_type,
                    browser,
                    context,
                    page,
                    challenge_url,
                    body,
                    {},
                )
                if not resolved:
                    runtime.mark_current_run(
                        "literature",
                        source,
                        keyword,
                        "incomplete",
                        "cnki_search_challenge_unresolved",
                    )
                    return records, browser, context
                snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
                if snapshot is None:
                    cnki_readiness, body = await classify_cnki_search_readiness(page)
            if snapshot is None and cnki_readiness not in {"records", "explicit_no_results"}:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    "cnki_search_results_not_ready",
                )
                runtime.skip(source, keyword, "CNKI search did not reach result cards or an explicit zero-result state")
                return records, browser, context
        if source == "ACS Publications" and snapshot is None:
            acs_readiness, body = await classify_acs_search_readiness(page, body)
            for _ in range(2):
                if acs_readiness in {"records", "explicit_no_results"}:
                    break
                if not await submit_acs_browser_search(page, keyword):
                    break
                response_status = 0
                acs_readiness, body = await wait_for_acs_search_readiness(page)
                if acs_readiness == "challenge":
                    resolved, browser, context, page = await handle_search_verification_challenge(
                        runtime,
                        source,
                        keyword,
                        browser_type,
                        browser,
                        context,
                        page,
                        page_url,
                        body,
                        {},
                    )
                    if not resolved:
                        runtime.mark_current_run(
                            "literature",
                            source,
                            keyword,
                            "incomplete",
                            "acs_search_challenge_unresolved_after_query_resume",
                        )
                        return records, browser, context
                    snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
                    if snapshot is not None:
                        acs_readiness = "records"
                        break
                    acs_readiness, body = await classify_acs_search_readiness(page)
            if acs_readiness not in {"records", "explicit_no_results"}:
                runtime.mark_current_run(
                    "literature",
                    source,
                    keyword,
                    "incomplete",
                    "acs_search_results_not_ready_after_verification",
                )
                runtime.skip(
                    source,
                    keyword,
                    "ACS dedicated search did not reach result cards or an explicit zero-result state after verification",
                )
                return records, browser, context
        if source == "IEEE Xplore API" and snapshot is None and ieee_readiness == "timeout":
            runtime.mark_current_run(
                "literature",
                source,
                keyword,
                "incomplete",
                "ieee_results_not_ready",
            )
            runtime.skip(
                source,
                keyword,
                "IEEE results did not reach cards or an explicit zero-result state before timeout",
            )
            return records, browser, context
        if source == "IEEE Xplore API" and snapshot is None and ieee_readiness == "challenge":
            runtime.mark_current_run(
                "literature",
                source,
                keyword,
                "incomplete",
                "search_challenge_unresolved",
            )
            runtime.skip(
                source,
                keyword,
                "search_challenge_unresolved:challenge_reappeared_while_ieee_results_loaded",
            )
            return records, browser, context
        if snapshot is not None:
            html_text = first_string(snapshot.get("html"))
            parse_base_url = first_string(snapshot.get("final_url")) or page_url
            next_url = first_string(snapshot.get("next_url"))
            has_unresolved_next_control = bool(snapshot.get("has_next_control")) and not next_url
            body = "no results found" if snapshot.get("explicit_no_results") else "sanitized search result snapshot"
        else:
            ready_selector = (
                None
                if source == "IEEE Xplore API"
                else WEB_SOURCE_DYNAMIC_READY_SELECTORS.get(source)
            )
            if ready_selector:
                try:
                    await page.wait_for_selector(ready_selector, timeout=10000)
                except Exception:
                    pass
                body = await page_body_text(page)
            html_text = await page.content()
            parse_base_url = first_string(page.url) or page_url
            next_url = await browser_profile_next_url(page, profile)
            has_unresolved_next_control = False
        page_records = parser(html_text, parse_base_url, source, keyword, len(records))
        if source == "Web of Science Starter API (Clarivate)":
            await enrich_wos_browser_details(runtime, source, keyword, context, page_records)
        if (
            source == "Elsevier"
            and snapshot is None
        ):
            browser, context, page, details_ok = (
                await enrich_sciencedirect_browser_details(
                    runtime,
                    source,
                    keyword,
                    browser_type,
                    browser,
                    context,
                    page,
                    page_records,
                )
            )
            if not details_ok:
                return records, browser, context
        if source == CNKI_SOURCE and snapshot is None:
            browser, context, page, details_ok = await enrich_cnki_browser_details(
                runtime,
                source,
                keyword,
                browser_type,
                browser,
                context,
                page,
                page_records,
            )
            if not details_ok:
                return records, browser, context
        if source == WANFANG_SOURCE and snapshot is None:
            browser, context, page, details_ok = await enrich_wanfang_browser_details(
                runtime,
                source,
                keyword,
                browser_type,
                browser,
                context,
                page,
                page_records,
            )
            if not details_ok:
                return records, browser, context
        if source not in {CNKI_SOURCE, WANFANG_SOURCE}:
            await enrich_browser_records(runtime, source, keyword, page_records)
        if source == "IEEE Xplore API":
            browser, context, page, details_ok = await enrich_ieee_browser_details(
                runtime,
                source,
                keyword,
                browser_type,
                browser,
                context,
                page,
                page_records,
            )
            if not details_ok:
                return records, browser, context
        if not page_records and not browser_profile_has_explicit_no_results(source, body):
            transient_reason = browser_profile_transient_error(source, body)
            reason = transient_reason or (
                "browser_navigation_timeout_without_results"
                if navigation_timed_out
                else "source_web_results_not_detected"
            )
            runtime.mark_current_run("literature", source, keyword, "incomplete", reason)
            runtime.skip(
                source,
                keyword,
                f"web source returned a transient service boundary: {transient_reason}"
                if transient_reason
                else "dedicated web parser found no result cards on a non-empty page",
            )
            return records, browser, context
        exhausted = not next_url and not has_unresolved_next_control
        completed_pages += 1
        persist_search_page(runtime, "literature", source, keyword, page_records, next_token="" if exhausted else next_url, exhausted=exhausted, page_number=completed_pages)
        records.extend(page_records)
        if has_unresolved_next_control:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "next_page_control_without_resumable_url")
            break
        if exhausted:
            break
        if next_url in seen_pages:
            runtime.mark_current_run("literature", source, keyword, "incomplete", "repeated_page_url")
            break
        page_url = next_url
    return records, browser, context


async def search_public_browser_literature(runtime: SearchRuntime, source: str, policy: SourceAccessPolicy, keyword: str, limit: int) -> list[LiteratureRecord]:
    query_url = build_web_search_url(source, policy, keyword, limit)
    if not query_url:
        runtime.browser_disabled(source, keyword, "browser fallback disabled by default; no API key is required")
        return []
    try:
        async_playwright = load_async_playwright()

        async with runtime.browser_sem:
            await wait_for_rate_limiter(
                runtime.limiter,
                urllib.parse.urlparse(query_url).netloc,
                kind="browser",
                source=source,
            )
            async with async_playwright() as pw:
                browser, launch_error = await launch_named_browser(
                    pw.chromium,
                    "chromium",
                    headless=True,
                )
                if browser is None:
                    raise RuntimeError(launch_error or "chromium_launch_failed")
                context = await browser.new_context()
                records, browser, context = await search_profiled_browser_pages(runtime, source, keyword, pw.chromium, browser, context, query_url)
                await context.close()
                await browser.close()
        return records
    except Exception as exc:
        runtime.skip(source, keyword, f"public browser fallback failed: {safe_error_text(str(exc))}")
        return []


async def search_restricted_web_literature(runtime: SearchRuntime, source: str, policy: SourceAccessPolicy, keyword: str, limit: int) -> list[LiteratureRecord]:
    if not restricted_web_fallback_enabled(runtime.config):
        runtime.browser_disabled(source, keyword, "restricted web fallback disabled or missing valid login config")
        return []
    query_url = build_web_search_url(source, policy, keyword, limit)
    if not query_url:
        runtime.skip(source, keyword, "restricted web fallback has no configured search URL")
        return []
    pw = browser = context = None
    try:
        async with runtime.browser_sem:
            pw, browser, context, authenticated = await open_restricted_browser_context(runtime, source, policy)
            if not authenticated:
                runtime.skip(source, keyword, "restricted web authentication failed after script and external control")
                return []
            records, browser, context = await search_profiled_browser_pages(runtime, source, keyword, pw.chromium, browser, context, query_url)
            runtime.restricted_auth(source, keyword, runtime.config.path, "success", f"restricted web metadata parsed: {len(records)} records")
            return records
    except Exception as exc:
        runtime.restricted_auth(source, keyword, restricted_access_mode(runtime.config), "failed", f"restricted web failed: {safe_error_text(str(exc))}")
        runtime.skip(source, keyword, f"restricted web failed: {safe_error_text(str(exc))}")
        return []
    finally:
        if context is not None:
            await context.close()
        if browser is not None:
            await browser.close()
        if pw is not None:
            await pw.stop()


async def search_browser_fallback_literature(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[LiteratureRecord]:
    policy = literature_source_auth_policy.get(source) or SourceAccessPolicy("none", web_search_url=url)
