def web_adapter_should_use_restricted_path(policy: SourceAccessPolicy, config: SearchConfig) -> bool:
    requested_path = first_string(SEARCH_TASK_CONTEXT.get().get("path"))
    if requested_path == "public_browser":
        return False
    if requested_path == "restricted_browser":
        return True
    return policy_allows_restricted_access(policy, config)


