def prepare_wanfang_resource_run(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    checkpoint_path: str,
) -> None:
    if runtime.state_store is None:
        return
    previous = runtime.state_store.get_run(
        "literature",
        keyword,
        source,
        checkpoint_path,
    ) or {}
    runtime.state_store.mark_run(
        "literature",
        keyword,
        source,
        checkpoint_path,
        runtime.config_fingerprint,
        "running",
        next_token=str(previous.get("next_token") or ""),
        pages=int(previous.get("pages") or 0),
        fetched=int(previous.get("fetched") or 0),
        accepted=int(previous.get("accepted") or 0),
        duplicates=int(previous.get("duplicates") or 0),
        dropped=int(previous.get("dropped") or 0),
        total_hint=previous.get("total_hint"),
        page_signature=str(previous.get("page_signature") or ""),
        reason="",
    )


def wanfang_browser_transport_escalation_reason(
    run: dict[str, Any] | None,
) -> str:
    if not run or first_string(run.get("status")) not in {
        "incomplete",
        "failed",
    }:
        return ""
    reason = first_string(run.get("reason"))
    if any(
        reason == candidate or reason.startswith(f"{candidate}:")
        for candidate in WANFANG_BROWSER_TRANSPORT_RETRY_REASONS
    ):
        return reason
    return ""


def wanfang_resource_browser_transport_escalation_reason(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    checkpoint_path: str,
) -> str:
    if runtime.state_store is None:
        return ""
    return wanfang_browser_transport_escalation_reason(
        runtime.state_store.get_run(
            "literature",
            keyword,
            source,
            checkpoint_path,
        )
    )


def clear_wanfang_transport_skips_before_retry(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    start_index: int,
) -> None:
    prefix = runtime.skipped_sources[:start_index]
    suffix = [
        event
        for event in runtime.skipped_sources[start_index:]
        if not (
            event.source == source
            and event.keyword == keyword
            and event.reason
            == "Wanfang search did not reach result cards or an explicit zero-result state"
        )
    ]
    runtime.skipped_sources[:] = [*prefix, *suffix]


async def launch_wanfang_public_browser_layer(
    browser_type: Any,
    browser_name: str,
) -> tuple[Any | None, Any | None, str]:
    browser, launch_error = await launch_named_browser(
        browser_type,
        browser_name,
        headless=browser_name == "chromium",
    )
    if browser is None:
        return None, None, launch_error
    try:
        context = await browser.new_context()
    except Exception as exc:
        await close_restricted_browser_attempt(browser, None)
        return None, None, f"{browser_name}_context_failed:{exc.__class__.__name__}"
    return browser, context, ""


async def launch_wanfang_restricted_browser_layer(
    runtime: SearchRuntime,
    source: str,
    policy: SourceAccessPolicy,
    browser_type: Any,
    browser_name: str,
) -> tuple[Any | None, Any | None, str]:
    state_path = auth_state_path(runtime.config, source, policy)
    if not state_path.exists():
        return None, None, "wanfang_auth_state_missing"
    browser, launch_error = await launch_named_browser(
        browser_type,
        browser_name,
        headless=browser_name == "chromium",
    )
    if browser is None:
        return None, None, launch_error
    context = None
    try:
        context = await browser.new_context(storage_state=str(state_path))
        page = await context.new_page()
        confirmation_url = auth_state_confirmation_url(source, policy)
        if confirmation_url:
            await page.goto(
                confirmation_url,
                wait_until="domcontentloaded",
                timeout=30000,
            )
        confirmation = await confirm_imported_auth_state_status(
            page,
            source,
            runtime.config.school,
            "wanfang_browser_transport_switch",
            school_aliases=runtime.config.school_aliases,
        )
        if confirmation.status != "confirmed":
            await close_restricted_browser_attempt(browser, context)
            return (
                None,
                None,
                "wanfang_auth_state_not_confirmed_after_transport_switch:"
                f"{confirmation.status}",
            )
        await prepare_browser_context_handoff_page(context)
        return browser, context, ""
    except Exception as exc:
        await close_restricted_browser_attempt(browser, context)
        return (
            None,
            None,
            f"wanfang_{browser_name}_auth_state_import_failed:{exc.__class__.__name__}",
        )


async def persist_observed_wanfang_institution_state(
    runtime: SearchRuntime,
    source: str,
    policy: SourceAccessPolicy,
    browser: Any,
    context: Any,
    fallback_browser_name: str,
) -> tuple[bool, str]:
    try:
        attestation_saved, attestation_reason = await persist_search_auth_context_state(
            context,
            runtime.config,
            source,
            policy,
            "exact_institution_marker",
        )
        if not attestation_saved:
            return False, attestation_reason
        registered_browser = parent_browser_control_for_browser(browser)
        selected_browser = normalize_browser_name(
            registered_browser.browser_name
            if registered_browser is not None
            else fallback_browser_name,
            fallback_browser_name,
        )
        save_auth_browser_transport(
            runtime.config,
            source,
            selected_browser,
            selected_browser == "chrome",
            policy,
        )
        return True, "wanfang_existing_institution_session_saved"
    except Exception as exc:
        return False, f"wanfang_existing_institution_state_save_failed:{exc.__class__.__name__}"


def wanfang_aggregate_run_status(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    checkpoint_paths: Iterable[str],
) -> tuple[str, str]:
    if runtime.state_store is None:
        return "complete", "wanfang_resource_paths_completed_without_checkpoint"
    runs = [
        runtime.state_store.get_run("literature", keyword, source, path) or {}
        for path in checkpoint_paths
    ]
    statuses = [first_string(run.get("status")) for run in runs]
    reasons = [first_string(run.get("reason")) for run in runs if run.get("reason")]
    if runs and all(status == "complete" for status in statuses):
        return "complete", "wanfang_all_resource_paths_exhausted"
    for status in ("failed", "blocked", "incomplete", "running", "pending"):
        if status in statuses:
            normalized = "incomplete" if status in {"running", "pending"} else status
            return normalized, next(
                (reason for reason in reasons if reason),
                f"wanfang_resource_path_{normalized}",
            )
    return "incomplete", "wanfang_resource_path_status_missing"


async def search_wanfang_web_adapter(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
    page_size: int,
) -> list[LiteratureRecord]:
    del url, page_size
    policy = literature_source_auth_policy[source]
    restricted = web_adapter_should_use_restricted_path(policy, runtime.config)
    primary_path = first_string(SEARCH_TASK_CONTEXT.get().get("path")) or (
        "restricted_browser" if restricted else "public_browser"
    )
    checkpoint_paths = [
        f"{primary_path}:{resource_key}"
        for resource_key, _, _ in WANFANG_RESOURCE_PATHS
    ]
    records: list[LiteratureRecord] = []
    pw = browser = context = None
    active_browser_name = "chromium"
    try:
        async with runtime.browser_sem:
            if restricted:
                if not restricted_web_fallback_enabled(runtime.config):
                    runtime.browser_disabled(
                        source,
                        keyword,
                        "restricted web fallback disabled or missing valid login config",
                    )
                    runtime.mark_current_run(
                        "literature",
                        source,
                        keyword,
                        "blocked",
                        "wanfang_restricted_browser_configuration_missing",
                        path=primary_path,
                    )
                    return []
                pw, browser, context, authenticated = await open_restricted_browser_context(
                    runtime,
                    source,
                    policy,
                )
                if not authenticated:
                    runtime.skip(
                        source,
                        keyword,
                        "Wanfang institution authentication failed after script and external control",
                    )
                    return []
                browser_type = pw.chromium
                registered_browser = parent_browser_control_for_browser(browser)
                active_browser_name = normalize_browser_name(
                    registered_browser.browser_name
                    if registered_browser is not None
                    else "",
                    "chromium",
                )
            else:
                async_playwright = load_async_playwright()
                pw = await async_playwright().start()
                browser, context, launch_error = await launch_wanfang_public_browser_layer(
                    pw.chromium,
                    "chromium",
                )
                if browser is None or context is None:
                    raise RuntimeError(launch_error or "chromium_launch_failed")
                browser_type = pw.chromium

            parent_context = SEARCH_TASK_CONTEXT.get()
            for resource_key, resource_label, resource_url in WANFANG_RESOURCE_PATHS:
                checkpoint_path = f"{primary_path}:{resource_key}"
                if (
                    runtime.state_store is not None
                    and runtime.state_store.reusable_run(
                        "literature",
                        keyword,
                        source,
                        checkpoint_path,
                        runtime.config_fingerprint,
                    )
                ):
                    continue
                prepare_wanfang_resource_run(
                    runtime,
                    source,
                    keyword,
                    checkpoint_path,
                )
                token = SEARCH_TASK_CONTEXT.set(
                    parent_context
                    | {
                        "path": primary_path,
                        "checkpoint_path": checkpoint_path,
                        "wanfang_resource_key": resource_key,
                        "wanfang_resource_label": resource_label,
                    }
                )
                try:
                    transport_skip_start = len(runtime.skipped_sources)
                    try:
                        resource_records, browser, context = (
                            await search_profiled_browser_pages(
                                runtime,
                                source,
                                keyword,
                                browser_type,
                                browser,
                                context,
                                resource_url,
                            )
                        )
                    except Exception as exc:
                        resource_records = []
                        runtime.mark_current_run(
                            "literature",
                            source,
                            keyword,
                            "incomplete",
                            f"wanfang_browser_transport_failure:{exc.__class__.__name__}",
                        )
                    records.extend(resource_records)
                    escalation_reason = (
                        wanfang_resource_browser_transport_escalation_reason(
                            runtime,
                            source,
                            keyword,
                            checkpoint_path,
                        )
                    )
                    if (
                        active_browser_name == "chromium"
                        and escalation_reason
                    ):
                        runtime.degrade(
                            source,
                            keyword,
                            "bundled Chromium did not reach the Wanfang result "
                            f"surface ({escalation_reason}); retrying the same "
                            "resource once with Playwright Chrome"
                            + (
                                " using the saved institution state"
                                if restricted
                                else ""
                            ),
                        )
                        if restricted and context is not None:
                            persisted, persist_reason = await persist_search_auth_context_state(
                                context,
                                runtime.config,
                                source,
                                policy,
                                "exact_institution_marker",
                            )
                            if not persisted:
                                runtime.mark_current_run(
                                    "literature",
                                    source,
                                    keyword,
                                    "incomplete",
                                    "wanfang_transport_state_not_published:"
                                    f"{persist_reason}",
                                )
                                break
                        await parent_browser_switch_cooldown(browser, context)
                        browser = context = None
                        if restricted:
                            browser, context, launch_error = (
                                await launch_wanfang_restricted_browser_layer(
                                    runtime,
                                    source,
                                    policy,
                                    browser_type,
                                    "chrome",
                                )
                            )
                        else:
                            browser, context, launch_error = (
                                await launch_wanfang_public_browser_layer(
                                    browser_type,
                                    "chrome",
                                )
                            )
                        if browser is None or context is None:
                            runtime.mark_current_run(
                                "literature",
                                source,
                                keyword,
                                "incomplete",
                                "wanfang_playwright_chrome_unavailable:"
                                f"{launch_error or 'chrome_launch_failed'}",
                            )
                            break
                        active_browser_name = "chrome"
                        prepare_wanfang_resource_run(
                            runtime,
                            source,
                            keyword,
                            checkpoint_path,
                        )
                        clear_wanfang_transport_skips_before_retry(
                            runtime,
                            source,
                            keyword,
                            transport_skip_start,
                        )
                        retry_records, browser, context = (
                            await search_profiled_browser_pages(
                                runtime,
                                source,
                                keyword,
                                browser_type,
                                browser,
                                context,
                                resource_url,
                            )
                        )
                        records.extend(retry_records)
                finally:
                    SEARCH_TASK_CONTEXT.reset(token)

            aggregate_status, aggregate_reason = wanfang_aggregate_run_status(
                runtime,
                source,
                keyword,
                checkpoint_paths,
            )
            runtime.mark_current_run(
                "literature",
                source,
                keyword,
                aggregate_status,
                aggregate_reason,
                path=primary_path,
            )
            if restricted:
                runtime.restricted_auth(
                    source,
                    keyword,
                    runtime.config.path,
                    "success" if aggregate_status == "complete" else "incomplete",
                    f"wanfang_restricted_metadata_parsed:{len(records)} records",
                )
            return records
    except Exception as exc:
        runtime.mark_current_run(
            "literature",
            source,
            keyword,
            "failed",
            f"wanfang_browser_failed:{exc.__class__.__name__}",
            path=primary_path,
        )
        runtime.skip(
            source,
            keyword,
            f"Wanfang browser search failed: {safe_error_text(str(exc))}",
        )
        return records
    finally:
        if context is not None:
            try:
                await context.close()
            except Exception:
                pass
        if browser is not None:
            try:
                await browser.close()
            except Exception:
                pass
        if pw is not None:
            try:
                await pw.stop()
            except Exception:
                pass


def identity_query_builder(keyword: str) -> str:
    return keyword


def query_variant(
    variant_id: str,
    field_scope: str,
    *,
    coverage_required: bool = True,
    subsumes: tuple[str, ...] = (),
) -> QueryVariant:
    return QueryVariant(
        variant_id=variant_id,
        field_scope=field_scope,
        query_builder=identity_query_builder,
        coverage_required=coverage_required,
        subsumes=subsumes,
    )


