def google_patents_landing_url(raw_id: str | None, publication: str | None) -> str:
    raw = first_string(raw_id)
    if raw:
        if raw.startswith("http://") or raw.startswith("https://"):
            return raw
        return "https://patents.google.com/" + raw.lstrip("/")
    pub = first_string(publication)
    if pub:
        return f"https://patents.google.com/patent/{pub}/en"
    return ""


def publication_from_google_patents_url(url: str | None) -> str:
    match = re.search(r"/patent/([^/?#]+)/?", first_string(url))
    return match.group(1) if match else ""


def google_patent_url_from_links(links: list[dict[str, Any]]) -> str:
    for link in links:
        href = unwrap_google_redirect_url(first_string(link.get("href")))
        if not href:
            continue
        try:
            parsed = urllib.parse.urlsplit(href)
        except ValueError:
            continue
        if parsed.netloc.casefold().endswith("patents.google.com") and "/patent/" in parsed.path:
            return href
    return ""


def google_patents_xhr_records(data: dict[str, Any], source: str, keyword: str) -> list[PatentRecord]:
    clusters = data.get("results", {}).get("cluster", [])
    records: list[PatentRecord] = []
    for cluster in clusters:
        if not isinstance(cluster, dict):
            continue
        for item in cluster.get("result", []):
            patent = item.get("patent", {}) if isinstance(item, dict) else {}
            publication = first_string(patent.get("publication_number"))
            raw_id = first_string(item.get("id")) if isinstance(item, dict) else ""
            page_url = google_patents_landing_url(raw_id, publication)
            title = html.unescape(re.sub(r"<[^>]+>", "", first_string(patent.get("title")))).strip()
            inventors = clean_people(patent.get("inventor") or patent.get("assignee"))
            records.append(
                PatentRecord(
                    patent_name=title or publication or page_url,
                    authors=inventors,
                    year=parse_year(patent.get("publication_date") or patent.get("filing_date") or patent.get("priority_date")),
                    url=page_url,
                    source=source,
                    keyword=keyword,
                    rank=int(item.get("rank", len(records))) + 1 if isinstance(item, dict) else len(records) + 1,
                    raw_id=raw_id or publication,
                    publication_number=publication or publication_from_google_patents_url(page_url) or None,
                )
            )
    return records


def parse_google_patents_results(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    records = google_patents_xhr_records(data, source, keyword)
    for offset, record in enumerate(records, start=1):
        record.rank = rank_start + offset
    return records


def parse_google_patents_browser_item(item: dict[str, Any], source: str, keyword: str, rank: int) -> PatentRecord | None:
    links = item.get("links") if isinstance(item.get("links"), list) else []
    url = google_patent_url_from_links([link for link in links if isinstance(link, dict)])
    publication = publication_from_google_patents_url(url)
    title = first_string(item.get("title")) or publication or url
    if not title:
        title = first_string(next((link.get("text") for link in links if isinstance(link, dict) and first_string(link.get("text"))), ""))
    if not title:
        return None
    return PatentRecord(
        patent_name=title,
        authors=[],
        year=parse_year(first_string(item.get("text"))),
        url=url,
        source=source,
        keyword=keyword,
        rank=rank,
        raw_id=url or None,
        publication_number=publication or None,
    )


async def extract_google_patents_page_items(page: Any) -> list[dict[str, Any]]:
    return await page.evaluate(
        """() => {
            const candidates = [
                ...Array.from(document.querySelectorAll('search-result-item, article, .result, .search-result')),
                ...Array.from(document.querySelectorAll('a[href*="/patent/"]')).map((a) => a.closest('search-result-item, article, .result, .search-result') || a)
            ];
            const seen = new Set();
            const cards = candidates.filter((card) => {
                if (!card || seen.has(card)) return false;
                seen.add(card);
                return true;
            });
            return cards.map((card, i) => {
                const links = Array.from(card.querySelectorAll ? card.querySelectorAll('a') : [card]).map((a) => ({
                    text: (a.innerText || '').trim(),
                    href: a.href || ''
                })).filter((link) => link.href || link.text);
                const title = (card.querySelector?.('h3,h4,a')?.innerText || card.innerText || '').split('\\n')[0].trim();
                const text = (card.innerText || '').trim();
                return {title, text, links, rank: i + 1};
            }).filter((item) => item.title || item.links.length);
        }"""
    )


async def google_patents_next_control(page: Any) -> Any | None:
    selectors = (
        "a#next_page",
        "a[aria-label='Next']",
        "a[aria-label*='Next page' i]",
        "a[rel='next']",
        "paper-button#next",
        "button[aria-label*='Next' i]",
    )
    for selector in selectors:
        try:
            locators = page.locator(selector)
            for index in range(await locators.count()):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=500):
                    continue
                disabled = first_string(await locator.get_attribute("disabled"))
                aria_disabled = first_string(
                    await locator.get_attribute("aria-disabled")
                ).casefold()
                if disabled or aria_disabled == "true":
                    continue
                return locator
        except Exception:
            continue
    return None


async def search_google_patents_browser(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[PatentRecord]:
    page_size = source_page_size(limit, 100, 10)
    records: list[PatentRecord] = []
    xhr_url = "https://patents.google.com/xhr/query"
    parent_context = SEARCH_TASK_CONTEXT.get()
    xhr_context_token = SEARCH_TASK_CONTEXT.set(
        parent_context | {"path": "xhr", "checkpoint_path": "xhr"}
    )
    browser_start_page = 0
    try:
        token, completed_pages = resumed_page_state(
            runtime, "patent", source, keyword, "0"
        )
        page_number = parse_int(token) or 0
        while True:
            embedded_query = urllib.parse.urlencode(
                {
                    "q": quoted_search_phrase(current_query_text(keyword)),
                    "num": page_size,
                    "page": page_number,
                }
            )
            attempt = await runtime.request_result(
                source,
                keyword,
                "GET",
                xhr_url,
                params={"url": embedded_query, "exp": ""},
            )
            if not attempt.ok:
                if attempt.status_code == 429:
                    runtime.mark_current_run(
                        "patent",
                        source,
                        keyword,
                        "incomplete",
                        attempt.reason or "google_patents_xhr_rate_limited",
                    )
                    return dedupe_patent_records(records)
                browser_start_page = page_number
                runtime.mark_current_run(
                    "patent",
                    source,
                    keyword,
                    "incomplete",
                    f"google_patents_xhr_transport_boundary:{attempt.reason}",
                )
                break
            try:
                data = attempt.response.json()
                results = data.get("results") or {}
                page_records = parse_google_patents_results(
                    data, source, keyword, len(records)
                )
                raw_count = sum(
                    len(cluster.get("result", []))
                    for cluster in results.get("cluster", [])
                    if isinstance(cluster, dict)
                )
                total_pages = parse_int(results.get("total_num_pages"))
                total_results = parse_int(results.get("total_num_results"))
            except Exception as exc:
                runtime.skip(
                    source,
                    keyword,
                    f"Google Patents JSON parse error: {safe_error_text(str(exc))}",
                )
                browser_start_page = page_number
                runtime.mark_current_run(
                    "patent",
                    source,
                    keyword,
                    "incomplete",
                    "google_patents_xhr_schema_boundary",
                )
                break
            next_page = page_number + 1
            server_exhausted = bool(
                raw_count == 0
                or (total_pages is not None and next_page >= total_pages)
                or (total_pages is None and raw_count < page_size)
            )
            visible_window = (
                total_pages * page_size if total_pages is not None else None
            )
            source_capped = bool(
                server_exhausted
                and total_results is not None
                and visible_window is not None
                and total_results > visible_window
            )
            completed_pages += 1
            persist_search_page(
                runtime,
                "patent",
                source,
                keyword,
                page_records,
                next_token="" if server_exhausted else str(next_page),
                exhausted=server_exhausted and not source_capped,
                page_number=completed_pages,
                total_hint=total_results,
                reason=(
                    f"source_result_window_cap:{visible_window}"
                    if source_capped
                    else ""
                ),
            )
            records.extend(page_records)
            if server_exhausted:
                if source_capped:
                    runtime.mark_current_run(
                        "patent",
                        source,
                        keyword,
                        "incomplete",
                        f"source_result_window_cap:{visible_window}",
                    )
                return dedupe_patent_records(records)
            if next_page <= page_number:
                runtime.mark_current_run(
                    "patent",
                    source,
                    keyword,
                    "incomplete",
                    "repeated_page_number",
                )
                return dedupe_patent_records(records)
            page_number = next_page
    finally:
        SEARCH_TASK_CONTEXT.reset(xhr_context_token)

    try:
        async_playwright = load_async_playwright()
        browser_context_token = SEARCH_TASK_CONTEXT.set(
            parent_context
            | {"path": "public_browser", "checkpoint_path": "public_browser"}
        )
        async with runtime.global_sem:
            async with async_playwright() as pw:
                browser = await pw.chromium.launch(headless=True)
                context_kwargs: dict[str, Any] = {}
                context = await browser.new_context(**context_kwargs)
                page = await context.new_page()
                browser_token, browser_completed_pages = resumed_page_state(
                    runtime,
                    "patent",
                    source,
                    keyword,
                    str(browser_start_page),
                )
                page_number = parse_int(browser_token)
                if page_number is None:
                    page_number = browser_start_page
                seen_signatures: set[str] = set()
                while True:
                    query_url = f"{url}?{urllib.parse.urlencode({'q': quoted_search_phrase(current_query_text(keyword)), 'num': page_size, 'page': page_number})}"
                    await wait_for_rate_limiter(
                        runtime.limiter,
                        urllib.parse.urlparse(query_url).netloc,
                        kind="browser",
                        source=source,
                    )
                    await page.goto(query_url, wait_until="commit", timeout=30000)
                    try:
                        await page.wait_for_selector(
                            "search-result-item, article, .result, a[href*='/patent/']",
                            timeout=30000,
                        )
                    except Exception:
                        pass
                    body = await page.locator("body").inner_text(timeout=10000)
                    if body_has_verification_challenge(body):
                        resolved, browser, context, page = await handle_search_verification_challenge(
                            runtime,
                            source,
                            keyword,
                            pw.chromium,
                            browser,
                            context,
                            page,
                            query_url,
                            body,
                            context_kwargs,
                        )
                        if not resolved:
                            runtime.mark_current_run(
                                "patent",
                                source,
                                keyword,
                                "incomplete",
                                "google_patents_browser_challenge_unresolved",
                            )
                            await browser.close()
                            SEARCH_TASK_CONTEXT.reset(browser_context_token)
                            return dedupe_patent_records(records)
                    page_records: list[PatentRecord] = []
                    for item in await extract_google_patents_page_items(page):
                        record = parse_google_patents_browser_item(
                            item,
                            source,
                            keyword,
                            len(records) + len(page_records) + 1,
                        )
                        if record is not None:
                            page_records.append(record)
                    page_signature = search_page_signature(page_records)
                    if page_signature in seen_signatures:
                        runtime.mark_current_run(
                            "patent",
                            source,
                            keyword,
                            "incomplete",
                            "google_patents_browser_repeated_page",
                        )
                        break
                    seen_signatures.add(page_signature)
                    next_control = await google_patents_next_control(page)
                    exhausted = next_control is None
                    next_page = page_number + 1
                    browser_completed_pages += 1
                    persist_search_page(
                        runtime,
                        "patent",
                        source,
                        keyword,
                        page_records,
                        next_token="" if exhausted else str(next_page),
                        exhausted=exhausted,
                        page_number=browser_completed_pages,
                        page_signature=page_signature,
                    )
                    records.extend(page_records)
                    if exhausted:
                        break
                    page_number = next_page
                await browser.close()
        SEARCH_TASK_CONTEXT.reset(browser_context_token)
        return dedupe_patent_records(records)
    except Exception as exc:
        if "browser_context_token" in locals():
            try:
                SEARCH_TASK_CONTEXT.reset(browser_context_token)
            except Exception:
                pass
        runtime.skip(source, keyword, f"browser fallback failed: {safe_error_text(str(exc))}")
        if records:
            runtime.mark_current_run("patent", source, keyword, "incomplete", "browser_failed_after_partial_results")
        return dedupe_patent_records(records)


def epo_publication_number(document: Any) -> str:
    documents = document if isinstance(document, list) else [document]
    selected = next((item for item in documents if isinstance(item, dict) and item.get("@document-id-type") == "docdb"), None)
    if selected is None:
        selected = next((item for item in documents if isinstance(item, dict)), {})
    country = first_string(selected.get("country"))
    number = first_string(selected.get("doc-number"))
    kind = first_string(selected.get("kind"))
    return f"{country}{number}{kind}" if country and number else number


def epo_epodoc_input(value: Any) -> str:
    """Format a normalized publication number for an OPS epodoc request."""

    publication = normalize_publication_number(value)
    match = re.fullmatch(r"([A-Z]{2})(\d+)([A-Z]\d?)?", publication)
    if not match:
        return publication
    country, number, kind = match.groups()
    return f"{country}{number}{'.' + kind if kind else ''}"


def _epo_xml_local_name(node: Any) -> str:
    return first_string(getattr(node, "tag", "")).rsplit("}", 1)[-1]


def _epo_xml_node_text(node: Any) -> str:
    return re.sub(
        r"\s+",
        " ",
        " ".join(part.strip() for part in node.itertext() if part and part.strip()),
    ).strip()


def _epo_xml_document_id(reference: Any) -> tuple[str, str]:
    candidates: list[tuple[str, dict[str, str]]] = []
    for document_id in reference.iter():
        if _epo_xml_local_name(document_id) != "document-id":
            continue
        values: dict[str, str] = {}
        for node in document_id.iter():
            local = _epo_xml_local_name(node)
            if local in {"country", "doc-number", "kind", "date"} and node.text:
                values.setdefault(local, node.text.strip())
        id_type = first_string(
            next(
                (
                    value
                    for key, value in document_id.attrib.items()
                    if key.rsplit("}", 1)[-1] == "document-id-type"
                ),
                "",
            )
        ).casefold()
        candidates.append((id_type, values))
    selected = next(
        (values for id_type, values in candidates if id_type == "docdb"),
        candidates[0][1] if candidates else {},
    )
    publication = normalize_publication_number(
        f"{selected.get('country', '')}{selected.get('doc-number', '')}{selected.get('kind', '')}"
    )
    return publication, first_string(selected.get("date"))


def _epo_xml_reference(exchange_document: Any, name: str) -> tuple[str, str]:
    for reference in exchange_document.iter():
        if _epo_xml_local_name(reference) == name:
            return _epo_xml_document_id(reference)
    return "", ""


def _epo_xml_people(exchange_document: Any, singular: str) -> list[str]:
    names: list[str] = []
    for person in exchange_document.iter():
        if _epo_xml_local_name(person) != singular:
            continue
        value = ""
        for node in person.iter():
            if _epo_xml_local_name(node) == "name":
                value = _epo_xml_node_text(node)
                if value:
                    break
        if value and value not in names:
            names.append(value)
    return names


def parse_epo_ops_bibliographic_results(
    data: str,
    source: str,
    keyword: str,
    rank_start: int = 0,
) -> list[PatentRecord]:
    """Parse the official OPS exchange XML returned by bulk biblio retrieval.

    Search hits contain publication references only.  This parser intentionally
    consumes the separate published-data/biblio response and never invents
    titles, people, or dates when an element is absent.
    """

    root = ET.fromstring(data)
    records: list[PatentRecord] = []
    for exchange_document in root.iter():
        if _epo_xml_local_name(exchange_document) != "exchange-document":
            continue
        publication = normalize_publication_number(
            f"{first_string(exchange_document.attrib.get('country'))}"
            f"{first_string(exchange_document.attrib.get('doc-number'))}"
            f"{first_string(exchange_document.attrib.get('kind'))}"
        )
        publication_date = ""
        if not publication:
            publication, publication_date = _epo_xml_reference(
                exchange_document,
                "publication-reference",
            )
        else:
            _, publication_date = _epo_xml_reference(
                exchange_document,
                "publication-reference",
            )
        _, application_date = _epo_xml_reference(
            exchange_document,
            "application-reference",
        )
        title_candidates: list[tuple[bool, str]] = []
        for node in exchange_document.iter():
            if _epo_xml_local_name(node) != "invention-title":
                continue
            title = _epo_xml_node_text(node)
            if not title:
                continue
            language = first_string(
                next(
                    (
                        value
                        for key, value in node.attrib.items()
                        if key.rsplit("}", 1)[-1] in {"lang", "language"}
                    ),
                    "",
                )
            ).casefold()
            title_candidates.append((language == "en", title))
        title = next(
            (value for preferred, value in title_candidates if preferred),
            title_candidates[0][1] if title_candidates else "",
        )
        if not publication:
            continue
        records.append(
            PatentRecord(
                patent_name=title or publication,
                authors=_epo_xml_people(exchange_document, "inventor"),
                year=parse_year(publication_date or application_date),
                url=(
                    "https://worldwide.espacenet.com/patent/search?"
                    f"q={urllib.parse.quote(publication)}"
                ),
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=publication,
                publication_number=publication,
                applicants=_epo_xml_people(exchange_document, "applicant"),
                database="EPO OPS bibliographic",
                application_date=application_date or None,
                publication_date=publication_date or None,
            )
        )
    return records


def merge_epo_bibliographic_records(
    search_records: list[PatentRecord],
    bibliographic_records: list[PatentRecord],
) -> tuple[list[PatentRecord], int]:
    by_publication = {
        normalize_publication_number(record.publication_number): record
        for record in bibliographic_records
        if normalize_publication_number(record.publication_number)
    }
    enriched = 0
    for record in search_records:
        publication = normalize_publication_number(record.publication_number)
        detail = by_publication.get(publication)
        if detail is None:
            continue
        changed = False
        if (
            not record.patent_name
            or normalize_publication_number(record.patent_name) == publication
        ) and detail.patent_name:
            record.patent_name = detail.patent_name
            changed = True
        for attribute in (
            "authors",
            "year",
            "applicants",
            "database",
            "application_date",
            "publication_date",
        ):
            if not getattr(record, attribute) and getattr(detail, attribute):
                setattr(record, attribute, getattr(detail, attribute))
                changed = True
        enriched += int(changed)
    return search_records, enriched


def parse_epo_ops_results(data: dict[str, Any] | str, source: str, keyword: str, rank_start: int = 0) -> tuple[list[PatentRecord], int | None, int]:
    publications: list[str] = []
    total: int | None = None
    if isinstance(data, dict):
        search_result = data.get("ops:world-patent-data", {}).get("ops:biblio-search", {}).get("ops:search-result", {})
        hits = search_result.get("ops:publication-reference", [])
        if isinstance(hits, dict):
            hits = [hits]
        total = parse_int(search_result.get("@total-result-count"))
        for hit in hits:
            if isinstance(hit, dict):
                publication = epo_publication_number(hit.get("document-id", hit.get("ops:document-id", {})))
                if publication:
                    publications.append(publication)
    else:
        root = ET.fromstring(data)
        total = parse_int(next((value for key, value in root.attrib.items() if key.endswith("total-result-count")), None))
        for reference in root.iter():
            if reference.tag.rsplit("}", 1)[-1] != "publication-reference":
                continue
            values: dict[str, str] = {}
            for node in reference.iter():
                local = node.tag.rsplit("}", 1)[-1]
                if local in {"country", "doc-number", "kind"} and node.text and local not in values:
                    values[local] = node.text.strip()
            publication = f"{values.get('country', '')}{values.get('doc-number', '')}{values.get('kind', '')}"
            if publication:
                publications.append(publication)
    records = [
        PatentRecord(
            patent_name=publication,
            authors=[],
            year=None,
            url=f"https://worldwide.espacenet.com/patent/search?q={urllib.parse.quote(publication)}",
            source=source,
            keyword=keyword,
            rank=rank_start + offset,
            raw_id=publication,
            publication_number=publication,
        )
        for offset, publication in enumerate(publications, start=1)
    ]
    if isinstance(data, str) and "exchange-document" in data:
        records, _ = merge_epo_bibliographic_records(
            records,
            parse_epo_ops_bibliographic_results(
                data,
                source,
                keyword,
                rank_start,
            ),
        )
    return records, total, len(publications)


async def search_epo_ops(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[PatentRecord]:
    key = env_value("EPO_OPS_KEY")
    secret = env_value("EPO_OPS_SECRET")
    if not key or not secret:
        runtime.skip(source, keyword, "missing required credential(s): EPO_OPS_KEY/EPO_OPS_SECRET")
        return []
    token_value = base64.b64encode(f"{key}:{secret}".encode("utf-8")).decode("ascii")
    token_response = await runtime.request(source, keyword, "POST", "https://ops.epo.org/3.2/auth/accesstoken", headers={"Authorization": f"Basic {token_value}", "Content-Type": "application/x-www-form-urlencoded"}, data={"grant_type": "client_credentials"})
    if token_response is None:
        return []
    try:
        token = token_response.json()["access_token"]
    except Exception as exc:
        runtime.skip(source, keyword, f"token parse error: {safe_error_text(str(exc))}")
        return []
    page_size = source_page_size(limit, 100)
    token_value, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "1")
    start = parse_int(token_value) or 1
    records: list[PatentRecord] = []
    field_scope = current_query_field_scope("title")
    cql_field = "ab" if field_scope == "abstract" else "ti"
    query_text = current_query_text(keyword)
    bibliographic_incomplete_reason = ""
    while True:
        end = start + page_size - 1
        response = await runtime.request(
            source,
            keyword,
            "GET",
            url,
            headers={
                "Authorization": f"Bearer {token}",
                "Accept": "application/json, application/xml;q=0.9",
                "Range": f"{start}-{end}",
            },
            params={"q": f"{cql_field}={quoted_search_phrase(query_text)}"},
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("patent", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            content_type = first_string(response.headers.get("content-type") if hasattr(response, "headers") else "").casefold()
            payload: dict[str, Any] | str = response.json() if "json" in content_type else response.text
            page_records, total, raw_count = parse_epo_ops_results(payload, source, keyword, len(records))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("patent", source, keyword, "failed", "epo_ops_schema_error")
            return records
        biblio_reason = ""
        if page_records:
            # OPS documents bulk bibliographic retrieval with POST and limits a
            # request to 100 input references.  The search page size is already
            # capped at 100, so enrich the page in one official API call rather
            # than issuing one request per patent.
            epodoc_inputs = list(
                dict.fromkeys(
                    value
                    for record in page_records
                    if (value := epo_epodoc_input(record.publication_number))
                )
            )
            biblio_response = await runtime.request(
                source,
                keyword,
                "POST",
                "https://ops.epo.org/3.2/rest-services/published-data/"
                "publication/epodoc/biblio",
                headers={
                    "Authorization": f"Bearer {token}",
                    "Accept": "application/exchange+xml",
                    "Content-Type": "text/plain; charset=utf-8",
                },
                data="\n".join(epodoc_inputs),
            )
            if biblio_response is None:
                biblio_reason = "epo_bibliographic_enrichment_failed"
                runtime.degrade(
                    source,
                    keyword,
                    "epo_bibliographic_enrichment_failed",
                )
                runtime.mark_current_run(
                    "patent",
                    source,
                    keyword,
                    "incomplete",
                    "epo_bibliographic_enrichment_failed",
                )
            else:
                try:
                    bibliographic_records = parse_epo_ops_bibliographic_results(
                        biblio_response.text,
                        source,
                        keyword,
                        len(records),
                    )
                    page_records, enriched_count = merge_epo_bibliographic_records(
                        page_records,
                        bibliographic_records,
                    )
                    if enriched_count < len(page_records):
                        biblio_reason = (
                            "epo_bibliographic_enrichment_partial:"
                            f"{enriched_count}/{len(page_records)}"
                        )
                        runtime.degrade(
                            source,
                            keyword,
                            "epo_bibliographic_enrichment_partial:"
                            f"{enriched_count}/{len(page_records)}",
                        )
                        runtime.mark_current_run(
                            "patent",
                            source,
                            keyword,
                            "incomplete",
                            "epo_bibliographic_enrichment_partial:"
                            f"{enriched_count}/{len(page_records)}",
                        )
                except Exception as exc:
                    biblio_reason = "epo_bibliographic_schema_error"
                    runtime.degrade(
                        source,
                        keyword,
                        "epo_bibliographic_schema_error:"
                        f"{safe_error_text(str(exc))}",
                    )
                    runtime.mark_current_run(
                        "patent",
                        source,
                        keyword,
                        "incomplete",
                        "epo_bibliographic_schema_error",
                    )
        next_start = start + raw_count
        exhausted = raw_count == 0 or raw_count < page_size or (total is not None and next_start > total)
        completed_pages += 1
        persist_search_page(runtime, "patent", source, keyword, page_records, next_token="" if exhausted else str(next_start), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        if biblio_reason:
            bibliographic_incomplete_reason = (
                bibliographic_incomplete_reason or biblio_reason
            )
        if bibliographic_incomplete_reason:
            runtime.mark_current_run(
                "patent",
                source,
                keyword,
                "incomplete",
                bibliographic_incomplete_reason,
            )
        records.extend(page_records)
        if exhausted:
            break
        if next_start <= start:
            runtime.mark_current_run("patent", source, keyword, "incomplete", "repeated_offset")
            break
        start = next_start
    return records


def uspto_items(data: dict[str, Any]) -> list[dict[str, Any]]:
    items = data.get("results") or data.get("patentFileWrapperDataBag", []) or []
    return [item for item in items if isinstance(item, dict)]


def parse_uspto_odp_results(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    for offset, item in enumerate(uspto_items(data), start=1):
            app = first_string(item.get("applicationNumberText") or item.get("applicationNumber"))
            publication = first_string(item.get("publicationNumber") or item.get("patentNumber"))
            records.append(
                PatentRecord(
                    patent_name=first_string(item.get("inventionTitle") or item.get("title") or publication or app),
                    authors=clean_people(item.get("inventorName") or item.get("inventors") or item.get("applicantName")),
                    year=parse_year(item.get("publicationDate") or item.get("filingDate")),
                    url=f"https://data.uspto.gov/patent/file-wrapper/search/results?query={urllib.parse.quote(app or publication)}",
                    source=source,
                    keyword=keyword,
                    rank=rank_start + offset,
                    raw_id=app or publication,
                    publication_number=publication or None,
                )
            )
    return [record for record in records if record.patent_name]


async def search_uspto_odp(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[PatentRecord]:
    api_key = env_value("USPTO_ODP_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): USPTO_ODP_API_KEY")
        return []
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "0")
    offset = parse_int(token) or 0
    records: list[PatentRecord] = []
    field_scope = current_query_field_scope("title")
    uspto_field = {
        "title": "inventionTitle",
        "abstract": "abstractText",
        "claims": "claimText",
    }.get(field_scope, "inventionTitle")
    query_text = current_query_text(keyword)
    while True:
        response = await runtime.request(
            source,
            keyword,
            "POST",
            url,
            headers={"X-API-KEY": api_key},
            json={
                "q": f"{uspto_field}:{quoted_search_phrase(query_text)}",
                "pagination": {"offset": offset, "limit": page_size},
            },
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("patent", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = uspto_items(data)
            page_records = parse_uspto_odp_results(data, source, keyword, len(records))
            total = parse_int(data.get("total") or data.get("totalCount") or (data.get("pagination") or {}).get("total"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("patent", source, keyword, "failed", "uspto_odp_schema_error")
            return records
        next_offset = offset + len(raw_items)
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and next_offset >= total)
        completed_pages += 1
        persist_search_page(runtime, "patent", source, keyword, page_records, next_token="" if exhausted else str(next_offset), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_offset <= offset:
            runtime.mark_current_run("patent", source, keyword, "incomplete", "repeated_offset")
            break
        offset = next_offset
    return records


WIPO_PUBLICATION_PATTERN = re.compile(
    r"\b(?:WO|EP|US|CN|JP|KR|DE|FR|GB|CA|AU|IN|BR|MX|RU|EA|AP|OA|ZA)[\s/-]*\d{4,}(?:[\s/-]*[A-Z]\d?)?\b",
    re.IGNORECASE,
)


def normalize_publication_number(value: Any) -> str:
    text = first_string(value).upper().strip()
    return re.sub(r"[^A-Z0-9]", "", text)


def wipo_publication_number(*values: Any) -> str:
    for value in values:
        text = html.unescape(urllib.parse.unquote(first_string(value)))
        if not text:
            continue
        try:
            parsed = urllib.parse.urlsplit(text)
            query = urllib.parse.parse_qs(parsed.query)
            for key in ("docId", "docid", "publicationNumber", "publication_number"):
                candidate = normalize_publication_number(first_string(query.get(key)))
                if candidate:
                    return candidate
        except ValueError:
            pass
        match = WIPO_PUBLICATION_PATTERN.search(text)
        if match:
            return normalize_publication_number(match.group(0))
    return ""


def iter_nested_dicts(value: Any) -> list[dict[str, Any]]:
    found: list[dict[str, Any]] = []
    stack = [value]
    while stack:
        current = stack.pop()
        if isinstance(current, dict):
            found.append(current)
            stack.extend(current.values())
        elif isinstance(current, (list, tuple)):
            stack.extend(current)
    return found


def parse_wipo_patentscope_soap(data: Any, source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    seen: set[str] = set()
    for item in iter_nested_dicts(data):
        publication = wipo_publication_number(
            item.get("publicationNumber"),
            item.get("publication_number"),
            item.get("docId"),
            item.get("documentId"),
            item.get("identifier"),
        )
        if not publication or publication in seen:
            continue
        seen.add(publication)
        title = first_string(item.get("title") or item.get("inventionTitle") or item.get("name")) or publication
        record_url = first_string(item.get("url") or item.get("link"))
        if not record_url:
            record_url = f"https://patentscope.wipo.int/search/en/detail.jsf?docId={urllib.parse.quote(publication)}"
        records.append(
            PatentRecord(
                patent_name=title,
                authors=clean_people(item.get("inventors") or item.get("inventor") or item.get("applicants") or item.get("applicant")),
                year=parse_year(item.get("publicationDate") or item.get("publication_date") or item.get("date")),
                url=record_url,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=publication,
                publication_number=publication,
            )
        )
    return records


def parse_wipo_patentscope_results(data: str | dict[str, Any] | list[Any], base_url: str, source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    if not isinstance(data, str):
        return parse_wipo_patentscope_soap(data, source, keyword, rank_start)
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(data, "html.parser")
    anchors = soup.select(
        "a[href*='detail.jsf'], a[href*='docId='], a[href*='/patentscope/'], "
        "a[href*='/search/en/detail'], a.patent-title, .result-title a, .ps-result a"
    )
    records: list[PatentRecord] = []
    seen_urls: set[str] = set()
    for anchor in anchors:
        href = first_string(anchor.get("href"))
        if not href:
            continue
        record_url = urllib.parse.urljoin(base_url, href)
        if record_url in seen_urls:
            continue
        card = anchor.find_parent(["article", "li", "tr"]) or anchor.find_parent(
            "div", class_=re.compile(r"result|record|patent|hit", re.IGNORECASE)
        )
        container = card or anchor.parent or anchor
        container_text = " ".join(container.stripped_strings)
        publication = wipo_publication_number(record_url, anchor.get_text(" ", strip=True), container_text)
        title_node = container.select_one(".title, .result-title, .patent-title, h2, h3, h4") if hasattr(container, "select_one") else None
        title = first_string(title_node.get_text(" ", strip=True) if title_node else anchor.get_text(" ", strip=True))
        if not publication and not title:
            continue
        seen_urls.add(record_url)
        people_node = container.select_one(".inventor, .inventors, .applicant, .applicants, [class*='inventor'], [class*='applicant']") if hasattr(container, "select_one") else None
        people_text = first_string(people_node.get_text(" ", strip=True) if people_node else "")
        records.append(
            PatentRecord(
                patent_name=title or publication,
                authors=clean_people(people_text),
                year=parse_year(container_text),
                url=record_url,
                source=source,
                keyword=keyword,
                rank=rank_start + len(records) + 1,
                raw_id=publication or record_url,
                publication_number=publication or None,
            )
        )
    return records


def wipo_wsdl_url() -> str:
    value = env_value("PATENTSCOPE_WSDL_URL")
    if not value:
        return ""
    try:
        parsed = urllib.parse.urlsplit(value)
    except ValueError:
        return ""
    host = parsed.hostname.casefold() if parsed.hostname else ""
    if parsed.scheme not in {"https", "http"} or not (host == "wipo.int" or host.endswith(".wipo.int")):
        return ""
    return value


def inspect_wipo_soap_operations(wsdl_url: str, username: str, password: str) -> tuple[Any, list[str]]:
    zeep = importlib.import_module("zeep")
    kwargs: dict[str, Any] = {}
    if username and password:
        username_token = importlib.import_module("zeep.wsse.username").UsernameToken
        kwargs["wsse"] = username_token(username, password)
    client = zeep.Client(wsdl=wsdl_url, **kwargs)
    operations: list[str] = []
    for service in client.wsdl.services.values():
        for port in service.ports.values():
            operations.extend(str(name) for name in port.binding._operations)
    return client, sorted(set(operations))


def wipo_keyword_search_operation(operations: list[str]) -> str:
    preferred = ("searchpatent", "patentsearch", "search", "query", "find")
    lowered = {operation.casefold(): operation for operation in operations}
    for token in preferred:
        for normalized, operation in lowered.items():
            if token in normalized and not any(blocked in normalized for blocked in ("document", "download", "retrieve", "fetch")):
                return operation
    return ""


def call_wipo_soap_search(client: Any, operation_name: str, keyword: str) -> Any:
    operation = getattr(client.service, operation_name)
    signature = ""
    try:
        signature = str(client.service._binding._operations[operation_name].input.signature())
    except Exception:
        pass
    parameter_names = re.findall(r"([A-Za-z_][A-Za-z0-9_]*)\s*:", signature)
    for candidate in ("query", "searchQuery", "search_query", "keyword", "expression"):
        if candidate in parameter_names:
            return operation(**{candidate: keyword})
    if len(parameter_names) == 1:
        return operation(**{parameter_names[0]: keyword})
    return operation(keyword)


async def search_wipo_soap(runtime: SearchRuntime, source: str, keyword: str) -> list[PatentRecord]:
    parent_context = SEARCH_TASK_CONTEXT.get()
    context_token = SEARCH_TASK_CONTEXT.set(parent_context | {"path": "soap_probe"})
    try:
        configured_wsdl = env_value("PATENTSCOPE_WSDL_URL")
        wsdl_url = wipo_wsdl_url()
        if not configured_wsdl:
            runtime.mark_current_run("patent", source, keyword, "blocked", "soap_search_operation_unavailable:wsdl_not_configured")
            runtime.degrade(source, keyword, "WIPO SOAP probe skipped: PATENTSCOPE_WSDL_URL is not configured; continuing public browser path")
            return []
        if not wsdl_url:
            runtime.mark_current_run("patent", source, keyword, "blocked", "soap_search_operation_unavailable:wsdl_must_be_wipo_hosted")
            runtime.degrade(source, keyword, "WIPO SOAP probe rejected a non-WIPO WSDL URL; continuing public browser path")
            return []
        username = env_value("PATENTSCOPE_WEBSERVICE_USERNAME")
        password = env_value("PATENTSCOPE_WEBSERVICE_PASSWORD")
        try:
            client, operations = await asyncio.to_thread(inspect_wipo_soap_operations, wsdl_url, username, password)
        except Exception as exc:
            runtime.mark_current_run("patent", source, keyword, "incomplete", f"soap_wsdl_probe_failed:{exc.__class__.__name__}")
            runtime.degrade(source, keyword, f"WIPO SOAP WSDL probe failed; continuing public browser path: {safe_error_text(str(exc))}")
            return []
        operation = wipo_keyword_search_operation(operations)
        if not operation:
            runtime.mark_current_run("patent", source, keyword, "blocked", "soap_search_operation_unavailable")
            runtime.degrade(source, keyword, "WIPO WSDL has no keyword-search operation; continuing public browser path")
            return []
        if not username or not password:
            runtime.mark_current_run("patent", source, keyword, "blocked", "missing_credentials:PATENTSCOPE_WEBSERVICE_USERNAME/PATENTSCOPE_WEBSERVICE_PASSWORD")
            runtime.degrade(source, keyword, "WIPO SOAP search operation exists but credentials are missing; continuing public browser path")
            return []
        try:
            result = await asyncio.to_thread(call_wipo_soap_search, client, operation, keyword)
            helpers = importlib.import_module("zeep.helpers")
            serialized = helpers.serialize_object(result)
            records = parse_wipo_patentscope_results(serialized, wsdl_url, source, keyword)
        except Exception as exc:
            runtime.mark_current_run("patent", source, keyword, "incomplete", f"soap_search_failed:{exc.__class__.__name__}")
            runtime.degrade(source, keyword, f"WIPO SOAP search failed; continuing public browser path: {safe_error_text(str(exc))}")
            return []
        persist_search_page(runtime, "patent", source, keyword, records, next_token="", exhausted=False, page_number=1, reason="soap_pagination_unavailable")
        runtime.mark_current_run("patent", source, keyword, "incomplete", "soap_pagination_unavailable")
        return records
    finally:
        SEARCH_TASK_CONTEXT.reset(context_token)


async def wipo_page_signature(page: Any) -> str:
    try:
        return first_string(
            await page.evaluate(
                """() => {
                    const pageValue = document.querySelector('.ps-paginator--page--value')?.innerText || '';
                    const firstResult = document.querySelector('a[href*="detail.jsf"], a[href*="docId="]')?.href || '';
                    return `${pageValue.trim()}|${firstResult}`;
                }"""
            )
        )
    except Exception:
        return ""


async def wipo_next_control(page: Any) -> Any | None:
    selectors = (
        "a.js-paginator-next:not(.ui-state-disabled)",
        "a[aria-label='Next Page']:not(.ui-state-disabled)",
        "a[title='Next Page']:not(.ui-state-disabled)",
        "a.ui-paginator-next:not(.ui-state-disabled)",
    )
    for selector in selectors:
        locators = page.locator(selector)
        try:
            for index in range(await locators.count()):
                locator = locators.nth(index)
                if await locator.is_visible(timeout=500):
                    return locator
        except Exception:
            continue
    return None


async def wipo_advance_page(page: Any) -> bool:
    locator = await wipo_next_control(page)
    if locator is None:
        return False
    before = await wipo_page_signature(page)
    try:
        await locator.scroll_into_view_if_needed(timeout=5000)
        try:
            await locator.click(timeout=10000)
        except Exception:
            await locator.evaluate("element => element.click()")
        for _ in range(80):
            await page.wait_for_timeout(250)
            after = await wipo_page_signature(page)
            if after and after != before:
                return True
    except Exception:
        return False
    return False


def wipo_no_results(body: str) -> bool:
    lowered = body.casefold()
    return any(marker in lowered for marker in ("no result", "no patent", "0 result", "没有结果", "未找到"))


WIPO_QUERY_CONTROL_SELECTORS = (
    "form[id*='simpleSearch' i] input[id*='fpSearch' i]",
    "form[id*='simpleSearch' i] input[name*='fpSearch' i]",
    "form[id*='simpleSearch' i] input[id*='query' i]",
    "form[id*='simpleSearch' i] input[name*='query' i]",
    "form[id*='simpleSearch' i] textarea[id*='query' i]",
    "form[id*='simpleSearch' i] textarea[name*='query' i]",
    "form[id*='search' i] input[id*='query' i]",
    "form[id*='search' i] input[name*='query' i]",
    "input[id*='fpSearch' i]",
    "input[name*='fpSearch' i]",
    "input[id*='query' i]",
    "input[name*='query' i]",
    "textarea[id*='query' i]",
    "textarea[name*='query' i]",
)

WIPO_SUBMIT_CONTROL_SELECTORS = (
    "button[id*='searchButton' i]",
    "input[id*='searchButton' i][type='submit']",
    "button[id*='search' i][type='submit']",
    "input[id*='search' i][type='submit']",
    "button[type='submit']",
    "input[type='submit']",
    "button:has-text('Search')",
)

WIPO_RESULT_READY_SELECTORS = (
    "a[href*='detail.jsf']",
    "a[href*='docId=']",
    ".result-record",
    ".result-title",
    ".ps-result",
    "[class*='result-record']",
)


def wipo_public_search_entry_url() -> str:
    return patents_search_path_map.get(
        "WIPO PATENTSCOPE API",
        "https://patentscope.wipo.int/search/en/search.jsf",
    )


def wipo_access_boundary_reason(title: str, body: str) -> str:
    combined = " ".join((title or "", body or "")).casefold()
    challenge_type = classify_search_challenge(combined)
    if challenge_type in {"captcha_required", "robot_check", "cloudflare_or_waf"}:
        return "wipo_verification_required"
    if challenge_type == "access_denied" or any(
        marker in combined
        for marker in (
            "error 403 forbidden",
            "403 forbidden",
            "http 403",
            "access forbidden",
        )
    ):
        return "wipo_access_forbidden"
    if any(marker in combined for marker in ("error 429", "http 429", "too many requests")):
        return "wipo_rate_limited"
    if any(
        marker in combined
        for marker in (
            "error 500",
            "error 502",
            "error 503",
            "service unavailable",
            "bad gateway",
        )
    ):
        return "wipo_service_unavailable"
    if body_has_verification_challenge(combined):
        return "wipo_verification_required"
    return ""


async def wipo_page_title_and_body(page: Any) -> tuple[str, str]:
    try:
        title = first_string(await page.title())
    except Exception:
        title = ""
    return title, await page_body_text(page)


async def wipo_results_ready(page: Any, body: str = "") -> bool:
    if wipo_no_results(body):
        return True
    for selector in WIPO_RESULT_READY_SELECTORS:
        try:
            if await page.locator(selector).count() > 0:
                return True
        except Exception:
            continue
    return False


async def wipo_first_visible_locator(
    root: Any,
    selectors: tuple[str, ...],
    *,
    timeout_seconds: int,
) -> Any | None:
    deadline = time.monotonic() + max(1, timeout_seconds)
    while time.monotonic() < deadline:
        locator = await wipo_visible_locator_once(root, selectors)
        if locator is not None:
            return locator
        try:
            await root.page.wait_for_timeout(500)
        except Exception:
            try:
                await root.wait_for_timeout(500)
            except Exception:
                await asyncio.sleep(0.5)
    return None


async def wipo_visible_locator_once(root: Any, selectors: tuple[str, ...]) -> Any | None:
    for selector in selectors:
        try:
            locators = root.locator(selector)
            for index in range(await locators.count()):
                locator = locators.nth(index)
                if await locator.is_visible(timeout=500):
                    return locator
        except Exception:
            continue
    return None


async def wipo_submit_control(page: Any, query_control: Any) -> Any | None:
    try:
        form = query_control.locator("xpath=ancestor::form[1]")
        if await form.count() > 0:
            control = await wipo_first_visible_locator(
                form,
                WIPO_SUBMIT_CONTROL_SELECTORS,
                timeout_seconds=2,
            )
            if control is not None:
                return control
    except Exception:
        pass
    return await wipo_first_visible_locator(
        page,
        WIPO_SUBMIT_CONTROL_SELECTORS,
        timeout_seconds=3,
    )


async def submit_wipo_patentscope_search(page: Any, keyword: str) -> tuple[bool, str]:
    form_timeout = min(60, env_seconds("LAPS_WIPO_SEARCH_FORM_TIMEOUT_SECONDS", 20, 1))
    result_timeout = min(90, env_seconds("LAPS_WIPO_SEARCH_RESULT_TIMEOUT_SECONDS", 30, 1))
    query_control = None
    form_deadline = time.monotonic() + form_timeout
    while time.monotonic() < form_deadline:
        title, body = await wipo_page_title_and_body(page)
        boundary = wipo_access_boundary_reason(title, body)
        if boundary:
            return False, boundary
        if await wipo_results_ready(page, body):
            return True, "wipo_results_ready"
        query_control = await wipo_visible_locator_once(
            page,
            WIPO_QUERY_CONTROL_SELECTORS,
        )
        if query_control is not None:
            break
        try:
            await page.wait_for_timeout(500)
        except Exception:
            await asyncio.sleep(0.5)
    if query_control is None:
        title, body = await wipo_page_title_and_body(page)
        return False, wipo_access_boundary_reason(title, body) or "wipo_search_form_not_ready"
    try:
        await query_control.fill(keyword, timeout=5000)
        submit_control = await wipo_submit_control(page, query_control)
        if submit_control is not None:
            await submit_control.click(timeout=10000)
        else:
            await query_control.press("Enter", timeout=5000)
    except Exception as exc:
        return False, f"wipo_search_submit_failed:{exc.__class__.__name__}"

    deadline = time.monotonic() + result_timeout
    while time.monotonic() < deadline:
        title, body = await wipo_page_title_and_body(page)
        boundary = wipo_access_boundary_reason(title, body)
        if boundary:
            return False, boundary
        if await wipo_results_ready(page, body):
            return True, "wipo_results_ready"
        try:
            await page.wait_for_timeout(500)
        except Exception:
            await asyncio.sleep(0.5)
    return False, "wipo_search_result_not_ready"


async def resolve_wipo_access_state(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    browser_type: Any,
    browser: Any,
    context: Any,
    page: Any,
    target_url: str,
    context_kwargs: dict[str, Any],
) -> tuple[bool, Any, Any, Any, str]:
    title, body = await wipo_page_title_and_body(page)
    boundary = wipo_access_boundary_reason(title, body)
    if boundary == "wipo_verification_required":
        resolved, browser, context, page = await handle_search_verification_challenge(
            runtime,
            source,
            keyword,
            browser_type,
            browser,
            context,
            page,
            first_string(getattr(page, "url", "")) or target_url,
            body,
            context_kwargs,
        )
        if not resolved:
            runtime.mark_current_run(
                "patent",
                source,
                keyword,
                "incomplete",
                "search_challenge_unresolved",
            )
            return False, browser, context, page, body
        title, body = await wipo_page_title_and_body(page)
        boundary = wipo_access_boundary_reason(title, body)
    if boundary:
        runtime.skip(source, keyword, boundary)
        runtime.mark_current_run("patent", source, keyword, "incomplete", boundary)
        return False, browser, context, page, body
    return True, browser, context, page, body


async def search_wipo_patentscope(runtime: SearchRuntime, source: str, keyword: str, limit: int) -> list[PatentRecord]:
    soap_records = await search_wipo_soap(runtime, source, keyword)
    entry_url = wipo_public_search_entry_url()
    parent_context = SEARCH_TASK_CONTEXT.get()
    browser_token = SEARCH_TASK_CONTEXT.set(parent_context | {"path": "public_browser"})
    records: list[PatentRecord] = []
    try:
        resume_token, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "page:1")
        resume_page = parse_int(resume_token.removeprefix("page:")) or 1
        async_playwright = load_async_playwright()
        async with runtime.browser_sem:
            async with async_playwright() as pw:
                browser = await pw.chromium.launch(headless=True)
                context_kwargs: dict[str, Any] = {}
                context = await browser.new_context(**context_kwargs)
                page = await context.new_page()
                await wait_for_rate_limiter(
                    runtime.limiter,
                    urllib.parse.urlparse(entry_url).netloc,
                    kind="browser",
                    source=source,
                )
                await page.goto(entry_url, wait_until="domcontentloaded", timeout=30000)
                ready, browser, context, page, body = await resolve_wipo_access_state(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    entry_url,
                    context_kwargs,
                )
                if not ready:
                    await context.close()
                    await browser.close()
                    return dedupe_patent_records([*soap_records, *records])
                if not await wipo_results_ready(page, body):
                    submitted, submission_reason = await submit_wipo_patentscope_search(
                        page,
                        keyword,
                    )
                    ready, browser, context, page, body = await resolve_wipo_access_state(
                        runtime,
                        source,
                        keyword,
                        pw.chromium,
                        browser,
                        context,
                        page,
                        first_string(getattr(page, "url", "")) or entry_url,
                        context_kwargs,
                    )
                    if not ready:
                        await context.close()
                        await browser.close()
                        return dedupe_patent_records([*soap_records, *records])
                    if not await wipo_results_ready(page, body):
                        reason = (
                            "wipo_search_result_not_ready_after_verification"
                            if submission_reason == "wipo_verification_required"
                            else submission_reason
                        )
                        runtime.skip(source, keyword, reason)
                        runtime.mark_current_run("patent", source, keyword, "incomplete", reason)
                        await context.close()
                        await browser.close()
                        return dedupe_patent_records([*soap_records, *records])
                    if not submitted and submission_reason not in {
                        "wipo_verification_required",
                        "wipo_results_ready",
                    }:
                        runtime.degrade(
                            source,
                            keyword,
                            f"WIPO search continued after boundary recovery: {submission_reason}",
                        )
                current_page = 1
                if resume_page > 1:
                    runtime.degrade(source, keyword, "WIPO JSF checkpoint requires bounded page fast-forward within a new browser session")
                while current_page < resume_page:
                    ready, browser, context, page, _ = await resolve_wipo_access_state(
                        runtime,
                        source,
                        keyword,
                        pw.chromium,
                        browser,
                        context,
                        page,
                        first_string(getattr(page, "url", "")) or entry_url,
                        context_kwargs,
                    )
                    if not ready:
                        await context.close()
                        await browser.close()
                        return dedupe_patent_records([*soap_records, *records])
                    if not await wipo_advance_page(page):
                        runtime.mark_current_run("patent", source, keyword, "incomplete", "wipo_checkpoint_fast_forward_failed")
                        await context.close()
                        await browser.close()
                        return dedupe_patent_records([*soap_records, *records])
                    current_page += 1
                while True:
                    await page.wait_for_timeout(500)
                    ready, browser, context, page, body = await resolve_wipo_access_state(
                        runtime,
                        source,
                        keyword,
                        pw.chromium,
                        browser,
                        context,
                        page,
                        first_string(getattr(page, "url", "")) or entry_url,
                        context_kwargs,
                    )
                    if not ready:
                        break
                    if not await wipo_results_ready(page, body):
                        runtime.mark_current_run("patent", source, keyword, "incomplete", "wipo_results_not_detected")
                        break
                    page_records = parse_wipo_patentscope_results(await page.content(), first_string(page.url) or entry_url, source, keyword, len(records))
                    has_next = await wipo_next_control(page) is not None
                    if not page_records and not wipo_no_results(body):
                        runtime.mark_current_run("patent", source, keyword, "incomplete", "wipo_results_not_detected")
                        break
                    exhausted = not has_next
                    completed_pages += 1
                    persist_search_page(runtime, "patent", source, keyword, page_records, next_token="" if exhausted else f"page:{current_page + 1}", exhausted=exhausted, page_number=completed_pages)
                    records.extend(page_records)
                    if exhausted:
                        break
                    ready, browser, context, page, _ = await resolve_wipo_access_state(
                        runtime,
                        source,
                        keyword,
                        pw.chromium,
                        browser,
                        context,
                        page,
                        first_string(getattr(page, "url", "")) or entry_url,
                        context_kwargs,
                    )
                    if not ready:
                        break
                    before = await wipo_page_signature(page)
                    if not await wipo_advance_page(page):
                        ready, browser, context, page, _ = await resolve_wipo_access_state(
                            runtime,
                            source,
                            keyword,
                            pw.chromium,
                            browser,
                            context,
                            page,
                            first_string(getattr(page, "url", "")) or entry_url,
                            context_kwargs,
                        )
                        if not ready:
                            break
                        after = await wipo_page_signature(page)
                        if after and before and after != before:
                            current_page += 1
                            continue
                        runtime.mark_current_run("patent", source, keyword, "incomplete", "wipo_ajax_next_page_failed")
                        break
                    current_page += 1
                await context.close()
                await browser.close()
    except Exception as exc:
        error_text = safe_error_text(str(exc))
        runtime.skip(source, keyword, f"WIPO public browser failed: {error_text}")
        reason = "wipo_public_browser_timeout" if "timeout" in error_text.casefold() else "wipo_public_browser_failed"
        runtime.mark_current_run("patent", source, keyword, "incomplete" if records or reason.endswith("timeout") else "failed", reason)
    finally:
        SEARCH_TASK_CONTEXT.reset(browser_token)
    return dedupe_patent_records([*soap_records, *records])


def parse_pqai_results(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    for offset, item in enumerate(data.get("results", []), start=1):
            publication = first_string(item.get("publication_number") or item.get("publicationNumber"))
            records.append(PatentRecord(patent_name=first_string(item.get("title") or publication), authors=clean_people(item.get("inventors") or item.get("assignees")), year=parse_year(item.get("publication_date") or item.get("filing_date")), url=f"https://patents.google.com/patent/{publication}/en" if publication else first_string(item.get("url")), source=source, keyword=keyword, rank=rank_start + offset, raw_id=first_string(item.get("id") or publication), publication_number=publication or None))
    return [record for record in records if record.patent_name]


async def search_pqai(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[PatentRecord]:
    api_key = env_value("PQAI_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): PQAI_API_KEY")
        return []
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "0")
    offset = parse_int(token) or 0
    records: list[PatentRecord] = []
    while True:
        response = await runtime.request(
            source,
            keyword,
            "POST",
            url,
            headers={"X-API-Key": api_key},
            json={"q": quoted_search_phrase(keyword), "limit": page_size, "offset": offset},
        )
        if response is None:
            if completed_pages:
                runtime.mark_current_run("patent", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("results", [])
            page_records = parse_pqai_results(data, source, keyword, len(records))
            total = parse_int(data.get("total") or data.get("totalCount"))
            returned_next = parse_int(data.get("next") or data.get("next_offset"))
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("patent", source, keyword, "failed", "pqai_schema_error")
            return records
        next_offset = returned_next if returned_next is not None else offset + len(raw_items)
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and next_offset >= total)
        completed_pages += 1
        persist_search_page(runtime, "patent", source, keyword, page_records, next_token="" if exhausted else str(next_offset), exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_offset <= offset:
            runtime.mark_current_run("patent", source, keyword, "incomplete", "repeated_offset")
            break
        offset = next_offset
    return records


def lens_patent_publication_number(item: dict[str, Any]) -> str:
    publication = first_string(item.get("publication_number") or item.get("publicationNumber"))
    if publication:
        return normalize_publication_number(publication)
    for container_name in ("publication_numbers", "publication_references", "ids", "external_ids"):
        container = item.get(container_name)
        for candidate in container if isinstance(container, list) else [container]:
            if isinstance(candidate, dict):
                publication = first_string(candidate.get("value") or candidate.get("id") or candidate.get("publication_number"))
            else:
                publication = first_string(candidate)
            if publication:
                return normalize_publication_number(publication)
    return ""


def parse_lens_patent_results(data: dict[str, Any], source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    for offset, item in enumerate(data.get("data", []), start=1):
        if not isinstance(item, dict):
            continue
        publication = lens_patent_publication_number(item)
        lens_id = first_string(item.get("lens_id") or item.get("lensId"))
        record_url = first_string(item.get("url"))
        if not record_url and lens_id:
            record_url = f"https://www.lens.org/lens/patent/{urllib.parse.quote(lens_id)}"
        if not record_url and publication:
            record_url = f"https://patents.google.com/patent/{publication}/en"
        title = first_string(item.get("title") or item.get("invention_title")) or publication or lens_id
        if not title or not record_url:
            continue
        records.append(
            PatentRecord(
                patent_name=title,
                authors=clean_people(item.get("inventors") or item.get("applicants") or item.get("owners")),
                year=parse_year(item.get("publication_date") or item.get("filing_date") or item.get("year_published")),
                url=record_url,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=lens_id or publication,
                publication_number=publication or None,
            )
        )
    return records


async def search_lens_patent(runtime: SearchRuntime, source: str, url: str, keyword: str, limit: int) -> list[PatentRecord]:
    api_key = env_value("LENS_Patents_API_KEY")
    if not api_key:
        runtime.skip(source, keyword, "missing required credential(s): LENS_Patents_API_KEY")
        return []
    page_size = source_page_size(limit, 100)
    token, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "offset:0")
    records: list[PatentRecord] = []
    seen_tokens: set[str] = set()
    while token not in seen_tokens:
        seen_tokens.add(token)
        if token.startswith("scroll:"):
            payload: dict[str, Any] = {"scroll_id": token.removeprefix("scroll:")}
        else:
            offset = parse_int(token.removeprefix("offset:")) or 0
            payload = {
                "query": {
                    "query_string": {
                        "query": quoted_search_phrase(keyword),
                        "fields": ["title", "claims", "description"],
                        "default_operator": "and",
                    }
                },
                "size": page_size,
                "from": offset,
                "include": ["lens_id", "publication_number", "publication_numbers", "title", "inventors", "applicants", "publication_date", "filing_date", "url"],
            }
        response = await runtime.request(source, keyword, "POST", url, headers={"Authorization": f"Bearer {api_key}"}, json=payload)
        if response is None:
            if completed_pages:
                runtime.mark_current_run("patent", source, keyword, "incomplete", "request_failed_after_partial_results")
            return records
        try:
            data = response.json()
            raw_items = data.get("data", [])
            page_records = parse_lens_patent_results(data, source, keyword, len(records))
            total = parse_int(data.get("total") or (data.get("meta") or {}).get("total"))
            scroll_id = first_string(data.get("scroll_id") or data.get("scrollId"))
            if scroll_id:
                next_token = f"scroll:{scroll_id}"
            else:
                current_offset = parse_int(token.removeprefix("offset:")) or 0
                next_token = f"offset:{current_offset + len(raw_items)}"
        except Exception as exc:
            runtime.skip(source, keyword, f"parse error: {safe_error_text(str(exc))}")
            runtime.mark_current_run("patent", source, keyword, "failed", "lens_patent_schema_error")
            return records
        exhausted = not raw_items or len(raw_items) < page_size or (total is not None and len(records) + len(raw_items) >= total)
        completed_pages += 1
        persist_search_page(runtime, "patent", source, keyword, page_records, next_token="" if exhausted else next_token, exhausted=exhausted, page_number=completed_pages, total_hint=total)
        records.extend(page_records)
        if exhausted:
            break
        if next_token in seen_tokens:
            runtime.mark_current_run("patent", source, keyword, "incomplete", "repeated_cursor")
            break
        token = next_token
    return records


def has_google_adc() -> bool:
    credentials = env_value("GOOGLE_APPLICATION_CREDENTIALS")
    if credentials:
        os.environ.setdefault("GOOGLE_APPLICATION_CREDENTIALS", credentials)
        return True
    return False


def bigquery_row_value(row: Any, name: str) -> Any:
    if isinstance(row, dict):
        return row.get(name)
    try:
        return row[name]
    except Exception:
        return getattr(row, name, None)


def bigquery_localized_text(value: Any) -> str:
    values = value if isinstance(value, (list, tuple)) else [value]
    candidates: list[tuple[bool, str]] = []
    for item in values:
        if isinstance(item, dict):
            text = first_string(item.get("text") or item.get("value"))
            language = first_string(
                item.get("language") or item.get("lang")
            ).casefold()
        else:
            text = first_string(item)
            language = ""
        if text:
            candidates.append((language == "en", text))
    return next(
        (text for english, text in candidates if english),
        candidates[0][1] if candidates else "",
    )


def bigquery_patent_sql(localized_field: str) -> str:
    allowed_fields = {
        "title_localized",
        "abstract_localized",
        "claims_localized",
    }
    if localized_field not in allowed_fields:
        raise ValueError(f"Unsupported BigQuery localized field: {localized_field}")
    return f"""
    SELECT
      publication_number,
      COALESCE(
        (SELECT t.text FROM UNNEST(title_localized) t
         WHERE t.language = 'en' AND NULLIF(TRIM(t.text), '') IS NOT NULL
         LIMIT 1),
        (SELECT t.text FROM UNNEST(title_localized) t
         WHERE NULLIF(TRIM(t.text), '') IS NOT NULL
         LIMIT 1),
        ''
      ) AS patent_name,
      ARRAY_TO_STRING(ARRAY(SELECT i.name FROM UNNEST(inventor_harmonized) i), '; ') AS authors,
      CAST(FLOOR(publication_date / 10000) AS INT64) AS year,
      CONCAT('https://patents.google.com/patent/', publication_number, '/en') AS url
    FROM `patents-public-data.patents.publications`
    WHERE STRPOS(
            LOWER(ARRAY_TO_STRING(
              ARRAY(SELECT t.text FROM UNNEST({localized_field}) t),
              ' '
            )),
            LOWER(@keyword)
          ) > 0
      AND publication_number > @resume_after
    ORDER BY publication_number
    """


def parse_bigquery_patent_rows(rows: list[Any], source: str, keyword: str, rank_start: int = 0) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    for offset, row in enumerate(rows, start=1):
        publication = normalize_publication_number(bigquery_row_value(row, "publication_number"))
        record_url = first_string(bigquery_row_value(row, "url"))
        if not record_url and publication:
            record_url = f"https://patents.google.com/patent/{publication}/en"
        title = (
            first_string(bigquery_row_value(row, "patent_name"))
            or bigquery_localized_text(bigquery_row_value(row, "title_localized"))
            or publication
        )
        if not title or not record_url:
            continue
        records.append(
            PatentRecord(
                patent_name=title,
                authors=clean_people(bigquery_row_value(row, "authors")),
                year=parse_year(bigquery_row_value(row, "year")),
                url=record_url,
                source=source,
                keyword=keyword,
                rank=rank_start + offset,
                raw_id=publication,
                publication_number=publication or None,
            )
        )
    return records


async def search_google_bigquery_patents(runtime: SearchRuntime, source: str, keyword: str, limit: int) -> list[PatentRecord]:
    if not has_google_adc():
        runtime.skip(source, keyword, "missing required credential(s): GOOGLE_APPLICATION_CREDENTIALS")
        return []
    if source not in runtime.cost_notice_emitted:
        print(
            "Google BigQuery patent public-data query may incur costs; "
            "the current approval covers all configured query variants in this run."
        )
        runtime.cost_notice_emitted.add(source)
    try:
        bigquery = load_google_bigquery()

        def run_query() -> list[PatentRecord]:
            client = bigquery.Client()
            page_size = source_page_size(limit, 1000)
            resume_after, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "")
            field_scope = current_query_field_scope("multilingual_title")
            localized_field = {
                "multilingual_title": "title_localized",
                "multilingual_abstract": "abstract_localized",
                "multilingual_claims": "claims_localized",
            }.get(field_scope, "title_localized")
            query = bigquery_patent_sql(localized_field)
            job_config = bigquery.QueryJobConfig(
                query_parameters=[
                    bigquery.ScalarQueryParameter("keyword", "STRING", current_query_text(keyword)),
                    bigquery.ScalarQueryParameter("resume_after", "STRING", resume_after),
                ]
            )
            row_iterator = client.query(query, job_config=job_config).result(page_size=page_size)
            total = parse_int(getattr(row_iterator, "total_rows", None))
            records: list[PatentRecord] = []
            processed = 0
            for page in row_iterator.pages:
                raw_rows = list(page)
                page_records = parse_bigquery_patent_rows(raw_rows, source, keyword, len(records))
                processed += len(raw_rows)
                next_token = first_string(bigquery_row_value(raw_rows[-1], "publication_number")) if raw_rows else ""
                exhausted = not raw_rows or (total is not None and processed >= total)
                completed_pages += 1
                persist_search_page(runtime, "patent", source, keyword, page_records, next_token="" if exhausted else next_token, exhausted=exhausted, page_number=completed_pages, total_hint=total)
                records.extend(page_records)
            if processed == 0:
                persist_search_page(runtime, "patent", source, keyword, [], next_token="", exhausted=True, page_number=completed_pages + 1, total_hint=total or 0)
            elif total is None:
                runtime.mark_current_run("patent", source, keyword, "complete", "bigquery_row_iterator_exhausted")
            return records

        return await asyncio.to_thread(run_query)
    except Exception as exc:
        runtime.skip(source, keyword, f"BigQuery failed: {safe_error_text(str(exc))}")
        return []


async def search_wipo_adapter(runtime: SearchRuntime, source: str, url: str, keyword: str, page_size: int) -> list[PatentRecord]:
    del url
    return await search_wipo_patentscope(runtime, source, keyword, page_size)


async def search_bigquery_adapter(runtime: SearchRuntime, source: str, url: str, keyword: str, page_size: int) -> list[PatentRecord]:
    del url
    return await search_google_bigquery_patents(runtime, source, keyword, page_size)


def cnki_patent_site_page_size(requested: int) -> int:
    for candidate in (10, 20, 50):
        if requested <= candidate:
            return candidate
    return 50


def cnki_patent_no_results(body: str) -> bool:
    lowered = first_string(body).casefold()
    return any(
        marker.casefold() in lowered
        for marker in PATENT_WEB_SOURCE_NO_RESULT_MARKERS[CNKI_SOURCE]
    )


def cnki_patent_total_hint(body: str) -> int | None:
    match = re.search(r"共\s*(?:找到)?\s*([\d,]+)\s*条", body or "")
    return parse_int(match.group(1)) if match else None


async def cnki_patent_next_control(page: Any) -> Any | None:
    for selector in PATENT_WEB_SOURCE_PARSER_PROFILES[CNKI_SOURCE].next_links:
        try:
            locators = page.locator(selector)
            for index in range(await locators.count()):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=500):
                    continue
                text = first_string(await locator.inner_text(timeout=500))
                aria_label = first_string(await locator.get_attribute("aria-label"))
                title = first_string(await locator.get_attribute("title"))
                if not any(
                    value.casefold() in {"下一页", "next", "next page"}
                    for value in (text, aria_label, title)
                    if value
                ):
                    continue
                disabled = await locator.get_attribute("disabled")
                aria_disabled = first_string(
                    await locator.get_attribute("aria-disabled")
                ).casefold()
                classes = first_string(await locator.get_attribute("class")).casefold()
                if (
                    disabled is not None
                    or aria_disabled == "true"
                    or "disabled" in classes
                ):
                    return None
                return locator
        except Exception:
            continue
    return None


async def cnki_patent_page_signature(page: Any) -> str:
    try:
        values = await page.locator(
            "table.result-table-list td.name a[href*='/kcms2/article/abstract']"
        ).evaluate_all(
            "nodes => nodes.map(node => `${node.getAttribute('href') || ''}|${(node.textContent || '').trim()}`)"
        )
    except Exception:
        values = []
    material = json.dumps(values if isinstance(values, list) else [], ensure_ascii=False)
    return hashlib.sha1(material.encode("utf-8")).hexdigest() if values else ""


async def cnki_patent_results_state(page: Any) -> tuple[str, str]:
    body = await page_body_text(page)
    try:
        if await page.locator("table.result-table-list tbody tr").count() > 0:
            return "records", body
    except Exception:
        pass
    if cnki_patent_no_results(body):
        return "explicit_no_results", body
    if browser_internal_navigation_error_url(first_string(getattr(page, "url", ""))):
        return "navigation_error", body
    if await cnki_active_verification_challenge(page):
        return "challenge", body
    if restricted_search_authorization_needed(
        body,
        first_string(getattr(page, "url", "")),
    ):
        return "institution_login", body
    return "pending", body


async def wait_for_cnki_patent_results(page: Any) -> tuple[str, str]:
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_CNKI_PATENT_SEARCH_READY_TIMEOUT_SECONDS", 45, 1),
    )
    state = "pending"
    body = ""
    while time.monotonic() < deadline:
        state, body = await cnki_patent_results_state(page)
        if state != "pending":
            return state, body
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return state, body


async def submit_cnki_patent_search(
    page: Any,
    keyword: str,
    page_size: int,
) -> tuple[str, str]:
    query_locator = None
    for selector in PATENT_WEB_SOURCE_SEARCH_SURFACE_SELECTORS[CNKI_SOURCE]:
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                query_locator = candidate
                break
        except Exception:
            continue
    if query_locator is None:
        return "search_form_not_ready", await page_body_text(page)
    try:
        await query_locator.fill("", timeout=3000)
        await query_locator.press_sequentially(keyword, delay=25, timeout=15000)
    except Exception:
        return "search_form_not_ready", await page_body_text(page)
    submitted = await click_first_visible_async(
        page,
        PATENT_WEB_SOURCE_RESUME_ACTION_SELECTORS[CNKI_SOURCE],
    )
    if not submitted:
        try:
            await query_locator.press("Enter", timeout=3000)
            submitted = True
        except Exception:
            pass
    if not submitted:
        return "search_form_not_ready", await page_body_text(page)
    state, body = await wait_for_cnki_patent_results(page)
    if state == "records":
        await set_cnki_patent_page_size(page, page_size)
        state, body = await wait_for_cnki_patent_results(page)
    return state, body


async def set_cnki_patent_page_size(page: Any, requested: int) -> bool:
    selected_size = str(cnki_patent_site_page_size(requested))
    selectors = (
        "select[name='pageSize']",
        "select#pageSize",
        "select[name='pagesize']",
    )
    for selector in selectors:
        try:
            locator = page.locator(selector).first
            if not await locator.count() or not await locator.is_visible(timeout=300):
                continue
            options = await locator.locator("option").evaluate_all(
                "nodes => nodes.map(node => node.value)"
            )
            if selected_size not in options:
                continue
            current = first_string(await locator.input_value())
            if current == selected_size:
                return True
            await locator.select_option(selected_size, timeout=3000)
            deadline = time.monotonic() + 30
            while time.monotonic() < deadline:
                if await cnki_active_verification_challenge(page):
                    return False
                if first_string(await locator.input_value()) == selected_size:
                    await page.wait_for_timeout(750)
                    return True
                await page.wait_for_timeout(500)
            return False
        except Exception:
            continue
    return False


async def advance_cnki_patent_page(page: Any, previous_signature: str) -> str:
    locator = await cnki_patent_next_control(page)
    if locator is None:
        return "exhausted"
    try:
        await locator.click(timeout=5000)
    except Exception:
        return "click_failed"
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_CNKI_PATENT_PAGE_ADVANCE_TIMEOUT_SECONDS", 60, 1),
    )
    while time.monotonic() < deadline:
        if await cnki_active_verification_challenge(page):
            return "challenge"
        signature = await cnki_patent_page_signature(page)
        if signature and signature != previous_signature:
            return "advanced"
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return "unchanged"


def cnki_patent_snapshot_records(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    snapshots: list[dict[str, Any]],
) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    snapshot_count = len(snapshots)
    _, completed_pages = resumed_page_state(
        runtime,
        "patent",
        source,
        keyword,
        "page:1",
    )
    for offset, snapshot in enumerate(snapshots, start=1):
        page_records = parse_cnki_patent_search(
            first_string(snapshot.get("html")),
            first_string(snapshot.get("final_url")) or CNKI_PATENT_HOME,
            source,
            keyword,
            len(records),
        )
        has_next = bool(snapshot.get("has_next_control"))
        next_url = first_string(snapshot.get("next_url"))
        explicit_no_results = bool(snapshot.get("explicit_no_results"))
        exhausted = explicit_no_results or not has_next
        is_last_snapshot = offset == snapshot_count
        javascript_resume_required = (
            is_last_snapshot and has_next and not next_url
        )
        persist_search_page(
            runtime,
            "patent",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else f"page:{completed_pages + offset + 1}",
            exhausted=exhausted,
            page_number=completed_pages + offset,
            reason=(
                "ordinary_chrome_javascript_pager_requires_live_resume"
                if javascript_resume_required
                else ""
            ),
            raw_count=cnki_patent_candidate_count(
                first_string(snapshot.get("html"))
            ),
        )
        records.extend(page_records)
        if exhausted:
            break
        if javascript_resume_required:
            runtime.mark_current_run(
                "patent",
                source,
                keyword,
                "incomplete",
                "ordinary_chrome_javascript_pager_requires_live_resume",
            )
            break
    return records


def take_cnki_patent_external_resume(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
) -> list[PatentRecord] | None:
    resume = EXTERNAL_BROWSER_SEARCH_RESUME.get()
    if not isinstance(resume, dict):
        return None
    if (
        first_string(resume.get("source")) != source
        or first_string(resume.get("keyword")) != keyword
        or normalized_search_record_type(first_string(resume.get("record_type")))
        != "patent"
        or not isinstance(resume.get("snapshots"), list)
    ):
        return None
    EXTERNAL_BROWSER_SEARCH_RESUME.set(None)
    return cnki_patent_snapshot_records(
        runtime,
        source,
        keyword,
        list(resume["snapshots"]),
    )


async def search_cnki_patent_browser_once(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    page_size: int,
    *,
    restricted: bool,
) -> tuple[list[PatentRecord], str]:
    policy = patent_source_auth_policy[source]
    records: list[PatentRecord] = []
    pw = browser = context = None
    try:
        if restricted:
            pw, browser, context, authenticated = await open_restricted_browser_context(
                runtime,
                source,
                policy,
            )
            if not authenticated or browser is None or context is None:
                return [], "institution_authentication_failed"
        else:
            async_playwright = load_async_playwright()
            pw = await async_playwright().start()
            browser, launch_error = await launch_named_browser(
                pw.chromium,
                "chromium",
                headless=True,
            )
            if browser is None:
                return [], f"browser_launch_failed:{launch_error}"
            context = await browser.new_context()

        external_records = take_cnki_patent_external_resume(
            runtime,
            source,
            keyword,
        )
        if external_records is not None:
            return external_records, "external_snapshot_consumed"

        page = await browser_context_navigation_page(context)
        await wait_for_rate_limiter(
            runtime.limiter,
            urllib.parse.urlsplit(CNKI_PATENT_HOME).netloc,
            kind="browser",
            source=source,
        )
        response = await page.goto(
            CNKI_PATENT_HOME,
            wait_until="domcontentloaded",
            timeout=30000,
        )
        response_status = int(response.status) if response is not None else 0
        await page.wait_for_timeout(1500)
        state, body = await cnki_patent_results_state(page)
        if state in {"challenge", "navigation_error"} or response_status in {
            401,
            403,
            429,
        }:
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                pw.chromium,
                browser,
                context,
                page,
                cnki_patent_verification_resume_url(getattr(page, "url", "")),
                body,
                {},
            )
            if not resolved:
                return records, "cnki_patent_challenge_unresolved"
            external_records = take_cnki_patent_external_resume(
                runtime,
                source,
                keyword,
            )
            if external_records is not None:
                return external_records, "external_snapshot_consumed"
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            if snapshot is not None:
                return cnki_patent_snapshot_records(
                    runtime,
                    source,
                    keyword,
                    [snapshot],
                ), "challenge_snapshot_consumed"
            state, body = await wait_for_cnki_patent_results(page)
        if state == "institution_login" and not restricted:
            return records, "institution_login_required"
        if state not in {"records", "explicit_no_results"}:
            state, body = await submit_cnki_patent_search(page, keyword, page_size)
        if state == "institution_login" and not restricted:
            return records, "institution_login_required"
        if state in {"challenge", "navigation_error"}:
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                pw.chromium,
                browser,
                context,
                page,
                cnki_patent_verification_resume_url(getattr(page, "url", "")),
                body,
                {},
            )
            if not resolved:
                return records, "cnki_patent_challenge_unresolved"
            external_records = take_cnki_patent_external_resume(
                runtime,
                source,
                keyword,
            )
            if external_records is not None:
                return external_records, "external_snapshot_consumed"
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            if snapshot is not None:
                return cnki_patent_snapshot_records(
                    runtime,
                    source,
                    keyword,
                    [snapshot],
                ), "challenge_snapshot_consumed"
            state, body = await wait_for_cnki_patent_results(page)
        if state not in {"records", "explicit_no_results"}:
            return records, "cnki_patent_results_not_ready"

        resource, database_codes = extract_cnki_patent_database_scope(
            await page.content()
        )
        expected_databases = {"SCPD", "SOPD"}
        if resource and resource != "PATENT":
            return records, f"cnki_patent_resource_scope_mismatch:{resource}"
        if database_codes and not expected_databases.issubset(set(database_codes)):
            return records, "cnki_patent_database_scope_reduced"
        if not resource or not database_codes:
            runtime.degrade(
                source,
                keyword,
                "CNKI patent database scope was not exposed by the current page",
            )

        resume_token, completed_pages = resumed_page_state(
            runtime,
            "patent",
            source,
            keyword,
            "page:1",
        )
        resume_page = parse_int(resume_token.removeprefix("page:")) or 1
        current_page = 1
        if resume_page > 1:
            runtime.degrade(
                source,
                keyword,
                "CNKI JavaScript checkpoint requires visible page fast-forward",
            )
        while current_page < resume_page:
            before = await cnki_patent_page_signature(page)
            advance_state = await advance_cnki_patent_page(page, before)
            if advance_state == "challenge":
                body = await page_body_text(page)
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    cnki_patent_verification_resume_url(
                        getattr(page, "url", "")
                    ),
                    body,
                    {},
                )
                if resolved:
                    deadline = time.monotonic() + 60
                    while time.monotonic() < deadline:
                        after = await cnki_patent_page_signature(page)
                        if after and after != before:
                            advance_state = "advanced"
                            break
                        await page.wait_for_timeout(500)
            if advance_state != "advanced":
                return records, "cnki_patent_checkpoint_fast_forward_failed"
            current_page += 1

        seen_signatures: set[str] = set()
        while True:
            html_text = await page.content()
            body = await page_body_text(page)
            page_records = parse_cnki_patent_search(
                html_text,
                first_string(getattr(page, "url", "")) or CNKI_PATENT_HOME,
                source,
                keyword,
                len(records),
            )
            signature = await cnki_patent_page_signature(page)
            if signature and signature in seen_signatures:
                return records, "cnki_patent_repeated_page_signature"
            if signature:
                seen_signatures.add(signature)
            no_results = cnki_patent_no_results(body)
            try:
                raw_count = await page.locator(
                    "table.result-table-list tbody tr td.name a"
                ).count()
            except Exception:
                raw_count = len(page_records)
            if not page_records and not no_results:
                return records, "cnki_patent_results_not_detected"
            next_control = await cnki_patent_next_control(page)
            has_next = next_control is not None
            completed_pages += 1
            persist_search_page(
                runtime,
                "patent",
                source,
                keyword,
                page_records,
                next_token="" if not has_next else f"page:{current_page + 1}",
                exhausted=not has_next,
                page_number=completed_pages,
                total_hint=cnki_patent_total_hint(body),
                raw_count=raw_count,
                page_signature=signature,
            )
            records.extend(page_records)

            challenge_active = await cnki_active_verification_challenge(page)
            if challenge_active:
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    cnki_patent_verification_resume_url(
                        getattr(page, "url", "")
                    ),
                    body,
                    {},
                )
                if not resolved:
                    return records, "cnki_patent_challenge_unresolved_after_page_persist"
                if (
                    SEARCH_CHALLENGE_SNAPSHOT.get() is not None
                    and await cnki_active_verification_challenge(page)
                ):
                    return records, "cnki_patent_external_snapshot_requires_live_resume"
            if not has_next:
                return records, "complete"
            before = signature
            advance_state = await advance_cnki_patent_page(page, before)
            if advance_state == "challenge":
                body = await page_body_text(page)
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    first_string(getattr(page, "url", "")) or CNKI_PATENT_HOME,
                    body,
                    {},
                )
                if resolved:
                    deadline = time.monotonic() + 60
                    while time.monotonic() < deadline:
                        after = await cnki_patent_page_signature(page)
                        if after and after != before:
                            advance_state = "advanced"
                            break
                        await page.wait_for_timeout(500)
            if advance_state != "advanced":
                return records, f"cnki_patent_next_page_{advance_state}"
            current_page += 1
    except Exception as exc:
        return records, f"cnki_patent_browser_failed:{safe_error_text(str(exc))}"
    finally:
        await close_restricted_browser_attempt(browser, context)
        if pw is not None:
            try:
                await pw.stop()
            except Exception:
                pass


async def search_cnki_patent_adapter(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
    page_size: int,
) -> list[PatentRecord]:
    del url
    policy = patent_source_auth_policy[source]
    requested_path = first_string(SEARCH_TASK_CONTEXT.get().get("path"))
    restricted = requested_path == "restricted_browser"
    async with runtime.browser_sem:
        records, boundary = await search_cnki_patent_browser_once(
            runtime,
            source,
            keyword,
            cnki_patent_site_page_size(page_size),
            restricted=restricted,
        )
        if (
            not restricted
            and boundary == "institution_login_required"
            and policy_allows_restricted_access(policy, runtime.config)
        ):
            parent_context = SEARCH_TASK_CONTEXT.get()
            token = SEARCH_TASK_CONTEXT.set(
                parent_context | {"path": "restricted_browser"}
            )
            try:
                restricted_records, boundary = await search_cnki_patent_browser_once(
                    runtime,
                    source,
                    keyword,
                    cnki_patent_site_page_size(page_size),
                    restricted=True,
                )
                records.extend(restricted_records)
            finally:
                SEARCH_TASK_CONTEXT.reset(token)
    if boundary not in {"complete", "external_snapshot_consumed", "challenge_snapshot_consumed"}:
        status = (
            "blocked"
            if boundary in {
                "institution_login_required",
                "institution_authentication_failed",
            }
            else "incomplete"
        )
        runtime.mark_current_run("patent", source, keyword, status, boundary)
        runtime.skip(source, keyword, boundary)
    return dedupe_patent_records(records)


def wanfang_patent_site_page_size(requested: int) -> int:
    requested = max(1, int(requested))
    if requested <= 20:
        return 20
    if requested <= 30:
        return 30
    return 50


def wanfang_patent_result_search_surface(value: Any) -> bool:
    try:
        parsed = urllib.parse.urlsplit(first_string(value))
    except ValueError:
        return False
    return (
        (parsed.hostname or "").casefold() == "s.wanfangdata.com.cn"
        and (parsed.path or "").rstrip("/").casefold() == "/patent"
        and bool(first_string(urllib.parse.parse_qs(parsed.query).get("q", [""])[0]))
    )


def wanfang_patent_no_results(body: str) -> bool:
    lowered = first_string(body).casefold()
    return any(
        marker.casefold() in lowered
        for marker in PATENT_WEB_SOURCE_NO_RESULT_MARKERS[WANFANG_SOURCE]
    )


def wanfang_patent_total_hint(body: str) -> int | None:
    match = re.search(r"找到\s*([\d,]+)\s*条(?:文献|结果)?", body or "")
    return parse_int(match.group(1).replace(",", "")) if match else None


async def wanfang_patent_page_signature(page: Any) -> str:
    try:
        values = await page.locator(
            ".detail-list-wrap .normal-list .title-id-hidden, "
            ".detail-list-wrap .normal-list .title-area .title"
        ).all_inner_texts()
    except Exception:
        values = []
    normalized = [normalize_wanfang_title_text(value) for value in values if value]
    material = json.dumps(normalized, ensure_ascii=False)
    return hashlib.sha1(material.encode("utf-8")).hexdigest() if normalized else ""


async def wanfang_patent_next_control(page: Any) -> Any | None:
    for selector in PATENT_WEB_SOURCE_PARSER_PROFILES[WANFANG_SOURCE].next_links:
        try:
            locators = page.locator(selector)
            for index in range(await locators.count()):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=500):
                    continue
                style = first_string(await locator.get_attribute("style")).replace(" ", "").casefold()
                classes = first_string(await locator.get_attribute("class")).casefold()
                aria_disabled = first_string(
                    await locator.get_attribute("aria-disabled")
                ).casefold()
                if (
                    "display:none" in style
                    or "disabled" in classes
                    or "occupying" in classes
                    or aria_disabled == "true"
                ):
                    continue
                return locator
        except Exception:
            continue
    return None


async def wanfang_patent_results_state(page: Any) -> tuple[str, str]:
    body = await page_body_text(page)
    try:
        if await page.locator(
            PATENT_WEB_SOURCE_PARSER_PROFILES[WANFANG_SOURCE].cards[0]
        ).count() > 0:
            return "records", body
    except Exception:
        pass
    if wanfang_patent_no_results(body):
        return "explicit_no_results", body
    if browser_internal_navigation_error_url(first_string(getattr(page, "url", ""))):
        return "navigation_error", body
    if await wanfang_active_verification_challenge(page):
        return "challenge", body
    if await wanfang_login_surface_visible(page) or restricted_search_authorization_needed(
        body,
        first_string(getattr(page, "url", "")),
    ):
        return "institution_login", body
    return "pending", body


async def wait_for_wanfang_patent_results(page: Any) -> tuple[str, str]:
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_WANFANG_PATENT_SEARCH_READY_TIMEOUT_SECONDS", 45, 1),
    )
    state = "pending"
    body = ""
    while time.monotonic() < deadline:
        state, body = await wanfang_patent_results_state(page)
        if state != "pending":
            return state, body
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return state, body


async def submit_wanfang_patent_search(page: Any, keyword: str) -> tuple[str, str]:
    query_locator = None
    for selector in PATENT_WEB_SOURCE_SEARCH_SURFACE_SELECTORS[WANFANG_SOURCE]:
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                query_locator = candidate
                break
        except Exception:
            continue
    if query_locator is None:
        return "search_form_not_ready", await page_body_text(page)
    try:
        await query_locator.fill("", timeout=3000)
        await query_locator.press_sequentially(keyword, delay=25, timeout=15000)
        observed_query = first_string(await query_locator.input_value(timeout=1000))
        if observed_query != keyword:
            await query_locator.fill(keyword, timeout=3000)
            observed_query = first_string(await query_locator.input_value(timeout=1000))
        if observed_query != keyword:
            return "search_form_not_ready", await page_body_text(page)
        # Let Wanfang's Vue model consume the final input event before submit.
        await page.wait_for_timeout(500)
    except Exception:
        return "search_form_not_ready", await page_body_text(page)
    try:
        known_page_ids = {id(candidate) for candidate in page.context.pages}
    except Exception:
        known_page_ids = {id(page)}
    submitted = await click_first_visible_async(
        page,
        PATENT_WEB_SOURCE_RESUME_ACTION_SELECTORS[WANFANG_SOURCE],
    )
    if not submitted:
        try:
            await query_locator.press("Enter", timeout=3000)
            submitted = True
        except Exception:
            pass
    if not submitted:
        return "search_form_not_ready", await page_body_text(page)

    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_WANFANG_PATENT_SEARCH_READY_TIMEOUT_SECONDS", 45, 1),
    )
    result_page = page
    while time.monotonic() < deadline:
        try:
            new_pages = [
                candidate
                for candidate in page.context.pages
                if id(candidate) not in known_page_ids and not candidate.is_closed()
            ]
        except Exception:
            new_pages = []
        for candidate in reversed(new_pages):
            if wanfang_patent_result_search_surface(getattr(candidate, "url", "")):
                result_page = candidate
                break
        if wanfang_patent_result_search_surface(getattr(result_page, "url", "")):
            return await wait_for_wanfang_patent_results(result_page)
        try:
            await result_page.wait_for_timeout(250)
        except Exception:
            break
    return "pending", await page_body_text(result_page)


async def set_wanfang_patent_page_size(page: Any, requested: int) -> bool:
    selected = wanfang_patent_site_page_size(requested)
    try:
        select_box = page.locator(".wf-select.right-items .select-box").first
        if not await select_box.count() or not await select_box.is_visible(timeout=500):
            return selected == 20
        current_text = first_string(await select_box.inner_text(timeout=1000))
        if re.search(rf"\b{selected}\b", current_text):
            return True
        await select_box.click(timeout=3000)
        options = page.locator(".wf-select.right-items .wf-option")
        for index in range(await options.count()):
            option = options.nth(index)
            option_text = first_string(await option.inner_text(timeout=1000))
            if not re.search(rf"\b{selected}\b", option_text):
                continue
            before = await wanfang_patent_page_signature(page)
            await option.click(timeout=3000)
            deadline = time.monotonic() + 30
            while time.monotonic() < deadline:
                if await wanfang_active_verification_challenge(page):
                    return False
                after = await wanfang_patent_page_signature(page)
                current = first_string(await select_box.inner_text(timeout=1000))
                if re.search(rf"\b{selected}\b", current) and (
                    not before or not after or after != before
                ):
                    return True
                await page.wait_for_timeout(500)
            return False
    except Exception:
        return False
    return False


def wanfang_observed_locator_cache_key(
    raw_id: Any,
    title: Any,
    index: int,
) -> str:
    observed_id = first_string(raw_id)
    if observed_id:
        return f"raw_id:{observed_id}"
    normalized_title = normalize_patent_name(first_string(title))
    if normalized_title:
        return f"title:{normalized_title}"
    return f"card_index:{max(0, int(index))}"


def cache_wanfang_observed_locator(
    runtime: SearchRuntime,
    keyword: str,
    card_key: str,
    value: Any,
) -> str:
    detail_url = wanfang_patent_detail_url(value)
    if not detail_url:
        return ""
    cache_key = (WANFANG_SOURCE, first_string(keyword), first_string(card_key))
    if len(runtime.observed_locator_cache) >= 10000 and cache_key not in runtime.observed_locator_cache:
        runtime.observed_locator_cache.pop(next(iter(runtime.observed_locator_cache)))
    runtime.observed_locator_cache[cache_key] = detail_url
    return detail_url


async def observe_wanfang_patent_detail_urls(
    runtime: SearchRuntime,
    page: Any,
    context: Any,
) -> tuple[int, int, str]:
    source = WANFANG_SOURCE
    keyword = first_string(SEARCH_TASK_CONTEXT.get().get("keyword"))
    cards = page.locator(".detail-list-wrap .normal-list")
    try:
        card_count = await cards.count()
    except Exception as exc:
        return 0, 0, f"card_lookup_failed:{exc.__class__.__name__}"
    observed_count = 0
    missing_count = 0
    timeout_seconds = min(
        30,
        env_seconds("LAPS_WANFANG_PATENT_DETAIL_OBSERVE_TIMEOUT_SECONDS", 12, 1),
    )
    delay_seconds = env_seconds("LAPS_WANFANG_PATENT_DETAIL_DELAY_SECONDS", 1, 0)
    for index in range(card_count):
        if await wanfang_active_verification_challenge(page):
            return observed_count, card_count - observed_count, "challenge"
        card = cards.nth(index)
        raw_card_id = ""
        for attribute in ("data-doc-id", "data-id", "data-key"):
            try:
                raw_card_id = first_string(await card.get_attribute(attribute))
            except Exception:
                raw_card_id = ""
            if raw_card_id:
                break
        title = card.locator(".title-area .title").first
        try:
            title_text = first_string(await title.inner_text(timeout=500))
        except Exception:
            title_text = ""
        card_key = wanfang_observed_locator_cache_key(
            raw_card_id,
            title_text,
            index,
        )
        existing = wanfang_patent_detail_url(
            await card.get_attribute("data-observed-detail-url")
        )
        if not existing:
            existing = wanfang_patent_detail_url(
                runtime.observed_locator_cache.get(
                    (source, keyword, card_key),
                    "",
                )
            )
            if existing:
                try:
                    await card.evaluate(
                        "(node, url) => node.setAttribute('data-observed-detail-url', url)",
                        existing,
                    )
                except Exception:
                    pass
        if existing:
            observed_count += 1
            continue
        try:
            if not await title.count() or not await title.is_visible(timeout=500):
                missing_count += 1
                continue
        except Exception:
            missing_count += 1
            continue
        try:
            known_pages = {id(candidate) for candidate in list(context.pages)}
        except Exception:
            known_pages = {id(page)}
        search_url = first_string(getattr(page, "url", ""))
        observed_url = ""
        popup_page: Any | None = None
        await wait_for_rate_limiter(
            runtime.limiter,
            "d.wanfangdata.com.cn",
            kind="browser",
            source=source,
        )
        try:
            await title.click(timeout=5000)
        except Exception:
            missing_count += 1
            continue
        deadline = time.monotonic() + timeout_seconds
        while time.monotonic() < deadline:
            try:
                candidates = [
                    candidate
                    for candidate in list(context.pages)
                    if id(candidate) not in known_pages and not candidate.is_closed()
                ]
            except Exception:
                candidates = []
            for candidate in candidates:
                detail_url = wanfang_patent_detail_url(getattr(candidate, "url", ""))
                if detail_url:
                    observed_url = detail_url
                    popup_page = candidate
                    break
            if observed_url:
                break
            same_page_url = wanfang_patent_detail_url(getattr(page, "url", ""))
            if same_page_url and same_page_url != search_url:
                observed_url = same_page_url
                break
            try:
                await page.wait_for_timeout(250)
            except Exception:
                break
        if observed_url:
            observed_url = cache_wanfang_observed_locator(
                runtime,
                keyword,
                card_key,
                observed_url,
            )
            try:
                await card.evaluate(
                    "(node, url) => node.setAttribute('data-observed-detail-url', url)",
                    observed_url,
                )
                observed_count += 1
            except Exception:
                missing_count += 1
            if popup_page is not None:
                try:
                    await popup_page.close()
                except Exception:
                    pass
            elif first_string(getattr(page, "url", "")) != search_url:
                try:
                    await page.go_back(wait_until="domcontentloaded", timeout=20000)
                    await wait_for_wanfang_patent_results(page)
                except Exception:
                    return observed_count, missing_count, "same_page_return_failed"
        else:
            missing_count += 1
            for candidate in candidates:
                try:
                    await candidate.close()
                except Exception:
                    pass
        if delay_seconds:
            try:
                await page.wait_for_timeout(delay_seconds * 1000)
            except Exception:
                break
    return observed_count, missing_count, "complete"


async def advance_wanfang_patent_page(page: Any, previous_signature: str) -> str:
    locator = await wanfang_patent_next_control(page)
    if locator is None:
        return "exhausted"
    try:
        await locator.click(timeout=5000)
    except Exception:
        return "click_failed"
    deadline = time.monotonic() + min(
        90,
        env_seconds("LAPS_WANFANG_PATENT_PAGE_ADVANCE_TIMEOUT_SECONDS", 60, 1),
    )
    while time.monotonic() < deadline:
        if await wanfang_active_verification_challenge(page):
            return "challenge"
        signature = await wanfang_patent_page_signature(page)
        if signature and signature != previous_signature:
            return "advanced"
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return "unchanged"


def wanfang_patent_snapshot_records(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    snapshots: list[dict[str, Any]],
) -> list[PatentRecord]:
    records: list[PatentRecord] = []
    _, completed_pages = resumed_page_state(
        runtime,
        "patent",
        source,
        keyword,
        "page:1",
    )
    for offset, snapshot in enumerate(snapshots, start=1):
        html_text = first_string(snapshot.get("html"))
        page_records = parse_wanfang_patent_search(
            html_text,
            first_string(snapshot.get("final_url")) or WANFANG_PATENT_HOME,
            source,
            keyword,
            len(records),
        )
        has_next = bool(snapshot.get("has_next_control")) or wanfang_patent_html_has_next(
            html_text
        )
        next_url = first_string(snapshot.get("next_url"))
        exhausted = bool(snapshot.get("explicit_no_results")) or not has_next
        javascript_resume_required = offset == len(snapshots) and has_next and not next_url
        persist_search_page(
            runtime,
            "patent",
            source,
            keyword,
            page_records,
            next_token="" if exhausted else f"page:{completed_pages + offset + 1}",
            exhausted=exhausted,
            page_number=completed_pages + offset,
            reason=(
                "ordinary_chrome_javascript_pager_requires_live_resume"
                if javascript_resume_required
                else ""
            ),
            raw_count=wanfang_patent_candidate_count(html_text),
        )
        records.extend(page_records)
        if exhausted:
            break
        if javascript_resume_required:
            runtime.mark_current_run(
                "patent",
                source,
                keyword,
                "incomplete",
                "ordinary_chrome_javascript_pager_requires_live_resume",
            )
            break
    return records


def take_wanfang_patent_external_resume(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
) -> list[PatentRecord] | None:
    resume = EXTERNAL_BROWSER_SEARCH_RESUME.get()
    if not isinstance(resume, dict):
        return None
    if (
        first_string(resume.get("source")) != source
        or first_string(resume.get("keyword")) != keyword
        or normalized_search_record_type(first_string(resume.get("record_type")))
        != "patent"
        or not isinstance(resume.get("snapshots"), list)
    ):
        return None
    EXTERNAL_BROWSER_SEARCH_RESUME.set(None)
    return wanfang_patent_snapshot_records(
        runtime,
        source,
        keyword,
        list(resume["snapshots"]),
    )


async def search_wanfang_patent_browser_once(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    page_size: int,
    *,
    restricted: bool,
    browser_name: str = "chromium",
) -> tuple[list[PatentRecord], str]:
    policy = patent_source_auth_policy[source]
    records: list[PatentRecord] = []
    unresolved_urls = 0
    pw = browser = context = None
    try:
        async_playwright = load_async_playwright()
        if restricted and normalize_browser_name(browser_name) == "chromium":
            pw, browser, context, authenticated = await open_restricted_browser_context(
                runtime,
                source,
                policy,
            )
            if not authenticated or browser is None or context is None:
                return [], "institution_authentication_failed"
        else:
            pw = await async_playwright().start()
            if restricted:
                browser, context, launch_error = await launch_wanfang_restricted_browser_layer(
                    runtime,
                    source,
                    policy,
                    pw.chromium,
                    browser_name,
                )
            else:
                browser, context, launch_error = await launch_wanfang_public_browser_layer(
                    pw.chromium,
                    browser_name,
                )
            if browser is None or context is None:
                return [], f"browser_launch_failed:{launch_error or browser_name}"

        external_records = take_wanfang_patent_external_resume(runtime, source, keyword)
        if external_records is not None:
            return external_records, "external_snapshot_consumed"

        page = await browser_context_navigation_page(context)
        await wait_for_rate_limiter(
            runtime.limiter,
            "c.wanfangdata.com.cn",
            kind="browser",
            source=source,
        )
        response = await page.goto(
            WANFANG_PATENT_HOME,
            wait_until="domcontentloaded",
            timeout=30000,
        )
        response_status = int(response.status) if response is not None else 0
        await page.wait_for_timeout(1500)
        state, body = await wanfang_patent_results_state(page)
        if state in {"challenge", "navigation_error"} or response_status in {401, 403, 429}:
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                pw.chromium,
                browser,
                context,
                page,
                first_string(getattr(page, "url", "")) or WANFANG_PATENT_HOME,
                body,
                {},
            )
            if not resolved:
                return records, "wanfang_patent_challenge_unresolved"
            external_records = take_wanfang_patent_external_resume(runtime, source, keyword)
            if external_records is not None:
                return external_records, "external_snapshot_consumed"
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            if snapshot is not None:
                return wanfang_patent_snapshot_records(
                    runtime,
                    source,
                    keyword,
                    [snapshot],
                ), "challenge_snapshot_consumed"

        institution_confirmed = False
        if runtime.config.school:
            institution_confirmed = await wait_for_wanfang_configured_institution_marker(
                page,
                runtime.config.school,
                runtime.config.school_aliases,
            )
        if institution_confirmed:
            state_saved, state_reason = await persist_observed_wanfang_institution_state(
                runtime,
                source,
                policy,
                browser,
                context,
                browser_name,
            )
            runtime.restricted_auth(
                source,
                keyword,
                restricted_access_mode(runtime.config),
                "reused" if state_saved else "degraded",
                state_reason,
            )
        state, body = await submit_wanfang_patent_search(page, keyword)
        try:
            result_pages = [
                candidate
                for candidate in context.pages
                if wanfang_patent_result_search_surface(getattr(candidate, "url", ""))
            ]
            if result_pages:
                page = result_pages[-1]
        except Exception:
            pass
        if state == "institution_login" and not restricted:
            return records, "institution_login_required"
        if state in {"challenge", "navigation_error"}:
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                pw.chromium,
                browser,
                context,
                page,
                first_string(getattr(page, "url", "")) or WANFANG_PATENT_HOME,
                body,
                {},
            )
            if not resolved:
                return records, "wanfang_patent_challenge_unresolved"
            external_records = take_wanfang_patent_external_resume(runtime, source, keyword)
            if external_records is not None:
                return external_records, "external_snapshot_consumed"
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            if snapshot is not None:
                return wanfang_patent_snapshot_records(
                    runtime,
                    source,
                    keyword,
                    [snapshot],
                ), "challenge_snapshot_consumed"
            state, body = await wait_for_wanfang_patent_results(page)
        if state not in {"records", "explicit_no_results"}:
            return records, f"wanfang_patent_{state or 'results_not_ready'}"
        if state == "explicit_no_results":
            persist_search_page(
                runtime,
                "patent",
                source,
                keyword,
                [],
                next_token="",
                exhausted=True,
                page_number=1,
                total_hint=0,
                raw_count=0,
            )
            return records, "complete"

        if not await set_wanfang_patent_page_size(page, page_size):
            if await wanfang_active_verification_challenge(page):
                body = await page_body_text(page)
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    first_string(getattr(page, "url", "")),
                    body,
                    {},
                )
                if not resolved:
                    return records, "wanfang_patent_page_size_challenge_unresolved"

        resume_token, completed_pages = resumed_page_state(
            runtime,
            "patent",
            source,
            keyword,
            "page:1",
        )
        resume_page = parse_int(resume_token.removeprefix("page:")) or 1
        current_page = 1
        while current_page < resume_page:
            before = await wanfang_patent_page_signature(page)
            advance_state = await advance_wanfang_patent_page(page, before)
            if advance_state != "advanced":
                return records, "wanfang_patent_checkpoint_fast_forward_failed"
            current_page += 1

        seen_signatures: set[str] = set()
        while True:
            if await wanfang_active_verification_challenge(page):
                body = await page_body_text(page)
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    first_string(getattr(page, "url", "")),
                    body,
                    {},
                )
                if not resolved:
                    return records, "wanfang_patent_challenge_unresolved_before_page"
            _, missing_count, observation_state = await observe_wanfang_patent_detail_urls(
                runtime,
                page,
                context,
            )
            if observation_state == "challenge":
                return records, "wanfang_patent_challenge_during_detail_observation"
            unresolved_urls += missing_count
            html_text = await page.content()
            body = await page_body_text(page)
            signature = await wanfang_patent_page_signature(page)
            if signature and signature in seen_signatures:
                return records, "wanfang_patent_repeated_page_signature"
            if signature:
                seen_signatures.add(signature)
            page_records = parse_wanfang_patent_search(
                html_text,
                first_string(getattr(page, "url", "")) or WANFANG_PATENT_HOME,
                source,
                keyword,
                len(records),
            )
            raw_count = wanfang_patent_candidate_count(html_text)
            if not page_records and not wanfang_patent_no_results(body):
                return records, "wanfang_patent_results_not_detected"
            next_control = await wanfang_patent_next_control(page)
            has_next = next_control is not None
            completed_pages += 1
            persist_search_page(
                runtime,
                "patent",
                source,
                keyword,
                page_records,
                next_token="" if not has_next else f"page:{current_page + 1}",
                exhausted=not has_next,
                page_number=completed_pages,
                total_hint=wanfang_patent_total_hint(body),
                raw_count=raw_count,
                page_signature=signature,
                reason=(
                    f"wanfang_patent_detail_urls_missing:{missing_count}"
                    if missing_count
                    else ""
                ),
            )
            records.extend(page_records)
            if not has_next:
                return (
                    records,
                    f"wanfang_patent_detail_urls_missing:{unresolved_urls}"
                    if unresolved_urls
                    else "complete",
                )
            before = signature
            advance_state = await advance_wanfang_patent_page(page, before)
            if advance_state == "challenge":
                body = await page_body_text(page)
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    first_string(getattr(page, "url", "")),
                    body,
                    {},
                )
                if resolved:
                    deadline = time.monotonic() + 60
                    while time.monotonic() < deadline:
                        after = await wanfang_patent_page_signature(page)
                        if after and after != before:
                            advance_state = "advanced"
                            break
                        await page.wait_for_timeout(500)
            if advance_state != "advanced":
                return records, f"wanfang_patent_next_page_{advance_state}"
            current_page += 1
    except Exception as exc:
        return records, f"wanfang_patent_browser_failed:{safe_error_text(str(exc))}"
    finally:
        await close_restricted_browser_attempt(browser, context)
        if pw is not None:
            try:
                await pw.stop()
            except Exception:
                pass


def wanfang_patent_transport_boundary(boundary: str) -> bool:
    lowered = first_string(boundary).casefold()
    return any(
        marker in lowered
        for marker in (
            "browser_launch_failed",
            "navigation_error",
            "search_form_not_ready",
            "results_not_ready",
            "wanfang_patent_pending",
            "browser_failed",
        )
    )


async def search_wanfang_patent_adapter(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
    page_size: int,
) -> list[PatentRecord]:
    del url
    policy = patent_source_auth_policy[source]
    requested_path = first_string(SEARCH_TASK_CONTEXT.get().get("path"))
    restricted = requested_path == "restricted_browser"
    selected_page_size = wanfang_patent_site_page_size(page_size)
    async with runtime.browser_sem:
        records, boundary = await search_wanfang_patent_browser_once(
            runtime,
            source,
            keyword,
            selected_page_size,
            restricted=restricted,
        )
        if (
            not restricted
            and boundary == "institution_login_required"
            and policy_allows_restricted_access(policy, runtime.config)
        ):
            parent_context = SEARCH_TASK_CONTEXT.get()
            token = SEARCH_TASK_CONTEXT.set(
                parent_context | {"path": "restricted_browser"}
            )
            try:
                restricted_records, boundary = await search_wanfang_patent_browser_once(
                    runtime,
                    source,
                    keyword,
                    selected_page_size,
                    restricted=True,
                )
                records.extend(restricted_records)
                restricted = True
            finally:
                SEARCH_TASK_CONTEXT.reset(token)
        if wanfang_patent_transport_boundary(boundary):
            runtime.degrade(
                source,
                keyword,
                f"bundled Chromium did not complete Wanfang patent search ({boundary}); "
                "retrying once with Playwright Chrome",
            )
            await asyncio.sleep(verification_browser_fallback_cooldown_seconds())
            retry_records, boundary = await search_wanfang_patent_browser_once(
                runtime,
                source,
                keyword,
                selected_page_size,
                restricted=restricted,
                browser_name="chrome",
            )
            records.extend(retry_records)
    if boundary not in {
        "complete",
        "external_snapshot_consumed",
        "challenge_snapshot_consumed",
    }:
        status = (
            "blocked"
            if boundary in {
                "institution_login_required",
                "institution_authentication_failed",
            }
            else "incomplete"
        )
        runtime.mark_current_run("patent", source, keyword, status, boundary)
        runtime.skip(source, keyword, boundary)
    return dedupe_patent_records(records)


UYANIP_INVALID_CREDENTIAL_MARKERS = (
    "账号或密码错误",
    "用户名或密码错误",
    "账户或密码错误",
    "账号不存在",
    "密码不正确",
    "invalid credentials",
    "incorrect password",
)


def uyanip_credentials_configured(
    config: SearchConfig,
    policy: SourceAccessPolicy,
) -> bool:
    account, password = source_personal_credentials(config, policy)
    return bool(account and password)


def uyanip_saved_state_is_current(
    config: SearchConfig,
    source: str,
    policy: SourceAccessPolicy,
) -> bool:
    state_path = auth_state_path(config, source, policy)
    if not state_path.is_file():
        return False
    runtime_path = get_runtime_config_path()
    try:
        return not runtime_path.is_file() or state_path.stat().st_mtime_ns >= runtime_path.stat().st_mtime_ns
    except OSError:
        return False


def uyanip_result_surface_url(value: Any) -> bool:
    try:
        parsed = urllib.parse.urlsplit(first_string(value))
    except ValueError:
        return False
    host = (parsed.hostname or "").casefold().strip(".")
    return (
        (host == "uyanip.com" or host.endswith(".uyanip.com"))
        and (parsed.path or "").rstrip("/").casefold() == "/result"
    )


def uyanip_observed_login_resume_url(value: Any) -> str:
    try:
        parsed = urllib.parse.urlsplit(first_string(value))
    except ValueError:
        return ""
    values = urllib.parse.parse_qs(parsed.query).get("nextUrl", [])
    for value in values:
        candidate = urllib.parse.urljoin(UYANIP_HOME, first_string(value))
        if uyanip_result_surface_url(candidate):
            parts = urllib.parse.urlsplit(candidate)
            return urllib.parse.urlunsplit(
                ("https", parts.netloc.casefold(), parts.path, parts.query, "")
            )
    return ""


def uyanip_no_results(body: str) -> bool:
    lowered = first_string(body).casefold()
    return any(
        marker.casefold() in lowered
        for marker in PATENT_WEB_SOURCE_NO_RESULT_MARKERS[UYANIP_SOURCE]
    )


def uyanip_invalid_credentials(body: str) -> bool:
    lowered = first_string(body).casefold()
    return any(marker.casefold() in lowered for marker in UYANIP_INVALID_CREDENTIAL_MARKERS)


def uyanip_login_api_succeeded(response_status: int, payload: Any) -> bool:
    if not 200 <= response_status < 300 or not isinstance(payload, dict):
        return False
    error_code = payload.get("errCode")
    if isinstance(error_code, (int, float)) and not isinstance(error_code, bool):
        return int(error_code) == 0
    success = payload.get("success")
    if isinstance(success, bool):
        return success
    code = payload.get("code")
    if isinstance(code, (int, float)) and not isinstance(code, bool):
        return int(code) in {0, 200}
    return False


def uyanip_search_response_url(value: Any) -> bool:
    try:
        parsed = urllib.parse.urlsplit(first_string(value))
    except ValueError:
        return False
    host = (parsed.hostname or "").casefold().strip(".")
    path = (parsed.path or "").casefold()
    return host == "api.duyandb.com" and "/search" in path


def uyanip_xhr_total_hint(payload: Any) -> int | None:
    if not isinstance(payload, dict):
        return None
    containers = [payload]
    containers.extend(value for value in payload.values() if isinstance(value, dict))
    for container in containers:
        total = parse_int(uyanip_dict_value(container, "total", "totalCount", "count"))
        if total is not None and total >= 0:
            return total
    return None


def merge_uyanip_patent_records(
    xhr_records: list[PatentRecord],
    dom_records: list[PatentRecord],
) -> list[PatentRecord]:
    merged: list[PatentRecord] = []
    indexed: dict[str, PatentRecord] = {}
    for candidate in [*xhr_records, *dom_records]:
        key = normalize_resume_url(candidate.url) if candidate.url else ""
        if not key:
            key = first_string(candidate.raw_id).casefold()
        if not key:
            key = " ".join(candidate.patent_name.casefold().split())
        existing = indexed.get(key)
        if existing is None:
            indexed[key] = candidate
            merged.append(candidate)
            continue
        if not existing.url and candidate.url:
            existing.url = candidate.url
        if not existing.publication_number and candidate.publication_number:
            existing.publication_number = candidate.publication_number
        if not existing.raw_id and candidate.raw_id:
            existing.raw_id = candidate.raw_id
        if not existing.authors and candidate.authors:
            existing.authors = candidate.authors
        if not existing.applicants and candidate.applicants:
            existing.applicants = candidate.applicants
        if existing.year is None and candidate.year is not None:
            existing.year = candidate.year
        if not existing.application_date and candidate.application_date:
            existing.application_date = candidate.application_date
        if not existing.publication_date and candidate.publication_date:
            existing.publication_date = candidate.publication_date
        if not existing.database and candidate.database:
            existing.database = candidate.database
    for rank, record in enumerate(merged, start=1):
        record.rank = rank
    return merged


def parse_latest_uyanip_page_records(
    captured_payloads: list[Any],
    html_text: str,
    base_url: str,
    source: str,
    keyword: str,
    rank_start: int,
) -> tuple[list[PatentRecord], str, bool, int | None, int]:
    xhr_records: list[PatentRecord] = []
    next_token = ""
    exhausted = False
    total_hint: int | None = None
    for payload in reversed(captured_payloads):
        parsed, candidate_token, candidate_exhausted = parse_uyanip_patent_xhr(
            payload,
            base_url,
            source,
            keyword,
            rank_start,
        )
        if parsed:
            xhr_records = parsed
            next_token = candidate_token
            exhausted = candidate_exhausted
            total_hint = uyanip_xhr_total_hint(payload)
            break
    dom_records = parse_uyanip_patent_search(
        html_text,
        base_url,
        source,
        keyword,
        rank_start,
    )
    merged = merge_uyanip_patent_records(xhr_records, dom_records)
    raw_count = max(len(xhr_records), len(uyanip_patent_cards(html_text)))
    if total_hint is None:
        for payload in reversed(captured_payloads):
            candidate_total = uyanip_xhr_total_hint(payload)
            if candidate_total is not None:
                total_hint = candidate_total
                break
    if not xhr_records:
        exhausted = not uyanip_patent_html_has_next(html_text)
        next_token = "" if exhausted else "next_control"
    return merged, next_token, exhausted, total_hint, raw_count


async def install_uyanip_response_capture(page: Any, captured_payloads: list[Any]) -> None:
    async def capture(response: Any) -> None:
        if not uyanip_search_response_url(getattr(response, "url", "")):
            return
        try:
            payload = await response.json()
        except Exception:
            return
        if isinstance(payload, dict):
            captured_payloads.append(payload)

    def schedule(response: Any) -> None:
        asyncio.create_task(capture(response))

    try:
        page.on("response", schedule)
    except Exception:
        pass


async def uyanip_password_surface_visible(page: Any) -> bool:
    for selector in ("#password", "#password_xdhy", "input[name='password']"):
        try:
            locator = page.locator(selector).first
            if await locator.count() and await locator.is_visible(timeout=300):
                return True
        except Exception:
            continue
    return False


async def uyanip_login_required(page: Any, html_text: str = "") -> bool:
    del html_text
    current_url = first_string(getattr(page, "url", ""))
    parsed = urllib.parse.urlsplit(current_url)
    query = urllib.parse.parse_qs(parsed.query)
    if first_string(query.get("login", [""])[0]) == "1":
        return True
    if await uyanip_password_surface_visible(page):
        return True
    return False


async def uyanip_page_has_challenge(page: Any, body: str = "") -> bool:
    return await page_has_active_verification_challenge(
        page,
        source=UYANIP_SOURCE,
        body=body or await page_body_text(page),
    )


async def uyanip_results_state(
    page: Any,
    captured_payloads: list[Any],
) -> tuple[str, str, str]:
    body = await page_body_text(page)
    html_text = ""
    try:
        html_text = await page.content()
    except Exception:
        pass
    if await uyanip_page_has_challenge(page, body):
        return "challenge", body, html_text
    for payload in reversed(captured_payloads):
        if uyanip_xhr_record_dicts(payload):
            return "records", body, html_text
    if uyanip_patent_cards(html_text):
        return "records", body, html_text
    if uyanip_no_results(body):
        return "explicit_no_results", body, html_text
    if await uyanip_login_required(page, html_text):
        return "login_required", body, html_text
    if browser_internal_navigation_error_url(first_string(getattr(page, "url", ""))):
        return "navigation_error", body, html_text
    return "pending", body, html_text


async def wait_for_uyanip_results(
    page: Any,
    captured_payloads: list[Any],
) -> tuple[str, str, str]:
    deadline = time.monotonic() + min(
        120,
        env_seconds("LAPS_UYANIP_SEARCH_READY_TIMEOUT_SECONDS", 45, 1),
    )
    state = "pending"
    body = html_text = ""
    while time.monotonic() < deadline:
        state, body, html_text = await uyanip_results_state(page, captured_payloads)
        if state != "pending":
            return state, body, html_text
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return state, body, html_text


async def wait_for_uyanip_search_surface(
    page: Any,
    captured_payloads: list[Any],
) -> tuple[str, str, str]:
    deadline = time.monotonic() + min(
        60,
        env_seconds("LAPS_UYANIP_SEARCH_SURFACE_TIMEOUT_SECONDS", 20, 1),
    )
    state = "pending"
    body = html_text = ""
    while time.monotonic() < deadline:
        state, body, html_text = await uyanip_results_state(page, captured_payloads)
        if state != "pending" or uyanip_result_surface_url(getattr(page, "url", "")):
            return state, body, html_text
        try:
            await page.wait_for_timeout(250)
        except Exception:
            break
    return state, body, html_text


async def submit_uyanip_patent_search(
    page: Any,
    keyword: str,
    captured_payloads: list[Any],
) -> tuple[str, str, str]:
    query_locator = None
    for selector in PATENT_WEB_SOURCE_SEARCH_SURFACE_SELECTORS[UYANIP_SOURCE]:
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                query_locator = candidate
                break
        except Exception:
            continue
    if query_locator is None:
        return "search_form_not_ready", await page_body_text(page), ""
    try:
        await query_locator.fill(keyword, timeout=5000)
    except Exception:
        return "search_form_not_ready", await page_body_text(page), ""
    submitted = await click_first_visible_async(
        page,
        PATENT_WEB_SOURCE_RESUME_ACTION_SELECTORS[UYANIP_SOURCE],
    )
    if not submitted:
        try:
            await query_locator.press("Enter", timeout=3000)
            submitted = True
        except Exception:
            pass
    if not submitted:
        return "search_form_not_ready", await page_body_text(page), ""
    return await wait_for_uyanip_search_surface(page, captured_payloads)


async def submit_uyanip_result_page_search(
    page: Any,
    captured_payloads: list[Any],
) -> tuple[str, str, str]:
    if not uyanip_result_surface_url(getattr(page, "url", "")):
        return "result_search_surface_not_ready", await page_body_text(page), ""
    try:
        expression = page.locator("#exp").first
        if (
            not await expression.count()
            or not await expression.is_visible(timeout=500)
            or not first_string(await expression.input_value())
        ):
            return "result_search_expression_missing", await page_body_text(page), ""
    except Exception:
        return "result_search_expression_missing", await page_body_text(page), ""
    controls: list[Any] = []
    try:
        buttons = page.locator("button:visible")
        for index in range(await buttons.count()):
            button = buttons.nth(index)
            if first_string(await button.inner_text(timeout=500)) == "检索":
                controls.append(button)
    except Exception:
        controls = []
    if len(controls) != 1:
        return "result_search_submit_ambiguous", await page_body_text(page), ""
    try:
        await controls[0].click(timeout=5000)
    except Exception:
        return "result_search_submit_failed", await page_body_text(page), ""
    return await wait_for_uyanip_results(page, captured_payloads)


async def login_uyanip_with_playwright(
    page: Any,
    config: SearchConfig,
    policy: SourceAccessPolicy,
) -> str:
    current_host = (urllib.parse.urlsplit(first_string(getattr(page, "url", ""))).hostname or "").casefold()
    if not (current_host == "uyanip.com" or current_host.endswith(".uyanip.com")):
        return "login_host_not_allowed"
    account, password = source_personal_credentials(config, policy)
    if not account or not password:
        return "uyanip_credentials_missing"
    if not await uyanip_password_surface_visible(page):
        await click_first_visible_async(page, ("#login-open", "a[href*='login']"))
        try:
            await page.wait_for_timeout(750)
        except Exception:
            pass
    username_locator = None
    password_locator = None
    for selector in ("#username", "#username_xdhy", "input[name='username']"):
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                username_locator = candidate
                break
        except Exception:
            continue
    for selector in ("#password", "#password_xdhy", "input[name='password']"):
        try:
            candidate = page.locator(selector).first
            if await candidate.count() and await candidate.is_visible(timeout=500):
                password_locator = candidate
                break
        except Exception:
            continue
    if username_locator is None or password_locator is None:
        return "uyanip_login_form_not_ready"
    login_response_states: list[str] = []

    async def capture_login_response(response: Any) -> None:
        try:
            parsed = urllib.parse.urlsplit(first_string(getattr(response, "url", "")))
        except ValueError:
            return
        if (
            (parsed.hostname or "").casefold() != "api.duyandb.com"
            or (parsed.path or "").casefold() != "/auth/auth/login"
        ):
            return
        try:
            payload = await response.json()
        except Exception:
            payload = None
        response_status = int(getattr(response, "status", 0) or 0)
        if uyanip_login_api_succeeded(response_status, payload):
            login_response_states.append("success")
        elif response_status in {400, 401, 403}:
            login_response_states.append("rejected")

    def schedule_login_response(response: Any) -> None:
        asyncio.create_task(capture_login_response(response))

    try:
        page.on("response", schedule_login_response)
    except Exception:
        pass
    try:
        await username_locator.fill(account, timeout=5000)
        await password_locator.fill(password, timeout=5000)
    except Exception:
        return "uyanip_login_form_not_ready"
    submitted = await click_first_visible_async(
        page,
        ("#login", "#login_xdhy", "button[type='submit']:visible"),
    )
    if not submitted:
        return "uyanip_login_submit_not_ready"
    deadline = time.monotonic() + min(
        120,
        env_seconds("LAPS_UYANIP_LOGIN_TIMEOUT_SECONDS", 60, 1),
    )
    while time.monotonic() < deadline:
        body = await page_body_text(page)
        if uyanip_invalid_credentials(body):
            return "uyanip_credentials_invalid"
        if "rejected" in login_response_states:
            return "uyanip_credentials_invalid"
        if await uyanip_page_has_challenge(page, body):
            return "uyanip_login_challenge"
        password_visible = await uyanip_password_surface_visible(page)
        if "success" in login_response_states and not password_visible:
            return "success"
        if not password_visible and (
            uyanip_result_surface_url(getattr(page, "url", ""))
            or any(
                marker in body.casefold()
                for marker in ("退出登录", "退出", "个人中心", "我的度衍", "logout")
            )
        ):
            return "success"
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return "uyanip_login_timeout"


async def uyanip_page_signature(
    page: Any,
    captured_payloads: list[Any],
) -> str:
    html_text = ""
    try:
        html_text = await page.content()
    except Exception:
        pass
    records, _, _, _, _ = parse_latest_uyanip_page_records(
        captured_payloads,
        html_text,
        first_string(getattr(page, "url", "")) or UYANIP_HOME,
        UYANIP_SOURCE,
        "",
        0,
    )
    values = [
        record.url or first_string(record.raw_id) or record.patent_name
        for record in records
    ]
    if not values:
        return ""
    material = json.dumps(values, ensure_ascii=False, sort_keys=True)
    return hashlib.sha1(material.encode("utf-8")).hexdigest()


async def uyanip_next_control(page: Any) -> Any | None:
    try:
        page_links = page.locator(".page a")
        current_page = 0
        for index in range(await page_links.count()):
            locator = page_links.nth(index)
            classes = first_string(await locator.get_attribute("class")).casefold()
            if "active" in classes:
                current_page = parse_int(await locator.inner_text()) or 0
                break
        if current_page:
            next_page = current_page + 1
            for index in range(await page_links.count()):
                locator = page_links.nth(index)
                if not await locator.is_visible(timeout=300):
                    continue
                if (parse_int(await locator.inner_text()) or 0) == next_page:
                    return locator
    except Exception:
        pass
    for selector in PATENT_WEB_SOURCE_PARSER_PROFILES[UYANIP_SOURCE].next_links:
        try:
            locators = page.locator(selector)
            for index in range(await locators.count()):
                locator = locators.nth(index)
                if not await locator.is_visible(timeout=300):
                    continue
                disabled = await locator.get_attribute("disabled")
                aria_disabled = first_string(await locator.get_attribute("aria-disabled")).casefold()
                classes = first_string(await locator.get_attribute("class")).casefold()
                if disabled is not None or aria_disabled == "true" or "disabled" in classes:
                    continue
                return locator
        except Exception:
            continue
    return None


async def advance_uyanip_patent_page(
    page: Any,
    captured_payloads: list[Any],
    previous_signature: str,
) -> str:
    locator = await uyanip_next_control(page)
    if locator is None:
        return "exhausted"
    payload_count = len(captured_payloads)
    try:
        await locator.click(timeout=5000)
    except Exception:
        return "click_failed"
    deadline = time.monotonic() + min(
        120,
        env_seconds("LAPS_UYANIP_PAGE_ADVANCE_TIMEOUT_SECONDS", 60, 1),
    )
    while time.monotonic() < deadline:
        body = await page_body_text(page)
        if await uyanip_page_has_challenge(page, body):
            return "challenge"
        signature = await uyanip_page_signature(page, captured_payloads[payload_count:])
        if signature and signature != previous_signature:
            return "advanced"
        try:
            await page.wait_for_timeout(500)
        except Exception:
            break
    return "unchanged"


def uyanip_snapshot_records(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    snapshot: dict[str, Any],
) -> list[PatentRecord]:
    records = parse_uyanip_patent_search(
        first_string(snapshot.get("html")),
        first_string(snapshot.get("final_url")) or UYANIP_HOME,
        source,
        keyword,
    )
    has_next = bool(snapshot.get("has_next_control"))
    persist_search_page(
        runtime,
        "patent",
        source,
        keyword,
        records,
        next_token="page:2" if has_next else "",
        exhausted=not has_next,
        page_number=1,
        reason="ordinary_chrome_javascript_pager_requires_live_resume" if has_next else "",
        raw_count=len(uyanip_patent_cards(first_string(snapshot.get("html")))),
    )
    return records


def uyanip_transport_boundary(boundary: str) -> bool:
    lowered = first_string(boundary).casefold()
    return any(
        marker in lowered
        for marker in (
            "browser_launch_failed",
            "navigation_error",
            "search_form_not_ready",
            "results_not_ready",
            "login_form_not_ready",
            "login_submit_not_ready",
            "login_timeout",
            "browser_failed",
        )
    )


async def search_uyanip_patent_browser_once(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    page_size: int,
    *,
    restricted: bool,
    browser_name: str = "chromium",
) -> tuple[list[PatentRecord], str]:
    del page_size
    policy = patent_source_auth_policy[source]
    records: list[PatentRecord] = []
    captured_payloads: list[Any] = []
    pw = browser = context = None
    try:
        async_playwright = load_async_playwright()
        pw = await async_playwright().start()
        normalized_browser = normalize_browser_name(browser_name, "chromium")
        browser, launch_error = await launch_named_browser(
            pw.chromium,
            normalized_browser,
            headless=not restricted,
        )
        if browser is None:
            return records, f"browser_launch_failed:{launch_error or normalized_browser}"
        state_path = auth_state_path(runtime.config, source, policy)
        context_kwargs: dict[str, Any] = {}
        state_reused = uyanip_saved_state_is_current(runtime.config, source, policy)
        if state_reused:
            context_kwargs["storage_state"] = str(state_path)
        try:
            context = await browser.new_context(**context_kwargs)
        except Exception:
            if not state_reused:
                raise
            state_reused = False
            context_kwargs.pop("storage_state", None)
            context = await browser.new_context()
        page = await browser_context_navigation_page(context)
        await install_uyanip_response_capture(page, captured_payloads)
        await wait_for_rate_limiter(
            runtime.limiter,
            "www.uyanip.com",
            kind="browser",
            source=source,
        )
        response = await page.goto(UYANIP_HOME, wait_until="domcontentloaded", timeout=30000)
        response_status = int(response.status) if response is not None else 0
        await page.wait_for_timeout(1500)
        state, body, html_text = await uyanip_results_state(page, captured_payloads)
        if state == "challenge" or response_status in {401, 403, 429}:
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                pw.chromium,
                browser,
                context,
                page,
                first_string(getattr(page, "url", "")) or UYANIP_HOME,
                body,
                context_kwargs,
            )
            if not resolved:
                return records, "uyanip_challenge_unresolved"
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            if snapshot is not None:
                return uyanip_snapshot_records(runtime, source, keyword, snapshot), "challenge_snapshot_consumed"
            captured_payloads = []
            await install_uyanip_response_capture(page, captured_payloads)
            state, body, html_text = await wait_for_uyanip_results(page, captured_payloads)

        if state_reused:
            runtime.restricted_auth(
                source,
                keyword,
                "personal",
                "reused",
                "uyanip_saved_personal_session_loaded",
            )

        login_attempted = False
        home_search_submitted = False
        result_search_submitted = False
        while state not in {"records", "explicit_no_results", "challenge"}:
            if state == "login_required":
                if not restricted:
                    return records, (
                        "uyanip_saved_state_expired"
                        if state_reused
                        else "uyanip_login_required"
                    )
                if login_attempted:
                    return records, "uyanip_login_required_after_success"
                login_attempted = True
                observed_resume_url = uyanip_observed_login_resume_url(
                    getattr(page, "url", "")
                )
                login_status = await login_uyanip_with_playwright(
                    page,
                    runtime.config,
                    policy,
                )
                if login_status == "uyanip_login_challenge":
                    body = await page_body_text(page)
                    resolved, browser, context, page = await handle_search_verification_challenge(
                        runtime,
                        source,
                        keyword,
                        pw.chromium,
                        browser,
                        context,
                        page,
                        first_string(getattr(page, "url", "")) or UYANIP_HOME,
                        body,
                        context_kwargs,
                        control_reason="site_personal_login_challenge",
                    )
                    if not resolved:
                        return records, "uyanip_login_challenge_unresolved"
                    snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
                    if snapshot is not None:
                        return (
                            uyanip_snapshot_records(
                                runtime,
                                source,
                                keyword,
                                snapshot,
                            ),
                            "challenge_snapshot_consumed",
                        )
                    login_status = (
                        "success"
                        if not await uyanip_login_required(page)
                        else "uyanip_login_challenge_still_present"
                    )
                if login_status != "success":
                    return records, login_status
                persisted, persist_reason = await persist_search_auth_context_state(
                    context,
                    runtime.config,
                    source,
                    policy,
                    "site_personal_session",
                )
                if not persisted:
                    return records, f"uyanip_auth_state_not_published:{persist_reason}"
                save_auth_browser_transport(
                    runtime.config,
                    source,
                    normalized_browser,
                    restricted,
                    policy,
                )
                runtime.restricted_auth(
                    source,
                    keyword,
                    "personal",
                    "success",
                    "uyanip_personal_login_succeeded",
                )
                captured_payloads = []
                await install_uyanip_response_capture(page, captured_payloads)
                current_url = first_string(getattr(page, "url", ""))
                if observed_resume_url and not uyanip_result_surface_url(current_url):
                    await wait_for_rate_limiter(
                        runtime.limiter,
                        "www.uyanip.com",
                        kind="browser",
                        source=source,
                    )
                    await page.goto(
                        observed_resume_url,
                        wait_until="domcontentloaded",
                        timeout=30000,
                    )
                    await page.wait_for_timeout(1000)
                state, body, html_text = await uyanip_results_state(
                    page,
                    captured_payloads,
                )
                if uyanip_result_surface_url(getattr(page, "url", "")):
                    state, body, html_text = await uyanip_results_state(
                        page,
                        captured_payloads,
                    )
                continue
            if uyanip_result_surface_url(getattr(page, "url", "")):
                if result_search_submitted:
                    return records, f"uyanip_{state or 'results_not_ready'}"
                result_search_submitted = True
                state, body, html_text = await submit_uyanip_result_page_search(
                    page,
                    captured_payloads,
                )
            else:
                if home_search_submitted:
                    return records, f"uyanip_{state or 'results_not_ready'}"
                home_search_submitted = True
                state, body, html_text = await submit_uyanip_patent_search(
                    page,
                    keyword,
                    captured_payloads,
                )
        if state == "challenge":
            resolved, browser, context, page = await handle_search_verification_challenge(
                runtime,
                source,
                keyword,
                pw.chromium,
                browser,
                context,
                page,
                first_string(getattr(page, "url", "")) or UYANIP_HOME,
                body,
                context_kwargs,
            )
            if not resolved:
                return records, "uyanip_challenge_unresolved"
            snapshot = SEARCH_CHALLENGE_SNAPSHOT.get()
            if snapshot is not None:
                return uyanip_snapshot_records(runtime, source, keyword, snapshot), "challenge_snapshot_consumed"
            captured_payloads = []
            await install_uyanip_response_capture(page, captured_payloads)
            state, body, html_text = await wait_for_uyanip_results(page, captured_payloads)
        if state == "explicit_no_results":
            _, completed_pages = resumed_page_state(runtime, "patent", source, keyword, "page:1")
            persist_search_page(
                runtime,
                "patent",
                source,
                keyword,
                [],
                next_token="",
                exhausted=True,
                page_number=completed_pages + 1,
                total_hint=0,
                raw_count=0,
            )
            return records, "complete"
        if state != "records":
            return records, f"uyanip_{state or 'results_not_ready'}"

        resume_token, completed_pages = resumed_page_state(
            runtime,
            "patent",
            source,
            keyword,
            "page:1",
        )
        resume_page = parse_int(resume_token.removeprefix("page:")) or 1
        current_page = 1
        while current_page < resume_page:
            before = await uyanip_page_signature(page, captured_payloads)
            advance_state = await advance_uyanip_patent_page(page, captured_payloads, before)
            if advance_state != "advanced":
                return records, "uyanip_checkpoint_fast_forward_failed"
            current_page += 1

        seen_signatures: set[str] = set()
        while True:
            body = await page_body_text(page)
            if await uyanip_page_has_challenge(page, body):
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    first_string(getattr(page, "url", "")) or UYANIP_HOME,
                    body,
                    context_kwargs,
                )
                if not resolved:
                    return records, "uyanip_challenge_unresolved_before_page"
            html_text = await page.content()
            page_records, xhr_next_token, xhr_exhausted, total_hint, raw_count = (
                parse_latest_uyanip_page_records(
                    captured_payloads,
                    html_text,
                    first_string(getattr(page, "url", "")) or UYANIP_HOME,
                    source,
                    keyword,
                    len(records),
                )
            )
            signature = await uyanip_page_signature(page, captured_payloads)
            if signature and signature in seen_signatures:
                return records, "uyanip_repeated_page_signature"
            if signature:
                seen_signatures.add(signature)
            no_results = uyanip_no_results(body)
            if not page_records and not no_results:
                return records, "uyanip_results_not_detected"
            next_control = await uyanip_next_control(page)
            has_next = next_control is not None and not xhr_exhausted
            next_token = (
                xhr_next_token
                if has_next and xhr_next_token.startswith("page:")
                else (f"page:{current_page + 1}" if has_next else "")
            )
            completed_pages += 1
            persist_search_page(
                runtime,
                "patent",
                source,
                keyword,
                page_records,
                next_token=next_token,
                exhausted=not has_next,
                page_number=completed_pages,
                total_hint=total_hint,
                raw_count=raw_count,
                page_signature=signature,
            )
            records.extend(page_records)
            if not has_next:
                return records, "complete"
            before = signature
            payload_start = len(captured_payloads)
            advance_state = await advance_uyanip_patent_page(page, captured_payloads, before)
            if advance_state == "challenge":
                body = await page_body_text(page)
                resolved, browser, context, page = await handle_search_verification_challenge(
                    runtime,
                    source,
                    keyword,
                    pw.chromium,
                    browser,
                    context,
                    page,
                    first_string(getattr(page, "url", "")) or UYANIP_HOME,
                    body,
                    context_kwargs,
                )
                if not resolved:
                    return records, "uyanip_next_page_challenge_unresolved"
                deadline = time.monotonic() + 60
                while time.monotonic() < deadline:
                    after = await uyanip_page_signature(page, captured_payloads[payload_start:])
                    if after and after != before:
                        advance_state = "advanced"
                        break
                    await page.wait_for_timeout(500)
            if advance_state != "advanced":
                return records, f"uyanip_next_page_{advance_state}"
            captured_payloads = captured_payloads[payload_start:]
            current_page += 1
    except Exception as exc:
        return records, f"uyanip_browser_failed:{safe_error_text(str(exc))}"
    finally:
        await close_restricted_browser_attempt(browser, context)
        if pw is not None:
            try:
                await pw.stop()
            except Exception:
                pass


async def search_uyanip_patent_adapter(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
    page_size: int,
) -> list[PatentRecord]:
    del url
    policy = patent_source_auth_policy[source]
    requested_path = first_string(SEARCH_TASK_CONTEXT.get().get("path"))
    restricted = requested_path == "restricted_browser"
    async with runtime.browser_sem:
        records, boundary = await search_uyanip_patent_browser_once(
            runtime,
            source,
            keyword,
            page_size,
            restricted=restricted,
        )
        if not restricted and boundary in {
            "uyanip_login_required",
            "uyanip_saved_state_expired",
        }:
            if not uyanip_credentials_configured(runtime.config, policy):
                boundary = "uyanip_credentials_missing"
            else:
                parent_context = SEARCH_TASK_CONTEXT.get()
                token = SEARCH_TASK_CONTEXT.set(
                    parent_context | {"path": "restricted_browser"}
                )
                try:
                    restricted_records, boundary = await search_uyanip_patent_browser_once(
                        runtime,
                        source,
                        keyword,
                        page_size,
                        restricted=True,
                    )
                    records.extend(restricted_records)
                    restricted = True
                finally:
                    SEARCH_TASK_CONTEXT.reset(token)
        if uyanip_transport_boundary(boundary):
            runtime.degrade(
                source,
                keyword,
                f"bundled Chromium did not complete Uyan patent search ({boundary}); "
                "retrying once with Playwright Chrome",
            )
            await asyncio.sleep(verification_browser_fallback_cooldown_seconds())
            retry_records, boundary = await search_uyanip_patent_browser_once(
                runtime,
                source,
                keyword,
                page_size,
                restricted=restricted,
                browser_name="chrome",
            )
            records.extend(retry_records)
    if boundary not in {
        "complete",
        "challenge_snapshot_consumed",
    }:
        blocked_boundaries = {
            "uyanip_credentials_missing",
            "uyanip_credentials_invalid",
            "uyanip_login_required",
        }
        status = "blocked" if boundary in blocked_boundaries else "incomplete"
        runtime.mark_current_run("patent", source, keyword, status, boundary)
        runtime.skip(source, keyword, boundary)
    return dedupe_patent_records(records)


def build_patent_adapter_registry() -> dict[str, SourceSearchAdapter]:
    public_runner_names = {
        "Google Patents",
        "WIPO PATENTSCOPE API",
        CNKI_SOURCE,
        WANFANG_SOURCE,
        UYANIP_SOURCE,
    }
    restricted_runner_names = {CNKI_SOURCE, WANFANG_SOURCE, UYANIP_SOURCE}
    entries: list[SourceSearchAdapter] = []
    for spec in PATENT_SEARCH_SPECS:
        runner = globals().get(spec.actual_adapter)
        if not callable(runner):
            raise RuntimeError(
                f"Shared registry references missing patent runner: {spec.actual_adapter}"
            )
        entries.append(
            SourceSearchAdapter(
                spec.display_name,
                "patent",
                spec.parser,
                spec.paths,
                spec.pagination,
                runner,
                public_browser_runner=(
                    runner if spec.display_name in public_runner_names else None
                ),
                restricted_browser_runner=(
                    runner if spec.display_name in restricted_runner_names else None
                ),
            )
        )
    return {
        adapter.source: replace(
            adapter,
            query_variants=PATENT_QUERY_PROFILES[adapter.source],
        )
        for adapter in entries
    }


PATENT_SOURCE_ADAPTERS = build_patent_adapter_registry()


async def search_patent_source(
    runtime: SearchRuntime,
    source: str,
    url: str,
    keyword: str,
    keyword_index: int,
    source_index: int,
    limit: int,
) -> SourceAttemptResult:
    try:
        policy = patent_source_auth_policy.get(source)
        adapter = PATENT_SOURCE_ADAPTERS.get(source)
        if policy is None or adapter is None:
            runtime.skip(source, keyword, "missing source auth policy or adapter")
            return SourceAttemptResult([], "failed", "missing source auth policy or adapter")
        if source == "Google BigQuery" and source not in runtime.allowed_cost_sources:
            runtime.skip(source, keyword, "awaiting_cost_approval")
            return SourceAttemptResult(
                [],
                "blocked",
                "awaiting_cost_approval",
                path="cost_api",
                query_variant=current_query_variant(),
            )
        plan = build_access_plan(runtime.config, source, policy, keyword, is_patent=True)
        if not apply_access_plan(runtime, source, keyword, plan):
            reason = latest_source_reason(
                runtime,
                source,
                keyword,
                path=first_string(SEARCH_TASK_CONTEXT.get().get("path")) or plan.route,
                query_variant=current_query_variant(),
            ) or plan.reason
            return SourceAttemptResult(
                [],
                source_run_status(plan, [], reason),
                reason,
                path=first_string(SEARCH_TASK_CONTEXT.get().get("path")) or plan.route,
                query_variant=current_query_variant(),
            )
        if plan.route == "restricted_browser" and adapter.restricted_browser_runner:
            runner = adapter.restricted_browser_runner
        elif plan.route == "public_browser" and adapter.public_browser_runner:
            runner = adapter.public_browser_runner
        else:
            runner = adapter.runner
        records = await runner(runtime, source, url, keyword, limit)
        for record in records:
            record.keyword_index = keyword_index
            record.source_index = source_index
            record.source = source
            record.keyword = keyword
        path = first_string(SEARCH_TASK_CONTEXT.get().get("checkpoint_path") or SEARCH_TASK_CONTEXT.get().get("path")) or plan.route
        run = (
            runtime.state_store.get_run(
                "patent",
                keyword,
                source,
                path,
                current_query_variant(),
            )
            if runtime.state_store is not None
            else None
        ) or {}
        reason = latest_source_reason(
            runtime,
            source,
            keyword,
            path=path,
            query_variant=current_query_variant(),
        ) or first_string(run.get("reason"))
        status = finalized_attempt_status(run, plan, records, reason)
        if "query_field_unverified" in current_query_field_scope(""):
            # The public PATENTSCOPE form is usable, but its stable field
            # semantics have not been verified.  A successful HTTP/browser
            # traversal is therefore evidence of records, not complete query
            # coverage.
            status = "incomplete"
            reason = "query_field_unverified"
        return SourceAttemptResult(
            list(records),
            status,
            reason,
            path=path,
            query_variant=current_query_variant(),
        )
    except Exception as exc:
        runtime.skip(source, keyword, f"adapter failed: {safe_error_text(str(exc))}")
        return SourceAttemptResult(
            [],
            "failed",
            f"adapter failed: {safe_error_text(str(exc))}",
            path=first_string(SEARCH_TASK_CONTEXT.get().get("path")),
            query_variant=current_query_variant(),
        )


@dataclass(frozen=True)
class LiteratureResumeIndex:
    dois: frozenset[str]
    dois_with_pdf_url: frozenset[str]
    pdf_urls: frozenset[str]


def existing_literature_resume_index(
    records: list[LiteratureRecord],
) -> LiteratureResumeIndex:
    dois: set[str] = set()
    dois_with_pdf_url: set[str] = set()
    pdf_urls: set[str] = set()
    for record in records:
        doi = normalize_doi(record.doi)
        pdf_url = normalize_literature_pdf_url(record.url)
        if doi:
            dois.add(doi)
            if pdf_url:
                dois_with_pdf_url.add(doi)
        if pdf_url:
            pdf_urls.add(pdf_url)
    return LiteratureResumeIndex(
        dois=frozenset(dois),
        dois_with_pdf_url=frozenset(dois_with_pdf_url),
        pdf_urls=frozenset(pdf_urls),
    )


def normalize_resume_url(url: str | None) -> str:
    value = (url or "").strip()
    if not value:
        return ""
    parsed = urllib.parse.urlsplit(value)
    if not parsed.scheme or not parsed.netloc:
        return value.casefold().rstrip("/")
    scheme = parsed.scheme.casefold()
    netloc = parsed.netloc.casefold()
    path = parsed.path.rstrip("/")
    return urllib.parse.urlunsplit((scheme, netloc, path, parsed.query, ""))


def existing_patent_urls(records: list[PatentRecord]) -> set[str]:
    return {normalize_resume_url(record.url) for record in records if normalize_resume_url(record.url)}


def latest_source_reason(
    runtime: SearchRuntime,
    source: str,
    keyword: str,
    *,
    path: str = "",
    query_variant: str = "",
) -> str:
    for event in reversed(runtime.skipped_sources):
        if (
            event.source == source
            and event.keyword == keyword
            and (not path or event.path == path)
            and (not query_variant or event.query_variant == query_variant)
        ):
            return event.reason
    for event in reversed(runtime.browser_disabled_sources):
        if (
            event.source == source
            and event.keyword == keyword
            and (not path or event.path == path)
            and (not query_variant or event.query_variant == query_variant)
        ):
            return event.reason
    return ""


def source_fallback_hint(reason: str, path: str = "") -> str:
    lowered = reason.casefold()
    if not lowered:
        return ""
    if path in {"api", "api_degraded"} and any(
        marker in lowered
        for marker in (
            "api_key_invalid",
            "subscription_required",
            "quota_exhausted",
            "forbidden_unknown",
        )
    ):
        return "restricted_auth_required"
    if any(
        marker in lowered
        for marker in (
            "zero_result",
            "no_result",
            "schema_error",
            "parse error",
            "http 429",
            "rate_limited",
            "quota_exhausted",
            "challenge",
            "verification",
            "captcha",
            "subscription_required",
            "not subscribed",
            "institution_not_listed",
        )
    ):
        return ""
    if any(
        marker in lowered
        for marker in (
            "http 401",
            "http 403",
            "unauthorized",
            "forbidden",
            "authentication_required",
            "login_required",
            "sign_in_required",
            "access_permission_required",
            "entitlement_required",
        )
    ):
        return "restricted_auth_required"
    return ""


def source_reason_detail(reason: str) -> dict[str, Any]:
    """Normalize legacy adapter text into the v2 structured reason contract."""

    normalized = first_string(reason)
    lowered = normalized.casefold()
    retry_at = ""
    status_match = re.search(r"\bhttp[\s_:=-]*(\d{3})\b", lowered)
    status_code = int(status_match.group(1)) if status_match else 0
    if status_code:
        reason_code = f"http_{status_code}"
        category = (
            "authentication"
            if status_code == 401
            else "access_control"
            if status_code == 403
            else "rate_limit"
            if status_code == 429
            else "http"
        )
        retryable = status_code in {408, 425, 429, 500, 502, 503, 504}
    elif "query_field_unverified" in lowered:
        reason_code, category, retryable = (
            "query_field_unverified",
            "query_semantics",
            False,
        )
    elif "missing required credential" in lowered:
        reason_code, category, retryable = (
            "missing_required_credential",
            "configuration",
            False,
        )
    elif "awaiting_cost_approval" in lowered:
        reason_code, category, retryable = (
            "awaiting_cost_approval",
            "authorization",
            False,
        )
    elif any(token in lowered for token in ("api_key_invalid", "invalid api key")):
        reason_code, category, retryable = "api_key_invalid", "authentication", False
    elif any(token in lowered for token in ("subscription_required", "not subscribed")):
        reason_code, category, retryable = (
            "subscription_required",
            "authorization",
            False,
        )
    elif "quota_exhausted" in lowered:
        reason_code, category, retryable = "quota_exhausted", "rate_limit", True
    elif any(token in lowered for token in ("rate_limited", "rate limit")):
        reason_code, category, retryable = "rate_limited", "rate_limit", True
    elif any(token in lowered for token in ("timeout", "timed out")):
        reason_code, category, retryable = "timeout", "transport", True
    elif "cooldown" in lowered:
        reason_code, category, retryable = "cooldown_active", "rate_limit", True
    elif any(token in lowered for token in ("challenge", "verification", "captcha")):
        reason_code, category, retryable = "access_challenge", "access_control", True
    elif any(token in lowered for token in ("http 401", "unauthorized", "authentication_required")):
        reason_code, category, retryable = "authentication_required", "authentication", False
    elif any(token in lowered for token in ("http 403", "forbidden", "access denied")):
        reason_code, category, retryable = "access_forbidden", "access_control", False
    else:
        reason_code = re.sub(r"[^a-z0-9]+", "_", lowered).strip("_")[:120]
        category = "source_run"
        retryable = False
    retry_after = retry_after_seconds_from_text(normalized)
    if retryable and retry_after <= 0:
        retry_after = DEFAULT_TRANSIENT_RETRY_SECONDS
    if retryable and retry_after > 0:
        retry_at = retry_at_iso(retry_after)
    return structured_reason(
        reason_code or "unspecified",
        category=category,
        retryable=retryable,
        retry_at=retry_at,
    )


def source_run_status(
    plan: AccessPlan,
    records: list[Any],
    reason: str,
    reason_detail: Mapping[str, Any] | None = None,
) -> str:
    detail = dict(reason_detail or source_reason_detail(reason))
    reason_code = first_string(detail.get("reason_code"))
    category = first_string(detail.get("category"))
    if (
        plan.route in {"skip", "browser_disabled", "unimplemented"}
        or reason_code
        in {
            "missing_required_credential",
            "authentication_required",
            "api_key_invalid",
            "subscription_required",
            "awaiting_cost_approval",
            "http_401",
        }
        or category == "configuration"
    ):
        return "blocked"
    if bool(detail.get("retryable")) or reason_code in {
        "query_field_unverified",
        "access_challenge",
        "access_forbidden",
        "http_403",
        "forbidden_unknown",
        "quota_exhausted",
    }:
        return "incomplete"
    if reason and not records:
        return "failed"
    return "complete"


def finalized_attempt_status(
    run: dict[str, Any],
    plan: AccessPlan,
    records: list[Any],
    reason: str,
) -> str:
    status = first_string(run.get("status"))
    if status and status != "running":
        return status
    run_detail = {
        "reason_code": run.get("reason_code"),
        "category": run.get("category"),
        "retryable": bool(run.get("retryable")),
        "retry_at": run.get("retry_at"),
    }
    return source_run_status(
        plan,
        records,
        reason,
        run_detail if first_string(run.get("reason_code")) else None,
    )


def search_scheduler_limits(runtime: SearchRuntime) -> tuple[int, int]:
    default_workers = max(
        1,
        min(int(runtime.config.thread_num), DEFAULT_SEARCH_QUEUE_MAX_WORKERS),
    )
    worker_limit = positive_int_environment(
        "LAPS_SEARCH_QUEUE_WORKERS",
        default_workers,
    )
    queue_capacity = positive_int_environment(
        "LAPS_SEARCH_QUEUE_MAXSIZE",
        max(worker_limit, worker_limit * 2),
    )
    return worker_limit, queue_capacity


async def run_bounded_search_jobs(
    jobs: Iterable[Callable[[], Awaitable[Any]]],
    *,
    scheduler_name: str,
    worker_limit: int,
    queue_capacity: int,
    metrics_sink: dict[str, dict[str, Any]] | None = None,
) -> tuple[list[Any], dict[str, Any]]:
    """Run lazily-produced search jobs with fixed workers and a bounded queue."""

    if worker_limit <= 0 or queue_capacity <= 0:
        raise ValueError("Search scheduler worker and queue limits must be positive")
    queue: asyncio.Queue[Any] = asyncio.Queue(maxsize=queue_capacity)
    sentinel = object()
    results: list[Any] = []
    metrics: dict[str, Any] = {
        "scheduler": first_string(scheduler_name) or "search",
        "worker_limit": int(worker_limit),
        "queue_capacity": int(queue_capacity),
        "jobs_submitted": 0,
        "jobs_completed": 0,
        "jobs_failed": 0,
        "max_active_jobs": 0,
        "max_queue_depth": 0,
        "active_jobs": 0,
        "status": "running",
        "reason": structured_reason(
            "scheduler_running",
            category="scheduler",
        ),
    }
    if metrics_sink is not None:
        metrics_sink[scheduler_name] = metrics

    async def producer() -> None:
        for job in jobs:
            if not callable(job):
                raise TypeError("Search scheduler jobs must be async callables")
            await queue.put(job)
            metrics["jobs_submitted"] += 1
            metrics["max_queue_depth"] = max(
                int(metrics["max_queue_depth"]),
                queue.qsize(),
            )
        for _ in range(worker_limit):
            await queue.put(sentinel)

    async def worker() -> None:
        while True:
            job = await queue.get()
            try:
                if job is sentinel:
                    return
                metrics["active_jobs"] += 1
                metrics["max_active_jobs"] = max(
                    int(metrics["max_active_jobs"]),
                    int(metrics["active_jobs"]),
                )
                try:
                    result = await job()
                except asyncio.CancelledError:
                    if metrics["status"] == "running":
                        metrics["status"] = "cancelled"
                        metrics["reason"] = structured_reason(
                            "scheduler_cancelled",
                            category="scheduler",
                            retryable=True,
                        )
                    raise
                except Exception as exc:
                    metrics["jobs_failed"] += 1
                    metrics["status"] = "failed"
                    metrics["reason"] = structured_reason(
                        f"job_failed_{exc.__class__.__name__.casefold()}",
                        category="scheduler",
                        retryable=False,
                    )
                    raise
                else:
                    results.append(result)
                    metrics["jobs_completed"] += 1
                finally:
                    metrics["active_jobs"] -= 1
            finally:
                queue.task_done()

    producer_task = asyncio.create_task(
        producer(),
        name=f"laps-{scheduler_name}-producer",
    )
    worker_tasks = [
        asyncio.create_task(
            worker(),
            name=f"laps-{scheduler_name}-worker-{index + 1}",
        )
        for index in range(worker_limit)
    ]
    scheduler_tasks = [producer_task, *worker_tasks]
    try:
        await asyncio.gather(*scheduler_tasks)
    except BaseException as exc:
        for task in scheduler_tasks:
            if not task.done():
                task.cancel()
        await asyncio.gather(*scheduler_tasks, return_exceptions=True)
        if metrics["status"] == "running":
            cancelled = isinstance(exc, asyncio.CancelledError)
            metrics["status"] = "cancelled" if cancelled else "failed"
            metrics["reason"] = structured_reason(
                "scheduler_cancelled" if cancelled else f"producer_failed_{exc.__class__.__name__.casefold()}",
                category="scheduler",
                retryable=cancelled,
            )
        raise
    metrics["status"] = "complete"
    metrics["reason"] = structured_reason(
        "scheduler_complete",
        category="scheduler",
    )
    return results, metrics


def iter_literature_search_jobs(
    runtime: SearchRuntime,
    keywords: Iterable[str],
    page_size: int,
    selected_sources: set[str] | None,
) -> Iterable[Callable[[], Awaitable[tuple[str, str, list[LiteratureRecord]]]]]:
    """Plan each closure only when the bounded producer requests it."""

    for keyword_index, keyword in enumerate(keywords):
        for source_index, (source, url) in enumerate(literature_search_path_map.items()):
            if selected_sources and source not in selected_sources:
                continue
            policy = literature_source_auth_policy[source]
            adapter = LITERATURE_SOURCE_ADAPTERS[source]
            plan = build_access_plan(runtime.config, source, policy, keyword, is_patent=False)
            path = plan.route
            if runtime.state_store:
                runtime.state_store.invalidate_stale_runs(
                    "literature", keyword, source, runtime.config_fingerprint
                )
            pending_variants = tuple(
                variant
                for variant in effective_query_variants(adapter)
                if not runtime.state_store
                or not (
                    runtime.state_store.reusable_run(
                        "literature",
                        keyword,
                        source,
                        path,
                        runtime.config_fingerprint,
                        variant.variant_id,
                    )
                    or bool(
                        adapter.restricted_browser_runner
                        and runtime.state_store.reusable_run(
                            "literature",
                            keyword,
                            source,
                            "restricted_browser",
                            runtime.config_fingerprint,
                            variant.variant_id,
                        )
                    )
                )
            )
            if not pending_variants:
                continue

            async def run_one(
                source: str = source,
                url: str = url,
                keyword: str = keyword,
                keyword_index: int = keyword_index,
                source_index: int = source_index,
                plan: AccessPlan = plan,
                path: str = path,
                pending_variants: tuple[QueryVariant, ...] = pending_variants,
            ) -> tuple[str, str, list[LiteratureRecord]]:
                source_records: list[LiteratureRecord] = []
                for variant in pending_variants:
                    previous = (
                        runtime.state_store.get_run(
                            "literature",
                            keyword,
                            source,
                            path,
                            variant.variant_id,
                        )
                        if runtime.state_store is not None
                        else None
                    ) or {}
                    if previous.get("config_fingerprint") != runtime.config_fingerprint:
                        previous = {}
                    if runtime.state_store is not None:
                        runtime.state_store.mark_run(
                            "literature",
                            keyword,
                            source,
                            path,
                            runtime.config_fingerprint,
                            "running",
                            query_variant=variant.variant_id,
                            next_token=str(previous.get("next_token") or ""),
                            pages=int(previous.get("pages") or 0),
                            fetched=int(previous.get("fetched") or 0),
                            accepted=int(previous.get("accepted") or 0),
                            duplicates=int(previous.get("duplicates") or 0),
                            updated_records=int(previous.get("updated_records") or 0),
                            conflicting_records=int(previous.get("conflicting_records") or 0),
                            dropped=int(previous.get("dropped") or 0),
                            total_hint=previous.get("total_hint"),
                            page_signature=str(previous.get("page_signature") or ""),
                            reason="",
                        )
                    token = SEARCH_TASK_CONTEXT.set(
                        {
                            "record_type": "literature",
                            "keyword": keyword,
                            "keyword_index": keyword_index,
                            "source_index": source_index,
                            "path": path,
                            "checkpoint_path": path,
                            "query_variant": variant.variant_id,
                            "field_scope": variant.field_scope,
                            "query_text": variant.build_query(keyword),
                            "resume_url": first_string(previous.get("next_token")),
                            "cursor_token": first_string(previous.get("next_token")),
                            "config_fingerprint": runtime.config_fingerprint,
                        }
                    )
                    try:
                        attempt = coerce_source_attempt_result(
                            await search_literature_source(
                                runtime,
                                source,
                                url,
                                keyword,
                                keyword_index,
                                source_index,
                                page_size,
                            ),
                            path=path,
                            query_variant=variant.variant_id,
                        )
                        source_records.extend(attempt.records)
                        if runtime.state_store is not None:
                            initial_run = runtime.state_store.get_run(
                                "literature",
                                keyword,
                                source,
                                path,
                                variant.variant_id,
                            ) or {}
                            if (
                                int(initial_run.get("pages") or 0) == 0
                                and initial_run.get("status") == "running"
                            ):
                                detail = attempt.reason_detail()
                                runtime.state_store.mark_run(
                                    "literature",
                                    keyword,
                                    source,
                                    path,
                                    runtime.config_fingerprint,
                                    attempt.status,
                                    query_variant=variant.variant_id,
                                    reason=attempt.reason or plan.reason,
                                    reason_code=first_string(detail.get("reason_code")),
                                    category=first_string(detail.get("category")),
                                    retryable=bool(detail.get("retryable")),
                                    retry_at=first_string(detail.get("retry_at")),
                                )
                    finally:
                        SEARCH_TASK_CONTEXT.reset(token)
                return source, keyword, dedupe_literature_records(source_records)

            yield run_one


async def collect_literature(
    runtime: SearchRuntime,
    keywords: list[str],
    page_size: int,
    existing_index: LiteratureResumeIndex | None = None,
    selected_sources: set[str] | None = None,
    migration_stats: dict[str, int] | None = None,
) -> list[LiteratureRecord]:
    existing_index = existing_index or LiteratureResumeIndex(
        dois=frozenset(),
        dois_with_pdf_url=frozenset(),
        pdf_urls=frozenset(),
    )
    jobs = iter_literature_search_jobs(
        runtime,
        keywords,
        page_size,
        selected_sources,
    )
    records: list[LiteratureRecord] = []
    worker_limit, queue_capacity = search_scheduler_limits(runtime)
    task_results, _ = await run_bounded_search_jobs(
        jobs,
        scheduler_name="literature",
        worker_limit=worker_limit,
        queue_capacity=queue_capacity,
        metrics_sink=runtime.scheduler_metrics,
    )
    for source, keyword, task_records in task_results:
        for record in task_records:
            doi = normalize_doi(record.doi)
            pdf_url = normalize_literature_pdf_url(record.url)
            if doi and doi in existing_index.dois:
                if doi in existing_index.dois_with_pdf_url or not pdf_url:
                    continue
            elif not doi and pdf_url and pdf_url in existing_index.pdf_urls:
                continue
            records.append(record)
    return dedupe_literature_records(
        [
            *literature_records_from_state(runtime.state_store, migration_stats),
            *records,
        ]
    )


def iter_patent_search_jobs(
    runtime: SearchRuntime,
    keywords: Iterable[str],
    page_size: int,
    selected_sources: set[str] | None,
) -> Iterable[Callable[[], Awaitable[tuple[str, str, list[PatentRecord]]]]]:
    """Plan each patent closure only as bounded queue capacity becomes available."""

    for keyword_index, keyword in enumerate(keywords):
        for source_index, (source, url) in enumerate(patents_search_path_map.items()):
            if selected_sources and source not in selected_sources:
                continue
            policy = patent_source_auth_policy[source]
            adapter = PATENT_SOURCE_ADAPTERS[source]
            plan = build_access_plan(runtime.config, source, policy, keyword, is_patent=True)
            path = (
                "cost_api"
                if source == "Google BigQuery"
                else "xhr"
                if source == "Google Patents"
                else plan.route
            )
            if runtime.state_store:
                runtime.state_store.invalidate_stale_runs(
                    "patent", keyword, source, runtime.config_fingerprint
                )
            pending_variants = tuple(
                variant
                for variant in effective_query_variants(adapter)
                if not runtime.state_store
                or not runtime.state_store.reusable_run(
                    "patent",
                    keyword,
                    source,
                    path,
                    runtime.config_fingerprint,
                    variant.variant_id,
                )
            )
            if not pending_variants:
                continue

            async def run_one(
                source: str = source,
                url: str = url,
                keyword: str = keyword,
                keyword_index: int = keyword_index,
                source_index: int = source_index,
                plan: AccessPlan = plan,
                path: str = path,
                pending_variants: tuple[QueryVariant, ...] = pending_variants,
            ) -> tuple[str, str, list[PatentRecord]]:
                source_records: list[PatentRecord] = []
                for variant in pending_variants:
                    previous = (
                        runtime.state_store.get_run(
                            "patent",
                            keyword,
                            source,
                            path,
                            variant.variant_id,
                        )
                        if runtime.state_store is not None
                        else None
                    ) or {}
                    if previous.get("config_fingerprint") != runtime.config_fingerprint:
                        previous = {}
                    if runtime.state_store is not None:
                        runtime.state_store.mark_run(
                            "patent",
                            keyword,
                            source,
                            path,
                            runtime.config_fingerprint,
                            "running",
                            query_variant=variant.variant_id,
                            next_token=str(previous.get("next_token") or ""),
                            pages=int(previous.get("pages") or 0),
                            fetched=int(previous.get("fetched") or 0),
                            accepted=int(previous.get("accepted") or 0),
                            duplicates=int(previous.get("duplicates") or 0),
                            updated_records=int(previous.get("updated_records") or 0),
                            conflicting_records=int(previous.get("conflicting_records") or 0),
                            dropped=int(previous.get("dropped") or 0),
                            total_hint=previous.get("total_hint"),
                            page_signature=str(previous.get("page_signature") or ""),
                            reason="",
                        )
                    token = SEARCH_TASK_CONTEXT.set(
                        {
                            "record_type": "patent",
                            "keyword": keyword,
                            "keyword_index": keyword_index,
                            "source_index": source_index,
                            "path": path,
                            "checkpoint_path": path,
                            "query_variant": variant.variant_id,
                            "field_scope": variant.field_scope,
                            "query_text": variant.build_query(keyword),
                            "resume_url": first_string(previous.get("next_token")),
                            "cursor_token": first_string(previous.get("next_token")),
                            "config_fingerprint": runtime.config_fingerprint,
                        }
                    )
                    try:
                        attempt = coerce_source_attempt_result(
                            await search_patent_source(
                                runtime,
                                source,
                                url,
                                keyword,
                                keyword_index,
                                source_index,
                                page_size,
                            ),
                            path=path,
                            query_variant=variant.variant_id,
                        )
                        source_records.extend(attempt.records)
                        if runtime.state_store is not None:
                            current = runtime.state_store.get_run(
                                "patent",
                                keyword,
                                source,
                                path,
                                variant.variant_id,
                            ) or {}
                            if (
                                int(current.get("pages") or 0) == 0
                                and current.get("status") == "running"
                            ):
                                if attempt.status == "complete":
                                    runtime.persist_page(
                                        "patent",
                                        source,
                                        keyword,
                                        path,
                                        SearchPage(
                                            records=list(attempt.records),
                                            exhausted=True,
                                            page_signature=search_page_signature(attempt.records),
                                        ),
                                        page_number=1,
                                        keyword_index=keyword_index,
                                        source_index=source_index,
                                    )
                                else:
                                    detail = attempt.reason_detail()
                                    runtime.state_store.mark_run(
                                        "patent",
                                        keyword,
                                        source,
                                        path,
                                        runtime.config_fingerprint,
                                        attempt.status,
                                        query_variant=variant.variant_id,
                                        reason=attempt.reason or plan.reason,
                                        reason_code=first_string(detail.get("reason_code")),
                                        category=first_string(detail.get("category")),
                                        retryable=bool(detail.get("retryable")),
                                        retry_at=first_string(detail.get("retry_at")),
                                    )
                            if "query_field_unverified" in variant.field_scope:
                                current = runtime.state_store.get_run(
                                    "patent",
                                    keyword,
                                    source,
                                    path,
                                    variant.variant_id,
                                ) or current
                                runtime.state_store.mark_run(
                                    "patent",
                                    keyword,
                                    source,
                                    path,
                                    runtime.config_fingerprint,
                                    "incomplete",
                                    query_variant=variant.variant_id,
                                    next_token=str(current.get("next_token") or ""),
                                    pages=int(current.get("pages") or 0),
                                    fetched=int(current.get("fetched") or 0),
                                    accepted=int(current.get("accepted") or 0),
                                    duplicates=int(current.get("duplicates") or 0),
                                    updated_records=int(current.get("updated_records") or 0),
                                    conflicting_records=int(current.get("conflicting_records") or 0),
                                    dropped=int(current.get("dropped") or 0),
                                    total_hint=current.get("total_hint"),
                                    page_signature=str(current.get("page_signature") or ""),
                                    reason="query_field_unverified",
                                )
                    finally:
                        SEARCH_TASK_CONTEXT.reset(token)
                return source, keyword, dedupe_patent_records(source_records)

            yield run_one


async def collect_patents(
    runtime: SearchRuntime,
    keywords: list[str],
    page_size: int,
    existing_urls: set[str] | None = None,
    selected_sources: set[str] | None = None,
) -> list[PatentRecord]:
    existing_urls = {normalize_resume_url(url) for url in (existing_urls or set()) if normalize_resume_url(url)}
    jobs = iter_patent_search_jobs(
        runtime,
        keywords,
        page_size,
        selected_sources,
    )
    records: list[PatentRecord] = []
    worker_limit, queue_capacity = search_scheduler_limits(runtime)
    task_results, _ = await run_bounded_search_jobs(
        jobs,
        scheduler_name="patent",
        worker_limit=worker_limit,
        queue_capacity=queue_capacity,
        metrics_sink=runtime.scheduler_metrics,
    )
    for source, keyword, task_records in task_results:
        for record in task_records:
            url = normalize_resume_url(record.url)
            if url and url in existing_urls:
                continue
            records.append(record)
    return dedupe_patent_records([*patent_records_from_state(runtime.state_store), *records])


def grouped_source_events(events: list[SkippedSource] | list[DegradedSource] | list[BrowserDisabledSource]) -> list[dict[str, Any]]:
    grouped: dict[tuple[str, str, str, str], set[str]] = defaultdict(set)
    for event in events:
        grouped[
            (
                event.source,
                event.path,
                event.query_variant,
                safe_error_text(event.reason),
            )
        ].add(event.keyword or "*")
    return [
        {
            "source": source,
            "path": path,
            "query_variant": query_variant,
            "reason": reason,
            "keywords": sorted(keywords),
            "count": len(keywords),
        }
        for (source, path, query_variant, reason), keywords in sorted(grouped.items())
    ]


def print_event_group(title: str, events: list[SkippedSource] | list[DegradedSource] | list[BrowserDisabledSource]) -> None:
    print(f"{title}:")
    grouped = grouped_source_events(events)
    if not grouped:
        print("[]")
    else:
        print(json.dumps(grouped, ensure_ascii=False, indent=2))


def grouped_restricted_auth_events(events: list[RestrictedAuthSource]) -> list[dict[str, Any]]:
    grouped: dict[tuple[str, str, str, str, str, str], set[str]] = defaultdict(set)
    for event in events:
        grouped[(event.source, event.path, event.query_variant, event.mode, event.status, safe_error_text(event.reason))].add(event.keyword or "*")
    return [
        {"source": source, "path": path, "query_variant": query_variant, "mode": mode, "status": status, "reason": reason, "keywords": sorted(keywords), "count": len(keywords)}
        for (source, path, query_variant, mode, status, reason), keywords in sorted(grouped.items())
    ]


def print_restricted_auth_group(events: list[RestrictedAuthSource]) -> None:
    print("Restricted authentication sources:")
    grouped = grouped_restricted_auth_events(events)
    if not grouped:
        print("[]")
    else:
        print(json.dumps(grouped, ensure_ascii=False, indent=2))


def print_summary(
    literature_records: list[LiteratureRecord],
    patent_records: list[PatentRecord],
    literature_path: Path,
    patent_path: Path,
    skipped_sources: list[SkippedSource],
    degraded_sources: list[DegradedSource],
    browser_disabled_sources: list[BrowserDisabledSource],
    restricted_auth_sources: list[RestrictedAuthSource] | None = None,
    dropped_literature_records: list[LiteratureRecord] | None = None,
    dropped_patent_records: list[PatentRecord] | None = None,
    literature_url_migration_stats: dict[str, int] | None = None,
) -> None:
    lit_rows, pat_rows = records_to_dataframes(literature_records, patent_records)
    dropped_literature_records = dropped_literature_records or []
    dropped_patent_records = dropped_patent_records or []
    print(f"Literature result count: {len(literature_records)}")
    print(
        "Literature locator summary: "
        + json.dumps(
            literature_locator_summary(literature_records),
            ensure_ascii=False,
            sort_keys=True,
        )
    )
    print(
        "Literature records dropped for missing DOI and stable PDF URL: "
        f"{len(dropped_literature_records)}"
    )
    print(
        "Literature legacy non-PDF URLs cleared: "
        f"{int((literature_url_migration_stats or {}).get('legacy_non_pdf_urls_cleared') or 0)}"
    )
    print(f"Patent result count: {len(patent_records)}")
    print(
        "Patent records dropped for missing publication number and URL: "
        f"{len(dropped_patent_records)}"
    )
    print(f"Literature CSV: {literature_path}")
    print(f"Patent CSV: {patent_path}")
    print("Literature preview (first 20):")
    print(json.dumps(lit_rows[:20], ensure_ascii=False, indent=2))
    print("Patent preview (first 20):")
    print(json.dumps(pat_rows[:20], ensure_ascii=False, indent=2))
    if dropped_literature_records:
        print("Dropped literature without DOI or stable PDF URL:")
        print(json.dumps(dropped_literature_summary(dropped_literature_records), ensure_ascii=False, indent=2))
    if dropped_patent_records:
        print("Dropped patents without publication number or URL:")
        print(json.dumps(dropped_patent_summary(dropped_patent_records), ensure_ascii=False, indent=2))
    print_event_group("Degraded optional/API sources", degraded_sources)
    print_event_group("Browser fallback disabled sources", browser_disabled_sources)
    print_restricted_auth_group(restricted_auth_sources or [])
    print_event_group("Skipped/failed sources", skipped_sources)


def utc_now() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds")


def as_path(value: str | None) -> Path | None:
    return Path(value).expanduser().resolve() if value else None


def parse_search_args(argv: list[str]) -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Search literature and patent metadata by keyword list.")
    parser.add_argument("keywords", nargs="*", help="Search keywords. Comma-separated values are supported.")
    parser.add_argument("--keywords", dest="keywords_text", default="", help="Comma-separated keyword list.")
    parser.add_argument("--keywords-file", default="", help="UTF-8 text file with one or more comma-separated keywords per line.")
    parser.add_argument("--batch-name", default="", help="Batch directory name under metadata/pdf roots. Defaults to a keyword-derived name.")
    parser.add_argument("--flat-output", action="store_true", help="Use the legacy flat metadata root without a keyword batch directory.")
    parser.add_argument("--metadata-root", default="", help="Exact metadata batch root. Contains literature_metadata_list and patents_metadata_list.")
    parser.add_argument("--pdf-root", default="", help="Exact PDF batch root used when --download-after-search is enabled.")
    parser.add_argument("--page-size", type=int, default=None, help="Records requested per API/page. This is not a total result limit.")
    parser.add_argument("--results-per-source", type=int, default=None, help=argparse.SUPPRESS)
    parser.add_argument("--literature-only", action="store_true", help="Search only literature metadata.")
    parser.add_argument("--patents-only", action="store_true", help="Search only patent metadata.")
    parser.add_argument("--literature-source", action="append", default=[], help="Exact literature source to run. Can be repeated; default runs the full map.")
    parser.add_argument("--patent-source", action="append", default=[], help="Exact patent source to run. Can be repeated; default runs the full map.")
    parser.add_argument("--allow-cost-source", action="append", default=[], help="Explicitly allow a cost-bearing exact source such as Google BigQuery.")
    parser.add_argument("--refresh", action="store_true", help="Reset selected source completion checkpoints but preserve metadata.")
    parser.add_argument("--force", action="store_true", help="Ignore existing metadata for selected record types and search again.")
    parser.add_argument("--status", action="store_true", help="Print current metadata progress for the selected batch and exit.")
    parser.add_argument("--materialize-checkpoint", action="store_true", help="Rebuild CSV/report from the local SQLite checkpoint without network or browser access.")
    parser.add_argument("--materialize-every-pages", type=int, default=None, help="Incrementally materialize CSV after this many committed pages (default: 10).")
    parser.add_argument("--materialize-every-seconds", type=int, default=None, help="Incrementally materialize CSV after this many seconds with new pages (default: 60).")
    parser.add_argument("--no-incremental-materialize", action="store_true", help="Disable background CSV/progress materialization; final output is still written.")
    parser.add_argument("--channel-inventory", action="store_true", help="Print the read-only search source/adapter/path inventory and exit.")
    parser.add_argument("--prepare-runtime", action="store_true", help="Prepare local Python/Playwright runtime and exit before search work.")
    parser.add_argument("--env-command-timeout-seconds", type=int, default=None, help="Timeout for environment setup commands such as pip and Playwright install.")
    parser.add_argument("--env-lock-timeout-seconds", type=int, default=None, help="Timeout while waiting for another process to finish environment setup.")
    parser.add_argument("--download-after-search", action="store_true", help="Run the download script after metadata search succeeds.")
    parser.add_argument(
        "--download-on-partial",
        action="store_true",
        help="With --download-after-search, download available records after a partial search; the overall exit code remains 3.",
    )
    parser.add_argument("--download-limit", type=int, default=None, help="Optional record limit forwarded to the download script.")
    parser.add_argument("--download-dry-run", action="store_true", help="Forward --dry-run to the download script.")
    parser.add_argument("--download-force", action="store_true", help="Forward --force to the download script.")
    parser.add_argument("--download-headful", action="store_true", help="Forward --headful to the download script.")
    parser.add_argument("--download-extra-arg", action="append", default=[], help="Additional raw argument forwarded to the download script. Can be repeated.")
    args = parser.parse_args(argv)
    if args.literature_only and args.patents_only:
        parser.error("--literature-only and --patents-only cannot be used together")
    if args.results_per_source is not None:
        parser.error("--results-per-source was removed because production search has no total limit; use --page-size for request batching")
    if args.page_size is not None and args.page_size < 1:
        parser.error("--page-size must be positive")
    if args.download_limit is not None and args.download_limit < 1:
        parser.error("--download-limit must be positive")
    for attr in ("materialize_every_pages", "materialize_every_seconds"):
        if getattr(args, attr) is not None and getattr(args, attr) < 1:
            parser.error(f"--{attr.replace('_', '-')} must be positive")
    for attr in ("env_command_timeout_seconds", "env_lock_timeout_seconds"):
        if getattr(args, attr) is not None and getattr(args, attr) < 1:
            parser.error(f"--{attr.replace('_', '-')} must be positive")
    if args.batch_name and args.flat_output:
        parser.error("--batch-name cannot be used with --flat-output")
    if args.metadata_root and args.batch_name:
        parser.error("--metadata-root is an exact batch root; do not combine it with --batch-name")
    if args.materialize_checkpoint and (args.refresh or args.force):
        parser.error("--materialize-checkpoint cannot be combined with --refresh or --force")
    if args.materialize_checkpoint and (args.literature_source or args.patent_source or args.allow_cost_source):
        parser.error("--materialize-checkpoint exports stored state and cannot be combined with source filters or cost approval")
    return args


def apply_environment_timeout_args(args: argparse.Namespace) -> None:
    arg_env_map = {
        "env_command_timeout_seconds": "LAPS_ENV_COMMAND_TIMEOUT_SECONDS",
        "env_lock_timeout_seconds": "LAPS_ENV_LOCK_TIMEOUT_SECONDS",
    }
    for attr, env_name in arg_env_map.items():
        value = getattr(args, attr, None)
        if value is not None:
            os.environ[env_name] = str(value)


def resolve_keywords_from_args(args: argparse.Namespace, *, allow_prompt: bool) -> list[str]:
    groups: list[list[str]] = []
    if args.keywords_text:
        groups.append(parse_keywords(args.keywords_text))
    if args.keywords_file:
        groups.append(read_keywords_file(Path(args.keywords_file).expanduser()))
    if args.keywords:
        groups.append(parse_keywords(" ".join(args.keywords)))
    keywords = merge_keywords(*groups)
    if not keywords and allow_prompt:
        keywords = parse_keywords(input("请输入关键词，多个关键词可用中文逗号或英文逗号分隔: "))
    return keywords


def resolve_batch_name(args: argparse.Namespace, keywords: list[str]) -> str | None:
    if args.metadata_root or args.flat_output:
        return None
    if args.batch_name:
        return safe_batch_name(args.batch_name)
    if keywords:
        return batch_name_from_keywords(keywords)
    return None


def resolve_page_size(args: argparse.Namespace) -> int:
    if os.getenv("LAPS_RESULTS_PER_SOURCE", "").strip():
        raise ValueError("LAPS_RESULTS_PER_SOURCE was removed because production search has no total limit; use LAPS_SEARCH_PAGE_SIZE")
    raw = args.page_size if args.page_size is not None else os.getenv("LAPS_SEARCH_PAGE_SIZE", "100")
    try:
        value = int(raw)
    except (TypeError, ValueError) as exc:
        raise ValueError("LAPS_SEARCH_PAGE_SIZE/--page-size must be a positive integer") from exc
    if value < 1:
        raise ValueError("LAPS_SEARCH_PAGE_SIZE/--page-size must be positive")
    return value


def resolve_incremental_materialization(args: argparse.Namespace) -> tuple[int, int, bool]:
    raw_pages = (
        args.materialize_every_pages
        if args.materialize_every_pages is not None
        else os.getenv("LAPS_MATERIALIZE_EVERY_PAGES", "10")
    )
    raw_seconds = (
        args.materialize_every_seconds
        if args.materialize_every_seconds is not None
        else os.getenv("LAPS_MATERIALIZE_EVERY_SECONDS", "60")
    )
    try:
        pages = int(raw_pages)
        seconds = int(raw_seconds)
    except (TypeError, ValueError) as exc:
        raise ValueError(
            "Incremental materialization page/second settings must be positive integers"
        ) from exc
    if pages < 1 or seconds < 1:
        raise ValueError(
            "Incremental materialization page/second settings must be positive integers"
        )
    return pages, seconds, not args.no_incremental_materialize


def exact_source_selection(values: list[str], available: dict[str, str], label: str) -> set[str]:
    selected = {str(value).strip() for value in values if str(value).strip()}
    unknown = sorted(selected - set(available))
    if unknown:
        raise ValueError(f"Unknown {label} source(s): {', '.join(unknown)}")
    return selected


def source_adapter_inventory(
    config: SearchConfig,
    source_map: dict[str, str],
    policy_map: dict[str, SourceAuthPolicy],
    adapters: dict[str, SourceSearchAdapter],
    *,
    is_patent: bool,
) -> list[dict[str, Any]]:
    output: list[dict[str, Any]] = []
    registry_specs = {
        spec.display_name: spec
        for spec in (
            PATENT_SEARCH_SPECS if is_patent else LITERATURE_SEARCH_SPECS
        )
    }
    for order, source in enumerate(source_map, start=1):
        policy = policy_map[source]
        adapter = adapters.get(source)
        registry_spec = registry_specs.get(source)
        browser_path_declared = bool(
            adapter and BROWSER_ADAPTER_PATHS.intersection(adapter.paths)
        )
        dedicated_parser_registered = bool(
            adapter
            and adapter.parser_name
            and adapter.parser_name != "parse_generic_search_results"
        )
        plan = build_access_plan(config, source, policy, "*", is_patent=is_patent)
        auth_entries = (
            policy_auth_entries(source, policy)
            if policy.institutional_web_allowed
            else ()
        )
        site_personal_auth_capable = bool(
            policy.runtime_personal_credential_keys
            and adapter is not None
            and adapter.restricted_browser_runner is not None
        )
        output.append(
            {
                "order": order,
                "source": source,
                "record_type": "patent" if is_patent else "literature",
                "nominal_endpoint": (
                    registry_spec.nominal_endpoint if registry_spec else ""
                ),
                "executed_endpoint": (
                    registry_spec.endpoint if registry_spec else source_map[source]
                ),
                "actual_adapter": (
                    registry_spec.actual_adapter if registry_spec else ""
                ),
                "primary_auth_scope": (
                    registry_spec.auth_scope if registry_spec else "unknown"
                ),
                "fallback_resolver": (
                    registry_spec.fallback_resolver if registry_spec else ""
                ),
                "fallback_auth_scope": (
                    registry_spec.fallback_auth_scope if registry_spec else ""
                ),
                "adapter_registered": adapter is not None,
                "parser": adapter.parser_name if adapter else "",
                "paths": list(adapter.paths) if adapter else [],
                "pagination": adapter.pagination if adapter else "",
                "query_variants": [
                    {
                        "variant_id": variant.variant_id,
                        "field_scope": variant.field_scope,
                        "coverage_required": variant.coverage_required,
                        "subsumes": list(variant.subsumes),
                    }
                    for variant in effective_query_variants(adapter)
                ]
                if adapter
                else [],
                "coverage_scope": (
                    "source_visible"
                    if source == "Google Scholar"
                    else "query_field_unverified"
                    if adapter
                    and any(
                        "query_field_unverified" in variant.field_scope
                        for variant in effective_query_variants(adapter)
                    )
                    else "source_queryable"
                ),
                "browser_path_declared": browser_path_declared,
                "browser_escalation_controller": (
                    adapter.browser_escalation_controller
                    if browser_path_declared and adapter
                    else ""
                ),
                "browser_escalation_policy": (
                    browser_escalation_policy_contract()
                    if browser_path_declared
                    else {}
                ),
                "control_authorization": (
                    control_authorization_contract()
                    if browser_path_declared
                    else {}
                ),
                "dedicated_parser_registered": dedicated_parser_registered,
                "access_route": "blocked" if plan.route in {"skip", "browser_disabled", "unimplemented"} else plan.route,
                "access_reason": plan.reason,
                "missing_keys": list(plan.missing_keys),
                "credential_independent_fixture_required": bool(plan.missing_keys),
                "institution_auth_capable": bool(
                    policy.institutional_web_allowed
                    and adapter is not None
                    and adapter.restricted_browser_runner is not None
                ),
                "auth_state_scope": source_auth_state_scope(source, policy)
                if policy.institutional_web_allowed or site_personal_auth_capable
                else "",
                "auth_entry_url": policy.auth_entry_url or policy.web_search_url
                if policy.institutional_web_allowed
                else "",
                "auth_entries": [
                    {"id": entry.entry_id, "mode": entry.mode}
                    for entry in auth_entries
                ]
                if policy.institutional_web_allowed
                else [],
                "restricted_parser_registered": bool(adapter and adapter.restricted_browser_runner),
                "site_personal_auth_capable": site_personal_auth_capable,
                "site_personal_auth_scope": (
                    source_auth_state_scope(source, policy)
                    if site_personal_auth_capable
                    else ""
                ),
                "site_personal_credentials_configured": bool(
                    site_personal_auth_capable
                    and all(source_personal_credentials(config, policy))
                ),
            }
        )
    return output


def print_search_channel_inventory() -> None:
    validate_source_policies()
    load_project_dotenv_into_env()
    load_api_user_config_into_env()
    config = validate_config(load_config())
    literature = source_adapter_inventory(
        config,
        literature_search_path_map,
        literature_source_auth_policy,
        LITERATURE_SOURCE_ADAPTERS,
        is_patent=False,
    )
    patents = source_adapter_inventory(
        config,
        patents_search_path_map,
        patent_source_auth_policy,
        PATENT_SOURCE_ADAPTERS,
        is_patent=True,
    )
    literature_auth_sources = [row for row in literature if row["institution_auth_capable"]]
    patent_auth_sources = [row for row in patents if row["institution_auth_capable"]]
    patent_site_personal_auth_sources = [
        row for row in patents if row["site_personal_auth_capable"]
    ]
    json_print(
        {
            "literature": literature,
            "patents": patents,
            "literature_count": len(literature),
            "patent_count": len(patents),
            "literature_institution_auth_source_count": len(literature_auth_sources),
            "literature_institution_auth_scope_count": len(
                {row["auth_state_scope"] for row in literature_auth_sources}
            ),
            "patent_institution_auth_source_count": len(patent_auth_sources),
            "patent_institution_auth_scope_count": len(
                {row["auth_state_scope"] for row in patent_auth_sources}
            ),
            "patent_site_personal_auth_source_count": len(
                patent_site_personal_auth_sources
            ),
            "patent_site_personal_auth_scope_count": len(
                {
                    row["site_personal_auth_scope"]
                    for row in patent_site_personal_auth_sources
                }
            ),
            "missing_literature_adapters": sorted(set(literature_search_path_map) - set(LITERATURE_SOURCE_ADAPTERS)),
            "missing_patent_adapters": sorted(set(patents_search_path_map) - set(PATENT_SOURCE_ADAPTERS)),
            "generic_parser_channels": sorted(
                adapter.source
                for adapter in [*LITERATURE_SOURCE_ADAPTERS.values(), *PATENT_SOURCE_ADAPTERS.values()]
                if adapter.parser_name == "parse_generic_search_results"
            ),
        }
    )


def read_search_state_summary(batch_name: str | None, metadata_root: Path | None) -> list[dict[str, Any]]:
    path = search_state_path(batch_name, metadata_root)
    if not path.exists():
        return []
    with SearchStateStore(path) as store:
        return store.summary()


def print_search_status(batch_name: str | None, metadata_root: Path | None) -> None:
    literature_path, patent_path = output_paths(batch_name=batch_name, metadata_root=metadata_root)
    lit_rows = read_csv_rows(literature_path)
    pat_rows = read_csv_rows(patent_path)
    missing_doi_rows = [row for row in lit_rows if not normalize_doi(row.get("doi"))]
    missing_locator_rows = [
        row
        for row in lit_rows
        if not normalize_doi(row.get("doi"))
        and not stable_literature_pdf_url(row.get("url"))
    ]
    pdf_url_rows = [
        row for row in lit_rows if stable_literature_pdf_url(row.get("url"))
    ]
    missing_url_rows = [row for row in pat_rows if not normalize_resume_url(row.get("url"))]
    missing_patent_locator_rows = [
        row
        for row in pat_rows
        if not normalize_publication_number(row.get("publication_number"))
        and not normalize_resume_url(row.get("url"))
    ]
    v2_literature_path, v2_patent_path, manifest_path, canonical_database_path = (
        canonical_v2_paths(batch_name, metadata_root)
    )
    payload = {
        "batch_name": batch_name or "",
        "metadata_root": str(metadata_batch_root(batch_name, metadata_root).resolve()),
        "literature_csv": str(literature_path.resolve()),
        "patents_csv": str(patent_path.resolve()),
        "literature_rows": len(lit_rows),
        "literature_missing_doi_rows": len(missing_doi_rows),
        "literature_pdf_url_rows": len(pdf_url_rows),
        "literature_stable_pdf_url_rows": len(pdf_url_rows),
        "literature_missing_doi_and_stable_pdf_url_rows": len(
            missing_locator_rows
        ),
        "literature_missing_doi_and_pdf_url_rows": len(missing_locator_rows),
        "patent_rows": len(pat_rows),
        "patent_missing_url_rows": len(missing_url_rows),
        "patent_missing_publication_number_and_url_rows": len(
            missing_patent_locator_rows
        ),
        "literature_keywords": sorted({row.get("keyword", "") for row in lit_rows if row.get("keyword")}),
        "patent_keywords": sorted({row.get("keyword", "") for row in pat_rows if row.get("keyword")}),
        "literature_sources": sorted({row.get("source", "") for row in lit_rows if row.get("source")}),
        "patent_sources": sorted({row.get("source", "") for row in pat_rows if row.get("source")}),
        "search_report": str(search_status_path(batch_name, metadata_root).resolve()),
        "search_progress": str(search_progress_path(batch_name, metadata_root).resolve()),
        "search_state": str(search_state_path(batch_name, metadata_root).resolve()),
        "literature_records_v2": str(v2_literature_path.resolve()),
        "patent_records_v2": str(v2_patent_path.resolve()),
        "handoff_manifest_v2": str(manifest_path.resolve()),
        "canonical_database_v2": str(canonical_database_path.resolve()),
        "v2_materialized": all(
            path.exists()
            for path in (
                v2_literature_path,
                v2_patent_path,
                manifest_path,
                canonical_database_path,
            )
        ),
        "source_runs": [
            source_run_report_payload(run)
            for run in read_search_state_summary(batch_name, metadata_root)
        ],
    }
    json_print(sanitize_search_report_value(payload))


def selected_search_source_runs(
    source_runs: list[dict[str, Any]],
    *,
    keywords: list[str],
    include_literature: bool,
    include_patents: bool,
    literature_sources: set[str] | None = None,
    patent_sources: set[str] | None = None,
    config_fingerprint: str = "",
) -> list[dict[str, Any]]:
    selected_keywords = set(keywords)
    selected_literature_sources = literature_sources or set(
        literature_search_path_map
    )
    selected_patent_sources = patent_sources or set(patents_search_path_map)
    selected: list[dict[str, Any]] = []
    for run in source_runs:
        record_type = first_string(run.get("record_type"))
        source = first_string(run.get("source"))
        keyword = first_string(run.get("keyword"))
        if selected_keywords and keyword not in selected_keywords:
            continue
        if config_fingerprint and first_string(
            run.get("config_fingerprint")
        ) != config_fingerprint:
            continue
        if record_type == "literature":
            if not include_literature or source not in selected_literature_sources:
                continue
        elif record_type == "patent":
            if not include_patents or source not in selected_patent_sources:
                continue
        else:
            continue
        selected.append(run)
    return selected


SearchSourceKey = tuple[str, str, str]


def expected_search_source_keys(
    *,
    keywords: Iterable[str],
    include_literature: bool,
    include_patents: bool,
    literature_sources: Iterable[str] | None = None,
    patent_sources: Iterable[str] | None = None,
) -> set[SearchSourceKey]:
    """Return the keyword/source coverage that a completed request must own.

    Paths and query variants are adapter-internal and may be selected
    dynamically, but every requested keyword/source pair must create at least
    one source-run row.  This catches lazy-producer interruption before a job
    was registered at all.
    """

    normalized_keywords = {
        first_string(keyword) for keyword in keywords if first_string(keyword)
    }
    expected: set[SearchSourceKey] = set()
    if include_literature:
        sources = literature_sources or literature_search_path_map.keys()
        expected.update(
            ("literature", keyword, source)
            for keyword in normalized_keywords
            for source in sources
        )
    if include_patents:
        sources = patent_sources or patents_search_path_map.keys()
        expected.update(
            ("patent", keyword, source)
            for keyword in normalized_keywords
            for source in sources
        )
    return expected


def missing_expected_source_runs(
    source_runs: Iterable[Mapping[str, Any]],
    expected_source_keys: Iterable[SearchSourceKey] | None,
) -> list[SearchSourceKey]:
    if expected_source_keys is None:
        return []
    observed = {
        (
            first_string(run.get("record_type")),
            first_string(run.get("keyword")),
            first_string(run.get("source")),
        )
        for run in source_runs
    }
    return sorted(set(expected_source_keys) - observed)


def search_completion_status(
    source_runs: list[dict[str, Any]],
    expected_source_keys: Iterable[SearchSourceKey] | None = None,
) -> str:
    statuses = [first_string(run.get("status")) for run in source_runs]
    statuses = [status for status in statuses if status]
    if missing_expected_source_runs(source_runs, expected_source_keys):
        return "partial"
    if not statuses:
        return "failed"
    if all(status == "complete" for status in statuses):
        return "complete"
    # Provider/adapter exhaustion is a business-level partial result even when
    # every selected source failed.  ``failed`` is reserved for fatal program,
    # state, I/O, or contract errors handled by the CLI boundary.
    return "partial"


def search_completion_exit_code(status: str) -> int:
    return {"complete": 0, "partial": 3, "failed": 1}.get(status, 1)


def should_run_download_after_search(
    args: argparse.Namespace,
    completion_status: str,
) -> bool:
    return bool(
        args.download_after_search
        and (
            completion_status == "complete"
            or (
                completion_status == "partial"
                and bool(getattr(args, "download_on_partial", False))
            )
        )
    )


_SEARCH_REPORT_SENSITIVE_QUERY_KEYS = frozenset(
    {
        "access_token",
        "api_key",
        "apikey",
        "authorization",
        "client_secret",
        "code",
        "continuation_token",
        "cookie",
        "cursor",
        "key",
        "oauth_token",
        "page_token",
        "password",
        "refresh_token",
        "secret",
        "session",
        "sig",
        "signature",
        "state",
        "token",
        "x-amz-credential",
        "x-amz-security-token",
        "x-amz-signature",
    }
)


def sanitize_search_url_for_output(value: str) -> str:
    try:
        parsed = urllib.parse.urlsplit(value)
    except ValueError:
        return value
    if parsed.scheme.casefold() not in {"http", "https"} or not parsed.netloc:
        return value
    netloc = parsed.netloc
    if "@" in netloc:
        netloc = "***@" + netloc.rsplit("@", 1)[-1]
    pairs = urllib.parse.parse_qsl(parsed.query, keep_blank_values=True)
    query = urllib.parse.urlencode(
        [
            (
                key,
                "***"
                if key.casefold() in _SEARCH_REPORT_SENSITIVE_QUERY_KEYS
                or "cursor" in key.casefold()
                or key.casefold().endswith("token")
                else item,
            )
            for key, item in pairs
        ],
        doseq=True,
        safe="*",
    )
    return urllib.parse.urlunsplit(
        (parsed.scheme, netloc, parsed.path, query, "")
    )


def sanitize_search_text_for_output(value: Any) -> str:
    text = "" if value is None else str(value)
    return re.sub(
        r"https?://[^\s\"'<>]+",
        lambda match: sanitize_search_url_for_output(match.group(0)),
        text,
        flags=re.I,
    )


def sanitize_search_report_value(value: Any, field_name: str = "") -> Any:
    if isinstance(value, Mapping):
        return {
            str(key): sanitize_search_report_value(item, str(key))
            for key, item in value.items()
        }
    if isinstance(value, (list, tuple, set)):
        return [sanitize_search_report_value(item, field_name) for item in value]
    if value is None or isinstance(value, (int, float, bool)):
        return value
    text = str(value)
    normalized_name = field_name.casefold().replace("-", "_")
    if "cursor" in normalized_name or normalized_name in {
        "next_token",
        "page_token",
        "continuation_token",
    }:
        return hashlib.sha256(text.encode("utf-8")).hexdigest()[:16] if text else ""
    if any(
        token in normalized_name
        for token in ("password", "secret", "api_key", "authorization", "cookie")
    ):
        return "***" if text else ""
    return sanitize_search_text_for_output(text)


def source_run_report_payload(run: Mapping[str, Any]) -> dict[str, Any]:
    payload = dict(run)
    inferred = source_reason_detail(first_string(run.get("reason")))
    reason_code = first_string(run.get("reason_code")) or first_string(
        inferred.get("reason_code")
    )
    has_structured_reason = bool(first_string(run.get("reason_code")))
    category = (
        first_string(run.get("category"))
        if has_structured_reason
        else first_string(inferred.get("category"))
    )
    payload["reason_detail"] = structured_reason(
        reason_code or "unspecified",
        category=category or "source_run",
        retryable=(
            bool(run.get("retryable"))
            if has_structured_reason
            else bool(inferred.get("retryable"))
        ),
        retry_at=first_string(run.get("retry_at"))
        or first_string(inferred.get("retry_at")),
    )
    return sanitize_search_report_value(payload)


def write_search_report(
    batch_name: str | None,
    metadata_root: Path | None,
    pdf_root: Path | None,
    keywords: list[str],
    literature_records: list[LiteratureRecord],
    patent_records: list[PatentRecord],
    skipped_sources: list[SkippedSource],
    degraded_sources: list[DegradedSource],
    browser_disabled_sources: list[BrowserDisabledSource],
    restricted_auth_sources: list[RestrictedAuthSource],
    dropped_literature_records: list[LiteratureRecord],
    dropped_patent_records: list[PatentRecord],
    mode: str,
    source_runs: list[dict[str, Any]] | None = None,
    literature_url_migration_stats: dict[str, int] | None = None,
    completion_status: str | None = None,
    v2_handoff: dict[str, Any] | None = None,
    scheduler_metrics: Mapping[str, Mapping[str, Any]] | None = None,
    doi_cache_summary: Mapping[str, Any] | None = None,
    doi_cache_runtime_metrics: Mapping[str, int] | None = None,
    expected_source_keys: Iterable[SearchSourceKey] | None = None,
) -> Path:
    literature_path, patent_path = output_paths(batch_name=batch_name, metadata_root=metadata_root)
    report_path = search_status_path(batch_name, metadata_root)
    report_path.parent.mkdir(parents=True, exist_ok=True)
    effective_source_runs = source_runs or []
    expected_key_set = (
        set(expected_source_keys) if expected_source_keys is not None else None
    )
    effective_completion_status = completion_status or search_completion_status(
        effective_source_runs,
        expected_key_set,
    )
    missing_source_runs = missing_expected_source_runs(
        effective_source_runs,
        expected_key_set,
    )
    status_counts = Counter(
        first_string(run.get("status")) or "unknown"
        for run in effective_source_runs
    )
    patent_drop_summary = patent_missing_url_report_summary(
        dropped_patent_records,
        effective_source_runs,
    )
    payload = {
        "ok": effective_completion_status == "complete",
        "status": effective_completion_status,
        "created_at": utc_now(),
        "batch_name": batch_name or "",
        "mode": mode,
        "keywords": keywords,
        "metadata_root": str(metadata_batch_root(batch_name, metadata_root).resolve()),
        "pdf_root": str(pdf_batch_root(batch_name, pdf_root).resolve()),
        "literature_csv": str(literature_path.resolve()),
        "patents_csv": str(patent_path.resolve()),
        "literature_count": len(literature_records),
        "literature_locator_summary": literature_locator_summary(
            literature_records
        ),
        "literature_missing_doi_and_stable_pdf_url_dropped": dropped_literature_summary(
            dropped_literature_records
        ),
        "literature_missing_doi_and_pdf_url_dropped": {
            **dropped_literature_summary(dropped_literature_records),
            "deprecated": True,
            "note": "Compatibility alias; URL-only records require a stable PDF URL.",
        },
        "literature_missing_doi_dropped": {
            **dropped_literature_summary(dropped_literature_records),
            "deprecated": True,
            "note": "URL-only stable PDF records are accepted; this compatibility field counts records missing both DOI and stable PDF URL.",
        },
        "literature_legacy_non_pdf_urls_cleared": int(
            (literature_url_migration_stats or {}).get(
                "legacy_non_pdf_urls_cleared"
            )
            or 0
        ),
        "patent_count": len(patent_records),
        "patent_missing_publication_number_and_url_dropped": patent_drop_summary,
        "patent_missing_url_dropped": {
            **patent_drop_summary,
            "deprecated": True,
            "note": "Patent records with either a normalized publication number or a URL are retained.",
        },
        "literature_sources": sorted({record.source for record in literature_records if record.source}),
        "patent_sources": sorted({record.source for record in patent_records if record.source}),
        "skipped_sources": grouped_source_events(skipped_sources),
        "degraded_sources": grouped_source_events(degraded_sources),
        "browser_disabled_sources": grouped_source_events(browser_disabled_sources),
        "restricted_auth_sources": grouped_restricted_auth_events(restricted_auth_sources),
        "source_run_status_counts": dict(sorted(status_counts.items())),
        "source_runs": [
            source_run_report_payload(run) for run in effective_source_runs
        ],
        "expected_source_run_count": (
            len(expected_key_set) if expected_key_set is not None else None
        ),
        "missing_source_runs": [
            {
                "record_type": record_type,
                "keyword": keyword,
                "source": source,
                "reason_detail": structured_reason(
                    "source_run_missing",
                    category="scheduler_recovery",
                    retryable=True,
                ),
            }
            for record_type, keyword, source in missing_source_runs
        ],
        "v2_handoff": v2_handoff or {},
        "scheduler": {
            name: dict(value)
            for name, value in sorted((scheduler_metrics or {}).items())
        },
        "doi_enrichment_cache": {
            **dict(doi_cache_summary or {}),
            "runtime_events": [
                {
                    "event": name,
                    "count": int(count),
                    "reason": structured_reason(
                        name,
                        category="doi_enrichment_cache",
                        retryable=name in {
                            "transient_not_cached",
                            "indeterminate_not_cached",
                        },
                    ),
                }
                for name, count in sorted(
                    (doi_cache_runtime_metrics or {}).items()
                )
            ],
        },
        "query_profiles": {
            "literature": [
                {
                    "source": source,
                    "coverage_scope": (
                        "source_visible" if source == "Google Scholar" else "source_queryable"
                    ),
                    "variants": [
                        {
                            "variant_id": variant.variant_id,
                            "field_scope": variant.field_scope,
                        }
                        for variant in effective_query_variants(adapter)
                    ],
                }
                for source, adapter in LITERATURE_SOURCE_ADAPTERS.items()
            ],
            "patents": [
                {
                    "source": source,
                    "coverage_scope": (
                        "query_field_unverified"
                        if any(
                            "query_field_unverified" in variant.field_scope
                            for variant in effective_query_variants(adapter)
                        )
                        else "source_queryable"
                    ),
                    "variants": [
                        {
                            "variant_id": variant.variant_id,
                            "field_scope": variant.field_scope,
                        }
                        for variant in effective_query_variants(adapter)
                    ],
                }
                for source, adapter in PATENT_SOURCE_ADAPTERS.items()
            ],
        },
    }
    safe_payload = sanitize_search_report_value(payload)
    written, reason = write_json_atomic(report_path, safe_payload)
    if not written:
        raise OSError(f"search_report_atomic_write_failed:{reason}")
    return report_path


def run_download_after_search(args: argparse.Namespace, batch_name: str | None, metadata_root: Path | None, pdf_root: Path | None) -> int:
    command = [sys.executable, str(DOWNLOAD_SCRIPT_PATH), "--metadata-root", str(metadata_batch_root(batch_name, metadata_root)), "--pdf-root", str(pdf_batch_root(batch_name, pdf_root))]
    if args.literature_only:
        command.append("--literature-only")
    if args.patents_only:
        command.append("--patents-only")
    if args.download_limit is not None:
        command.extend(["--limit", str(args.download_limit)])
    if args.download_dry_run:
        command.append("--dry-run")
    if args.download_force:
        command.append("--force")
    if args.download_headful:
        command.append("--headful")
    command.extend(args.download_extra_arg or [])
    print("Running download script:")
    print(" ".join(command))
    completed = subprocess.run(command)
    return int(completed.returncode)


def write_search_fatal_report(
    *,
    batch_name: str | None,
    metadata_root: Path | None,
    pdf_root: Path | None,
    stage: str,
    exc: BaseException,
    keywords: Iterable[str] = (),
    mode: str = "search",
) -> Path:
    """Atomically replace any stale search success report after a fatal error."""

    report_path = search_status_path(batch_name, metadata_root)
    reason_code = f"fatal_{exc.__class__.__name__.casefold()}"
    payload = sanitize_search_report_value(
        {
            "ok": False,
            "status": "failed",
            "created_at": utc_now(),
            "batch_name": batch_name or "",
            "mode": mode,
            "keywords": list(keywords),
            "failure_stage": first_string(stage) or "unknown",
            "reason_code": reason_code,
            "reason_detail": structured_reason(
                reason_code,
                category="fatal",
                retryable=False,
            ),
            "error_type": exc.__class__.__name__,
            "message": safe_error_text(str(exc))[:1000],
            "metadata_root": str(
                metadata_batch_root(batch_name, metadata_root).resolve()
            ),
            "pdf_root": str(pdf_batch_root(batch_name, pdf_root).resolve()),
            "registry_version": REGISTRY_VERSION,
            "registry_schema_version": REGISTRY_SCHEMA_VERSION,
            "canonical_schema_version": CANONICAL_SCHEMA_VERSION,
        }
    )
    written, reason = write_json_atomic(report_path, payload)
    if not written:
        raise OSError(f"search_fatal_report_atomic_write_failed:{reason}")
    return report_path


def download_run_report_path(
    batch_name: str | None,
    pdf_root: Path | None,
) -> Path:
    return pdf_batch_root(batch_name, pdf_root) / "outputs" / "download_run_report.json"


def read_download_run_report_summary(path: Path) -> dict[str, Any]:
    try:
        payload = json.loads(path.read_text(encoding="utf-8-sig"))
    except (OSError, UnicodeError, json.JSONDecodeError) as exc:
        return {
            "present": path.is_file(),
            "valid": False,
            "path": str(path.resolve()),
            "error": safe_error_text(f"{exc.__class__.__name__}: {exc}"),
        }
    if not isinstance(payload, Mapping):
        return {
            "present": True,
            "valid": False,
            "path": str(path.resolve()),
            "error": "download_report_not_object",
        }
    status = first_string(payload.get("status")).casefold()
    ok_value = bool(payload.get("ok"))
    valid = status in {"complete", "partial", "failed"} and ok_value == (
        status == "complete"
    )
    return sanitize_search_report_value(
        {
            "present": True,
            "valid": valid,
            "path": str(path.resolve()),
            "run_id": first_string(payload.get("run_id")),
            "status": status,
            "ok": ok_value,
            "completion_scope": first_string(payload.get("completion_scope")),
            "error": "" if valid else "download_report_status_contract_invalid",
        }
    )


def combined_workflow_outcome(
    search_status: str,
    *,
    download_executed: bool,
    download_exit_code: int | None = None,
    download_report_valid: bool = True,
    download_report_status: str = "",
) -> tuple[str, int]:
    """Aggregate search/download while preserving fatal/config exit priority."""

    normalized_search = first_string(search_status).casefold()
    if normalized_search == "failed":
        return "failed", 1
    if not download_executed:
        return (
            ("complete", 0)
            if normalized_search == "complete"
            else ("partial", 3)
        )
    exit_code = int(download_exit_code if download_exit_code is not None else 1)
    if exit_code == 2:
        return "failed", 2
    if exit_code == 1 or exit_code not in {0, 3}:
        return "failed", 1
    if not download_report_valid:
        return "failed", 1
    expected_download_status = "complete" if exit_code == 0 else "partial"
    if first_string(download_report_status).casefold() != expected_download_status:
        return "failed", 1
    if normalized_search == "partial" or exit_code == 3:
        return "partial", 3
    return "complete", 0


def write_combined_workflow_report(
    *,
    batch_name: str | None,
    metadata_root: Path | None,
    pdf_root: Path | None,
    search_status: str,
    download_requested: bool,
    download_executed: bool,
    download_exit_code: int | None = None,
) -> tuple[Path, str, int]:
    download_path = download_run_report_path(batch_name, pdf_root)
    download_summary = (
        read_download_run_report_summary(download_path)
        if download_executed
        else {
            "present": download_path.is_file(),
            "valid": False,
            "path": str(download_path.resolve()),
            "status": "not_run",
            "ok": False,
            "reason_code": "search_not_complete",
        }
    )
    overall_status, overall_exit = combined_workflow_outcome(
        search_status,
        download_executed=download_executed,
        download_exit_code=download_exit_code,
        download_report_valid=bool(download_summary.get("valid")),
        download_report_status=first_string(download_summary.get("status")),
    )
    report_path = workflow_status_path(batch_name, metadata_root)
    payload = sanitize_search_report_value(
        {
            "schema": "laps_search_download_workflow_v1",
            "created_at": utc_now(),
            "status": overall_status,
            "ok": overall_status == "complete",
            "exit_code": overall_exit,
            "search": {
                "status": search_status,
                "ok": search_status == "complete",
                "report_path": str(search_status_path(batch_name, metadata_root).resolve()),
            },
            "download": {
                "requested": download_requested,
                "executed": download_executed,
                "exit_code": download_exit_code,
                **download_summary,
            },
        }
    )
    written, reason = write_json_atomic(report_path, payload)
    if not written:
        raise OSError(f"workflow_report_atomic_write_failed:{reason}")
    return report_path, overall_status, overall_exit


def materialize_search_checkpoint(
    args: argparse.Namespace,
    batch_name: str | None,
    metadata_root: Path | None,
    pdf_root: Path | None,
    keywords: list[str],
) -> int:
    state_path = search_state_path(batch_name, metadata_root)
    if not state_path.exists():
        print(f"Search checkpoint does not exist: {state_path.resolve()}", file=sys.stderr)
        return 2
    literature_path, patent_path = output_paths(batch_name=batch_name, metadata_root=metadata_root)
    literature_url_migration_stats: dict[str, int] = {}
    with SearchStateStore(state_path) as state_store:
        effective_keywords = keywords or state_store.keywords()
        literature_candidates = (
            read_literature_records(
                literature_path,
                migration_stats=literature_url_migration_stats,
            )
            if args.patents_only
            else literature_records_from_state(
                state_store,
                migration_stats=literature_url_migration_stats,
            )
        )
        patent_candidates = (
            read_patent_records(patent_path)
            if args.literature_only
            else patent_records_from_state(state_store)
        )
        source_runs = selected_search_source_runs(
            state_store.summary(),
            keywords=effective_keywords,
            include_literature=not args.patents_only,
            include_patents=not args.literature_only,
        )
        persisted_expected_source_keys = state_store.requested_source_keys(
            keywords=effective_keywords,
            include_literature=not args.patents_only,
            include_patents=not args.literature_only,
        )
        canonical_state_records = canonical_records_from_state_store(state_store)
        doi_cache_summary = state_store.doi_enrichment_cache_summary()
    observed_source_keys: set[SearchSourceKey] = {
        (
            first_string(run.get("record_type")),
            first_string(run.get("keyword")),
            first_string(run.get("source")),
        )
        for run in source_runs
        if first_string(run.get("record_type"))
        and first_string(run.get("keyword"))
        and first_string(run.get("source"))
    }
    # New runs persist their requested provider scope before any network I/O.
    # Legacy checkpoints cannot prove which absent providers were requested,
    # so their only truthful fallback is the source-run scope they do contain.
    planned_pairs = {
        (record_type, keyword)
        for record_type, keyword, _ in persisted_expected_source_keys
    }
    expected_source_keys = persisted_expected_source_keys | {
        key
        for key in observed_source_keys
        if (key[0], key[1]) not in planned_pairs
    }
    completion_status = search_completion_status(
        source_runs,
        expected_source_keys,
    )
    literature_with_locator, dropped_literature_records = (
        split_literature_records_by_required_locator(literature_candidates)
    )
    patents_with_url, dropped_patent_records = split_patent_records_by_required_url(patent_candidates)
    literature_records = dedupe_literature_records(literature_with_locator)
    patent_records = dedupe_patent_records(patents_with_url)
    literature_path, patent_path = write_outputs(
        literature_records,
        patent_records,
        batch_name=batch_name,
        metadata_root=metadata_root,
    )
    mode = (
        "checkpoint_materialize_literature"
        if args.literature_only
        else "checkpoint_materialize_patents"
        if args.patents_only
        else "checkpoint_materialize_all"
    )
    try:
        v2_handoff = materialize_v2_handoff(
            [
                *canonical_state_records,
                *(
                    canonical_record_from_search_record(record)
                    for record in literature_candidates
                ),
                *(
                    canonical_record_from_search_record(record)
                    for record in patent_candidates
                ),
            ],
            batch_name=batch_name,
            metadata_root=metadata_root,
            search_status=completion_status,
            legacy_literature_count=len(literature_records),
            legacy_patent_count=len(patent_records),
        )
    except Exception as exc:
        write_search_fatal_report(
            batch_name=batch_name,
            metadata_root=metadata_root,
            pdf_root=pdf_root,
            stage="canonical_v2_materialization",
            exc=exc,
            keywords=effective_keywords,
            mode=mode,
        )
        print(
            f"Canonical v2 materialization failed: {safe_error_text(str(exc))}",
            file=sys.stderr,
        )
        return 1
    report_path = write_search_report(
        batch_name,
        metadata_root,
        pdf_root,
        effective_keywords,
        literature_records,
        patent_records,
        [],
        [],
        [],
        [],
        dropped_literature_records,
        dropped_patent_records,
        mode,
        source_runs,
        literature_url_migration_stats,
        completion_status,
        v2_handoff,
        scheduler_metrics={},
        doi_cache_summary=doi_cache_summary,
        doi_cache_runtime_metrics={},
        expected_source_keys=expected_source_keys,
    )
    print_summary(
        literature_records,
        patent_records,
        literature_path,
        patent_path,
        [],
        [],
        [],
        [],
        dropped_literature_records,
        dropped_patent_records,
        literature_url_migration_stats,
    )
    print(f"Search report: {report_path.resolve()}")
    print(f"Handoff manifest: {v2_handoff['manifest_path']}")
    if should_run_download_after_search(args, completion_status):
        download_exit = run_download_after_search(
            args, batch_name, metadata_root, pdf_root
        )
        workflow_path, _, overall_exit = write_combined_workflow_report(
            batch_name=batch_name,
            metadata_root=metadata_root,
            pdf_root=pdf_root,
            search_status=completion_status,
            download_requested=True,
            download_executed=True,
            download_exit_code=download_exit,
        )
        print(f"Workflow report: {workflow_path.resolve()}")
        return overall_exit
    if args.download_after_search and completion_status != "complete":
        print(
            "Download-after-search was skipped because search status is "
            f"{completion_status}; use --download-on-partial only for partial runs."
        )
        workflow_path, _, overall_exit = write_combined_workflow_report(
            batch_name=batch_name,
            metadata_root=metadata_root,
            pdf_root=pdf_root,
            search_status=completion_status,
            download_requested=True,
            download_executed=False,
        )
        print(f"Workflow report: {workflow_path.resolve()}")
        return overall_exit
    return search_completion_exit_code(completion_status)


async def async_main(argv: list[str] | None = None) -> int:
    SEARCH_FAILURE_CONTEXT.clear()
    argv = list(sys.argv[1:] if argv is None else argv)
    if argv and argv[0] == "config":
        ensure_tools_environment()
        ensure_config_file()
        return handle_config_command(argv[1:])
    args = parse_search_args(argv)
    apply_environment_timeout_args(args)
    if args.channel_inventory:
        print_search_channel_inventory()
        return 0
    if args.prepare_runtime:
        environment_report = ensure_tools_environment()
        payload = {
            "ok": True,
            "prepared_runtime": True,
            "venv": str(VENV_DIR),
            "playwright_browsers": str(PLAYWRIGHT_DIR),
            "chromium_installed": chromium_installed(),
            "environment": {
                "command_timeout_seconds": environment_command_timeout_seconds(),
                "lock_timeout_seconds": environment_lock_timeout_seconds(),
                "lock_path": str(environment_lock_path()),
            },
            "environment_report": environment_report,
        }
        print(json.dumps(payload, ensure_ascii=False, indent=2))
        return 0
    metadata_root = as_path(args.metadata_root)
    pdf_root = as_path(args.pdf_root)
    keywords = resolve_keywords_from_args(args, allow_prompt=not args.status and not args.materialize_checkpoint)
    batch_name = resolve_batch_name(args, keywords)
    mode = "literature" if args.literature_only else "patents" if args.patents_only else "all"
    SEARCH_FAILURE_CONTEXT.update(
        {
            "batch_name": batch_name,
            "metadata_root": metadata_root,
            "pdf_root": pdf_root,
            "keywords": list(keywords),
            "mode": mode,
            "stage": "initialization",
        }
    )
    if args.status:
        print_search_status(batch_name, metadata_root)
        return 0
    if args.materialize_checkpoint:
        return materialize_search_checkpoint(args, batch_name, metadata_root, pdf_root, keywords)
    if not keywords:
        print("No valid keywords were provided.", file=sys.stderr)
        return 2

    SEARCH_FAILURE_CONTEXT["stage"] = "environment_bootstrap"
    ensure_tools_environment()
    ensure_local_git_repository()
    ensure_config_file()
    validate_source_policies()
    try:
        load_project_dotenv_into_env()
        load_api_user_config_into_env()
        config = validate_config(load_config())
    except (TypeError, ValueError) as exc:
        print(f"Invalid search configuration: {safe_error_text(str(exc))}", file=sys.stderr)
        return 2
    if not config.valid_path:
        print(
            "Invalid search configuration: path must be 'institution' or 'personal'.",
            file=sys.stderr,
        )
        return 2
    try:
        page_size = resolve_page_size(args)
        doi_cache_ttl_seconds("positive")
        doi_cache_ttl_seconds("negative")
        configured_scheduler_workers = positive_int_environment(
            "LAPS_SEARCH_QUEUE_WORKERS",
            max(
                1,
                min(config.thread_num, DEFAULT_SEARCH_QUEUE_MAX_WORKERS),
            ),
        )
        positive_int_environment(
            "LAPS_SEARCH_QUEUE_MAXSIZE",
            configured_scheduler_workers * 2,
        )
        materialize_every_pages, materialize_every_seconds, incremental_enabled = (
            resolve_incremental_materialization(args)
        )
        selected_literature_sources = exact_source_selection(args.literature_source, literature_search_path_map, "literature")
        selected_patent_sources = exact_source_selection(args.patent_source, patents_search_path_map, "patent")
        allowed_cost_sources = exact_source_selection(args.allow_cost_source, patents_search_path_map, "cost")
    except ValueError as exc:
        print(safe_error_text(str(exc)), file=sys.stderr)
        return 2
    invalid_cost_sources = allowed_cost_sources - {"Google BigQuery"}
    if invalid_cost_sources:
        print(f"Source is not classified as cost-bearing: {', '.join(sorted(invalid_cost_sources))}", file=sys.stderr)
        return 2
    skipped_sources: list[SkippedSource] = []
    degraded_sources: list[DegradedSource] = []
    browser_disabled_sources: list[BrowserDisabledSource] = []
    restricted_auth_sources: list[RestrictedAuthSource] = []
    literature_path, patent_path = output_paths(batch_name=batch_name, metadata_root=metadata_root)
    literature_url_migration_stats: dict[str, int] = {}
    existing_literature = (
        []
        if args.force and not args.patents_only
        else read_literature_records(
            literature_path,
            migration_stats=literature_url_migration_stats,
        )
    )
    existing_patents = [] if args.force and not args.literature_only else read_patent_records(patent_path)
    config_fingerprint = search_config_fingerprint(config, page_size=page_size)
    expected_source_keys = expected_search_source_keys(
        keywords=keywords,
        include_literature=not args.patents_only,
        include_patents=not args.literature_only,
        literature_sources=(
            selected_literature_sources or literature_search_path_map.keys()
        ),
        patent_sources=(selected_patent_sources or patents_search_path_map.keys()),
    )
    SEARCH_FAILURE_CONTEXT["stage"] = "search_execution"
    with SearchStateStore(search_state_path(batch_name, metadata_root)) as state_store:
        if args.refresh or args.force:
            if not args.patents_only:
                state_store.reset(
                    "literature",
                    selected_literature_sources or None,
                    clear_occurrences=args.force,
                )
            if not args.literature_only:
                state_store.reset(
                    "patent",
                    selected_patent_sources or None,
                    clear_occurrences=args.force,
                )
        # This transaction precedes the producer/worker queue so a process
        # interruption cannot silently erase never-started source jobs from a
        # later checkpoint report.
        state_store.replace_requested_source_scope(
            expected_source_keys,
            config_fingerprint,
        )
        async with build_httpx_client() as client:
            runtime = SearchRuntime(
                config=config,
                client=client,
                skipped_sources=skipped_sources,
                degraded_sources=degraded_sources,
                browser_disabled_sources=browser_disabled_sources,
                restricted_auth_sources=restricted_auth_sources,
                global_sem=asyncio.Semaphore(config.thread_num),
                state_store=state_store,
                config_fingerprint=config_fingerprint,
                allowed_cost_sources=allowed_cost_sources,
            )
            materializer = IncrementalMaterializer(
                state_store=state_store,
                batch_name=batch_name,
                metadata_root=metadata_root,
                baseline_literature=list(existing_literature),
                baseline_patents=list(existing_patents),
                every_pages=materialize_every_pages,
                every_seconds=materialize_every_seconds,
                enabled=incremental_enabled,
            )
            runtime.materializer = materializer
            literature_task = collect_literature(
                runtime,
                keywords,
                page_size,
                existing_literature_resume_index(existing_literature),
                selected_literature_sources or None,
                literature_url_migration_stats,
            ) if not args.patents_only else None
            patent_task = collect_patents(
                runtime,
                keywords,
                page_size,
                existing_patent_urls(existing_patents),
                selected_patent_sources or None,
            ) if not args.literature_only else None
            if literature_task is not None and patent_task is not None:
                new_literature, new_patents = await asyncio.gather(literature_task, patent_task)
            elif literature_task is not None:
                new_literature = await literature_task
                new_patents = []
            elif patent_task is not None:
                new_literature = []
                new_patents = await patent_task
            else:
                new_literature, new_patents = [], []
            source_runs = selected_search_source_runs(
                state_store.summary(),
                keywords=keywords,
                include_literature=not args.patents_only,
                include_patents=not args.literature_only,
                literature_sources=selected_literature_sources or None,
                patent_sources=selected_patent_sources or None,
                config_fingerprint=config_fingerprint,
            )
            completion_status = search_completion_status(
                source_runs,
                expected_source_keys,
            )
            await materializer.final_flush(completion_status)
            canonical_state_records = canonical_records_from_state_store(
                state_store
            )
            scheduler_metrics = {
                name: dict(value)
                for name, value in runtime.scheduler_metrics.items()
            }
            doi_cache_summary = state_store.doi_enrichment_cache_summary()
            doi_cache_runtime_metrics = dict(
                runtime.doi_enrichment_cache_metrics
            )
    SEARCH_FAILURE_CONTEXT["stage"] = "legacy_materialization"
    literature_with_locator, dropped_literature_records = (
        split_literature_records_by_required_locator(
            [*existing_literature, *new_literature]
        )
    )
    patents_with_url, dropped_patent_records = split_patent_records_by_required_url([*existing_patents, *new_patents])
    literature_records = dedupe_literature_records(literature_with_locator)
    patent_records = dedupe_patent_records(patents_with_url)
    literature_path, patent_path = write_outputs(literature_records, patent_records, batch_name=batch_name, metadata_root=metadata_root)
    SEARCH_FAILURE_CONTEXT["stage"] = "canonical_v2_materialization"
    try:
        v2_handoff = materialize_v2_handoff(
            [
                *canonical_state_records,
                *(
                    canonical_record_from_search_record(record)
                    for record in [*existing_literature, *new_literature]
                ),
                *(
                    canonical_record_from_search_record(record)
                    for record in [*existing_patents, *new_patents]
                ),
            ],
            batch_name=batch_name,
            metadata_root=metadata_root,
            search_status=completion_status,
            legacy_literature_count=len(literature_records),
            legacy_patent_count=len(patent_records),
        )
    except Exception as exc:
        write_search_fatal_report(
            batch_name=batch_name,
            metadata_root=metadata_root,
            pdf_root=pdf_root,
            stage="canonical_v2_materialization",
            exc=exc,
            keywords=keywords,
            mode=mode,
        )
        print(
            f"Canonical v2 materialization failed: {safe_error_text(str(exc))}",
            file=sys.stderr,
        )
        return 1
    SEARCH_FAILURE_CONTEXT["stage"] = "search_report"
    report_path = write_search_report(
        batch_name,
        metadata_root,
        pdf_root,
        keywords,
        literature_records,
        patent_records,
        skipped_sources,
        degraded_sources,
        browser_disabled_sources,
        restricted_auth_sources,
        dropped_literature_records,
        dropped_patent_records,
        mode,
        source_runs,
        literature_url_migration_stats,
        completion_status,
        v2_handoff,
        scheduler_metrics=scheduler_metrics,
        doi_cache_summary=doi_cache_summary,
        doi_cache_runtime_metrics=doi_cache_runtime_metrics,
        expected_source_keys=expected_source_keys,
    )
    print_summary(literature_records, patent_records, literature_path, patent_path, skipped_sources, degraded_sources, browser_disabled_sources, restricted_auth_sources, dropped_literature_records, dropped_patent_records, literature_url_migration_stats)
    print(f"Search report: {report_path.resolve()}")
    print(f"Handoff manifest: {v2_handoff['manifest_path']}")
    if should_run_download_after_search(args, completion_status):
        SEARCH_FAILURE_CONTEXT["stage"] = "download_after_search"
        download_exit = run_download_after_search(
            args, batch_name, metadata_root, pdf_root
        )
        workflow_path, _, overall_exit = write_combined_workflow_report(
            batch_name=batch_name,
            metadata_root=metadata_root,
            pdf_root=pdf_root,
            search_status=completion_status,
            download_requested=True,
            download_executed=True,
            download_exit_code=download_exit,
        )
        print(f"Workflow report: {workflow_path.resolve()}")
        return overall_exit
    if args.download_after_search and completion_status != "complete":
        print(
            "Download-after-search was skipped because search status is "
            f"{completion_status}; use --download-on-partial only for partial runs."
        )
        workflow_path, _, overall_exit = write_combined_workflow_report(
            batch_name=batch_name,
            metadata_root=metadata_root,
            pdf_root=pdf_root,
            search_status=completion_status,
            download_requested=True,
            download_executed=False,
        )
        print(f"Workflow report: {workflow_path.resolve()}")
        return overall_exit
    return search_completion_exit_code(completion_status)


def main() -> None:
    try:
        raise SystemExit(asyncio.run(async_main()))
    except EnvironmentBootstrapError as exc:
        context = dict(SEARCH_FAILURE_CONTEXT)
        try:
            report_path = write_search_fatal_report(
                batch_name=context.get("batch_name"),
                metadata_root=context.get("metadata_root"),
                pdf_root=context.get("pdf_root"),
                stage=first_string(context.get("stage")) or "environment_bootstrap",
                exc=exc,
                keywords=context.get("keywords") or (),
                mode=first_string(context.get("mode")) or "search",
            )
            print(f"Search report: {report_path.resolve()}", file=sys.stderr)
        except Exception as report_exc:
            print(
                "Fatal search report write failed: "
                f"{safe_error_text(str(report_exc))}",
                file=sys.stderr,
            )
        print(f"Environment bootstrap failed ({exc.reason}): {exc}", file=sys.stderr)
        raise SystemExit(1) from exc
    except Exception as exc:
        context = dict(SEARCH_FAILURE_CONTEXT)
        try:
            report_path = write_search_fatal_report(
                batch_name=context.get("batch_name"),
                metadata_root=context.get("metadata_root"),
                pdf_root=context.get("pdf_root"),
                stage=first_string(context.get("stage")) or "cli_boundary",
                exc=exc,
                keywords=context.get("keywords") or (),
                mode=first_string(context.get("mode")) or "search",
            )
            print(f"Search report: {report_path.resolve()}", file=sys.stderr)
        except Exception as report_exc:
            print(
                "Fatal search report write failed: "
                f"{safe_error_text(str(report_exc))}",
                file=sys.stderr,
            )
        print(f"Search failed: {safe_error_text(str(exc))}", file=sys.stderr)
        raise SystemExit(1) from exc


if __name__ == "__main__":
    main()
